    private enum SupervisorMemoryFactFollowUpCategory: String, CaseIterable {
        case goalAndDone = "goal_and_done"
        case decision = "decision"
        case blocker = "blocker"
        case evidence = "evidence"

        var question: String {
            switch self {
            case .goalAndDone:
                return "这个项目的长期目标和完成标准分别是什么？"
            case .decision:
                return "我们为什么走当前这条路径？关键决策和原因是什么？"
            case .blocker:
                return "现在卡在哪里，已经试过什么，下一步准备做什么？"
            case .evidence:
                return "哪些日志、结果、回执或实验可以作为这次判断的依据？"
            }
        }

        var example: String {
            switch self {
            case .goalAndDone:
                return "目标是……，完成标准是……"
            case .decision:
                return "我们决定……，原因是……"
            case .blocker:
                return "现在卡在……，已经试过……，下一步是……"
            case .evidence:
                return "证据是…… / 把……作为依据"
            }
        }

        var tailLabel: String {
            switch self {
            case .goalAndDone:
                return "长期目标和完成标准"
            case .decision:
                return "关键决策和原因"
            case .blocker:
                return "当前卡点、已试动作和下一步"
            case .evidence:
                return "判断依据"
            }
        }
    }

