    private init(
        registerForEvents: Bool = true,
        backgroundSupervisorServicesEnabled: Bool = true,
        supervisorHubGrantPreflightEnabled: Bool = true,
        supervisorEventLoopAutoFollowUpEnabled: Bool = true,
        persistSupervisorRuntimeState: Bool = true,
        allowPersistentProjectRegistryFallback: Bool = true,
        supervisorCalendarReminderStateStore: SupervisorCalendarReminderStateStore? = nil,
        supervisorPersonalMemoryStore: SupervisorPersonalMemoryStore? = nil,
        supervisorPersonalReviewStore: SupervisorPersonalReviewNoteStore? = nil,
        supervisorCrossLinkStore: SupervisorCrossLinkStore? = nil,
        supervisorSpeechSynthesizer: SupervisorSpeechSynthesizer? = nil,
        conversationSessionController: SupervisorConversationSessionController? = nil,
        voiceSessionCoordinator: VoiceSessionCoordinator? = nil
    ) {
        self.supervisorCalendarReminderStateStore = supervisorCalendarReminderStateStore ?? .shared
        self.supervisorPersonalMemoryStore = supervisorPersonalMemoryStore ?? .shared
        self.supervisorPersonalReviewStore = supervisorPersonalReviewStore ?? .shared
        self.supervisorCrossLinkStore = supervisorCrossLinkStore ?? .shared
        self.voiceSessionCoordinator = voiceSessionCoordinator ?? VoiceSessionCoordinator.shared
        self.conversationSessionController = conversationSessionController ?? SupervisorConversationSessionController.shared
        let voicePackInventoryResolver: () -> [HubModel] = {
            HubModelManager.shared.availableModels
        }
        self.supervisorSpeechSynthesizer = supervisorSpeechSynthesizer ?? SupervisorSpeechSynthesizer(
            hubVoicePackSpeakSink: { lines, preferences, playbackResolution in
                guard playbackResolution.resolvedSource == .hubVoicePack else {
                    return .unavailable(reasonCode: "hub_voice_pack_not_selected", detail: "")
                }
                let preferredModelID = playbackResolution.resolvedHubVoicePackID
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                guard !preferredModelID.isEmpty else {
                    return .unavailable(reasonCode: "hub_voice_pack_missing_id", detail: "")
                }

                let text = lines
                    .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
                    .filter { !$0.isEmpty }
                    .joined(separator: "\n")
                guard !text.isEmpty else {
                    return .unavailable(reasonCode: "hub_voice_pack_empty_text", detail: "")
                }

                let result = HubIPCClient.synthesizeVoiceViaLocalHub(
                    preferredModelID: preferredModelID,
                    text: text,
                    localeIdentifier: preferences.localeIdentifier,
                    voiceColor: preferences.timbre.rawValue,
                    speechRate: Double(preferences.speechRateMultiplier),
                    timeoutSec: 1.5
                )
                guard result.ok, let audioFilePath = result.audioFilePath else {
                    return .unavailable(
                        reasonCode: result.reasonCode ?? result.runtimeReasonCode ?? result.error ?? "hub_voice_pack_runtime_failed",
                        detail: result.detail ?? ""
                    )
                }
                guard HubVoicePackAudioPlayback.playFile(atPath: audioFilePath) else {
                    return .unavailable(
                        reasonCode: "hub_voice_pack_audio_playback_failed",
                        detail: audioFilePath
                    )
                }
                return .spoken(
                    VoicePlaybackDeliveryMetadata(
                        actualSource: .hubVoicePack,
                        provider: result.provider ?? "",
                        modelID: result.modelId ?? preferredModelID,
                        engineName: result.engineName ?? "",
                        speakerId: result.speakerId ?? "",
                        deviceBackend: result.deviceBackend ?? "",
                        nativeTTSUsed: result.nativeTTSUsed,
                        fallbackMode: result.fallbackMode ?? "",
                        fallbackReasonCode: result.fallbackReasonCode ?? "",
                        audioFormat: result.audioFormat ?? "",
                        voiceName: result.voiceName ?? "",
                        reasonCode: result.reasonCode ?? "hub_voice_pack_played",
                        detail: result.detail ?? "",
                        auditLine: result.ttsAuditLine ?? ""
                    )
                )
            },
            playbackResolutionResolver: { preferences in
                SupervisorSpeechPlaybackRouting.resolve(
                    preferences: preferences,
                    availableModels: voicePackInventoryResolver(),
                    voicePackReadyEvaluator: { modelID in
                        HubIPCClient.isLocalHubVoicePackPlaybackAvailable(
                            preferredModelID: modelID
                        )
                    }
                )
            },
            hubVoicePackReadinessEvaluator: { preferences in
                HubIPCClient.isLocalHubVoicePackPlaybackAvailable(
                    preferredModelID: preferences.preferredHubVoicePackID
                )
            },
            hubVoicePackInterruptSink: {
                HubVoicePackAudioPlayback.stop()
            }
        )
        self.backgroundSupervisorServicesEnabled = backgroundSupervisorServicesEnabled
        self.supervisorHubGrantPreflightEnabled = supervisorHubGrantPreflightEnabled
        self.supervisorEventLoopAutoFollowUpEnabled = supervisorEventLoopAutoFollowUpEnabled
        self.persistSupervisorRuntimeState = persistSupervisorRuntimeState
        self.allowPersistentProjectRegistryFallback = allowPersistentProjectRegistryFallback
        self.supervisorSpeechSynthesizer.playbackActivitySink = { [weak self] activity in
            self?.applyVoicePlaybackActivity(activity)
        }
        loadEscalationPolicyFromDefaults()
        if persistSupervisorRuntimeState {
            supervisorJurisdictionRegistry = SupervisorJurisdictionRegistryStore.load()
            loadActionLedgerFromDisk()
            loadRuntimeStateFromDisk()
        } else {
            supervisorJurisdictionRegistry = .ownerDefault()
        }
        bindVoiceRuntime()
        bindConversationSession()
        if registerForEvents {
            setupEventListeners()
        }
    }

    static func makeForTesting(
        enableSupervisorHubGrantPreflight: Bool = false,
        enableSupervisorEventLoopAutoFollowUp: Bool = false,
        backgroundSupervisorServicesEnabled: Bool = false,
        persistSupervisorRuntimeState: Bool = false,
        supervisorCalendarReminderStateStore: SupervisorCalendarReminderStateStore? = nil,
        supervisorPersonalMemoryStore: SupervisorPersonalMemoryStore? = nil,
        supervisorPersonalReviewStore: SupervisorPersonalReviewNoteStore? = nil,
        supervisorCrossLinkStore: SupervisorCrossLinkStore? = nil,
        supervisorSpeechSynthesizer: SupervisorSpeechSynthesizer? = nil,
        conversationSessionController: SupervisorConversationSessionController? = nil,
        voiceSessionCoordinator: VoiceSessionCoordinator? = nil
    ) -> SupervisorManager {
        SupervisorManager(
            registerForEvents: false,
            backgroundSupervisorServicesEnabled: backgroundSupervisorServicesEnabled,
            supervisorHubGrantPreflightEnabled: enableSupervisorHubGrantPreflight,
            supervisorEventLoopAutoFollowUpEnabled: enableSupervisorEventLoopAutoFollowUp,
            persistSupervisorRuntimeState: persistSupervisorRuntimeState,
            allowPersistentProjectRegistryFallback: false,
            supervisorCalendarReminderStateStore: supervisorCalendarReminderStateStore,
            supervisorPersonalMemoryStore: supervisorPersonalMemoryStore,
            supervisorPersonalReviewStore: supervisorPersonalReviewStore,
            supervisorCrossLinkStore: supervisorCrossLinkStore,
            supervisorSpeechSynthesizer: supervisorSpeechSynthesizer,
            conversationSessionController: conversationSessionController,
            voiceSessionCoordinator: voiceSessionCoordinator
        )
    }

    var blockerEscalationCooldownMinutes: Int {
        Int(max(1, round(blockerEscalationCooldownSec / 60.0)))
    }

    func setBlockerEscalationThreshold(_ value: Int) {
        let normalized = normalizedEscalationThreshold(value)
        blockerEscalationThreshold = normalized
        UserDefaults.standard.set(normalized, forKey: escalationThresholdDefaultsKey)
        UserDefaults.standard.set(normalized, forKey: legacyEscalationThresholdDefaultsKey)
    }

    func setBlockerEscalationCooldownMinutes(_ value: Int) {
        let normalized = normalizedEscalationCooldownMinutes(value)
        blockerEscalationCooldownSec = Double(normalized) * 60.0
        UserDefaults.standard.set(normalized, forKey: escalationCooldownMinutesDefaultsKey)
        UserDefaults.standard.set(normalized, forKey: legacyEscalationCooldownMinutesDefaultsKey)
    }

    func resetBlockerEscalationPolicyToDefaults() {
        setBlockerEscalationThreshold(Self.defaultsThreshold)
        setBlockerEscalationCooldownMinutes(Self.defaultsCooldownMinutes)
    }

    func setAppModel(_ appModel: AppModel) {
        self.appModel = appModel
        modelManager.setAppModel(appModel)
        appModelCancellables.removeAll()
        supervisorOfficialSkillsChannelBaselineCaptured = false
        supervisorOfficialSkillsChannelLastTransitionFingerprint = ""
        supervisorOfficialSkillsChannelLastDegradedFollowUpStatus = ""
        supervisorOfficialSkillsChannelStatusLine = ""
        supervisorOfficialSkillsChannelTransitionLine = ""
        supervisorOfficialSkillsChannelDetailLine = ""
        supervisorOfficialSkillsChannelTopBlockersLine = ""
        supervisorOfficialSkillsChannelTopBlockerSummaries = []
        appModel.settingsStore.$settings
            .sink { [weak self] settings in
                self?.updateConversationSessionPolicy(using: settings.voice)
                self?.refreshSupervisorPersonaStatusLine()
                self?.refreshWakeProfileStatus()
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &appModelCancellables)
        appModel.$hubConnected
            .sink { [weak self] _ in
                self?.refreshWakeProfileStatus()
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &appModelCancellables)
        appModel.$hubRemoteConnected
            .sink { [weak self] _ in
                self?.refreshWakeProfileStatus()
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &appModelCancellables)
        appModel.$hubRemoteRoute
            .sink { [weak self] _ in
                self?.refreshWakeProfileStatus()
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &appModelCancellables)
        appModel.$hubRemoteLinking
            .sink { [weak self] _ in
                self?.refreshWakeProfileStatus()
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &appModelCancellables)
        appModel.$hubPairingPort
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$hubGrpcPort
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$hubInternetHost
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$runtimeStatus
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$modelsState
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$bridgeAlive
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$bridgeEnabled
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$selectedProjectId
            .sink { [weak self] _ in self?.refreshVoiceReadinessSnapshot() }
            .store(in: &appModelCancellables)
        appModel.$registry
            .sink { [weak self] _ in
                guard let self else { return }
                self.rebuildPendingSupervisorSkillApprovalViewState()
                Task { @MainActor in
                    await self.refreshSupervisorMemorySnapshot(reason: "registry_changed")
                }
            }
            .store(in: &appModelCancellables)
        appModel.$skillsCompatibilitySnapshot
            .sink { [weak self] snapshot in
                guard let self else { return }
                self.handleOfficialSkillsChannelSnapshot(snapshot)
            }
            .store(in: &appModelCancellables)
        updateConversationSessionPolicy(using: appModel.settingsStore.settings.voice)
        refreshSupervisorPersonaStatusLine()
        refreshWakeProfileStatus()
        refreshVoiceReadinessSnapshot()
        if backgroundSupervisorServicesEnabled {
            restartHeartbeatTimer()
            restartSchedulerPollTimer()
            Task { @MainActor in
                await refreshSchedulerSnapshot(force: true)
            }
        }
        _ = runSupervisorDoctorPreflight(reason: "app_model_attached", emitSystemMessage: false)
        if backgroundSupervisorServicesEnabled {
            emitHeartbeatIfNeeded(force: true, reason: "app_model_attached")
        }
        rebuildPendingSupervisorSkillApprovalViewState()
        Task { @MainActor in
            await refreshSupervisorMemorySnapshot(reason: "app_model_attached")
        }
    }

    private func handleOfficialSkillsChannelSnapshot(_ snapshot: AXSkillsDoctorSnapshot) {
        let statusLine = composeSupervisorOfficialSkillsChannelStatusLine(for: snapshot)
        let transitionLine = composeSupervisorOfficialSkillsChannelTransitionLine(for: snapshot)
        let detailLine = composeSupervisorOfficialSkillsChannelDetailLine(for: snapshot)
        let topBlockersLine = composeSupervisorOfficialSkillsChannelTopBlockersLine(for: snapshot)
        let topBlockerSummaries = snapshot.officialPackageLifecycleTopBlockerSummaries
        let transitionFingerprint = composeSupervisorOfficialSkillsChannelTransitionFingerprint(for: snapshot)
        let previousStatusLine = supervisorOfficialSkillsChannelStatusLine
        let statusLineChanged = statusLine != supervisorOfficialSkillsChannelStatusLine
        let transitionLineChanged = transitionLine != supervisorOfficialSkillsChannelTransitionLine
        let detailLineChanged = detailLine != supervisorOfficialSkillsChannelDetailLine
        let topBlockersLineChanged = topBlockersLine != supervisorOfficialSkillsChannelTopBlockersLine
        let topBlockerSummariesChanged = topBlockerSummaries != supervisorOfficialSkillsChannelTopBlockerSummaries
        let statusChanged = statusLineChanged
            || transitionLineChanged
            || detailLineChanged
            || topBlockersLineChanged
            || topBlockerSummariesChanged
        let degradedFollowUp = shouldScheduleSupervisorOfficialSkillsChannelFollowUp(
            snapshot,
            previousStatusLine: previousStatusLine,
            transitionFingerprint: transitionFingerprint
        )
        if officialSkillsChannelHasExplicitHealthyStatus(snapshot) {
            supervisorOfficialSkillsChannelLastDegradedFollowUpStatus = ""
        }

        supervisorOfficialSkillsChannelStatusLine = statusLine
        supervisorOfficialSkillsChannelTransitionLine = transitionLine
        supervisorOfficialSkillsChannelDetailLine = detailLine
        supervisorOfficialSkillsChannelTopBlockersLine = topBlockersLine
        supervisorOfficialSkillsChannelTopBlockerSummaries = topBlockerSummaries

        if !supervisorOfficialSkillsChannelBaselineCaptured {
            supervisorOfficialSkillsChannelBaselineCaptured = true
            supervisorOfficialSkillsChannelLastTransitionFingerprint = transitionFingerprint
            if degradedFollowUp {
                scheduleSupervisorOfficialSkillsChannelFollowUp(snapshot)
            }
            if statusChanged {
                Task { @MainActor in
                    await refreshSupervisorMemorySnapshot(reason: "official_skills_channel_baseline")
                }
            }
            return
        }

        let transitionChanged = !transitionFingerprint.isEmpty
            && transitionFingerprint != supervisorOfficialSkillsChannelLastTransitionFingerprint
        supervisorOfficialSkillsChannelLastTransitionFingerprint = transitionFingerprint

        if transitionChanged {
            appendRecentEvent("official skills channel: \(transitionLine)")
        }
        if degradedFollowUp {
            scheduleSupervisorOfficialSkillsChannelFollowUp(snapshot)
        }

        guard statusChanged || transitionChanged else { return }
        Task { @MainActor in
            await refreshSupervisorMemorySnapshot(
                reason: transitionChanged
                    ? "official_skills_channel_transition"
                    : "official_skills_channel_status"
            )
        }
    }

    private func composeSupervisorOfficialSkillsChannelStatusLine(
        for snapshot: AXSkillsDoctorSnapshot
    ) -> String {
        snapshot.officialChannelSummaryLine
    }

    private func composeSupervisorOfficialSkillsChannelTransitionLine(
        for snapshot: AXSkillsDoctorSnapshot
    ) -> String {
        let summary = snapshot.officialChannelLastTransitionSummary
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !summary.isEmpty else { return "" }
        let kind = snapshot.officialChannelLastTransitionKind
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !kind.isEmpty else { return summary }
        return "\(kind): \(summary)"
    }

    private func composeSupervisorOfficialSkillsChannelDetailLine(
        for snapshot: AXSkillsDoctorSnapshot
    ) -> String {
        let detail = snapshot.officialChannelDetailLine.trimmingCharacters(in: .whitespacesAndNewlines)
        let transitionSummary = snapshot.officialChannelLastTransitionSummary
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !detail.isEmpty else { return "" }
        if !transitionSummary.isEmpty, detail == "transition=\(transitionSummary)" {
            return ""
        }
        return detail
    }

    private func composeSupervisorOfficialSkillsChannelTopBlockersLine(
        for snapshot: AXSkillsDoctorSnapshot
    ) -> String {
        snapshot.officialChannelTopBlockersLine.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func composeSupervisorOfficialSkillsChannelTransitionFingerprint(
        for snapshot: AXSkillsDoctorSnapshot
    ) -> String {
        let summary = snapshot.officialChannelLastTransitionSummary
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !summary.isEmpty else { return "" }
        let atMs = max(0, snapshot.officialChannelLastTransitionAtMs)
        let kind = snapshot.officialChannelLastTransitionKind
            .trimmingCharacters(in: .whitespacesAndNewlines)
        return "\(atMs)|\(kind)|\(summary)"
    }

    private func shouldScheduleSupervisorOfficialSkillsChannelFollowUp(
        _ snapshot: AXSkillsDoctorSnapshot,
        previousStatusLine: String,
        transitionFingerprint: String
    ) -> Bool {
        guard supervisorEventLoopAutoFollowUpEnabled || supervisorEventLoopResponseOverride != nil else {
            return false
        }
        let nextDegraded = officialSkillsChannelStatusIsDegraded(snapshot)
        guard nextDegraded else { return false }
        let nextStatusToken = snapshot.officialChannelStatus.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let previousDegraded = officialSkillsChannelStatusLineIsDegraded(previousStatusLine)
        if !transitionFingerprint.isEmpty {
            return transitionFingerprint != supervisorOfficialSkillsChannelLastTransitionFingerprint
        }
        if supervisorOfficialSkillsChannelLastDegradedFollowUpStatus == nextStatusToken {
            return false
        }
        return !previousDegraded
    }

    private func officialSkillsChannelStatusIsDegraded(_ snapshot: AXSkillsDoctorSnapshot) -> Bool {
        let status = snapshot.officialChannelStatus.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        return status == "failed" || status == "missing"
    }

    private func officialSkillsChannelHasExplicitHealthyStatus(_ snapshot: AXSkillsDoctorSnapshot) -> Bool {
        let status = snapshot.officialChannelStatus.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        guard !status.isEmpty else { return false }
        return status != "failed" && status != "missing"
    }

    private func officialSkillsChannelStatusLineIsDegraded(_ statusLine: String) -> Bool {
        let normalized = statusLine.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        return normalized.contains(" official failed")
            || normalized.contains(" official missing")
            || normalized.hasPrefix("official failed")
            || normalized.hasPrefix("official missing")
    }

    private func scheduleSupervisorOfficialSkillsChannelFollowUp(
        _ snapshot: AXSkillsDoctorSnapshot
    ) {
        let status = snapshot.officialChannelStatus.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !status.isEmpty else { return }
        supervisorOfficialSkillsChannelLastDegradedFollowUpStatus = status.lowercased()

        let transitionKind = snapshot.officialChannelLastTransitionKind
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let transitionSummary = snapshot.officialChannelLastTransitionSummary
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let error = snapshot.officialChannelErrorCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let maintenanceSourceKind = snapshot.officialChannelMaintenanceSourceKind
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let channelId = snapshot.officialChannelID.trimmingCharacters(in: .whitespacesAndNewlines)
        let summary = capped(
            [
                status,
                transitionKind.isEmpty
                    ? transitionSummary
                    : "\(transitionKind): \(transitionSummary)",
                error.isEmpty ? "" : "err=\(error)"
            ]
            .filter { !$0.isEmpty }
            .joined(separator: " · "),
            maxChars: 220
        )
        let dedupeStatus = status.lowercased()
        let dedupeTransition = transitionKind.isEmpty ? "status_only" : transitionKind.lowercased()
        let dedupeAtMs = max(
            0,
            max(snapshot.officialChannelLastTransitionAtMs, snapshot.officialChannelUpdatedAtMs)
        )
        let lines = [
            "自动跟进官方 skills channel 降级事件。",
            "trigger=\(SupervisorCommandTriggerSource.officialSkillsChannel.rawValue)",
            "project_ref=Official Skills Channel",
            "channel_id=\(channelId.isEmpty ? "official" : channelId)",
            "channel_status=\(status)",
            "skill_count=\(max(0, snapshot.officialChannelSkillCount))",
            "maintenance_enabled=\(snapshot.officialChannelMaintenanceEnabled)",
            "maintenance_source_kind=\(maintenanceSourceKind.isEmpty ? "(none)" : maintenanceSourceKind)",
            "transition_kind=\(transitionKind.isEmpty ? "(none)" : transitionKind)",
            "transition_summary=\(transitionSummary.isEmpty ? "(none)" : transitionSummary)",
            "reason_code=official_skills_channel_\(dedupeStatus)",
            "review_trigger=\(SupervisorReviewTrigger.blockerDetected.rawValue)",
            "review_level_hint=\(SupervisorReviewLevel.r2Strategic.rawValue)",
            "review_run_kind=\(SupervisorReviewRunKind.eventDriven.rawValue)",
            "policy_reason=official_channel_status_degraded",
            "summary=\(summary.isEmpty ? "official skills channel degraded" : summary)"
        ] + (error.isEmpty ? [] : ["error_code=\(error)"])

        queueSupervisorEventLoopTurn(
            userMessage: lines.joined(separator: "\n"),
            triggerSource: .officialSkillsChannel,
            dedupeKey: "official_skills_channel:\(dedupeStatus):\(dedupeTransition):\(dedupeAtMs)"
        )
    }

    private func setupEventListeners() {
        eventBus.eventPublisher
            .sink { [weak self] event in
                self?.handleEvent(event)
            }
            .store(in: &cancellables)
    }

    private func bindVoiceRuntime() {
        voiceRuntimeState = voiceSessionCoordinator.runtimeState
        voiceRouteDecision = voiceSessionCoordinator.routeDecision
        voiceAuthorizationStatus = voiceSessionCoordinator.authorizationStatus
        voicePermissionSnapshot = voiceSessionCoordinator.permissionSnapshot
        voiceActiveHealthReasonCode = voiceSessionCoordinator.activeHealthReasonCode ?? ""
        voiceFunASRSidecarHealth = voiceSessionCoordinator.funASRSidecarHealth
        voiceWakeProfileSnapshot = voiceWakeProfileStore.snapshot
        updateConversationSessionPolicy(using: currentVoicePreferences())

        voiceWakeProfileStore.$snapshot
            .sink { [weak self] snapshot in
                self?.voiceWakeProfileSnapshot = snapshot
                self?.updateConversationSessionPolicy(using: self?.currentVoicePreferences() ?? .default())
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &cancellables)

        voiceSessionCoordinator.$runtimeState
            .sink { [weak self] state in
                self?.voiceRuntimeState = state
                self?.interruptSupervisorPlaybackIfNeeded(for: state)
                if state.state == .failClosed {
                    self?.conversationSessionController.registerRouteFailClosed(reasonCode: state.reasonCode)
                }
                self?.refreshVoiceReadinessSnapshot()
                self?.flushPendingSupervisorSkillApprovalVoiceAnnouncementBacklogIfNeeded()
            }
            .store(in: &cancellables)

        voiceSessionCoordinator.$routeDecision
            .sink { [weak self] decision in
                self?.voiceRouteDecision = decision
                self?.updateConversationSessionPolicy(using: self?.currentVoicePreferences() ?? .default())
                self?.refreshVoiceReadinessSnapshot()
                self?.flushPendingSupervisorSkillApprovalVoiceAnnouncementBacklogIfNeeded()
            }
            .store(in: &cancellables)

        voiceSessionCoordinator.$authorizationStatus
            .sink { [weak self] status in
                self?.voiceAuthorizationStatus = status
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &cancellables)

        voiceSessionCoordinator.$permissionSnapshot
            .sink { [weak self] snapshot in
                self?.voicePermissionSnapshot = snapshot
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &cancellables)

        voiceSessionCoordinator.$activeHealthReasonCode
            .sink { [weak self] reason in
                self?.voiceActiveHealthReasonCode = reason ?? ""
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &cancellables)

        voiceSessionCoordinator.$funASRSidecarHealth
            .sink { [weak self] snapshot in
                self?.voiceFunASRSidecarHealth = snapshot
                self?.refreshVoiceReadinessSnapshot()
            }
            .store(in: &cancellables)

        voiceSessionCoordinator.$lastWakeEvent
            .compactMap { $0 }
            .sink { [weak self] event in
                self?.handleVoiceWakeEvent(event)
            }
            .store(in: &cancellables)
    }

    private func bindConversationSession() {
        conversationSessionSnapshot = conversationSessionController.snapshot

        conversationSessionController.$snapshot
            .sink { [weak self] snapshot in
                self?.conversationSessionSnapshot = snapshot
                self?.refreshVoiceReadinessSnapshot()
                self?.flushPendingSupervisorSkillApprovalVoiceAnnouncementBacklogIfNeeded()
            }
            .store(in: &cancellables)
    }

    private func updateConversationSessionPolicy(using preferences: VoiceRuntimePreferences) {
        conversationSessionController.configure(
            policy: .default(),
            wakeMode: resolvedConversationWakeMode(for: preferences),
            route: voiceRouteDecision.route
        )
    }

    private func resolvedConversationWakeMode(for preferences: VoiceRuntimePreferences) -> VoiceWakeMode {
        if preferences.wakeMode == .pushToTalk {
            return .pushToTalk
        }
        return voiceWakeProfileSnapshot.effectiveWakeMode
    }

    private func currentVoicePreferences(personaSlot: SupervisorPersonaSlot? = nil) -> VoiceRuntimePreferences {
        xtVoicePreferencesApplyingPersonaOverlay(
            appModel?.settingsStore.settings.voice ?? .default(),
            personaSlot: personaSlot ?? currentSupervisorExecutionPersona()
        )
    }

    func effectiveVoicePreferencesForDiagnostics() -> VoiceRuntimePreferences {
        currentVoicePreferences()
    }

    private func currentWakeProfilePairingReady() -> Bool {
        guard let appModel else { return false }
        return appModel.hubConnected || appModel.hubRemoteConnected
    }

    private func refreshWakeProfileStatus() {
        let preferences = currentVoicePreferences()
        voiceSessionCoordinator.setPreferences(preferences)
        voiceWakeProfileStore.applyPreferences(preferences)
        Task { @MainActor [weak self] in
            guard let self else { return }
            await self.voiceWakeProfileStore.refresh(pairingReady: self.currentWakeProfilePairingReady())
        }
    }

    private func interruptSupervisorPlaybackIfNeeded(for state: SupervisorVoiceRuntimeState) {
        guard currentVoicePreferences().interruptOnSpeech else { return }
        switch state.state {
        case .listening, .transcribing:
            cancelPendingTalkLoopResume()
            _ = supervisorSpeechSynthesizer.interruptCurrentPlayback()
        case .idle, .completed, .failClosed:
            break
        }
    }

    private func interruptSupervisorPlaybackForWakeEventIfNeeded() {
        guard currentVoicePreferences().interruptOnSpeech else { return }
        cancelPendingTalkLoopResume()
        _ = supervisorSpeechSynthesizer.interruptCurrentPlayback()
    }

    @discardableResult
    func previewSupervisorVoicePlayback() -> SupervisorSpeechSynthesizer.Outcome {
        var preferences = currentVoicePreferences()
        preferences.autoReportMode = .full
        preferences.quietHours.enabled = false

        let locale = VoiceSupportedLocale(rawValue: preferences.localeIdentifier) ?? .chineseMainland
        let speedLabel = String(format: "%.2fx", preferences.speechRateMultiplier)
        let playbackResolution = supervisorSpeechSynthesizer.playbackResolution(for: preferences)
        let selectedVoicePackTitle: String? = {
            guard playbackResolution.resolvedSource == .hubVoicePack else { return nil }
            return HubVoicePackCatalog.model(
                modelID: playbackResolution.resolvedHubVoicePackID,
                models: HubModelManager.shared.availableModels
            )?.capabilityPresentationModel.displayName
        }()
        let script = SupervisorVoiceScriptBuilder.previewScript(
            locale: locale,
            timbre: preferences.timbre,
            speedLabel: speedLabel,
            resolvedOutput: playbackResolution.resolvedSource,
            selectedVoicePackTitle: selectedVoicePackTitle
        )

        return dispatchSupervisorVoiceJob(
            SupervisorVoiceTTSJob(
                trigger: .userQueryReply,
                priority: .normal,
                script: script,
                dedupeKey: "voice-preview-\(UUID().uuidString.lowercased())"
            ),
            preferences: preferences,
            source: "voice_preview",
            now: Date(),
            suppressRapidSameSourceRepeat: false,
            cancelPendingHeartbeat: true
        )
    }

    @discardableResult
    func speakSupervisorVoiceText(
        _ text: String,
        personaSlot: SupervisorPersonaSlot? = nil
    ) -> SupervisorSpeechSynthesizer.Outcome {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else {
            return .suppressed("empty_script")
        }
        var preferences = currentVoicePreferences(personaSlot: personaSlot)
        preferences.autoReportMode = .full
        preferences.quietHours.enabled = false
        let script = trimmed
            .split(separator: "\n", omittingEmptySubsequences: true)
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }

        return dispatchSupervisorVoiceJob(
            SupervisorVoiceTTSJob(
                trigger: .userQueryReply,
                priority: .normal,
                script: script,
                dedupeKey: "voice-skill-\(UUID().uuidString.lowercased())"
            ),
            preferences: preferences,
            source: "voice_skill",
            now: Date(),
            suppressRapidSameSourceRepeat: false,
            cancelPendingHeartbeat: true
        )
    }

    @discardableResult
    func stopSupervisorVoicePlayback() -> Bool {
        supervisorSpeechSynthesizer.interruptCurrentPlayback()
    }

    private func beginHeartbeatVoiceDispatch() -> UInt64 {
        heartbeatVoiceDispatchTask?.cancel()
        heartbeatVoiceDispatchTask = nil
        heartbeatVoiceDispatchGeneration &+= 1
        return heartbeatVoiceDispatchGeneration
    }

    private func cancelPendingHeartbeatVoiceDispatch(preemptedBy source: String? = nil) {
        let hadPendingTask = heartbeatVoiceDispatchTask != nil
        _ = beginHeartbeatVoiceDispatch()
        guard hadPendingTask else { return }
        let normalizedSource = source?
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: " ", with: "_") ?? ""
        let reason = normalizedSource.isEmpty
            ? "preempted_by_new_dispatch"
            : "preempted_by_\(normalizedSource)"
        recordRuntimeActivity(
            "voice_dispatch state=cancelled source=heartbeat reason=\(reason)"
        )
    }

    private func isCurrentHeartbeatVoiceDispatch(_ generation: UInt64) -> Bool {
        heartbeatVoiceDispatchGeneration == generation
    }

    private func finishHeartbeatVoiceDispatchIfCurrent(_ generation: UInt64) {
        guard isCurrentHeartbeatVoiceDispatch(generation) else { return }
        heartbeatVoiceDispatchTask = nil
    }

    private func normalizedVoiceDispatchFingerprint(
        for job: SupervisorVoiceTTSJob
    ) -> String {
        SupervisorVoiceFingerprint.normalized(lines: job.script)
    }

    private func shouldSuppressRecentVoiceDispatch(
        source: String,
        job: SupervisorVoiceTTSJob,
        now: Date
    ) -> (reasonCode: String, detail: String)? {
        let nowSec = now.timeIntervalSince1970
        recentVoiceDispatchesBySource = recentVoiceDispatchesBySource.filter {
            nowSec - $0.value.spokenAt < upstreamVoiceDispatchDuplicateWindowSec
        }
        recentVoiceDispatchesByFingerprint = recentVoiceDispatchesByFingerprint.filter {
            nowSec - $0.value.spokenAt < upstreamVoiceDispatchDuplicateWindowSec
        }
        guard job.priority != .interrupt else { return nil }
        let fingerprint = normalizedVoiceDispatchFingerprint(for: job)

        if let previous = recentVoiceDispatchesBySource[source],
           previous.fingerprint == fingerprint,
           nowSec - previous.spokenAt < upstreamVoiceDispatchDuplicateWindowSec {
            return ("source_duplicate_suppressed", "")
        }

        if let previous = recentVoiceDispatchesByFingerprint[fingerprint],
           previous.source != source,
           nowSec - previous.spokenAt < upstreamVoiceDispatchDuplicateWindowSec {
            return ("cross_source_duplicate_suppressed", previous.source)
        }

        return nil
    }

    private func rememberVoiceDispatch(
        source: String,
        job: SupervisorVoiceTTSJob,
        now: Date
    ) {
        let fingerprint = normalizedVoiceDispatchFingerprint(for: job)
        recentVoiceDispatchesBySource[source] = (
            fingerprint: fingerprint,
            spokenAt: now.timeIntervalSince1970
        )
        recentVoiceDispatchesByFingerprint[fingerprint] = (
            source: source,
            spokenAt: now.timeIntervalSince1970
        )
    }

    private func appendVoiceDispatchAudit(
        source: String,
        state: String,
        reasonCode: String,
        detail: String = "",
        now: Date = Date()
    ) {
        let normalizedSource = source.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedState = state.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSource.isEmpty, !normalizedState.isEmpty else { return }

        voiceDispatchAuditEntries.insert(
            SupervisorVoiceDispatchAuditEntry(
                id: UUID().uuidString.lowercased(),
                createdAt: now.timeIntervalSince1970,
                source: normalizedSource,
                state: normalizedState,
                reasonCode: reasonCode.trimmingCharacters(in: .whitespacesAndNewlines),
                detail: detail.trimmingCharacters(in: .whitespacesAndNewlines)
            ),
            at: 0
        )
        if voiceDispatchAuditEntries.count > voiceDispatchAuditMaxEntries {
            voiceDispatchAuditEntries.removeLast(voiceDispatchAuditEntries.count - voiceDispatchAuditMaxEntries)
        }
    }

    private func recordVoiceDispatchActivity(
        state: String,
        source: String,
        job: SupervisorVoiceTTSJob,
        reasonCode: String,
        detail: String = ""
    ) {
        let preview = capped(job.script.joined(separator: " | "), maxChars: 96)
            .replacingOccurrences(of: "\n", with: " ")
        var tokens = [
            "voice_dispatch",
            "state=\(state)",
            "source=\(source)",
            "trigger=\(job.trigger.rawValue)",
            "priority=\(job.priority.rawValue)",
            "reason=\(reasonCode)",
            "preview=\(preview.isEmpty ? "(none)" : preview)"
        ]
        let trimmedDetail = detail.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmedDetail.isEmpty {
            tokens.append("detail=\(capped(trimmedDetail, maxChars: 96))")
        }
        recordRuntimeActivity(tokens.joined(separator: " "))
    }

    @discardableResult
    private func dispatchSupervisorVoiceJob(
        _ job: SupervisorVoiceTTSJob,
        preferences: VoiceRuntimePreferences,
        source: String,
        now: Date = Date(),
        suppressRapidSameSourceRepeat: Bool = true,
        cancelPendingHeartbeat: Bool = false
    ) -> SupervisorSpeechSynthesizer.Outcome {
        if cancelPendingHeartbeat {
            cancelPendingHeartbeatVoiceDispatch(preemptedBy: source)
        }
        if suppressRapidSameSourceRepeat,
           let suppression = shouldSuppressRecentVoiceDispatch(source: source, job: job, now: now) {
            appendRecentEvent("voice dispatch suppressed upstream: \(source)")
            appendVoiceDispatchAudit(
                source: source,
                state: "suppressed",
                reasonCode: suppression.reasonCode,
                detail: suppression.detail,
                now: now
            )
            recordVoiceDispatchActivity(
                state: "suppressed",
                source: source,
                job: job,
                reasonCode: suppression.reasonCode,
                detail: suppression.detail
            )
            return .suppressed(suppression.reasonCode)
        }

        let outcome = supervisorSpeechSynthesizer.speak(
            job: job,
            preferences: preferences,
            now: now
        )
        if outcome == .spoken {
            rememberVoiceDispatch(source: source, job: job, now: now)
            appendVoiceDispatchAudit(
                source: source,
                state: "spoken",
                reasonCode: "dispatched",
                now: now
            )
        } else if case .suppressed(let reasonCode) = outcome {
            appendVoiceDispatchAudit(
                source: source,
                state: "suppressed",
                reasonCode: reasonCode,
                now: now
            )
            recordVoiceDispatchActivity(
                state: "suppressed",
                source: source,
                job: job,
                reasonCode: reasonCode
            )
        }
        return outcome
    }

    func executeSupervisorVoiceSkillAction(
        action: String,
        text: String? = nil
    ) -> SupervisorVoiceSkillExecutionResult {
        if let override = Self.withSupervisorVoiceSkillActionTestingLock({
            Self.supervisorVoiceSkillActionOverrideForTesting
        }) {
            return override(action, text)
        }

        let normalizedAction = action.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        var preferences = currentVoicePreferences()
        let resolution = supervisorSpeechSynthesizer.playbackResolution(for: preferences)

        switch normalizedAction {
        case "status":
            return supervisorVoiceSkillExecutionResult(
                action: normalizedAction,
                ok: true,
                reasonCode: "status_ready",
                detail: "",
                preferences: preferences,
                resolution: resolution
            )
        case "preview":
            let outcome = previewSupervisorVoicePlayback()
            preferences = currentVoicePreferences()
            return supervisorVoiceSkillExecutionResult(
                action: normalizedAction,
                outcome: outcome,
                preferences: preferences,
                resolution: supervisorSpeechSynthesizer.playbackResolution(for: preferences)
            )
        case "speak":
            let outcome = speakSupervisorVoiceText(text ?? "")
            preferences = currentVoicePreferences()
            return supervisorVoiceSkillExecutionResult(
                action: normalizedAction,
                outcome: outcome,
                preferences: preferences,
                resolution: supervisorSpeechSynthesizer.playbackResolution(for: preferences)
            )
        case "stop":
            let stopped = stopSupervisorVoicePlayback()
            return supervisorVoiceSkillExecutionResult(
                action: normalizedAction,
                ok: stopped,
                reasonCode: stopped ? "playback_stopped" : "no_active_playback",
                detail: "",
                preferences: preferences,
                resolution: resolution
            )
        default:
            return supervisorVoiceSkillExecutionResult(
                action: normalizedAction,
                ok: false,
                reasonCode: "unsupported_action",
                detail: normalizedAction,
                preferences: preferences,
                resolution: resolution
            )
        }
    }

    private func supervisorVoiceSkillExecutionResult(
        action: String,
        ok: Bool,
        reasonCode: String,
        detail: String,
        preferences: VoiceRuntimePreferences,
        resolution: VoicePlaybackResolution
    ) -> SupervisorVoiceSkillExecutionResult {
        SupervisorVoiceSkillExecutionResult(
            action: action,
            ok: ok,
            reasonCode: reasonCode,
            detail: detail,
            playbackPreference: preferences.playbackPreference.rawValue,
            persona: preferences.persona.rawValue,
            timbre: preferences.timbre.rawValue,
            speechRateMultiplier: Double(preferences.speechRateMultiplier),
            localeIdentifier: preferences.localeIdentifier,
            resolution: resolution,
            activity: voicePlaybackActivity
        )
    }

    private func supervisorVoiceSkillExecutionResult(
        action: String,
        outcome: SupervisorSpeechSynthesizer.Outcome,
        preferences: VoiceRuntimePreferences,
        resolution: VoicePlaybackResolution
    ) -> SupervisorVoiceSkillExecutionResult {
        switch outcome {
        case .spoken:
            return supervisorVoiceSkillExecutionResult(
                action: action,
                ok: true,
                reasonCode: voicePlaybackActivity.reasonCode,
                detail: voicePlaybackActivity.detail,
                preferences: preferences,
                resolution: resolution
            )
        case .suppressed(let reasonCode):
            return supervisorVoiceSkillExecutionResult(
                action: action,
                ok: false,
                reasonCode: reasonCode,
                detail: voicePlaybackActivity.detail,
                preferences: preferences,
                resolution: resolution
            )
        }
    }

    private func handleVoiceWakeEvent(_ event: VoiceWakeEvent) {
        let selection = resolveSupervisorPersonaSelectionForWakePhrase(
            event.phrase,
            applySideEffects: true,
            timestamp: event.timestamp
        )
        if let invocation = selection.resolution.invocation {
            appendRecentEvent(
                "voice wake persona: \(selection.executionPersona.displayName) via \(invocation.matchedAlias)"
            )
        } else if selection.resolution.reasonCode == "ambiguous_match"
            || selection.resolution.reasonCode == "generic_wake_fallback" {
            appendRecentEvent(
                "voice wake persona fallback: \(selection.resolution.reasonCode) -> \(selection.executionPersona.displayName)"
            )
        }

        interruptSupervisorPlaybackForWakeEventIfNeeded()
        conversationSessionController.configure(route: event.route)
        conversationSessionController.registerWakeHit(
            now: Date(timeIntervalSince1970: event.timestamp)
        )
        conversationWindowBridge.requestOpen(
            reason: event.phrase,
            focusConversation: true
        )
    }

    private func cancelPendingTalkLoopResume() {
        pendingTalkLoopResumeTask?.cancel()
        pendingTalkLoopResumeTask = nil
    }

    private func scheduleTalkLoopResumeIfNeeded(
        triggeredByVoice: Bool,
        allowProactiveResume: Bool = false,
        spokenOutcome: SupervisorSpeechSynthesizer.Outcome,
        replyText: String,
        source: String
    ) {
        guard triggeredByVoice || allowProactiveResume else { return }
        guard spokenOutcome == .spoken else { return }
        guard conversationSessionController.snapshot.isConversing else { return }
        guard conversationSessionController.snapshot.wakeMode != .pushToTalk else { return }

        let trimmed = replyText.trimmingCharacters(in: .whitespacesAndNewlines)
        let script = trimmed.isEmpty ? ["Supervisor response"] : conciseVoiceReplyScript(trimmed)
        let job = SupervisorVoiceTTSJob(
            trigger: .userQueryReply,
            priority: .normal,
            script: script.isEmpty ? ["Supervisor response"] : script,
            dedupeKey: "talk_loop_resume:\(source)"
        )
        let delay = min(
            8.0,
            max(
                0.9,
                supervisorSpeechSynthesizer.estimatedPlaybackDuration(
                    job: job,
                    preferences: currentVoicePreferences()
                ) + 0.12
            )
        )

        cancelPendingTalkLoopResume()
        pendingTalkLoopResumeTask = Task { @MainActor [weak self] in
            guard let self else { return }
            try? await Task.sleep(nanoseconds: UInt64(delay * 1_000_000_000))
            guard !Task.isCancelled else { return }
            await self.resumeTalkLoopListeningIfNeeded(source: source)
        }
    }

    private func resumeTalkLoopListeningIfNeeded(source: String) async {
        defer { pendingTalkLoopResumeTask = nil }
        guard conversationSessionController.snapshot.isConversing else { return }
        guard conversationSessionController.snapshot.wakeMode != .pushToTalk else { return }
        guard voiceRouteDecision.route.supportsLiveCapture else { return }
        guard !isProcessing else { return }
        guard !voiceSessionCoordinator.isRecording else { return }
        let resumed = await voiceSessionCoordinator.resumeListeningForTalkLoop()
        guard resumed else { return }
        appendRecentEvent("voice talk loop resumed: \(source)")
    }

    func openConversationSession(openedBy: SupervisorConversationOpenedBy = .manualButton) {
        switch openedBy {
        case .manualButton:
            conversationSessionController.manualOpen()
        case .wakePhrase, .promptPhrase:
            conversationSessionController.registerWakeHit()
        case .voiceReplyFollowup:
            conversationSessionController.registerAssistantTurn(spoken: true)
        }
    }

    func endConversationSession(reasonCode: String = "manual_close") {
        cancelPendingTalkLoopResume()
        conversationSessionController.endConversation(reasonCode: reasonCode)
    }

    private func speakSupervisorVoiceAuthorizationUpdate(
        resolution: SupervisorVoiceAuthorizationResolution,
        challengeToken: String
    ) {
        let stateToken = resolution.state.rawValue
        let detailToken = resolution.denyCode ?? resolution.reasonCode ?? "none"
        let script = conciseVoiceAuthorizationScript(
            resolution: resolution,
            challengeToken: challengeToken
        )
        let job = SupervisorVoiceTTSJob(
            trigger: .authorization,
            priority: resolution.state == .verified ? .normal : .interrupt,
            script: [script],
            dedupeKey: "voice_auth:\(stateToken):\(challengeToken):\(detailToken)"
        )
        _ = dispatchSupervisorVoiceJob(
            job,
            preferences: currentVoicePreferences(),
            source: "voice_authorization",
            suppressRapidSameSourceRepeat: true,
            cancelPendingHeartbeat: true
        )
    }

    private func conciseVoiceAuthorizationScript(
        resolution: SupervisorVoiceAuthorizationResolution,
        challengeToken: String
    ) -> String {
        switch resolution.state {
        case .pending:
            return "已发出语音授权挑战（Voice authorization challenge issued）。Challenge \(challengeToken)。"
        case .escalatedToMobile:
            return "语音授权需要移动端确认（Voice authorization requires mobile confirmation）。Challenge \(challengeToken)。"
        case .verified:
            return "语音授权已验证通过（Voice authorization verified）。Challenge \(challengeToken)。"
        case .denied:
            let deny = resolution.denyCode ?? "denied"
            return "语音授权已拒绝（Voice authorization denied）。Reason \(deny)。"
        case .failClosed:
            let reason = resolution.reasonCode ?? "unknown"
            return "语音授权已进入失败闭锁（Voice authorization failed closed）。Reason \(reason)。"
        }
    }

    func handleEvent(_ event: AXEvent) {
        var forceHeartbeat = false
        var heartbeatReason = "event"
        switch event {
        case .projectCreated(let entry):
            let portfolioEvent = SupervisorPortfolioSnapshotBuilder.makeActionEvent(from: entry, kind: .created)
            if supervisorJurisdictionRegistry.allowsEventVisibility(portfolioEvent) {
                let text = "新增项目：\(entry.displayName)"
                appendRecentEvent(text)
                appendProjectActionEvent(portfolioEvent)
                deliverProjectActionNotificationIfNeeded(portfolioEvent)
            }
            Task { @MainActor in
                await refreshSupervisorMemorySnapshot(reason: "project_created")
            }
            forceHeartbeat = true
            heartbeatReason = "project_created"
        case .projectUpdated(let entry):
            let eventTime = Date().timeIntervalSince1970
            let baselinePortfolioEvent = SupervisorPortfolioSnapshotBuilder.makeActionEvent(
                from: entry,
                kind: .updated,
                now: eventTime
            )
            let portfolioEvent: SupervisorProjectActionEvent
            if baselinePortfolioEvent.eventType == .progressed || baselinePortfolioEvent.eventType == .completed {
                let digest = supervisorMemoryDigest(entry)
                portfolioEvent = SupervisorPortfolioSnapshotBuilder.makeActionEvent(
                    from: entry,
                    kind: .updated,
                    shadowedBackgroundNoteCount: digest.shadowedBackgroundNoteCount,
                    weakOnlyBackgroundNoteCount: digest.weakOnlyBackgroundNoteCount,
                    memoryCompactionSignal: digest.memoryCompactionRollup.map(
                        SupervisorMemoryCompactionSignalBuilder.build
                    ),
                    now: eventTime
                )
            } else {
                portfolioEvent = baselinePortfolioEvent
            }
            if supervisorJurisdictionRegistry.allowsEventVisibility(portfolioEvent) {
                appendRecentEvent(portfolioEvent.actionTitle)
                appendProjectActionEvent(portfolioEvent)
                deliverProjectActionNotificationIfNeeded(portfolioEvent)
            }
            Task { @MainActor in
                await refreshSupervisorMemorySnapshot(reason: "project_updated")
            }
            forceHeartbeat = true
            heartbeatReason = "project_updated"
        case .projectRemoved(let entry):
            let portfolioEvent = SupervisorPortfolioSnapshotBuilder.makeActionEvent(from: entry, kind: .removed)
            if supervisorJurisdictionRegistry.allowsEventVisibility(portfolioEvent) {
                let text = "移除项目：\(entry.displayName)"
                appendRecentEvent(text)
                appendProjectActionEvent(portfolioEvent)
                deliverProjectActionNotificationIfNeeded(portfolioEvent)
            }
            Task { @MainActor in
                await refreshSupervisorMemorySnapshot(reason: "project_removed")
            }
            forceHeartbeat = true
            heartbeatReason = "project_removed"
        case .sessionCreated(let info):
            let text = "创建了新会话：\(info.title)"
            appendRecentEvent(text)
            addSystemMessage(text)
        case .sessionUpdated(let info):
            let text = "更新了会话：\(info.title)"
            appendRecentEvent(text)
            addSystemMessage(text)
        case .messageCreated(let sessionId, _):
            let text = "项目 \(sessionId) 收到新消息"
            appendRecentEvent(text)
            addSystemMessage(text)
            Task { @MainActor in
                await refreshSupervisorMemorySnapshot(reason: "message_created")
            }
        case .toolCallCreated(let sessionId, let toolCall):
            let text = "项目 \(sessionId) 执行工具：\(toolCall.tool.rawValue)"
            appendRecentEvent(text)
            addSystemMessage(text)
            Task { @MainActor in
                await refreshSupervisorMemorySnapshot(reason: "tool_call_created")
            }
        case .supervisorIncident(let incident):
            appendSupervisorIncident(incident)
            let projectText = incident.projectID?.uuidString ?? "n/a"
            let text = "泳道 \(incident.laneID) 事件：\(incident.incidentCode) -> \(incident.proposedAction.rawValue) (deny=\(incident.denyCode), latency=\(incident.takeoverLatencyMs ?? -1)ms, project=\(projectText))"
            appendRecentEvent(text)
            if incident.severity == .high || incident.severity == .critical || incident.requiresUserAck {
                addSystemMessage("🚧 \(text)\n审计: \(incident.auditRef)")
                pushSupervisorIncidentNotification(incident)
            }
            forceHeartbeat = true
            heartbeatReason = "incident_handled"
        case .supervisorLaneHealth(let snapshot):
            let changed = applySupervisorLaneHealthSnapshot(snapshot)
            if changed {
                let summary = snapshot.summary
                let text = "lane 健康态：running=\(summary.running), blocked=\(summary.blocked), stalled=\(summary.stalled), failed=\(summary.failed)"
                appendRecentEvent(text)
                forceHeartbeat = true
                heartbeatReason = "lane_health_changed"
            }
        case .supervisorGuidanceAck(let record):
            let changed = handleSupervisorGuidanceAckEvent(record)
            if changed {
                forceHeartbeat = true
                heartbeatReason = "guidance_ack_follow_up"
            }
        default:
            break
        }
        emitHeartbeatIfNeeded(force: forceHeartbeat, reason: heartbeatReason)
    }

    func sendMessage(_ text: String, fromVoice: Bool = false) {
        let message = SupervisorMessage(
            id: UUID().uuidString,
            role: .user,
            content: text,
            isVoice: fromVoice,
            timestamp: Date().timeIntervalSince1970
        )
        messages.append(message)
        conversationSessionController.registerUserTurn(fromVoice: fromVoice)

        isProcessing = true

        Task {
            await processUserMessage(text, fromVoice: fromVoice)
        }
    }

    private func processUserMessage(_ text: String, fromVoice: Bool) async {
        defer {
            isProcessing = false
            drainPendingSupervisorEventLoopIfNeeded()
        }

        cancelPendingTalkLoopResume()
        let personalMemoryCapture = captureSupervisorPersonalMemoryIfNeeded(from: text)

        if let localCaptureReply = localSupervisorPersonalMemoryCaptureReply(
            for: text,
            capture: personalMemoryCapture
        ) {
            recordSupervisorReplyExecution(mode: .localDirectReply, actualModelId: nil)
            let spokenOutcome = fromVoice ? speakSupervisorVoiceReply(localCaptureReply) : .suppressed("not_voice_triggered")
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: text,
                    responseText: localCaptureReply,
                    triggerSource: .userTurn,
                    triggeredByVoice: fromVoice,
                    spokenOutcome: spokenOutcome,
                    replySource: "personal_memory_capture",
                    personaSlot: nil
                )
            )
            return
        }

        if let local = await handleLocalPreflightCommand(text) {
            recordSupervisorReplyExecution(mode: .localPreflight, actualModelId: nil)
            let spokenOutcome = fromVoice ? speakSupervisorVoiceReply(local) : .suppressed("not_voice_triggered")
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: text,
                    responseText: local,
                    triggerSource: .userTurn,
                    triggeredByVoice: fromVoice,
                    spokenOutcome: spokenOutcome,
                    replySource: "local_preflight",
                    personaSlot: nil
                )
            )
            return
        }

        if fromVoice,
           await handleActiveVoiceAuthorizationVoiceInputIfApplicable(text) {
            recordSupervisorReplyExecution(mode: .localDirectAction, actualModelId: nil)
            return
        }

        if fromVoice,
           let pendingGrantReply = await supervisorPendingGrantVoiceReplyIfApplicable(text) {
            recordSupervisorReplyExecution(mode: .localDirectAction, actualModelId: nil)
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: text,
                    responseText: pendingGrantReply.text,
                    triggerSource: .userTurn,
                    triggeredByVoice: fromVoice,
                    spokenOutcome: pendingGrantReply.spokenOutcome,
                    replySource: "pending_grant_voice_reply",
                    personaSlot: nil
                )
            )
            return
        }

        if let hubProjectionReply = await supervisorBriefProjectionReplyIfApplicable(
            text,
            fromVoice: fromVoice
        ) {
            recordSupervisorReplyExecution(mode: .hubBriefProjection, actualModelId: nil)
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: text,
                    responseText: hubProjectionReply.text,
                    triggerSource: .userTurn,
                    triggeredByVoice: fromVoice,
                    spokenOutcome: hubProjectionReply.spokenOutcome,
                    replySource: fromVoice ? "hub_projection_voice_reply" : "hub_projection_text_reply",
                    personaSlot: nil
                )
            )
            return
        }

        let personaSelection = resolveSupervisorPersonaSelection(
            for: text,
            applySideEffects: true
        )
        let response = await generateSupervisorResponse(
            text,
            triggerSource: .userTurn,
            personaSlot: personaSelection.executionPersona
        )
        let turnRoutingDecision = resolveSupervisorTurnRoutingDecision(
            userMessage: text,
            projects: allProjects()
        )

        let spokenOutcome = fromVoice
            ? speakSupervisorVoiceReply(response, personaSlot: personaSelection.executionPersona)
            : .suppressed("not_voice_triggered")
        completeSupervisorAssistantTurn(
            SupervisorAfterTurnLifecycleContext(
                userMessage: text,
                responseText: response,
                triggerSource: .userTurn,
                triggeredByVoice: fromVoice,
                spokenOutcome: spokenOutcome,
                replySource: "generated_supervisor_reply",
                personaSlot: personaSelection.executionPersona,
                turnRoutingDecision: turnRoutingDecision,
                turnRoutingDeltaCursor: currentSupervisorFocusPointerDeltaCursorCandidate()
            )
        )
    }

    private func syncVoiceConversationForPendingMemoryFactFollowUpIfNeeded(fromVoice: Bool) {
        guard fromVoice else { return }
        guard activeSupervisorMemoryFactFollowUp() != nil else { return }
        conversationSessionController.holdConversationForFollowUp()
    }

    private func completeSupervisorAssistantTurn(
        _ context: SupervisorAfterTurnLifecycleContext
    ) {
        let now = currentSupervisorAfterTurnDate()
        guard let normalizedResponse = appendSupervisorAssistantMessage(
            context.responseText,
            timestamp: now
        ) else {
            return
        }
        var normalizedContext = context
        normalizedContext.responseText = normalizedResponse
        runSupervisorAfterTurnLifecycle(
            normalizedContext,
            now: now
        )
    }

    private func runSupervisorAfterTurnLifecycle(
        _ context: SupervisorAfterTurnLifecycleContext,
        now: Date
    ) {
        syncSupervisorFocusPointersAfterTurn(
            context,
            now: now
        )
        syncSupervisorAfterTurnWritebackClassification(
            context,
            now: now
        )
        syncSupervisorTurnExplainabilityAfterTurn(
            context,
            now: now
        )
        if context.lifecycle.shouldRecordReviewNote {
            recordSupervisorReviewNoteIfNeeded(
                userMessage: context.userMessage,
                response: context.responseText,
                triggerSource: context.triggerSource
            )
        }
        if context.lifecycle.shouldSyncDerivedPersonalContext {
            syncSupervisorDerivedPersonalContextAfterTurn(
                now: now,
                replySource: context.replySource,
                personaSlot: context.personaSlot
            )
        }
        if context.lifecycle.shouldRegisterConversationTurn {
            conversationSessionController.registerAssistantTurn(spoken: context.spokenOutcome == .spoken)
        }
        if context.triggerSource == .userTurn,
           context.lifecycle.shouldRegisterConversationTurn {
            let createdAt = now.timeIntervalSince1970
            let userMessage = context.userMessage
            let responseText = context.responseText
            Task {
                _ = await HubIPCClient.appendSupervisorConversationTurn(
                    userText: userMessage,
                    assistantText: responseText,
                    createdAt: createdAt
                )
            }
        }
        if context.lifecycle.shouldScheduleTalkLoopResume {
            scheduleTalkLoopResumeIfNeeded(
                triggeredByVoice: context.triggeredByVoice,
                allowProactiveResume: context.allowProactiveResume,
                spokenOutcome: context.spokenOutcome,
                replyText: context.responseText,
                source: context.replySource
            )
        }
        if context.lifecycle.shouldSyncVoiceMemoryFollowUp {
            syncVoiceConversationForPendingMemoryFactFollowUpIfNeeded(fromVoice: context.triggeredByVoice)
        }
    }

    private func syncSupervisorFocusPointersAfterTurn(
        _ context: SupervisorAfterTurnLifecycleContext,
        now: Date
    ) {
        guard context.triggerSource == .userTurn else { return }
        let decision = context.turnRoutingDecision ?? resolveSupervisorTurnRoutingDecision(
            userMessage: context.userMessage,
            projects: allProjects(),
            now: now
        )
        let next = SupervisorFocusPointerUpdater.update(
            previous: supervisorFocusPointerState,
            decision: decision,
            userMessage: context.userMessage,
            projects: allProjects(),
            personalMemory: supervisorPersonalMemoryStore.snapshot,
            now: now,
            deltaCursor: context.turnRoutingDeltaCursor
        )
        guard next != supervisorFocusPointerState else { return }
        supervisorFocusPointerState = next
        saveRuntimeStateToDisk()
    }

    private func syncSupervisorAfterTurnWritebackClassification(
        _ context: SupervisorAfterTurnLifecycleContext,
        now: Date
    ) {
        let projects = projectsForTriggerSource(context.triggerSource)
        let routingDecision = context.turnRoutingDecision ?? resolveSupervisorTurnRoutingDecision(
            userMessage: context.userMessage,
            projects: projects,
            now: now
        )
        var classification = SupervisorAfterTurnWritebackClassifier.classify(
            SupervisorAfterTurnWritebackClassificationRequest(
                userMessage: context.userMessage,
                responseText: context.responseText,
                routingDecision: routingDecision,
                projects: projects,
                personalMemory: supervisorPersonalMemoryStore.snapshot
            ),
            now: now
        )
        if context.triggerSource == .userTurn,
           !classification.durableCandidates.isEmpty {
            classification.mirrorStatus = .pending
            classification.mirrorTarget = XTSupervisorDurableCandidateMirror.mirrorTarget
            classification.mirrorAttempted = true
            classification.mirrorErrorCode = nil
            classification.localStoreRole = XTSupervisorDurableCandidateMirror.localStoreRole
        }
        supervisorAfterTurnWritebackClassification = classification
        syncSupervisorMemoryAssemblySnapshotMirrorState(using: classification)
        syncSupervisorUserScopeWriteback(
            classification: classification,
            userMessage: context.userMessage,
            triggerSource: context.triggerSource,
            now: now
        )
        syncSupervisorProjectScopeWriteback(
            classification: classification,
            routingDecision: routingDecision,
            userMessage: context.userMessage,
            triggerSource: context.triggerSource,
            projects: projects,
            now: now
        )
        syncSupervisorCrossLinkWriteback(
            classification: classification,
            routingDecision: routingDecision,
            userMessage: context.userMessage,
            projects: projects,
            now: now
        )
        mirrorSupervisorDurableCandidatesIfNeeded(
            classification: classification,
            triggerSource: context.triggerSource,
            createdAt: now.timeIntervalSince1970
        )
    }

    private func syncSupervisorTurnExplainabilityAfterTurn(
        _ context: SupervisorAfterTurnLifecycleContext,
        now: Date
    ) {
        let projects = projectsForTriggerSource(context.triggerSource)
        let decision = context.turnRoutingDecision ?? resolveSupervisorTurnRoutingDecision(
            userMessage: context.userMessage,
            projects: projects,
            now: now
        )
        supervisorLatestTurnRoutingDecision = decision
        supervisorLatestTurnContextAssembly = assembleSupervisorTurnContext(
            routingDecision: decision,
            personaSlot: context.personaSlot,
            memoryText: supervisorMemoryPreview
        )
        supervisorLatestModelRouteContext = resolvedSupervisorModelRouteContext(
            userMessage: context.userMessage,
            projects: projects
        )
    }

    private func mirrorSupervisorDurableCandidatesIfNeeded(
        classification: SupervisorAfterTurnWritebackClassification,
        triggerSource: SupervisorCommandTriggerSource,
        createdAt: Double
    ) {
        guard triggerSource == .userTurn else { return }
        guard !classification.durableCandidates.isEmpty else { return }

        let fingerprint = supervisorAfterTurnWritebackMirrorFingerprint(classification)
        Task { [weak self] in
            let result = await XTSupervisorDurableCandidateMirror.mirror(
                classification: classification,
                createdAt: createdAt
            )
            self?.applySupervisorDurableCandidateMirrorResult(
                result,
                fingerprint: fingerprint
            )
        }
    }

    private func applySupervisorDurableCandidateMirrorResult(
        _ result: SupervisorDurableCandidateMirrorResult,
        fingerprint: String
    ) {
        guard var current = supervisorAfterTurnWritebackClassification else { return }
        guard supervisorAfterTurnWritebackMirrorFingerprint(current) == fingerprint else { return }

        current.mirrorStatus = result.status
        current.mirrorTarget = result.target
        current.mirrorAttempted = result.attempted
        current.mirrorErrorCode = result.errorCode
        current.localStoreRole = XTSupervisorDurableCandidateMirror.localStoreRole
        supervisorAfterTurnWritebackClassification = current
        syncSupervisorMemoryAssemblySnapshotMirrorState(using: current)

        var activity = "after_turn durable_candidate_mirror · status=\(result.status.rawValue) · target=\(result.target)"
        if let error = result.errorCode, !error.isEmpty {
            activity += " · reason=\(error)"
        }
        recordRuntimeActivity(activity)
    }

    private func supervisorAfterTurnWritebackMirrorFingerprint(
        _ classification: SupervisorAfterTurnWritebackClassification
    ) -> String {
        classification.durableCandidates
            .map(\.auditRef)
            .sorted()
            .joined(separator: "|")
    }

    private func syncSupervisorMemoryAssemblySnapshotMirrorState(
        using classification: SupervisorAfterTurnWritebackClassification
    ) {
        guard var snapshot = supervisorMemoryAssemblySnapshot else { return }
        let mirrorState = supervisorDurableCandidateMirrorSnapshotState(from: classification)
        snapshot.durableCandidateMirrorStatus = mirrorState.status
        snapshot.durableCandidateMirrorTarget = mirrorState.target
        snapshot.durableCandidateMirrorAttempted = mirrorState.attempted
        snapshot.durableCandidateMirrorErrorCode = mirrorState.errorCode
        snapshot.durableCandidateLocalStoreRole = mirrorState.localStoreRole
        publishSupervisorMemoryAssemblyState(snapshot)
    }

    private func supervisorDurableCandidateMirrorSnapshotState(
        from classification: SupervisorAfterTurnWritebackClassification?
    ) -> (
        status: SupervisorDurableCandidateMirrorStatus,
        target: String?,
        attempted: Bool,
        errorCode: String?,
        localStoreRole: String
    ) {
        guard let classification else {
            return (
                status: .notNeeded,
                target: nil,
                attempted: false,
                errorCode: nil,
                localStoreRole: XTSupervisorDurableCandidateMirror.localStoreRole
            )
        }

        return (
            status: classification.mirrorStatus,
            target: classification.mirrorTarget,
            attempted: classification.mirrorAttempted,
            errorCode: classification.mirrorErrorCode,
            localStoreRole: classification.localStoreRole
        )
    }

    private func syncSupervisorCrossLinkWriteback(
        classification: SupervisorAfterTurnWritebackClassification,
        routingDecision: SupervisorTurnRoutingDecision?,
        userMessage: String,
        projects: [AXProjectEntry],
        now: Date
    ) {
        let candidates = classification.candidates.filter { $0.scope == .crossLinkScope }
        guard !candidates.isEmpty else { return }

        var upserted = 0
        for candidate in candidates {
            guard let record = supervisorCrossLinkRecord(
                from: candidate,
                routingDecision: routingDecision,
                userMessage: userMessage,
                projects: projects,
                now: now
            ) else {
                continue
            }
            supervisorCrossLinkStore.upsert(
                record,
                intent: .afterTurnCacheRefresh
            )
            upserted += 1
        }

        guard upserted > 0 else { return }
        recordRuntimeActivity(
            "after_turn cross_links · upserted=\(upserted) · \(classification.summaryLine)"
        )
    }

    private func syncSupervisorUserScopeWriteback(
        classification: SupervisorAfterTurnWritebackClassification,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource,
        now: Date
    ) {
        guard triggerSource == .userTurn else { return }

        let userCandidates = classification.candidates.filter { $0.scope == .userScope }
        guard !userCandidates.isEmpty else { return }

        let requestedRecordTypes = Set(userCandidates.map(\.recordType))
        let existingSnapshot = supervisorPersonalMemoryStore.snapshot.normalized()
        let currentPreferredName = existingSnapshot.preferredUserName()?.lowercased()
        var records: [SupervisorPersonalMemoryRecord] = []

        if requestedRecordTypes.contains("preferred_name"),
           let capture = SupervisorPersonalMemoryAutoCapture.extract(from: userMessage) {
            let nextPreferredName = capture.preferredUserName.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            if currentPreferredName != nextPreferredName {
                records.append(capture.preferredUserNameRecord(now: now))
            }
        }

        let explicitRecords = SupervisorPersonalMemoryAutoCapture.extractAdditionalRecords(
            from: userMessage,
            now: now
        )
        for record in explicitRecords where requestedRecordTypes.contains(record.category.rawValue) {
            if existingSnapshot.item(for: record.memoryId) == nil {
                records.append(record)
            }
        }

        if requestedRecordTypes.contains("personal_preference"),
           let inferredRecord = SupervisorPersonalMemoryAutoCapture.inferredStableUserContextRecord(
                from: userMessage,
                now: now
           ),
           existingSnapshot.item(for: inferredRecord.memoryId) == nil {
            records.append(inferredRecord)
        }

        let deduplicated = deduplicatedSupervisorPersonalMemoryRecords(records)
        guard !deduplicated.isEmpty else { return }

        for record in deduplicated {
            supervisorPersonalMemoryStore.upsert(
                record,
                intent: .afterTurnCacheRefresh
            )
        }

        recordRuntimeActivity(
            "after_turn user_memory · upserted=\(deduplicated.count) · \(classification.summaryLine)"
        )
    }

    private func syncSupervisorProjectScopeWriteback(
        classification: SupervisorAfterTurnWritebackClassification,
        routingDecision: SupervisorTurnRoutingDecision?,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource,
        projects: [AXProjectEntry],
        now: Date
    ) {
        guard triggerSource == .userTurn else { return }
        guard classification.candidates.contains(where: { $0.scope == .projectScope }) else { return }
        guard !shouldSkipSupervisorProjectScopeWriteback(userMessage) else { return }
        guard let project = supervisorProjectForAfterTurnWriteback(
            routingDecision: routingDecision,
            projects: projects
        ) else {
            return
        }

        let intent = supervisorAfterTurnProjectWritebackIntent(
            userMessage: userMessage,
            classification: classification
        )
        guard intent.hasFacts else { return }

        let context = supervisorMemoryContext(for: project)
        do {
            let result = try applySupervisorNaturalMemoryPatch(
                intent,
                project: project,
                ctx: context
            )
            guard !result.appliedKinds.isEmpty else { return }
            refreshSupervisorMemorySnapshotNow()
            recordRuntimeActivity(
                "after_turn project_memory · project=\(project.displayName) · \(result.appliedKinds.joined(separator: ","))"
            )
        } catch {
            recordRuntimeActivity(
                "after_turn project_memory_failed · project=\(project.displayName) · error=\(String(describing: error))"
            )
        }
    }

    private func shouldSkipSupervisorProjectScopeWriteback(_ userMessage: String) -> Bool {
        guard lastSupervisorReplyExecutionMode == SupervisorReplyExecutionMode.localDirectAction.rawValue else {
            return false
        }
        let normalized = normalizedLookupKey(userMessage)
        return isNaturalSupervisorMemoryPatchRequest(normalized) || looksLikeSupervisorNaturalMemoryPatchFacts(userMessage)
    }

    private func supervisorProjectForAfterTurnWriteback(
        routingDecision: SupervisorTurnRoutingDecision?,
        projects: [AXProjectEntry]
    ) -> AXProjectEntry? {
        if let projectID = routingDecision?.focusedProjectId?.trimmingCharacters(in: .whitespacesAndNewlines),
           !projectID.isEmpty,
           let matched = projects.first(where: { $0.projectId == projectID }) {
            return matched
        }

        let focusedName = routingDecision?.focusedProjectName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !focusedName.isEmpty else { return nil }
        let normalizedFocusedName = normalizedLookupKey(focusedName)
        return projects.first { normalizedLookupKey($0.displayName) == normalizedFocusedName }
    }

    private func supervisorAfterTurnProjectWritebackIntent(
        userMessage: String,
        classification: SupervisorAfterTurnWritebackClassification
    ) -> SupervisorNaturalMemoryPatchIntent {
        var intent = parseSupervisorNaturalMemoryPatchIntent(
            userMessage,
            explicitRequest: false
        )

        let projectRecordTypes = Set(
            classification.candidates
                .filter { $0.scope == .projectScope }
                .map(\.recordType)
        )
        let normalizedMessage = userMessage.trimmingCharacters(in: .whitespacesAndNewlines)

        if intent.blockerSummary?.isEmpty ?? true,
           projectRecordTypes.contains("project_blocker") {
            intent.blockerSummary = supervisorAfterTurnProjectBlockerFallback(from: normalizedMessage)
        }

        if intent.nextStepSummary?.isEmpty ?? true,
           projectRecordTypes.contains("project_plan_change") {
            intent.nextStepSummary = supervisorAfterTurnProjectNextStepFallback(from: normalizedMessage)
        }

        if intent.currentStateSummary?.isEmpty ?? true,
           intent.blockerSummary?.isEmpty == false,
           !normalizedMessage.isEmpty {
            intent.currentStateSummary = capped(normalizedMessage, maxChars: 160)
        }

        return intent
    }

    private func supervisorAfterTurnProjectBlockerFallback(from text: String) -> String? {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }

        let patterns = [
            #"(?i)blocker\s*[是:：]\s*([^，。,；;!?！？]+)"#,
            #"现在卡在\s*([^，。,；;!?！？]+)"#,
            #"卡点是\s*([^，。,；;!?！？]+)"#,
            #"阻塞是\s*([^，。,；;!?！？]+)"#
        ]

        for pattern in patterns {
            if let match = firstRegexCapture(pattern, in: trimmed) {
                return sanitizeSupervisorNaturalMemoryPatchValue(match)
            }
        }

        if trimmed.localizedCaseInsensitiveContains("grant pending") {
            return "grant pending"
        }
        return nil
    }

    private func supervisorAfterTurnProjectNextStepFallback(from text: String) -> String? {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }

        let patterns = [
            #"下一步是\s*([^，。,；;!?！？]+)"#,
            #"接下来是\s*([^，。,；;!?！？]+)"#,
            #"接下来先\s*([^，。,；;!?！？]+)"#,
            #"后面先\s*([^，。,；;!?！？]+)"#,
            #"(?i)next step is\s*([^,.;!?]+)"#
        ]

        for pattern in patterns {
            if let match = firstRegexCapture(pattern, in: trimmed) {
                return sanitizeSupervisorNaturalMemoryPatchValue(match)
            }
        }

        return nil
    }

    private func firstRegexCapture(_ pattern: String, in text: String) -> String? {
        guard let regex = try? NSRegularExpression(pattern: pattern) else { return nil }
        let range = NSRange(text.startIndex..., in: text)
        guard let match = regex.firstMatch(in: text, options: [], range: range),
              match.numberOfRanges > 1,
              let captureRange = Range(match.range(at: 1), in: text) else {
            return nil
        }
        return String(text[captureRange])
    }

    private func supervisorCrossLinkRecord(
        from candidate: SupervisorAfterTurnWritebackCandidate,
        routingDecision: SupervisorTurnRoutingDecision?,
        userMessage: String,
        projects: [AXProjectEntry],
        now: Date
    ) -> SupervisorCrossLinkRecord? {
        let nowMs = Int64((now.timeIntervalSince1970 * 1000.0).rounded())
        let normalizedMessage = firstNonEmptyLine(in: userMessage).trimmingCharacters(in: .whitespacesAndNewlines)
        let summary = capped(normalizedMessage.isEmpty ? candidate.recordType : normalizedMessage, maxChars: 180)

        switch candidate.recordType {
        case "person_waiting_on_project":
            guard let personName = routingDecision?.focusedPersonName?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !personName.isEmpty,
                  let projectId = routingDecision?.focusedProjectId?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !projectId.isEmpty else {
                return nil
            }
            let projectName = supervisorResolvedProjectDisplayName(
                projectId: projectId,
                fallback: routingDecision?.focusedProjectName,
                projects: projects
            )
            let stablePerson = normalizedSupervisorCrossLinkStableToken(personName)
            return SupervisorCrossLinkRecord(
                schemaVersion: SupervisorCrossLinkRecord.currentSchemaVersion,
                linkId: "person_waiting_on_project:\(stablePerson):\(projectId)",
                kind: .personWaitingOnProject,
                status: .active,
                summary: summary,
                personName: personName,
                commitmentId: nil,
                projectId: projectId,
                projectName: projectName,
                backingRecordRefs: [candidate.auditRef, candidate.sourceRef],
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                auditRef: candidate.auditRef
            )

        case "commitment_depends_on_project":
            guard let commitmentId = routingDecision?.focusedCommitmentId?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !commitmentId.isEmpty,
                  let projectId = routingDecision?.focusedProjectId?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !projectId.isEmpty else {
                return nil
            }
            let projectName = supervisorResolvedProjectDisplayName(
                projectId: projectId,
                fallback: routingDecision?.focusedProjectName,
                projects: projects
            )
            return SupervisorCrossLinkRecord(
                schemaVersion: SupervisorCrossLinkRecord.currentSchemaVersion,
                linkId: "commitment_depends_on_project:\(commitmentId):\(projectId)",
                kind: .commitmentDependsOnProject,
                status: .active,
                summary: summary,
                personName: routingDecision?.focusedPersonName ?? "",
                commitmentId: commitmentId,
                projectId: projectId,
                projectName: projectName,
                backingRecordRefs: [candidate.auditRef, candidate.sourceRef],
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                auditRef: candidate.auditRef
            )

        default:
            return nil
        }
    }

    private func supervisorResolvedProjectDisplayName(
        projectId: String,
        fallback: String?,
        projects: [AXProjectEntry]
    ) -> String {
        if let matched = projects.first(where: { $0.projectId == projectId })?.displayName,
           !matched.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return matched
        }
        let trimmedFallback = fallback?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return trimmedFallback.isEmpty ? projectId : trimmedFallback
    }

    private func resolvedSupervisorProjectEntry(projectId: String) -> AXProjectEntry? {
        let normalizedProjectId = projectId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedProjectId.isEmpty else { return nil }

        let visibleProjects = allProjects()
        if let matched = visibleProjects.first(where: {
            $0.projectId.compare(normalizedProjectId, options: .caseInsensitive) == .orderedSame
        }) {
            return matched
        }

        let known = knownProjects()
        if let matched = known.first(where: {
            $0.projectId.compare(normalizedProjectId, options: .caseInsensitive) == .orderedSame
        }) {
            return matched
        }

        if case .matched(let matched) = resolveProjectReference(normalizedProjectId, in: known) {
            return matched
        }
        return nil
    }

    private func deduplicatedSupervisorPersonalMemoryRecords(
        _ records: [SupervisorPersonalMemoryRecord]
    ) -> [SupervisorPersonalMemoryRecord] {
        var seen = Set<String>()
        var ordered: [SupervisorPersonalMemoryRecord] = []
        for record in records {
            let memoryID = record.memoryId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !memoryID.isEmpty else { continue }
            guard seen.insert(memoryID).inserted else { continue }
            ordered.append(record)
        }
        return ordered
    }

    private func syncSupervisorDerivedPersonalContextAfterTurn(
        now: Date,
        replySource: String,
        personaSlot: SupervisorPersonaSlot?
    ) {
        let policy = currentSupervisorPersonalPolicy(personaSlot: personaSlot)
        let personalMemory = supervisorPersonalMemoryStore.snapshot
        let previousState = lastSupervisorDerivedPersonalContextState
        supervisorPersonalReviewStore.syncDerivedNotes(
            policy: policy,
            personalMemory: personalMemory,
            now: now,
            intent: .derivedRefresh
        )

        let followUpLedger = SupervisorFollowUpLedgerBuilder.build(
            from: personalMemory,
            now: now
        )
        let followUpSummary = SupervisorFollowUpLedgerBuilder.summary(from: followUpLedger)
        let reviewPreview = supervisorPersonalReviewStore.preview(
            policy: policy,
            personalMemory: personalMemory,
            now: now
        )
        let currentState = supervisorDerivedPersonalContextState(
            reviewPreview: reviewPreview,
            followUpLedger: followUpLedger
        )
        let derivedSummary = buildSupervisorAfterTurnDerivedSummary(
            previous: previousState,
            current: currentState,
            replySource: replySource
        )
        supervisorAfterTurnDerivedSummary = derivedSummary
        lastSupervisorDerivedPersonalContextState = currentState

        let fingerprint = [
            replySource,
            String(reviewPreview.dueCount),
            String(reviewPreview.overdueCount),
            String(followUpSummary.openCount),
            String(followUpSummary.overdueCount),
            derivedSummary.debugLine
        ].joined(separator: "|")

        if reviewPreview.dueCount > 0 || followUpSummary.openCount > 0 {
            guard fingerprint != lastSupervisorAfterTurnDerivedStatusFingerprint else { return }
            recordRuntimeActivity(
                "after_turn \(replySource) · reviews_due=\(reviewPreview.dueCount) · reviews_overdue=\(reviewPreview.overdueCount) · follow_ups=\(followUpSummary.openCount) · follow_ups_overdue=\(followUpSummary.overdueCount) · \(derivedSummary.debugLine)"
            )
            lastSupervisorAfterTurnDerivedStatusFingerprint = fingerprint
            return
        }

        guard !lastSupervisorAfterTurnDerivedStatusFingerprint.isEmpty else { return }
        recordRuntimeActivity("after_turn \(replySource) · personal_context_clear · \(derivedSummary.debugLine)")
        lastSupervisorAfterTurnDerivedStatusFingerprint = ""
    }

    private func supervisorDerivedPersonalContextState(
        reviewPreview: SupervisorPersonalReviewPreview,
        followUpLedger: SupervisorFollowUpLedgerSnapshot
    ) -> SupervisorDerivedPersonalContextState {
        SupervisorDerivedPersonalContextState(
            reviewDueCount: reviewPreview.dueCount,
            reviewOverdueCount: reviewPreview.overdueCount,
            followUpOpenCount: followUpLedger.items.count,
            followUpOverdueCount: followUpLedger.items.filter { $0.urgency == .overdue }.count,
            reviewLabels: reviewPreview.dueNotes.map {
                SupervisorDerivedContextLabel(
                    id: $0.reviewId,
                    label: supervisorAfterTurnReviewLabel($0)
                )
            },
            followUpLabels: followUpLedger.items.map {
                SupervisorDerivedContextLabel(
                    id: $0.followUpId,
                    label: supervisorAfterTurnFollowUpLabel($0)
                )
            }
        )
    }

    private func buildSupervisorAfterTurnDerivedSummary(
        previous: SupervisorDerivedPersonalContextState?,
        current: SupervisorDerivedPersonalContextState,
        replySource: String
    ) -> SupervisorAfterTurnDerivedSummary {
        let previousReviewIDs = Set(previous?.reviewLabels.map(\.id) ?? [])
        let previousFollowUpIDs = Set(previous?.followUpLabels.map(\.id) ?? [])
        let currentReviewIDs = Set(current.reviewLabels.map(\.id))
        let currentFollowUpIDs = Set(current.followUpLabels.map(\.id))

        let addedReviews = current.reviewLabels
            .filter { !previousReviewIDs.contains($0.id) }
            .map(\.label)
        let clearedReviews = (previous?.reviewLabels ?? [])
            .filter { !currentReviewIDs.contains($0.id) }
            .map(\.label)
        let addedFollowUps = current.followUpLabels
            .filter { !previousFollowUpIDs.contains($0.id) }
            .map(\.label)
        let clearedFollowUps = (previous?.followUpLabels ?? [])
            .filter { !currentFollowUpIDs.contains($0.id) }
            .map(\.label)

        let reviewDelta = current.reviewDueCount - (previous?.reviewDueCount ?? 0)
        let followUpDelta = current.followUpOpenCount - (previous?.followUpOpenCount ?? 0)
        let reviewOverdueDelta = current.reviewOverdueCount - (previous?.reviewOverdueCount ?? 0)
        let followUpOverdueDelta = current.followUpOverdueCount - (previous?.followUpOverdueCount ?? 0)
        let previousBacklogCount = (previous?.reviewDueCount ?? 0) + (previous?.followUpOpenCount ?? 0)
        let currentBacklogCount = current.reviewDueCount + current.followUpOpenCount

        let trend: SupervisorAfterTurnDerivedSummary.Trend = {
            if currentBacklogCount == 0 {
                return previousBacklogCount > 0 ? .cleared : (previous == nil ? .idle : .stable)
            }
            guard let previous else { return .initialized }
            if reviewDelta > 0 || followUpDelta > 0 || reviewOverdueDelta > 0 || followUpOverdueDelta > 0 {
                return .increased
            }
            if reviewDelta < 0 || followUpDelta < 0 || reviewOverdueDelta < 0 || followUpOverdueDelta < 0 {
                return .reduced
            }
            if current.reviewLabels != previous.reviewLabels || current.followUpLabels != previous.followUpLabels {
                return .stable
            }
            return .stable
        }()

        let statusLine: String = {
            if currentBacklogCount == 0 {
                switch trend {
                case .cleared:
                    return "Latest after-turn: personal backlog cleared."
                case .idle, .stable:
                    return "Latest after-turn: no due personal reviews or open follow-ups."
                default:
                    return "Latest after-turn: personal backlog cleared."
                }
            }

            let reviewDeltaText = supervisorAfterTurnDeltaText(reviewDelta)
            let followUpDeltaText = supervisorAfterTurnDeltaText(followUpDelta)
            return "Latest after-turn: reviews \(current.reviewDueCount) due\(reviewDeltaText) · follow-ups \(current.followUpOpenCount) open\(followUpDeltaText) · \(supervisorAfterTurnTrendSummary(trend))"
        }()

        var detailLines: [String] = []
        if !addedReviews.isEmpty {
            detailLines.append("New reviews: \(supervisorAfterTurnJoinedLabels(addedReviews))")
        }
        if !clearedReviews.isEmpty {
            detailLines.append("Cleared reviews: \(supervisorAfterTurnJoinedLabels(clearedReviews))")
        }
        if !addedFollowUps.isEmpty {
            detailLines.append("New follow-ups: \(supervisorAfterTurnJoinedLabels(addedFollowUps))")
        }
        if !clearedFollowUps.isEmpty {
            detailLines.append("Cleared follow-ups: \(supervisorAfterTurnJoinedLabels(clearedFollowUps))")
        }
        if detailLines.isEmpty, current.reviewDueCount > 0 {
            detailLines.append("Due reviews: \(supervisorAfterTurnJoinedLabels(current.reviewLabels.map(\.label)))")
        }
        if detailLines.isEmpty, current.followUpOpenCount > 0 {
            detailLines.append("Open follow-ups: \(supervisorAfterTurnJoinedLabels(current.followUpLabels.map(\.label)))")
        }
        if current.reviewOverdueCount > 0, reviewOverdueDelta > 0 || detailLines.isEmpty {
            detailLines.append("Overdue reviews now: \(current.reviewOverdueCount)")
        }
        if current.followUpOverdueCount > 0, followUpOverdueDelta > 0 || detailLines.isEmpty {
            detailLines.append("Overdue follow-ups now: \(current.followUpOverdueCount)")
        }
        if currentBacklogCount == 0, detailLines.isEmpty, trend == .cleared {
            detailLines.append("No open personal reviews or follow-ups remain.")
        }

        let debugParts = [
            "trend=\(trend.rawValue)",
            "reviews_due=\(current.reviewDueCount)",
            "reviews_overdue=\(current.reviewOverdueCount)",
            "follow_ups=\(current.followUpOpenCount)",
            "follow_ups_overdue=\(current.followUpOverdueCount)",
            addedReviews.isEmpty ? nil : "new_reviews=\(supervisorAfterTurnJoinedLabels(addedReviews, maxItems: 2))",
            clearedReviews.isEmpty ? nil : "cleared_reviews=\(supervisorAfterTurnJoinedLabels(clearedReviews, maxItems: 2))",
            addedFollowUps.isEmpty ? nil : "new_follow_ups=\(supervisorAfterTurnJoinedLabels(addedFollowUps, maxItems: 2))",
            clearedFollowUps.isEmpty ? nil : "cleared_follow_ups=\(supervisorAfterTurnJoinedLabels(clearedFollowUps, maxItems: 2))"
        ].compactMap { $0 }

        return SupervisorAfterTurnDerivedSummary(
            replySource: replySource,
            trend: trend,
            hasOverdueItems: current.reviewOverdueCount > 0 || current.followUpOverdueCount > 0,
            reviewDueCount: current.reviewDueCount,
            reviewOverdueCount: current.reviewOverdueCount,
            followUpOpenCount: current.followUpOpenCount,
            followUpOverdueCount: current.followUpOverdueCount,
            statusLine: statusLine,
            detailLines: Array(detailLines.prefix(4)),
            debugLine: capped(debugParts.joined(separator: " · "), maxChars: 220)
        )
    }

    private func supervisorAfterTurnReviewLabel(
        _ note: SupervisorPersonalReviewNoteRecord
    ) -> String {
        let anchor = note.reviewAnchor.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !anchor.isEmpty else { return note.reviewType.displayName }
        return "\(note.reviewType.displayName) (\(anchor))"
    }

    private func supervisorAfterTurnFollowUpLabel(
        _ item: SupervisorFollowUpLedgerItem
    ) -> String {
        let person = item.personName.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !person.isEmpty else { return item.title }
        return "\(item.title) · \(person)"
    }

    private func supervisorAfterTurnDeltaText(_ delta: Int) -> String {
        if delta > 0 { return " (+\(delta))" }
        if delta < 0 { return " (\(delta))" }
        return ""
    }

    private func supervisorAfterTurnTrendSummary(
        _ trend: SupervisorAfterTurnDerivedSummary.Trend
    ) -> String {
        switch trend {
        case .idle:
            return "backlog idle"
        case .initialized:
            return "backlog initialized"
        case .increased:
            return "backlog increased"
        case .reduced:
            return "backlog reduced"
        case .cleared:
            return "backlog cleared"
        case .stable:
            return "backlog stable"
        }
    }

    private func supervisorAfterTurnJoinedLabels(
        _ labels: [String],
        maxItems: Int = 3
    ) -> String {
        let trimmed = labels
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        guard !trimmed.isEmpty else { return "(none)" }
        let head = Array(trimmed.prefix(maxItems))
        if trimmed.count > maxItems {
            return head.joined(separator: ", ") + ", +\(trimmed.count - maxItems) more"
        }
        return head.joined(separator: ", ")
    }

    private func currentSupervisorAfterTurnDate() -> Date {
        supervisorAfterTurnNowOverrideForTesting?() ?? Date()
    }

    private func generateSupervisorResponse(
        _ userMessage: String,
        triggerSource: SupervisorCommandTriggerSource = .userTurn,
        personaSlot: SupervisorPersonaSlot? = nil
    ) async -> String {
        let projects = projectsForTriggerSource(triggerSource)
        let executionPersona = personaSlot ?? currentSupervisorExecutionPersona()
        if let routingReply = directSupervisorPersonaRoutingReplyIfApplicable(
            userMessage,
            personaSlot: executionPersona
        ) {
            recordSupervisorReplyExecution(mode: .localDirectReply, actualModelId: nil)
            return routingReply
        }
        if let directReply = directSupervisorPreflightReplyIfApplicable(
            userMessage,
            projects: projects
        ) {
            recordSupervisorReplyExecution(mode: .localDirectReply, actualModelId: nil)
            return directReply
        }
        if let directAction = directSupervisorActionIfApplicable(userMessage, projects: projects) {
            recordSupervisorReplyExecution(mode: .localDirectAction, actualModelId: nil)
            return directAction
        }
        if let directRepoInspection = await directSupervisorRepoInspectionReplyIfApplicable(
            userMessage,
            projects: projects
        ) {
            recordSupervisorReplyExecution(mode: .localDirectAction, actualModelId: nil)
            return directRepoInspection
        }

        primeSupervisorMemoryAwareConversationStateIfNeeded(userMessage)
        await refreshSchedulerSnapshot(force: false)
        let configuredPreferredModel = modelManager.getPreferredModel(for: .supervisor)
        let preferredModel = resolvedPreferredSupervisorModelID(configuredModelId: configuredPreferredModel)
        let memoryInfo = await buildSupervisorMemoryV1(
            userMessage: userMessage,
            triggerSource: triggerSource
        )
        publishSupervisorMemoryInfo(memoryInfo)
        let prompt = buildSupervisorSystemPrompt(
            userMessage: userMessage,
            projects: projects,
            preferredModel: preferredModel,
            memoryInfo: memoryInfo,
            personaSlot: executionPersona
        )

        do {
            let rid = try await hubClient.enqueueGenerate(
                prompt: prompt,
                taskType: "supervisor",
                preferredModelId: preferredModel,
                explicitModelId: nil,
                appId: "x_terminal_supervisor",
                maxTokens: 2048,
                temperature: 0.7,
                topP: 0.95,
                autoLoad: true
            )

            var response = ""
            var actualModelId: String?
            var requestedModelId: String?
            var executionPath: String?
            var fallbackReasonCode: String?
            for try await ev in await hubClient.streamResponse(reqId: rid, timeoutSec: 300.0) {
                if ev.type == "delta", let t = ev.text {
                    response += t
                }
                let modelId = (ev.actualModelIdFromMetadata ?? ev.model_id)?
                    .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                if !modelId.isEmpty {
                    actualModelId = modelId
                }
                let requested = ev.requestedModelIdFromMetadata?
                    .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                if !requested.isEmpty {
                    requestedModelId = requested
                }
                let path = ev.executionPathFromMetadata?
                    .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                if !path.isEmpty {
                    executionPath = path
                }
                let fallback = (ev.fallbackReasonCodeFromMetadata ?? ev.denyCodeFromMetadata)?
                    .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                if !fallback.isEmpty {
                    fallbackReasonCode = fallback
                }
            }
            let resolvedRequestedModelId = requestedModelId?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                ? requestedModelId
                : preferredModel
            let normalizedExecutionPath = executionPath?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let normalizedFallbackReasonCode = fallbackReasonCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let resolvedExecutionMode: SupervisorReplyExecutionMode =
                normalizedExecutionPath == SupervisorReplyExecutionMode.hubDowngradedToLocal.rawValue
                ? .hubDowngradedToLocal
                : .remoteModel

            if let strictFailure = strictSupervisorRemoteModelMismatchResponse(
                preferredModelId: preferredModel,
                actualModelId: actualModelId
            ) {
                recordSupervisorReplyExecution(
                    mode: resolvedExecutionMode,
                    actualModelId: actualModelId,
                    requestedModelId: resolvedRequestedModelId,
                    failureReasonCode: normalizedExecutionPath == SupervisorReplyExecutionMode.hubDowngradedToLocal.rawValue
                        ? (normalizedFallbackReasonCode.isEmpty ? "downgrade_to_local" : normalizedFallbackReasonCode)
                        : nil
                )
                return strictFailure
            }

            let sanitizedResponse = sanitizeSupervisorRemoteResponse(
                response,
                userMessage: userMessage,
                projects: projects
            )
            if sanitizedResponse != response {
                recordSupervisorReplyExecution(
                    mode: .localFallbackAfterRemoteError,
                    actualModelId: actualModelId,
                    requestedModelId: preferredModel,
                    failureReasonCode: "sanitized_remote_response"
                )
                return sanitizedResponse
            }

            let finalizedResponse = finalizeSupervisorModelResponseForDelivery(
                sanitizedResponse,
                userMessage: userMessage,
                triggerSource: triggerSource,
                personaSlot: executionPersona
            )
            if finalizedResponse.usedLocalFallback {
                recordSupervisorReplyExecution(
                    mode: .localFallbackAfterRemoteError,
                    actualModelId: nil,
                    requestedModelId: preferredModel,
                    failureReasonCode: "empty_remote_response"
                )
                return finalizedResponse.text
            }
            if resolvedExecutionMode == .hubDowngradedToLocal {
                recordSupervisorReplyExecution(
                    mode: .hubDowngradedToLocal,
                    actualModelId: actualModelId,
                    requestedModelId: resolvedRequestedModelId,
                    failureReasonCode: normalizedFallbackReasonCode.isEmpty ? "downgrade_to_local" : normalizedFallbackReasonCode
                )
                return finalizedResponse.text
            }
            recordSupervisorReplyExecution(
                mode: .remoteModel,
                actualModelId: actualModelId,
                requestedModelId: resolvedRequestedModelId,
                failureReasonCode: nil
            )
            return finalizedResponse.text
        } catch {
            print("Supervisor AI error: \(error)")
            let failureContext = supervisorRemoteFailureContext(
                for: error,
                preferredModelId: preferredModel
            )
            recordSupervisorReplyExecution(
                mode: .localFallbackAfterRemoteError,
                actualModelId: nil,
                requestedModelId: failureContext.requestedModelId,
                failureReasonCode: failureContext.failureReasonCode
            )
            return renderSupervisorFailureResponse(
                error: error,
                userMessage: userMessage,
                personaSlot: executionPersona
            )
        }
    }

    private func finalizeSupervisorModelResponseForDelivery(
        _ response: String,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource,
        personaSlot: SupervisorPersonaSlot? = nil
    ) -> (text: String, usedLocalFallback: Bool) {
        let processedResponse = processSupervisorCommands(
            response,
            userMessage: userMessage,
            triggerSource: triggerSource
        )
        let trimmedProcessed = processedResponse.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedProcessed.isEmpty else {
            return (
                generateFallbackResponse(
                    userMessage,
                    personaSlot: personaSlot
                ),
                true
            )
        }

        return (
            finalizeSupervisorGeneratedResponseWithCalendarReminderIfNeeded(
                trimmedProcessed
            ),
            false
        )
    }

    private func queueSupervisorEventLoopTurn(
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource,
        dedupeKey: String
    ) {
        guard supervisorEventLoopAutoFollowUpEnabled || supervisorEventLoopResponseOverride != nil else { return }
        let normalizedMessage = userMessage.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedKey = dedupeKey.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedMessage.isEmpty, !normalizedKey.isEmpty else { return }
        let now = Date().timeIntervalSince1970
        let metadata = supervisorEventLoopMetadata(
            userMessage: normalizedMessage,
            triggerSource: triggerSource,
            dedupeKey: normalizedKey
        )

        pruneSupervisorEventLoopTriggerLedger(now: now)
        if supervisorEventLoopRecentTriggerLedger[normalizedKey] != nil {
            let detail = supervisorEventLoopActivityDetail(
                triggerSummary: metadata.summary,
                dedupeKey: normalizedKey,
                policySummary: metadata.policySummary
            )
            _ = appendActionLedger(
                action: "supervisor_event_loop",
                targetRef: normalizedKey,
                projectId: metadata.projectId.isEmpty ? nil : metadata.projectId,
                projectName: metadata.projectName.isEmpty ? nil : metadata.projectName,
                role: nil,
                modelId: nil,
                status: "deduped",
                reasonCode: "duplicate_trigger",
                detail: detail,
                verifiedAt: now,
                triggerSource: triggerSource.rawValue
            )
            appendSupervisorEventLoopActivity(
                SupervisorEventLoopActivity(
                    id: UUID().uuidString,
                    createdAt: now,
                    updatedAt: now,
                    triggerSource: triggerSource.rawValue,
                    status: "deduped",
                    reasonCode: "duplicate_trigger",
                    dedupeKey: normalizedKey,
                    projectId: metadata.projectId,
                    projectName: metadata.projectName,
                    triggerSummary: metadata.summary,
                    resultSummary: "",
                    policySummary: metadata.policySummary,
                    blockedSummary: metadata.blockedSummary,
                    policyReason: metadata.policyReason,
                    governanceTruth: metadata.governanceTruth
                )
            )
            return
        }
        supervisorEventLoopRecentTriggerLedger[normalizedKey] = now

        let activityId = UUID().uuidString
        let ledgerId = appendActionLedger(
            action: "supervisor_event_loop",
            targetRef: normalizedKey,
            projectId: metadata.projectId.isEmpty ? nil : metadata.projectId,
            projectName: metadata.projectName.isEmpty ? nil : metadata.projectName,
            role: nil,
            modelId: nil,
            status: "queued",
            reasonCode: "queued",
            detail: supervisorEventLoopActivityDetail(
                triggerSummary: metadata.summary,
                dedupeKey: normalizedKey,
                policySummary: metadata.policySummary
            ),
            verifiedAt: nil,
            triggerSource: triggerSource.rawValue
        )

        let trigger = SupervisorEventLoopTrigger(
            activityId: activityId,
            ledgerId: ledgerId,
            userMessage: normalizedMessage,
            triggerSource: triggerSource,
            dedupeKey: normalizedKey,
            projectId: metadata.projectId,
            projectName: metadata.projectName,
            triggerSummary: metadata.summary,
            policySummary: metadata.policySummary,
            blockedSummary: metadata.blockedSummary,
            policyReason: metadata.policyReason,
            governanceTruth: metadata.governanceTruth
        )
        appendSupervisorEventLoopActivity(
            SupervisorEventLoopActivity(
                id: activityId,
                createdAt: now,
                updatedAt: now,
                triggerSource: triggerSource.rawValue,
                status: "queued",
                reasonCode: "queued",
                dedupeKey: normalizedKey,
                projectId: metadata.projectId,
                projectName: metadata.projectName,
                triggerSummary: metadata.summary,
                resultSummary: "",
                policySummary: metadata.policySummary,
                blockedSummary: metadata.blockedSummary,
                policyReason: metadata.policyReason,
                governanceTruth: metadata.governanceTruth
            )
        )
        if isProcessing || supervisorEventLoopTask != nil {
            pendingSupervisorEventLoopTriggers.append(trigger)
            refreshSupervisorEventLoopRuntimeState()
            return
        }

        startSupervisorEventLoopTurn(trigger)
    }

    private func supervisorEventLoopMetadata(
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource,
        dedupeKey: String
    ) -> (
        projectId: String,
        projectName: String,
        summary: String,
        policySummary: String,
        blockedSummary: String,
        policyReason: String,
        governanceTruth: String
    ) {
        let projectId = supervisorEventLoopLineValue("project_id", in: userMessage)
            .trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
        let projectName = [
            supervisorEventLoopLineValue("project_ref", in: userMessage),
            projectId,
            triggerSource.rawValue,
        ]
        .map { $0.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines) }
        .first { !$0.isEmpty } ?? triggerSource.rawValue

        let reviewTrigger = supervisorEventLoopLineValue("review_trigger", in: userMessage)
            .trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
        let reasonCode = supervisorEventLoopLineValue("reason_code", in: userMessage)
            .trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
        let nextSafeAction = supervisorEventLoopLineValue("next_safe_action", in: userMessage)
            .trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
        let uiReviewSummary = supervisorEventLoopLineValue("ui_review_summary", in: userMessage)
            .trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
        let uiReviewRepairSummary = supervisorEventLoopLineValue("ui_review_repair_summary", in: userMessage)
            .trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
        let primarySummary = [
            nextSafeAction == "open_ui_review" ? uiReviewRepairSummary : "",
            nextSafeAction == "open_ui_review" ? uiReviewSummary : "",
            uiReviewRepairSummary,
            supervisorEventLoopLineValue("summary", in: userMessage),
            uiReviewSummary,
            supervisorEventLoopLineValue("policy_reason", in: userMessage),
            supervisorEventLoopLineValue("execution_detail", in: userMessage),
            supervisorEventLoopLineValue("ack_note", in: userMessage),
        ]
        .map { $0.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines) }
        .first { !$0.isEmpty }

        let summary: String
        if let primarySummary, !primarySummary.isEmpty {
            if !reviewTrigger.isEmpty {
                summary = capped("\(reviewTrigger) · \(primarySummary)", maxChars: 220)
            } else {
                summary = capped(primarySummary, maxChars: 220)
            }
        } else if !reviewTrigger.isEmpty {
            summary = capped(reviewTrigger, maxChars: 220)
        } else if !reasonCode.isEmpty {
            summary = capped(reasonCode, maxChars: 220)
        } else {
            summary = capped(dedupeKey, maxChars: 220)
        }

        return (
            projectId,
            projectName,
            summary,
            supervisorEventLoopPolicySummary(
                userMessage: userMessage,
                projectId: projectId
            ),
            supervisorEventLoopBlockedSummary(userMessage: userMessage),
            supervisorEventLoopPolicyReason(userMessage: userMessage),
            supervisorEventLoopGovernanceTruth(userMessage: userMessage, projectId: projectId)
        )
    }

    private func supervisorEventLoopLineValue(
        _ key: String,
        in message: String
    ) -> String {
        let needle = key.trimmingCharacters(in: .whitespacesAndNewlines) + "="
        guard !needle.isEmpty else { return "" }
        for rawLine in message.split(whereSeparator: \.isNewline) {
            let line = rawLine.trimmingCharacters(in: .whitespacesAndNewlines)
            guard line.hasPrefix(needle) else { continue }
            return String(line.dropFirst(needle.count)).trimmingCharacters(in: .whitespacesAndNewlines)
        }
        return ""
    }

    private func supervisorEventLoopPolicySummary(
        userMessage: String,
        projectId: String
    ) -> String {
        let reviewTriggerText = supervisorEventLoopDisplayValue(
            raw: supervisorEventLoopLineValue("review_trigger", in: userMessage),
            parser: SupervisorReviewTrigger.init(rawValue:),
            display: \.displayName
        )
        let cadenceText = supervisorEventLoopLineValue("event_followup_rhythm", in: userMessage)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let tierText = supervisorEventLoopDisplayValue(
            raw: supervisorEventLoopLineValue("effective_supervisor_tier", in: userMessage),
            parser: AXProjectSupervisorInterventionTier.init(rawValue:),
            display: \.displayName
        )
        let depthText = supervisorEventLoopDisplayValue(
            raw: supervisorEventLoopLineValue("effective_work_order_depth", in: userMessage),
            parser: AXProjectSupervisorWorkOrderDepth.init(rawValue:),
            display: \.displayName
        )
        let strengthText = supervisorEventLoopDisplayValue(
            raw: supervisorEventLoopLineValue("project_ai_strength_band", in: userMessage),
            parser: AXProjectAIStrengthBand.init(rawValue:),
            display: \.displayName
        )
        let nextSafeAction = supervisorEventLoopLineValue("next_safe_action", in: userMessage)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let uiReviewRepairAction = supervisorEventLoopLineValue("ui_review_repair_action", in: userMessage)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let uiReviewRepairFocus = supervisorEventLoopLineValue("ui_review_repair_focus", in: userMessage)
            .trimmingCharacters(in: .whitespacesAndNewlines)

        var parts: [String] = []
        if !reviewTriggerText.isEmpty {
            parts.append("review=\(reviewTriggerText)")
        }

        if !cadenceText.isEmpty {
            parts.append(cadenceText)
        }

        let explicitGovernanceParts = [
            tierText.isEmpty ? "" : "tier=\(tierText)",
            depthText.isEmpty ? "" : "depth=\(depthText)",
            strengthText.isEmpty ? "" : "strength=\(strengthText)"
        ]
        .filter { !$0.isEmpty }

        if !explicitGovernanceParts.isEmpty {
            parts.append(explicitGovernanceParts.joined(separator: " · "))
        }

        if !nextSafeAction.isEmpty {
            parts.append("next=\(nextSafeAction)")
        }
        if !uiReviewRepairAction.isEmpty {
            if !uiReviewRepairFocus.isEmpty {
                parts.append("repair=\(uiReviewRepairAction)@\(uiReviewRepairFocus)")
            } else {
                parts.append("repair=\(uiReviewRepairAction)")
            }
        }

        if !parts.isEmpty {
            return capped(parts.joined(separator: " · "), maxChars: 220)
        }

        guard let governance = resolvedSupervisorEventLoopGovernance(projectId: projectId) else {
            return ""
        }

        if reviewTriggerText.isEmpty {
            return capped(
                SupervisorReviewPolicyEngine.eventFollowUpCadenceSummary(governance: governance),
                maxChars: 220
            )
        }
        return capped(
            "review=\(reviewTriggerText) · \(SupervisorReviewPolicyEngine.eventFollowUpCadenceSummary(governance: governance))",
            maxChars: 220
        )
    }

    private func supervisorEventLoopBlockedSummary(
        userMessage: String
    ) -> String {
        let summary = [
            supervisorEventLoopLineValue("blocked_summary", in: userMessage),
            supervisorEventLoopLineValue("ui_review_repair_summary", in: userMessage),
            supervisorEventLoopLineValue("ui_review_summary", in: userMessage),
            supervisorEventLoopLineValue("summary", in: userMessage)
        ]
        .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        .first { !$0.isEmpty } ?? ""
        return capped(summary, maxChars: 220)
    }

    private func supervisorEventLoopPolicyReason(
        userMessage: String
    ) -> String {
        capped(
            supervisorEventLoopLineValue("policy_reason", in: userMessage)
                .trimmingCharacters(in: .whitespacesAndNewlines),
            maxChars: 220
        )
    }

    private func supervisorEventLoopGovernanceTruth(
        userMessage: String,
        projectId: String
    ) -> String {
        let resolvedGovernance = resolvedSupervisorEventLoopGovernance(projectId: projectId)
        let schedule = resolvedGovernance?.effectiveBundle.schedule

        return XTGovernanceTruthPresentation.truthLine(
            configuredExecutionTier: supervisorEventLoopFirstNonEmptyValue(
                supervisorEventLoopLineValue("execution_tier", in: userMessage),
                resolvedGovernance?.configuredBundle.executionTier.rawValue
            ),
            effectiveExecutionTier: supervisorEventLoopFirstNonEmptyValue(
                supervisorEventLoopLineValue("effective_execution_tier", in: userMessage),
                resolvedGovernance?.effectiveBundle.executionTier.rawValue
            ),
            configuredSupervisorTier: supervisorEventLoopFirstNonEmptyValue(
                supervisorEventLoopLineValue("supervisor_intervention_tier", in: userMessage),
                resolvedGovernance?.configuredBundle.supervisorInterventionTier.rawValue
            ),
            effectiveSupervisorTier: supervisorEventLoopFirstNonEmptyValue(
                supervisorEventLoopLineValue("effective_supervisor_intervention_tier", in: userMessage),
                supervisorEventLoopLineValue("effective_supervisor_tier", in: userMessage),
                resolvedGovernance?.effectiveBundle.supervisorInterventionTier.rawValue
            ),
            reviewPolicyMode: supervisorEventLoopFirstNonEmptyValue(
                supervisorEventLoopLineValue("review_policy_mode", in: userMessage),
                resolvedGovernance?.effectiveBundle.reviewPolicyMode.rawValue
            ),
            progressHeartbeatSeconds: supervisorEventLoopLineIntValue(
                "progress_heartbeat_sec",
                in: userMessage
            ) ?? schedule?.progressHeartbeatSeconds,
            reviewPulseSeconds: supervisorEventLoopLineIntValue(
                "review_pulse_sec",
                in: userMessage
            ) ?? schedule?.reviewPulseSeconds,
            brainstormReviewSeconds: supervisorEventLoopLineIntValue(
                "brainstorm_review_sec",
                in: userMessage
            ) ?? schedule?.brainstormReviewSeconds,
            compatSource: supervisorEventLoopFirstNonEmptyValue(
                supervisorEventLoopLineValue("governance_compat_source", in: userMessage),
                resolvedGovernance?.compatSource.rawValue
            )
        ) ?? ""
    }

    private func resolvedSupervisorEventLoopGovernance(
        projectId: String
    ) -> AXProjectResolvedGovernanceState? {
        let normalizedProjectId = projectId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedProjectId.isEmpty else { return nil }
        guard let project = resolvedSupervisorProjectEntry(projectId: normalizedProjectId),
              let ctx = projectContext(from: project) else {
            return nil
        }
        if let resolved = resolvedSupervisorProjectGovernanceState(
            projectId: normalizedProjectId,
            ctx: ctx
        ) {
            return resolved
        }

        let config = (try? AXProjectStore.loadOrCreateConfig(for: ctx)) ?? .default(forProjectRoot: ctx.root)
        let adaptationPolicy = AXProjectSupervisorAdaptationPolicy.default
        let strengthProfile = AXProjectAIStrengthAssessor.assess(
            ctx: ctx,
            adaptationPolicy: adaptationPolicy
        )
        return xtResolveProjectGovernance(
            projectRoot: ctx.root,
            config: config,
            projectAIStrengthProfile: strengthProfile,
            adaptationPolicy: adaptationPolicy,
            permissionReadiness: .current()
        )
    }

    private func supervisorEventLoopDisplayValue<Value>(
        raw: String,
        parser: (String) -> Value?,
        display: (Value) -> String
    ) -> String {
        let normalized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalized.isEmpty else { return "" }
        guard let value = parser(normalized) else { return normalized }
        return display(value)
    }

    private func supervisorEventLoopLineIntValue(
        _ key: String,
        in message: String
    ) -> Int? {
        let value = supervisorEventLoopLineValue(key, in: message)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !value.isEmpty else { return nil }
        return Int(value)
    }

    private func supervisorEventLoopFirstNonEmptyValue(
        _ values: String?...
    ) -> String? {
        for value in values {
            let trimmed = (value ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty {
                return trimmed
            }
        }
        return nil
    }

    private func supervisorEventLoopActivityDetail(
        triggerSummary: String,
        dedupeKey: String,
        resultSummary: String = "",
        policySummary: String = ""
    ) -> String {
        let normalizedTriggerSummary = triggerSummary.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedResultSummary = resultSummary.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedPolicySummary = policySummary.trimmingCharacters(in: .whitespacesAndNewlines)
        var lines: [String] = []
        if !normalizedTriggerSummary.isEmpty {
            lines.append("trigger=\(normalizedTriggerSummary)")
        }
        if !normalizedResultSummary.isEmpty {
            lines.append("result=\(normalizedResultSummary)")
        }
        if !normalizedPolicySummary.isEmpty {
            lines.append(normalizedPolicySummary)
        }
        lines.append("key=\(dedupeKey)")
        return capped(lines.joined(separator: "\n"), maxChars: 220)
    }

    private func appendSupervisorEventLoopActivity(
        _ activity: SupervisorEventLoopActivity
    ) {
        recentSupervisorEventLoopActivities.append(activity)
        if recentSupervisorEventLoopActivities.count > supervisorEventLoopActivityMaxEntries {
            recentSupervisorEventLoopActivities.removeFirst(
                recentSupervisorEventLoopActivities.count - supervisorEventLoopActivityMaxEntries
            )
        }
        refreshSupervisorEventLoopRuntimeState()
    }

    private func updateSupervisorEventLoopActivity(
        id: String,
        status: String,
        reasonCode: String,
        resultSummary: String? = nil
    ) {
        guard let index = recentSupervisorEventLoopActivities.lastIndex(where: { $0.id == id }) else { return }
        recentSupervisorEventLoopActivities[index].status = status
        recentSupervisorEventLoopActivities[index].reasonCode = reasonCode
        recentSupervisorEventLoopActivities[index].updatedAt = Date().timeIntervalSince1970
        if let resultSummary {
            let normalized = resultSummary.trimmingCharacters(in: .whitespacesAndNewlines)
            if !normalized.isEmpty {
                recentSupervisorEventLoopActivities[index].resultSummary = capped(normalized, maxChars: 220)
            }
        }
        refreshSupervisorEventLoopRuntimeState()
    }

    private func refreshSupervisorEventLoopRuntimeState() {
        let queuedCount = pendingSupervisorEventLoopTriggers.count
        let hasRunning = supervisorEventLoopTask != nil
        if hasRunning, queuedCount > 0 {
            supervisorEventLoopStatusLine = "running · queued \(queuedCount)"
            return
        }
        if hasRunning {
            supervisorEventLoopStatusLine = "running"
            return
        }
        if queuedCount > 0 {
            supervisorEventLoopStatusLine = "queued \(queuedCount)"
            return
        }
        supervisorEventLoopStatusLine = recentSupervisorEventLoopActivities.isEmpty ? "idle" : "idle · recent activity"
    }

    private func recordSupervisorReviewNoteIfNeeded(
        userMessage: String,
        response: String,
        triggerSource: SupervisorCommandTriggerSource
    ) {
        let trimmedResponse = response.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedResponse.isEmpty else { return }

        let projects = projectsForTriggerSource(triggerSource)
        guard let selection = focusedSupervisorProjectSelection(
            projects: projects,
            userMessage: userMessage
        ) else { return }
        guard shouldCaptureSupervisorReviewNote(
            userMessage: userMessage,
            response: trimmedResponse,
            triggerSource: triggerSource
        ) else { return }

        let project = selection.project
        let ctx = supervisorMemoryContext(for: project)
        let projectDigests = projects.map(supervisorMemoryDigest)
        let digest = supervisorMemoryDigest(project)
        let governance = loadSupervisorProjectDigestGovernanceContext(projectId: project.projectId, ctx: ctx)
        let config = (try? AXProjectStore.loadOrCreateConfig(for: ctx)) ?? .default(forProjectRoot: ctx.root)
        let resolvedGovernance = governance.resolvedGovernance
            ?? resolvedSupervisorProjectGovernanceState(
                projectId: project.projectId,
                ctx: ctx
            )
            ?? xtResolveProjectGovernance(
                projectRoot: ctx.root,
                config: config,
                effectiveRuntimeSurface: config.effectiveRuntimeSurfacePolicy()
            )
        let effectiveRuntimeSurface = resolvedGovernance.effectiveRuntimeSurface
        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        let explicitTrigger = explicitSupervisorReviewTriggerHint(in: userMessage)
        let trigger = explicitTrigger ?? inferredSupervisorReviewTrigger(
            userMessage: userMessage,
            triggerSource: triggerSource
        )
        let requestedReviewLevel = explicitSupervisorReviewLevelHint(in: userMessage) ?? inferredSupervisorReviewLevel(
            userMessage: userMessage,
            response: trimmedResponse,
            trigger: trigger
        )
        let runKind = explicitSupervisorReviewRunKindHint(in: userMessage)
            ?? defaultSupervisorReviewRunKind(triggerSource: triggerSource, trigger: trigger)
        let verdict = inferredSupervisorReviewVerdict(
            response: trimmedResponse,
            digest: digest
        )
        let routing = inferredSupervisorReviewDelivery(verdict: verdict)
        let policy = SupervisorReviewPolicyEngine.resolve(
            governance: resolvedGovernance,
            trigger: trigger,
            requestedReviewLevel: requestedReviewLevel,
            verdict: verdict,
            requestedDeliveryMode: routing.deliveryMode,
            requestedAckRequired: routing.ackRequired,
            runKind: runKind
        )
        let auditOnly = !policy.shouldReview && shouldPersistAuditOnlySupervisorReviewNote(
            triggerSource: triggerSource,
            trigger: trigger,
            explicitTrigger: explicitTrigger,
            response: trimmedResponse
        )
        guard policy.shouldReview || auditOnly else { return }

        let targetRole: SupervisorGuidanceTargetRole = auditOnly ? .supervisor : routing.targetRole
        let deliveryMode: SupervisorGuidanceDeliveryMode = auditOnly ? .contextAppend : routing.deliveryMode
        let ackRequired = auditOnly ? false : policy.ackRequired
        let reviewId = "review-\(String(project.projectId.prefix(8)).lowercased())-\(nowMs)"
        let auditRef = "audit-supervisor-review-\(String(project.projectId.prefix(8)).lowercased())-\(nowMs)"
        let doneDefinition = firstMeaningfulDigestValue([
            governance.specCapsule?.mvpDefinition,
            digest.nextStep
        ])
        let constraints = focusedSupervisorReviewConstraintItems(
            specCapsule: governance.specCapsule,
            config: config,
            effectiveRuntimeSurface: effectiveRuntimeSurface
        )
        let memoryCursor = supervisorReviewCursor(reviewId: reviewId, createdAtMs: nowMs)
        let reviewWorkflowState = supervisorWorkflowState(
            project: project,
            ctx: ctx,
            preferredJobId: currentTask?.projectId == project.projectId ? currentTask?.id : nil,
            preferredPlanId: nil,
            preferredRequestId: nil
        )
        let adaptation = resolvedGovernance.supervisorAdaptation
        let strengthProfile = adaptation.projectAIStrengthProfile
        let workOrderRef = supervisorReviewWorkOrderRef(
            job: reviewWorkflowState?.job,
            plan: reviewWorkflowState?.plan
        )
        var note = SupervisorReviewNoteBuilder.build(
            reviewId: reviewId,
            projectId: project.projectId,
            trigger: trigger,
            reviewLevel: policy.reviewLevel,
            verdict: verdict,
            targetRole: targetRole,
            deliveryMode: deliveryMode,
            ackRequired: ackRequired,
            effectiveSupervisorTier: adaptation.effectiveSupervisorTier,
            effectiveWorkOrderDepth: adaptation.effectiveWorkOrderDepth,
            projectAIStrengthBand: strengthProfile?.strengthBand,
            projectAIStrengthConfidence: strengthProfile?.confidence,
            projectAIStrengthAuditRef: strengthProfile?.auditRef,
            workOrderRef: workOrderRef,
            summary: supervisorReviewSummary(trimmedResponse),
            recommendedActions: supervisorReviewRecommendedActions(
                from: trimmedResponse,
                fallbackNextStep: digest.nextStep,
                policy: policy,
                adaptation: adaptation,
                workflowState: reviewWorkflowState
            ),
            anchorGoal: digest.goal,
            anchorDoneDefinition: doneDefinition,
            anchorConstraints: constraints,
            currentState: digest.currentState,
            nextStep: digest.nextStep,
            blocker: digest.blocker,
            memoryCursor: memoryCursor,
            createdAtMs: nowMs,
            auditRef: auditRef
        )
        let guidance = auditOnly
            ? nil
            : supervisorGuidanceInjection(
                from: note,
                policy: policy,
                injectedAtMs: nowMs
            )
        let reviewExecutionBrief = focusedSupervisorExecutionBrief(
            selection: selection,
            projectDigests: projectDigests,
            includeLongtermOutline: true
        )
        let reviewWorkflowObservation = focusedSupervisorWorkflowMemorySlice(
            projects: projects,
            userMessage: userMessage,
            selection: selection
        )?.observation
        note.projectStateHash = focusedSupervisorCurrentStateHash(
            digest: digest,
            doneDefinition: doneDefinition,
            executionBrief: reviewExecutionBrief,
            workflowObservation: reviewWorkflowObservation,
            workflowState: reviewWorkflowState,
            latestGuidance: guidance,
            pendingAckGuidance: guidance?.ackRequired == true && guidance?.ackStatus == .pending ? guidance : nil
        )
        note.portfolioStateHash = supervisorPortfolioStateHash(projectDigests)

        do {
            try SupervisorReviewNoteStore.upsert(note, for: ctx)
            if let guidance {
                try SupervisorGuidanceInjectionStore.upsert(guidance, for: ctx)
            }
            try SupervisorReviewScheduleStore.markReview(
                for: ctx,
                config: config,
                trigger: trigger,
                runKind: runKind,
                nowMs: nowMs
            )
            AXProjectStore.appendRawLog(
                [
                    "type": "supervisor_review_note",
                    "action": "create",
                    "project_id": project.projectId,
                    "review_id": note.reviewId,
                    "trigger": note.trigger.rawValue,
                    "review_level": note.reviewLevel.rawValue,
                    "verdict": note.verdict.rawValue,
                    "target_role": note.targetRole.rawValue,
                    "delivery_mode": note.deliveryMode.rawValue,
                    "ack_required": note.ackRequired,
                    "effective_supervisor_tier": note.effectiveSupervisorTier?.rawValue ?? "",
                    "effective_work_order_depth": note.effectiveWorkOrderDepth?.rawValue ?? "",
                    "project_ai_strength_band": note.projectAIStrengthBand?.rawValue ?? "",
                    "project_ai_strength_confidence": note.projectAIStrengthConfidence ?? 0,
                    "project_ai_strength_audit_ref": note.projectAIStrengthAuditRef ?? "",
                    "work_order_ref": note.workOrderRef ?? "",
                    "audit_ref": note.auditRef,
                    "summary": note.summary,
                    "recommended_actions": note.recommendedActions,
                    "review_run_kind": runKind.rawValue,
                    "policy_reason": auditOnly ? "structured_followup_audit_capture" : policy.policyReason,
                    "audit_only": auditOnly,
                    "timestamp_ms": nowMs
                ],
                for: ctx
            )
            if let guidance {
                AXProjectStore.appendRawLog(
                    [
                        "type": "supervisor_guidance_injection",
                        "action": "create",
                        "project_id": project.projectId,
                        "review_id": note.reviewId,
                        "injection_id": guidance.injectionId,
                        "target_role": guidance.targetRole.rawValue,
                        "delivery_mode": guidance.deliveryMode.rawValue,
                        "intervention_mode": guidance.interventionMode.rawValue,
                        "safe_point_policy": guidance.safePointPolicy.rawValue,
                        "ack_status": guidance.ackStatus.rawValue,
                        "ack_required": guidance.ackRequired,
                        "effective_supervisor_tier": guidance.effectiveSupervisorTier?.rawValue ?? "",
                        "effective_work_order_depth": guidance.effectiveWorkOrderDepth?.rawValue ?? "",
                        "work_order_ref": guidance.workOrderRef ?? "",
                        "expires_at_ms": guidance.expiresAtMs,
                        "retry_at_ms": guidance.retryAtMs,
                        "retry_count": guidance.retryCount,
                        "max_retry_count": guidance.maxRetryCount,
                        "policy_reason": policy.policyReason,
                        "audit_ref": guidance.auditRef,
                        "guidance_text": guidance.guidanceText,
                        "timestamp_ms": nowMs
                    ],
                    for: ctx
                )
            }
        } catch {
            print("Supervisor review note save failed: \(error)")
        }
    }

    private func shouldPersistAuditOnlySupervisorReviewNote(
        triggerSource: SupervisorCommandTriggerSource,
        trigger: SupervisorReviewTrigger,
        explicitTrigger: SupervisorReviewTrigger?,
        response: String
    ) -> Bool {
        guard triggerSource != .userTurn else { return false }
        guard explicitTrigger != nil else { return false }
        guard !response.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return false }

        switch trigger {
        case .periodicPulse, .blockerDetected, .planDrift, .failureStreak, .noProgressWindow, .preDoneSummary, .preHighRiskAction, .userOverride:
            return true
        case .periodicHeartbeat, .manualRequest:
            return false
        }
    }

    private func shouldCaptureSupervisorReviewNote(
        userMessage: String,
        response: String,
        triggerSource: SupervisorCommandTriggerSource
    ) -> Bool {
        if triggerSource != .userTurn {
            return true
        }
        let normalizedUser = normalizedSupervisorIntentText(userMessage)
        let normalizedResponse = normalizedSupervisorIntentText(response)
        let reviewTokens = [
            "审查", "审阅", "review", "上下文", "记忆", "执行方案", "计划", "plan",
            "下一步", "next step", "重构建议", "架构", "brainstorm", "方向", "跑偏",
            "blocker", "阻塞", "质量", "方法", "方案"
        ]
        return reviewTokens.contains { normalizedUser.contains($0) || normalizedResponse.contains($0) }
    }

    private func explicitSupervisorReviewTriggerHint(
        in userMessage: String
    ) -> SupervisorReviewTrigger? {
        explicitSupervisorReviewTokenValue(
            key: "review_trigger",
            in: userMessage
        ).flatMap(SupervisorReviewTrigger.init(rawValue:))
    }

    private func explicitSupervisorReviewLevelHint(
        in userMessage: String
    ) -> SupervisorReviewLevel? {
        explicitSupervisorReviewTokenValue(
            key: "review_level_hint",
            in: userMessage
        ).flatMap(SupervisorReviewLevel.init(rawValue:))
    }

    private func explicitSupervisorReviewRunKindHint(
        in userMessage: String
    ) -> SupervisorReviewRunKind? {
        explicitSupervisorReviewTokenValue(
            key: "review_run_kind",
            in: userMessage
        ).flatMap(SupervisorReviewRunKind.init(rawValue:))
    }

    private func explicitSupervisorReviewTokenValue(
        key: String,
        in text: String
    ) -> String? {
        let needle = "\(key)="
        for rawLine in text.split(whereSeparator: \.isNewline) {
            let line = rawLine.trimmingCharacters(in: .whitespacesAndNewlines)
            guard line.hasPrefix(needle) else { continue }
            let value = String(line.dropFirst(needle.count)).trimmingCharacters(in: .whitespacesAndNewlines)
            return value.isEmpty ? nil : value
        }
        return nil
    }

    private func defaultSupervisorReviewRunKind(
        triggerSource: SupervisorCommandTriggerSource,
        trigger: SupervisorReviewTrigger
    ) -> SupervisorReviewRunKind {
        switch triggerSource {
        case .userTurn:
            return .manual
        case .heartbeat:
            return trigger == .noProgressWindow ? .brainstorm : .pulse
        case .officialSkillsChannel, .guidanceAck, .automationSafePoint, .incident, .skillCallback, .externalTriggerIngress, .grantResolution, .approvalResolution:
            return .eventDriven
        }
    }

    private func inferredSupervisorReviewTrigger(
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource
    ) -> SupervisorReviewTrigger {
        let normalized = normalizedSupervisorIntentText(userMessage)
        switch triggerSource {
        case .heartbeat:
            return .periodicPulse
        case .officialSkillsChannel:
            if containsAny(normalized, ["channel_status=failed", "channel_status=missing"]) {
                return .blockerDetected
            }
            return .periodicPulse
        case .incident:
            return .blockerDetected
        case .skillCallback:
            if containsAny(
                normalized,
                [
                    "review_trigger=blocker_detected",
                    "status=failed",
                    "status=blocked",
                    "status=canceled",
                    "active_plan_status=failed",
                    "active_plan_status=blocked",
                    "active_job_status=failed",
                    "active_job_status=blocked"
                ]
            ) {
                return .blockerDetected
            }
            if containsAny(normalized, ["review_trigger=pre_done_summary"]) {
                return .preDoneSummary
            }
            if containsAny(normalized, ["status=completed"]) &&
                containsAny(normalized, ["active_plan_status=completed", "active_job_status=completed"]) {
                return .preDoneSummary
            }
            return .periodicPulse
        case .guidanceAck:
            if containsAny(normalized, ["ack_status=rejected", "status=rejected", "rejected"]) {
                return .planDrift
            }
            if containsAny(normalized, ["ack_status=deferred", "status=deferred", "deferred"]) {
                return .blockerDetected
            }
            return .manualRequest
        case .automationSafePoint:
            return .blockerDetected
        case .grantResolution, .approvalResolution:
            return .userOverride
        case .externalTriggerIngress:
            return .manualRequest
        case .userTurn:
            if isExplicitSupervisorReviewRequest(normalized) {
                return .manualRequest
            }
            if containsAny(normalized, ["blocker", "阻塞", "卡住"]) {
                return .blockerDetected
            }
            if containsAny(normalized, ["跑偏", "偏离", "方向", "drift"]) {
                return .planDrift
            }
            if containsAny(normalized, ["高风险", "上线", "发布", "验收"]) {
                return .preHighRiskAction
            }
            if containsAny(normalized, ["完成", "done", "交付"]) {
                return .preDoneSummary
            }
            return .manualRequest
        }
    }

    private func isExplicitSupervisorReviewRequest(_ normalized: String) -> Bool {
        containsAny(
            normalized,
            [
                "review",
                "审查",
                "审阅",
                "评审",
                "brainstorm",
                "上下文记忆",
                "context memory",
                "执行方案",
                "执行计划",
                "具体方案",
                "最具体的执行方案",
                "下一步方案",
                "给出方案"
            ]
        )
    }

    private func inferredSupervisorReviewLevel(
        userMessage: String,
        response: String,
        trigger: SupervisorReviewTrigger
    ) -> SupervisorReviewLevel {
        let normalized = normalizedSupervisorIntentText("\(userMessage)\n\(response)")
        switch trigger {
        case .preHighRiskAction, .preDoneSummary:
            return .r3Rescue
        case .blockerDetected, .planDrift, .failureStreak, .noProgressWindow:
            return .r2Strategic
        default:
            break
        }
        if containsAny(normalized, ["高风险", "停止", "暂停", "验收", "上线", "交付"]) {
            return .r3Rescue
        }
        if containsAny(normalized, ["brainstorm", "重构", "架构", "方向", "跑偏", "阻塞", "质量", "更好的"]) {
            return .r2Strategic
        }
        return .r1Pulse
    }

    private func inferredSupervisorReviewVerdict(
        response: String,
        digest: SupervisorMemoryProjectDigest
    ) -> SupervisorReviewVerdict {
        let normalized = normalizedSupervisorIntentText(response)
        if containsAny(normalized, ["高风险", "停止", "暂停", "越界", "kill switch", "fail closed"]) {
            return .highRisk
        }
        if containsAny(normalized, ["跑偏", "偏离", "错误方向", "wrong direction"]) {
            return .wrongDirection
        }
        if containsAny(normalized, ["更好的路径", "更优", "更稳", "建议改", "重规划", "replan", "替代路径"]) {
            return .betterPathFound
        }
        if containsAny(normalized, ["注意", "留意", "观察点", "风险"]) || !isDigestPlaceholder(digest.blocker, treatNoValueAsPlaceholder: true) {
            return .watch
        }
        return .onTrack
    }

    private func inferredSupervisorReviewDelivery(
        verdict: SupervisorReviewVerdict
    ) -> (targetRole: SupervisorGuidanceTargetRole, deliveryMode: SupervisorGuidanceDeliveryMode, ackRequired: Bool) {
        switch verdict {
        case .highRisk:
            return (.coder, .stopSignal, true)
        case .betterPathFound, .wrongDirection:
            return (.coder, .replanRequest, true)
        case .watch:
            return (.coder, .priorityInsert, false)
        case .onTrack:
            return (.coder, .contextAppend, false)
        }
    }

    private func supervisorReviewSummary(_ response: String) -> String {
        let lines = response
            .split(whereSeparator: \.isNewline)
            .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        let base = capped(lines.first ?? response, maxChars: 220)
        guard let readiness = currentSupervisorMemoryAssemblyReadinessForLanguageLayer(),
              !readiness.ready else {
            return base
        }

        let issueSummary = readiness.issues
            .prefix(2)
            .map(\.summary)
            .joined(separator: "；")
        let lead: String
        if issueSummary.isEmpty {
            lead = "当前 strategic memory 供给不足，不适合直接做战略纠偏。"
        } else {
            lead = "当前 strategic memory 供给不足（\(issueSummary)），不适合直接做战略纠偏。"
        }
        if base.isEmpty {
            return capped(lead, maxChars: 220)
        }
        return capped("\(lead) \(base)", maxChars: 220)
    }

    private func supervisorReviewRecommendedActions(
        from response: String,
        fallbackNextStep: String,
        policy: SupervisorReviewPolicyDecision,
        adaptation: AXProjectSupervisorAdaptationSnapshot,
        workflowState: (job: SupervisorJobRecord, plan: SupervisorPlanRecord?, skillCall: SupervisorSkillCallRecord?)?
    ) -> [String] {
        let parsed = response
            .split(whereSeparator: \.isNewline)
            .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
            .compactMap { line -> (value: String, structured: Bool)? in
                guard !line.isEmpty else { return nil }
                let normalized = line
                    .replacingOccurrences(of: #"^\d+\.\s*"#, with: "", options: .regularExpression)
                    .replacingOccurrences(of: #"^[-*•]\s*"#, with: "", options: .regularExpression)
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                guard !normalized.isEmpty else { return nil }
                guard normalized != line || normalized.count <= 160 else { return nil }
                return (capped(normalized, maxChars: 160), normalized != line)
            }

        let filtered = parsed.filter {
            let lowered = $0.value.lowercased()
            return !lowered.hasPrefix("##") && !lowered.hasPrefix("[")
        }
        let structured = filtered
            .filter(\.structured)
            .map(\.value)
        let readiness = currentSupervisorMemoryAssemblyReadinessForLanguageLayer()
        if !structured.isEmpty {
            let baseActions = Array(structured.prefix(4))
            if let readiness, !readiness.ready {
                return Array(
                    orderedUniqueReviewScalars(
                        supervisorMemoryRecoveryActions(for: readiness) + baseActions
                    ).prefix(4)
                )
            }
            return Array(
                orderedUniqueReviewScalars(
                    supervisorStructuredFollowupActions(
                        baseActions: baseActions,
                        fallbackNextStep: fallbackNextStep,
                        policy: policy,
                        adaptation: adaptation,
                        workflowState: workflowState
                    ) + baseActions
                ).prefix(supervisorReviewRecommendedActionLimit(for: adaptation))
            )
        }

        let candidates = filtered.map(\.value)
        let unstructured = candidates.filter {
            let lowered = $0.lowercased()
            return !lowered.hasPrefix("##") && !lowered.hasPrefix("[")
        }
        if !unstructured.isEmpty {
            let baseActions = Array(unstructured.prefix(4))
            if let readiness, !readiness.ready {
                return Array(
                    orderedUniqueReviewScalars(
                        supervisorMemoryRecoveryActions(for: readiness) + baseActions
                    ).prefix(4)
                )
            }
            return Array(
                orderedUniqueReviewScalars(
                    supervisorStructuredFollowupActions(
                        baseActions: baseActions,
                        fallbackNextStep: fallbackNextStep,
                        policy: policy,
                        adaptation: adaptation,
                        workflowState: workflowState
                    ) + baseActions
                ).prefix(supervisorReviewRecommendedActionLimit(for: adaptation))
            )
        }

        let fallback = fallbackNextStep.trimmingCharacters(in: .whitespacesAndNewlines)
        let baseActions: [String]
        if !fallback.isEmpty, !isDigestPlaceholder(fallback, treatContinueCurrentTaskAsPlaceholder: true) {
            baseActions = [capped(fallback, maxChars: 160)]
        } else {
            baseActions = ["继续当前路径，并在下一观察点重新评估质量与偏航风险"]
        }
        if let readiness, !readiness.ready {
            return Array(
                orderedUniqueReviewScalars(
                    supervisorMemoryRecoveryActions(for: readiness) + baseActions
                ).prefix(4)
            )
        }
        return Array(
            orderedUniqueReviewScalars(
                supervisorStructuredFollowupActions(
                    baseActions: baseActions,
                    fallbackNextStep: fallbackNextStep,
                    policy: policy,
                    adaptation: adaptation,
                    workflowState: workflowState
                ) + baseActions
            ).prefix(supervisorReviewRecommendedActionLimit(for: adaptation))
        )
    }

    private func supervisorReviewRecommendedActionLimit(
        for adaptation: AXProjectSupervisorAdaptationSnapshot
    ) -> Int {
        adaptation.effectiveWorkOrderDepth >= .executionReady ? 5 : 4
    }

    private func supervisorStructuredFollowupActions(
        baseActions: [String],
        fallbackNextStep: String,
        policy: SupervisorReviewPolicyDecision,
        adaptation: AXProjectSupervisorAdaptationSnapshot,
        workflowState: (job: SupervisorJobRecord, plan: SupervisorPlanRecord?, skillCall: SupervisorSkillCallRecord?)?
    ) -> [String] {
        let depth = adaptation.effectiveWorkOrderDepth
        guard depth >= .executionReady else { return [] }
        guard policy.reviewLevel != .r1Pulse || policy.interventionMode == .replanNextSafePoint else {
            return []
        }
        guard !supervisorActionsAlreadySatisfyStructuredFollowup(baseActions, depth: depth) else {
            return []
        }
        guard let workflowState else { return [] }
        if supervisorShouldRelaxStructuredFollowup(
            baseActions: baseActions,
            policy: policy,
            adaptation: adaptation,
            workflowState: workflowState
        ) {
            return []
        }

        let focusStep = supervisorStructuredFocusStep(
            plan: workflowState.plan,
            depth: depth
        )
        let followupBoundary = supervisorStructuredSafePointLabel(policy.safePointPolicy)
        let planRef = workflowState.plan?.planId.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let jobGoal = workflowState.job.goal.trimmingCharacters(in: .whitespacesAndNewlines)
        let fallback = fallbackNextStep.trimmingCharacters(in: .whitespacesAndNewlines)
        let focusStepLabel = focusStep.map(supervisorStructuredWorkflowStepLabel)
        let nextPendingStep = supervisorOrderedWorkflowSteps(workflowState.plan)
            .first(where: { $0.status == .pending && $0.stepId != focusStep?.stepId })
        let nextPendingLabel = nextPendingStep.map(supervisorStructuredWorkflowStepLabel)

        switch depth {
        case .executionReady:
            var actions: [String] = []
            if let focusStepLabel {
                actions.append(
                    "在\(followupBoundary) 先把 \(focusStepLabel) 补成 execution-ready 工单：写清执行 detail、依赖、验证 checkpoint 和失败后的 replan 条件。"
                )
            } else if !planRef.isEmpty {
                actions.append(
                    "在\(followupBoundary) 先把计划 \(planRef) 补成 execution-ready 工单：按顺序写清步骤、owner、执行 detail 和验证 checkpoint。"
                )
            } else if !jobGoal.isEmpty {
                actions.append(
                    "围绕当前任务「\(capped(jobGoal, maxChars: 72))」先产出 execution-ready 工单：至少 2-4 个顺序步骤，并补一个验证/验收 checkpoint。"
                )
            } else if !fallback.isEmpty {
                actions.append(
                    "先把「\(capped(fallback, maxChars: 72))」改写成 execution-ready 工单：写清步骤顺序、执行 detail、依赖和验证方式。"
                )
            }
            if !planRef.isEmpty {
                let target = nextPendingLabel ?? focusStepLabel ?? "当前计划"
                actions.append(
                    "围绕计划 \(planRef) 明确 \(target) 的 owner、完成定义和回执格式；确认后再推进后续步骤。"
                )
            }
            return actions
        case .stepLockedRescue:
            var actions: [String] = []
            let focus = focusStepLabel ?? nextPendingLabel ?? (!planRef.isEmpty ? "计划 \(planRef)" : "当前 rescue 工单")
            actions.append(
                "在\(followupBoundary) 按 step_locked_rescue 重排当前工单：只推进 \(focus) 这一个解阻塞步骤，未完成验证前不要并行推进后续步骤。"
            )
            if let nextPendingLabel {
                actions.append(
                    "把后续步骤（先从 \(nextPendingLabel) 开始）串成 depends_on，并在当前步骤后补一个验证/回滚检查点。"
                )
            } else {
                actions.append(
                    "在当前解阻塞步骤后补一个验证/回滚检查点，验证通过后再放行下一步。"
                )
            }
            return actions
        case .none, .brief, .milestoneContract:
            return []
        }
    }

    private func supervisorShouldRelaxStructuredFollowup(
        baseActions: [String],
        policy: SupervisorReviewPolicyDecision,
        adaptation: AXProjectSupervisorAdaptationSnapshot,
        workflowState: (job: SupervisorJobRecord, plan: SupervisorPlanRecord?, skillCall: SupervisorSkillCallRecord?)
    ) -> Bool {
        guard adaptation.effectiveWorkOrderDepth == .executionReady else { return false }
        guard policy.reviewLevel != .r3Rescue else { return false }
        guard let strengthBand = adaptation.projectAIStrengthProfile?.strengthBand,
              strengthBand >= .capable else {
            return false
        }

        return supervisorActionsShowAnchoredExecutionIntent(
            baseActions,
            workflowState: workflowState
        )
    }

    private func supervisorActionsShowAnchoredExecutionIntent(
        _ actions: [String],
        workflowState: (job: SupervisorJobRecord, plan: SupervisorPlanRecord?, skillCall: SupervisorSkillCallRecord?)
    ) -> Bool {
        let meaningfulActions = actions
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter {
                !$0.isEmpty &&
                !supervisorActionIsGenericFollowupPlaceholder($0)
            }
        guard meaningfulActions.count >= 2 else { return false }

        var anchors: [String] = []
        if let plan = workflowState.plan {
            anchors.append(plan.planId)
        }
        for step in supervisorOrderedWorkflowSteps(workflowState.plan).prefix(3) {
            anchors.append(step.stepId)
            anchors.append(step.title)
            anchors.append(supervisorStructuredWorkflowStepLabel(step))
        }

        let normalizedAnchors = anchors
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty && ($0.count >= 4 || $0.contains("-")) }
        guard !normalizedAnchors.isEmpty else { return false }

        let anchoredActionCount = meaningfulActions.filter { action in
            let lowered = action.lowercased()
            return normalizedAnchors.contains { anchor in
                lowered.contains(anchor.lowercased())
            }
        }.count

        return anchoredActionCount >= 2 || (anchoredActionCount >= 1 && meaningfulActions.count >= 3)
    }

    private func supervisorActionIsGenericFollowupPlaceholder(
        _ action: String
    ) -> Bool {
        if isDigestPlaceholder(action, treatContinueCurrentTaskAsPlaceholder: true) {
            return true
        }

        let lowered = action.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let genericPhrases = [
            "继续当前路径",
            "继续推进当前路径",
            "继续当前路线",
            "继续按当前路径",
            "继续按现有计划",
            "补一下后续计划",
            "补一下计划",
            "按当前路径继续",
            "continue current path",
            "continue the current path",
            "continue as planned",
        ]
        return genericPhrases.contains(where: lowered.contains)
    }

    private func supervisorActionsAlreadySatisfyStructuredFollowup(
        _ actions: [String],
        depth: AXProjectSupervisorWorkOrderDepth
    ) -> Bool {
        guard !actions.isEmpty else { return false }
        let tokens: [String]
        switch depth {
        case .executionReady:
            tokens = [
                "execution-ready", "execution ready", "工单", "步骤", "step",
                "detail", "依赖", "验证", "验收", "checkpoint", "replan"
            ]
        case .stepLockedRescue:
            tokens = [
                "step_locked_rescue", "解阻塞", "串行", "depends_on", "依赖",
                "验证", "checkpoint", "回滚", "只推进", "单步"
            ]
        case .none, .brief, .milestoneContract:
            return true
        }
        return actions.contains { action in
            containsAny(action.lowercased(), tokens)
        }
    }

    private func supervisorStructuredSafePointLabel(
        _ policy: SupervisorGuidanceSafePointPolicy
    ) -> String {
        switch policy {
        case .nextToolBoundary:
            return "下一个 tool boundary"
        case .nextStepBoundary:
            return "下一个 step boundary"
        case .checkpointBoundary:
            return "下一个 checkpoint"
        case .immediate:
            return "当前立即"
        }
    }

    private func supervisorStructuredFocusStep(
        plan: SupervisorPlanRecord?,
        depth: AXProjectSupervisorWorkOrderDepth
    ) -> SupervisorPlanStepRecord? {
        let orderedSteps = supervisorOrderedWorkflowSteps(plan)
        switch depth {
        case .stepLockedRescue:
            return orderedSteps.first(where: { $0.status == .blocked || $0.status == .awaitingAuthorization || $0.status == .running })
                ?? orderedSteps.first(where: { $0.status == .pending })
                ?? orderedSteps.first
        case .executionReady:
            return orderedSteps.first(where: { $0.status == .blocked || $0.status == .awaitingAuthorization })
                ?? orderedSteps.first(where: { $0.status == .pending })
                ?? orderedSteps.first(where: { $0.status == .running })
                ?? orderedSteps.first
        case .none, .brief, .milestoneContract:
            return nil
        }
    }

    private func supervisorOrderedWorkflowSteps(
        _ plan: SupervisorPlanRecord?
    ) -> [SupervisorPlanStepRecord] {
        guard let plan else { return [] }
        return plan.steps.sorted { lhs, rhs in
            if lhs.orderIndex != rhs.orderIndex {
                return lhs.orderIndex < rhs.orderIndex
            }
            return lhs.stepId < rhs.stepId
        }
    }

    private func supervisorStructuredWorkflowStepLabel(
        _ step: SupervisorPlanStepRecord
    ) -> String {
        let title = step.title.trimmingCharacters(in: .whitespacesAndNewlines)
        let stepId = step.stepId.trimmingCharacters(in: .whitespacesAndNewlines)
        if !stepId.isEmpty && !title.isEmpty {
            return "\(stepId) \(capped(title, maxChars: 72))"
        }
        if !title.isEmpty {
            return capped(title, maxChars: 72)
        }
        if !stepId.isEmpty {
            return stepId
        }
        return "当前步骤"
    }

    private func currentSupervisorMemoryAssemblyReadinessForLanguageLayer() -> SupervisorMemoryAssemblyReadiness? {
        guard supervisorMemoryAssemblySnapshot != nil else { return nil }
        return supervisorMemoryAssemblyReadiness
    }

    private func supervisorMemoryRecoveryActions(
        for readiness: SupervisorMemoryAssemblyReadiness
    ) -> [String] {
        var actions = [
            "先补齐长期目标和完成标准、关键决策原因、当前卡点与已试动作、以及可作为依据的日志或结果，再确认记忆深度达标后做战略纠偏"
        ]
        let issueCodes = Set(readiness.issueCodes)
        if issueCodes.contains("memory_review_floor_not_met") {
            actions.append("先把当前项目的深度记忆拉到至少 m3，再决定是否调整项目战略")
        }
        if issueCodes.contains("memory_strategic_anchor_underfed") {
            actions.append("先把项目长期目标、关键决策原因和当前卡点讲清楚，再给战略建议")
        }
        if issueCodes.contains("memory_focus_evidence_missing") {
            actions.append("先补你认可的日志、回执、实验结果这些依据，再判断是否需要 replan")
        }
        if issueCodes.contains("memory_core_layers_truncated") {
            actions.append("先补齐项目背景、近期变化和当前执行状态，再判断当前路径是否偏航")
        }
        return actions
    }

    private func focusedSupervisorReviewConstraintItems(
        specCapsule: SupervisorProjectSpecCapsule?,
        config: AXProjectConfig,
        effectiveRuntimeSurface: AXProjectRuntimeSurfaceEffectivePolicy
    ) -> [String] {
        var items: [String] = []
        if let specCapsule {
            items.append(contentsOf: specCapsule.nonGoals.prefix(3).map { "non_goal=\($0)" })
            items.append(contentsOf: specCapsule.techStackBlacklist.prefix(2).map { "tech_stack_blacklist=\($0)" })
            if !specCapsule.approvedTechStack.isEmpty {
                items.append("approved_tech_stack=\(specCapsule.approvedTechStack.prefix(3).joined(separator: " | "))")
            }
        }
        items.append("surface=\(config.runtimeSurfaceMode.rawValue)->\(effectiveRuntimeSurface.effectiveMode.rawValue)")
        items.append("override=\(effectiveRuntimeSurface.hubOverrideMode.rawValue)")
        if effectiveRuntimeSurface.killSwitchEngaged {
            items.append("kill_switch=on")
        }
        return items
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
    }

    private func startSupervisorEventLoopTurn(_ trigger: SupervisorEventLoopTrigger) {
        updateActionLedger(
            id: trigger.ledgerId,
            status: "running",
            reasonCode: "started",
            detail: supervisorEventLoopActivityDetail(
                triggerSummary: trigger.triggerSummary,
                dedupeKey: trigger.dedupeKey,
                policySummary: trigger.policySummary
            ),
            verifiedAt: nil
        )
        updateSupervisorEventLoopActivity(
            id: trigger.activityId,
            status: "running",
            reasonCode: "started"
        )
        supervisorEventLoopTask = Task { @MainActor [weak self] in
            guard let self else { return }
            await self.runSupervisorEventLoopTurn(trigger)
        }
        refreshSupervisorEventLoopRuntimeState()
    }

    private func runSupervisorEventLoopTurn(_ trigger: SupervisorEventLoopTrigger) async {
        let response: String
        if let override = supervisorEventLoopResponseOverride {
            let raw = await override(trigger.userMessage, trigger.triggerSource.rawValue)
            response = processSupervisorCommands(
                raw,
                userMessage: trigger.userMessage,
                triggerSource: trigger.triggerSource
            )
        } else {
            response = await generateSupervisorResponse(
                trigger.userMessage,
                triggerSource: trigger.triggerSource
            )
        }

        let trimmed = response.trimmingCharacters(in: .whitespacesAndNewlines)
        if !trimmed.isEmpty {
            let turnRoutingDecision = resolveSupervisorTurnRoutingDecision(
                userMessage: trigger.userMessage,
                projects: projectsForTriggerSource(trigger.triggerSource)
            )
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: trigger.userMessage,
                    responseText: trimmed,
                    triggerSource: trigger.triggerSource,
                    triggeredByVoice: false,
                    spokenOutcome: .suppressed("event_loop_text_reply"),
                    replySource: "event_loop_reply",
                    personaSlot: nil,
                    turnRoutingDecision: turnRoutingDecision,
                    turnRoutingDeltaCursor: currentSupervisorFocusPointerDeltaCursorCandidate(),
                    lifecycle: .backgroundAssistantReply
                )
            )
        }

        let completionStatus = trimmed.isEmpty ? "completed_empty" : "completed"
        let completionReason = trimmed.isEmpty ? "empty_response" : "ok"
        let completionDetail = supervisorEventLoopActivityDetail(
            triggerSummary: trigger.triggerSummary,
            dedupeKey: trigger.dedupeKey,
            resultSummary: trimmed.isEmpty ? "" : trimmed.replacingOccurrences(of: "\n", with: " "),
            policySummary: trigger.policySummary
        )
        updateActionLedger(
            id: trigger.ledgerId,
            status: completionStatus,
            reasonCode: completionReason,
            detail: completionDetail,
            verifiedAt: Date().timeIntervalSince1970
        )
        updateSupervisorEventLoopActivity(
            id: trigger.activityId,
            status: completionStatus,
            reasonCode: completionReason,
            resultSummary: trimmed.isEmpty ? nil : trimmed
        )
        supervisorEventLoopTask = nil
        refreshSupervisorEventLoopRuntimeState()
        drainPendingSupervisorEventLoopIfNeeded()
    }

    private func drainPendingSupervisorEventLoopIfNeeded() {
        guard !isProcessing else { return }
        guard supervisorEventLoopTask == nil else { return }
        guard !pendingSupervisorEventLoopTriggers.isEmpty else {
            refreshSupervisorEventLoopRuntimeState()
            return
        }
        let trigger = pendingSupervisorEventLoopTriggers.removeFirst()
        startSupervisorEventLoopTurn(trigger)
    }

    private func pruneSupervisorEventLoopTriggerLedger(now: TimeInterval) {
        let maxAge: TimeInterval = 15
        supervisorEventLoopRecentTriggerLedger = supervisorEventLoopRecentTriggerLedger.filter {
            now - $0.value < maxAge
        }
    }

    private func buildSupervisorEventLoopMessage(
        trigger: SupervisorCommandTriggerSource,
        project: AXProjectEntry,
        record: SupervisorSkillCallRecord,
        extraLines: [String]
    ) -> String {
        let workflowContext = supervisorEventLoopWorkflowContext(project: project, record: record)
        let baseLines = [
            "自动继续当前 governed workflow。",
            "trigger=\(trigger.rawValue)",
            "project_ref=\(project.displayName)",
            "project_id=\(project.projectId)",
            "job_id=\(record.jobId)",
            "plan_id=\(record.planId)",
            "step_id=\(record.stepId)",
            "request_id=\(record.requestId)",
            "skill_id=\(record.skillId)"
        ] + extraLines

        var lines = baseLines
        if !workflowContext.isEmpty {
            lines.append(workflowContext.trimmingCharacters(in: .whitespacesAndNewlines))
        }
        return lines.joined(separator: "\n")
    }

    private func scheduleSupervisorSkillCallbackFollowUp(
        record: SupervisorSkillCallRecord,
        project: AXProjectEntry,
        ctx: AXProjectContext,
        status: SupervisorSkillCallStatus,
        reason: String
    ) {
        let reviewHint = resolvedSupervisorSkillCallbackReviewHint(
            project: project,
            record: record,
            status: status
        )
        let normalizedReason = capped(
            reason.trimmingCharacters(in: .whitespacesAndNewlines).replacingOccurrences(of: "\n", with: " "),
            maxChars: 220
        )
        persistSupervisorUIReviewRepairGuidanceIfNeeded(
            record: record,
            project: project,
            ctx: ctx,
            status: status,
            reason: normalizedReason
        )
        let message = buildSupervisorEventLoopMessage(
            trigger: .skillCallback,
            project: project,
            record: record,
            extraLines: [
                "tool_name=\(record.toolName.isEmpty ? "(none)" : record.toolName)",
                "status=\(status.rawValue)",
                "review_trigger=\(reviewHint.trigger.rawValue)",
                "review_level_hint=\(reviewHint.reviewLevel.rawValue)",
                "review_run_kind=\(reviewHint.runKind.rawValue)",
                "summary=\(normalizedReason.isEmpty ? "(none)" : normalizedReason)"
            ] + supervisorSkillCallbackUIReviewExtraLines(
                requestId: record.requestId,
                ctx: ctx
            )
        )
        queueSupervisorEventLoopTurn(
            userMessage: message,
            triggerSource: .skillCallback,
            dedupeKey: "skill_callback:\(record.requestId):\(status.rawValue):\(reviewHint.trigger.rawValue)"
        )
    }

    private func persistSupervisorUIReviewRepairGuidanceIfNeeded(
        record: SupervisorSkillCallRecord,
        project: AXProjectEntry,
        ctx: AXProjectContext,
        status: SupervisorSkillCallStatus,
        reason: String
    ) {
        guard let evidenceRef = supervisorUIReviewAgentEvidenceRef(requestId: record.requestId, ctx: ctx),
              let snapshot = XTUIReviewAgentEvidenceStore.load(ref: evidenceRef, for: ctx),
              supervisorShouldRouteToUIReview(snapshot),
              let repair = SupervisorUIReviewRepairPlanner.guidance(for: snapshot) else {
            return
        }

        let semantics = supervisorUIReviewRepairGuidanceSemantics(
            projectId: project.projectId,
            snapshot: snapshot,
            repair: repair,
            status: status,
            ctx: ctx
        )
        let workflowState = supervisorWorkflowState(
            project: project,
            ctx: ctx,
            preferredJobId: record.jobId,
            preferredPlanId: record.planId,
            preferredRequestId: record.requestId
        )
        let workOrderRef = supervisorReviewWorkOrderRef(
            job: workflowState?.job,
            plan: workflowState?.plan
        )
        let guidanceText = supervisorUIReviewRepairGuidanceText(
            record: record,
            snapshot: snapshot,
            repair: repair,
            status: status,
            reason: reason,
            evidenceRef: evidenceRef
        )
        let injectionId = supervisorUIReviewRepairInjectionId(
            requestId: record.requestId,
            repairAction: repair.actionCode
        )
        let reviewId = supervisorUIReviewRepairReviewId(
            requestId: record.requestId,
            reviewId: snapshot.reviewID,
            repairAction: repair.actionCode
        )
        let existing = SupervisorGuidanceInjectionStore.record(
            injectionId: injectionId,
            for: ctx
        )
        if let existing,
           existing.reviewId == reviewId,
           existing.targetRole == semantics.targetRole,
           existing.deliveryMode == semantics.deliveryMode,
           existing.interventionMode == semantics.interventionMode,
           existing.safePointPolicy == semantics.safePointPolicy,
           existing.guidanceText == guidanceText,
           existing.ackRequired == semantics.ackRequired,
           existing.effectiveSupervisorTier == semantics.effectiveSupervisorTier,
           existing.effectiveWorkOrderDepth == semantics.effectiveWorkOrderDepth,
           existing.workOrderRef == workOrderRef {
            return
        }

        let injectedAtMs = max(record.updatedAtMs, snapshot.updatedAtMs)
        let lifecycle = supervisorGuidanceLifecycle(
            policy: SupervisorReviewPolicyDecision(
                shouldReview: true,
                reviewLevel: semantics.reviewLevel,
                reviewMemoryCeiling: semantics.effectiveSupervisorTier.defaultReviewMemoryCeiling,
                interventionMode: semantics.interventionMode,
                safePointPolicy: semantics.safePointPolicy,
                ackRequired: semantics.ackRequired,
                policyReason: semantics.policyReason
            ),
            injectedAtMs: injectedAtMs
        )
        let guidance = SupervisorGuidanceInjectionBuilder.build(
            injectionId: injectionId,
            reviewId: reviewId,
            projectId: project.projectId,
            targetRole: semantics.targetRole,
            deliveryMode: semantics.deliveryMode,
            interventionMode: semantics.interventionMode,
            safePointPolicy: semantics.safePointPolicy,
            guidanceText: guidanceText,
            ackStatus: .pending,
            ackRequired: semantics.ackRequired,
            effectiveSupervisorTier: semantics.effectiveSupervisorTier,
            effectiveWorkOrderDepth: semantics.effectiveWorkOrderDepth,
            workOrderRef: workOrderRef,
            ackNote: "",
            injectedAtMs: injectedAtMs,
            ackUpdatedAtMs: 0,
            expiresAtMs: lifecycle.expiresAtMs,
            retryAtMs: 0,
            retryCount: 0,
            maxRetryCount: lifecycle.maxRetryCount,
            auditRef: supervisorUIReviewRepairAuditRef(
                requestId: record.requestId,
                reviewId: snapshot.reviewID,
                repairAction: repair.actionCode,
                updatedAtMs: injectedAtMs
            )
        )

        do {
            try SupervisorGuidanceInjectionStore.upsert(guidance, for: ctx)
            AXProjectStore.appendRawLog(
                [
                    "type": "supervisor_guidance_injection",
                    "action": existing == nil ? "create" : "update",
                    "source": "ui_review_repair",
                    "project_id": project.projectId,
                    "request_id": record.requestId,
                    "review_id": guidance.reviewId,
                    "injection_id": guidance.injectionId,
                    "target_role": guidance.targetRole.rawValue,
                    "delivery_mode": guidance.deliveryMode.rawValue,
                    "intervention_mode": guidance.interventionMode.rawValue,
                    "safe_point_policy": guidance.safePointPolicy.rawValue,
                    "ack_status": guidance.ackStatus.rawValue,
                    "ack_required": guidance.ackRequired,
                    "effective_supervisor_tier": guidance.effectiveSupervisorTier?.rawValue ?? "",
                    "effective_work_order_depth": guidance.effectiveWorkOrderDepth?.rawValue ?? "",
                    "work_order_ref": guidance.workOrderRef ?? "",
                    "repair_action": repair.actionCode,
                    "repair_focus": repair.focusArea,
                    "ui_review_agent_evidence_ref": evidenceRef,
                    "ui_review_review_id": snapshot.reviewID,
                    "ui_review_verdict": snapshot.verdict.rawValue,
                    "skill_status": status.rawValue,
                    "skill_result_summary": reason,
                    "policy_reason": semantics.policyReason,
                    "audit_ref": guidance.auditRef,
                    "guidance_text": guidance.guidanceText,
                    "timestamp_ms": injectedAtMs
                ],
                for: ctx
            )
        } catch {
            print("Supervisor UI review repair guidance save failed: \(error)")
        }
    }

    private func supervisorUIReviewRepairGuidanceSemantics(
        projectId: String,
        snapshot: XTUIReviewAgentEvidenceSnapshot,
        repair: SupervisorUIReviewRepairGuidance,
        status: SupervisorSkillCallStatus,
        ctx: AXProjectContext
    ) -> (
        reviewLevel: SupervisorReviewLevel,
        targetRole: SupervisorGuidanceTargetRole,
        deliveryMode: SupervisorGuidanceDeliveryMode,
        interventionMode: SupervisorGuidanceInterventionMode,
        safePointPolicy: SupervisorGuidanceSafePointPolicy,
        ackRequired: Bool,
        effectiveSupervisorTier: AXProjectSupervisorInterventionTier,
        effectiveWorkOrderDepth: AXProjectSupervisorWorkOrderDepth,
        policyReason: String
    ) {
        let governance = resolvedSupervisorProjectGovernanceState(
            projectId: projectId,
            ctx: ctx
        )
        let effectiveSupervisorTier = governance?.supervisorAdaptation.effectiveSupervisorTier
            ?? governance?.effectiveBundle.supervisorInterventionTier
            ?? .s2PeriodicReview
        let effectiveWorkOrderDepth = governance?.supervisorAdaptation.effectiveWorkOrderDepth
            ?? effectiveSupervisorTier.defaultWorkOrderDepth
        let severe = supervisorUIReviewRepairIsStopworthy(
            snapshot: snapshot,
            repair: repair,
            status: status
        )
        let reviewLevel: SupervisorReviewLevel = severe || effectiveWorkOrderDepth == .stepLockedRescue
            ? .r3Rescue
            : .r2Strategic
        let deliveryMode: SupervisorGuidanceDeliveryMode = severe ? .stopSignal : .replanRequest
        let interventionMode: SupervisorGuidanceInterventionMode = severe
            ? .stopImmediately
            : .replanNextSafePoint
        let safePointPolicy: SupervisorGuidanceSafePointPolicy = severe
            ? .immediate
            : (effectiveWorkOrderDepth == .stepLockedRescue ? .checkpointBoundary : .nextStepBoundary)
        let ackRequired = severe || effectiveWorkOrderDepth >= .executionReady
        return (
            reviewLevel: reviewLevel,
            targetRole: .projectChat,
            deliveryMode: deliveryMode,
            interventionMode: interventionMode,
            safePointPolicy: safePointPolicy,
            ackRequired: ackRequired,
            effectiveSupervisorTier: effectiveSupervisorTier,
            effectiveWorkOrderDepth: effectiveWorkOrderDepth,
            policyReason: "ui_review_repair:\(repair.actionCode):status=\(status.rawValue):verdict=\(snapshot.verdict.rawValue)"
        )
    }

    private func supervisorUIReviewRepairIsStopworthy(
        snapshot: XTUIReviewAgentEvidenceSnapshot,
        repair: SupervisorUIReviewRepairGuidance,
        status: SupervisorSkillCallStatus
    ) -> Bool {
        if status == .blocked || status == .failed {
            return true
        }
        switch repair.actionCode {
        case "repair_primary_cta_visibility", "repair_interactive_target_exposure":
            return true
        default:
            break
        }
        return snapshot.issueCodes.contains {
            let normalized = $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            return normalized == "critical_action_not_visible"
                || normalized == "interactive_target_missing"
        }
    }

    private func supervisorUIReviewRepairGuidanceText(
        record: SupervisorSkillCallRecord,
        snapshot: XTUIReviewAgentEvidenceSnapshot,
        repair: SupervisorUIReviewRepairGuidance,
        status: SupervisorSkillCallStatus,
        reason: String,
        evidenceRef: String
    ) -> String {
        let issueCodes = snapshot.issueCodes
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        var lines: [String] = [
            repair.summary,
            "instruction=\(capped(repair.prompt, maxChars: 260))",
            "source=ui_review_repair",
            "request_id=\(record.requestId)",
            "skill_id=\(record.skillId)",
            "status=\(status.rawValue)",
            "ui_review_ref=\(evidenceRef)",
            "ui_review_review_id=\(snapshot.reviewID)",
            "ui_review_verdict=\(snapshot.verdict.rawValue)",
            "repair_action=\(repair.actionCode)",
            "repair_focus=\(repair.focusArea)",
            "next_safe_action=open_ui_review"
        ]
        if !issueCodes.isEmpty {
            lines.append("ui_review_issue_codes=\(issueCodes.joined(separator: ","))")
        }
        let reviewSummary = snapshot.summary.trimmingCharacters(in: .whitespacesAndNewlines)
        if !reviewSummary.isEmpty {
            lines.append("ui_review_summary=\(capped(reviewSummary, maxChars: 220))")
        }
        if !reason.isEmpty {
            lines.append("skill_result_summary=\(capped(reason, maxChars: 220))")
        }
        if let trend = snapshot.trend.first(where: {
            $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased().contains("status=")
        }) {
            lines.append("ui_review_trend=\(trend)")
        }
        return lines.joined(separator: "\n")
    }

    private func supervisorUIReviewRepairInjectionId(
        requestId: String,
        repairAction: String
    ) -> String {
        let requestToken = supervisorUIReviewRepairStableToken(requestId, fallback: "request")
        let actionToken = supervisorUIReviewRepairStableToken(repairAction, fallback: "repair")
        return "guidance-ui-review-\(requestToken)-\(actionToken)"
    }

    private func supervisorUIReviewRepairReviewId(
        requestId: String,
        reviewId: String,
        repairAction: String
    ) -> String {
        let requestToken = supervisorUIReviewRepairStableToken(requestId, fallback: "request")
        let reviewToken = supervisorUIReviewRepairStableToken(reviewId, fallback: "review")
        let actionToken = supervisorUIReviewRepairStableToken(repairAction, fallback: "repair")
        return "review-ui-review-\(requestToken)-\(reviewToken)-\(actionToken)"
    }

    private func supervisorUIReviewRepairAuditRef(
        requestId: String,
        reviewId: String,
        repairAction: String,
        updatedAtMs: Int64
    ) -> String {
        let requestToken = supervisorUIReviewRepairStableToken(requestId, fallback: "request")
        let reviewToken = supervisorUIReviewRepairStableToken(reviewId, fallback: "review")
        let actionToken = supervisorUIReviewRepairStableToken(repairAction, fallback: "repair")
        return "audit-ui-review-guidance-\(requestToken)-\(reviewToken)-\(actionToken)-\(max(0, updatedAtMs))"
    }

    private func supervisorUIReviewRepairStableToken(
        _ raw: String,
        fallback: String
    ) -> String {
        let lowered = raw.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let scalars = lowered.unicodeScalars.filter {
            CharacterSet.alphanumerics.contains($0) || $0 == "-" || $0 == "_"
        }
        let normalized = String(String.UnicodeScalarView(scalars))
        return normalized.isEmpty ? fallback : normalized
    }

    private func resolvedSupervisorSkillCallbackReviewHint(
        project: AXProjectEntry,
        record: SupervisorSkillCallRecord,
        status: SupervisorSkillCallStatus
    ) -> (trigger: SupervisorReviewTrigger, reviewLevel: SupervisorReviewLevel, runKind: SupervisorReviewRunKind) {
        let ctx = supervisorMemoryContext(for: project)
        let governance = resolvedSupervisorProjectGovernanceState(
            projectId: project.projectId,
            ctx: ctx
        )
        let effectiveTier = governance?.supervisorAdaptation.effectiveSupervisorTier
            ?? governance?.effectiveBundle.supervisorInterventionTier
            ?? .s0SilentAudit
        let effectiveWorkOrderDepth = governance?.supervisorAdaptation.effectiveWorkOrderDepth ?? .none
        let workflowState = supervisorWorkflowState(
            project: project,
            ctx: ctx,
            preferredJobId: record.jobId,
            preferredPlanId: record.planId,
            preferredRequestId: record.requestId
        )
        let plan = workflowState?.plan
        let job = workflowState?.job
        let stepStatus = plan?.steps.first(where: { $0.stepId == record.stepId })?.status

        if shouldRunSupervisorSkillCallbackBlockerReview(
            status: status,
            stepStatus: stepStatus,
            planStatus: plan?.status,
            jobStatus: job?.status
        ) {
            let reviewLevel: SupervisorReviewLevel = (
                effectiveWorkOrderDepth == .stepLockedRescue || effectiveTier >= .s4TightSupervision
            ) ? .r3Rescue : .r2Strategic
            return (.blockerDetected, reviewLevel, .eventDriven)
        }

        if shouldRunSupervisorSkillCallbackPreDoneReview(
            status: status,
            plan: plan,
            job: job,
            completedStepId: record.stepId
        ) {
            return (.preDoneSummary, .r3Rescue, .eventDriven)
        }

        let pulseLevel: SupervisorReviewLevel = effectiveWorkOrderDepth >= .executionReady
            ? .r2Strategic
            : .r1Pulse
        return (.periodicPulse, pulseLevel, .eventDriven)
    }

    private func shouldRunSupervisorSkillCallbackBlockerReview(
        status: SupervisorSkillCallStatus,
        stepStatus: SupervisorPlanStepStatus?,
        planStatus: SupervisorPlanStatus?,
        jobStatus: SupervisorJobStatus?
    ) -> Bool {
        let blockingSkillStatuses: Set<SupervisorSkillCallStatus> = [.blocked, .failed, .canceled]
        if blockingSkillStatuses.contains(status) {
            return true
        }

        let blockingStepStatuses: Set<SupervisorPlanStepStatus> = [.blocked, .failed, .canceled]
        if let stepStatus, blockingStepStatuses.contains(stepStatus) {
            return true
        }

        let blockingPlanStatuses: Set<SupervisorPlanStatus> = [.blocked, .failed, .canceled]
        if let planStatus, blockingPlanStatuses.contains(planStatus) {
            return true
        }

        let blockingJobStatuses: Set<SupervisorJobStatus> = [.blocked, .failed, .canceled]
        if let jobStatus, blockingJobStatuses.contains(jobStatus) {
            return true
        }

        return false
    }

    private func shouldRunSupervisorSkillCallbackPreDoneReview(
        status: SupervisorSkillCallStatus,
        plan: SupervisorPlanRecord?,
        job: SupervisorJobRecord?,
        completedStepId: String
    ) -> Bool {
        guard status == .completed else { return false }

        if let plan, plan.status == .completed {
            let hasOtherIncompleteSteps = plan.steps.contains { step in
                step.stepId != completedStepId && step.status != .completed
            }
            if !hasOtherIncompleteSteps {
                return true
            }
        }

        return job?.status == .completed
    }

    private func scheduleSupervisorGrantResolutionFollowUp(
        record: SupervisorSkillCallRecord,
        project: AXProjectEntry,
        reasonCode: String,
        summary: String
    ) {
        let normalizedSummary = capped(
            summary.trimmingCharacters(in: .whitespacesAndNewlines).replacingOccurrences(of: "\n", with: " "),
            maxChars: 220
        )
        let normalizedReasonCode = reasonCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let message = buildSupervisorEventLoopMessage(
            trigger: .grantResolution,
            project: project,
            record: record,
            extraLines: [
                "status=\(record.status.rawValue)",
                "reason_code=\(normalizedReasonCode.isEmpty ? "(none)" : normalizedReasonCode)",
                "summary=\(normalizedSummary.isEmpty ? "(none)" : normalizedSummary)"
            ]
        )
        queueSupervisorEventLoopTurn(
            userMessage: message,
            triggerSource: .grantResolution,
            dedupeKey: "grant_resolution:\(record.requestId):\(reasonCode)"
        )
    }

    private func scheduleSupervisorApprovalResolutionFollowUp(
        record: SupervisorSkillCallRecord,
        project: AXProjectEntry,
        reasonCode: String,
        summary: String
    ) {
        let normalizedSummary = capped(
            summary.trimmingCharacters(in: .whitespacesAndNewlines).replacingOccurrences(of: "\n", with: " "),
            maxChars: 220
        )
        let normalizedReasonCode = reasonCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let message = buildSupervisorEventLoopMessage(
            trigger: .approvalResolution,
            project: project,
            record: record,
            extraLines: [
                "status=\(record.status.rawValue)",
                "reason_code=\(normalizedReasonCode.isEmpty ? "(none)" : normalizedReasonCode)",
                "summary=\(normalizedSummary.isEmpty ? "(none)" : normalizedSummary)"
            ]
        )
        queueSupervisorEventLoopTurn(
            userMessage: message,
            triggerSource: .approvalResolution,
            dedupeKey: "approval_resolution:\(record.requestId):\(reasonCode)"
        )
    }

    private func scheduleSupervisorAutomationSafePointFollowUp(
        project: AXProjectEntry,
        runID: String,
        requestedState: XTAutomationRunState,
        guidance: SupervisorGuidanceInjectionRecord,
        executionDetail: String
    ) {
        let normalizedGuidance = capped(
            guidance.guidanceText
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .replacingOccurrences(of: "\n", with: " "),
            maxChars: 220
        )
        let normalizedDetail = capped(
            executionDetail
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .replacingOccurrences(of: "\n", with: " "),
            maxChars: 220
        )
        let workflowContext = supervisorEventLoopWorkflowContext(
            project: project,
            preferredJobId: nil,
            preferredPlanId: nil,
            preferredRequestId: nil,
            excludingStepId: nil
        )
        var lines = [
            "自动审查 automation safe point hold。",
            "trigger=\(SupervisorCommandTriggerSource.automationSafePoint.rawValue)",
            "project_ref=\(project.displayName)",
            "project_id=\(project.projectId)",
            "run_id=\(runID)",
            "requested_state=\(requestedState.rawValue)",
            "result_state=\(XTAutomationRunState.blocked.rawValue)",
            "review_id=\(guidance.reviewId)",
            "injection_id=\(guidance.injectionId)",
            "delivery_mode=\(guidance.deliveryMode.rawValue)",
            "intervention_mode=\(guidance.interventionMode.rawValue)",
            "safe_point_policy=\(guidance.safePointPolicy.rawValue)",
            "ack_required=\(guidance.ackRequired)",
            "guidance_text=\(normalizedGuidance.isEmpty ? "(none)" : normalizedGuidance)",
            "execution_detail=\(normalizedDetail.isEmpty ? "(none)" : normalizedDetail)"
        ]
        if !workflowContext.isEmpty {
            lines.append(workflowContext.trimmingCharacters(in: .whitespacesAndNewlines))
        }
        queueSupervisorEventLoopTurn(
            userMessage: lines.joined(separator: "\n"),
            triggerSource: .automationSafePoint,
            dedupeKey: "automation_safe_point:\(runID):\(guidance.injectionId):\(requestedState.rawValue)"
        )
    }

    @discardableResult
    private func handleAutomationSafePointHoldIfNeeded(
        runID: String,
        requestedState: XTAutomationRunState,
        project: AXProjectEntry? = nil,
        ctx: AXProjectContext,
        emitSystemMessage: Bool,
        executionDetail: String
    ) -> Bool {
        guard let guidance = try? automationRunCoordinator.safePointGuidanceForBlockedTransition(
            runID,
            requestedState: requestedState,
            in: ctx
        ) else {
            return false
        }

        let projectId = AXProjectRegistryStore.projectId(forRoot: ctx.root)
        let normalizedRootPath = AXProjectRegistryStore.normalizedRootPath(ctx.root)
        let project = knownProjects().first(where: { candidate in
            if candidate.projectId == projectId {
                return true
            }
            let rootPath = candidate.rootPath.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !rootPath.isEmpty else { return false }
            return AXProjectRegistryStore.normalizedRootPath(URL(fileURLWithPath: rootPath)) == normalizedRootPath
        })
            ?? project
            ?? automationProjectEntry(for: ctx)
        let normalizedDetail = capped(
            executionDetail
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .replacingOccurrences(of: "\n", with: " "),
            maxChars: 220
        )
        appendRecentEvent("automation safe point hold: \(project.displayName) -> \(guidance.safePointPolicy.rawValue)")
        if emitSystemMessage {
            let guidanceSummary = capped(
                guidance.guidanceText
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                    .replacingOccurrences(of: "\n", with: " "),
                maxChars: 220
            )
            addSystemMessage(
                """
automation 在 safe point 暂停
项目: \(project.displayName)
run_id: \(runID)
requested_state: \(requestedState.rawValue)
review_id: \(guidance.reviewId)
injection_id: \(guidance.injectionId)
safe_point_policy: \(guidance.safePointPolicy.rawValue)
intervention_mode: \(guidance.interventionMode.rawValue)
detail: \(normalizedDetail.isEmpty ? "(none)" : normalizedDetail)
guidance: \(guidanceSummary.isEmpty ? "(none)" : guidanceSummary)
"""
            )
        }
        scheduleSupervisorAutomationSafePointFollowUp(
            project: project,
            runID: runID,
            requestedState: requestedState,
            guidance: guidance,
            executionDetail: normalizedDetail
        )
        Task { @MainActor in
            await refreshSupervisorMemorySnapshot(reason: "automation_safe_point_hold")
        }
        return true
    }

    @discardableResult
    private func handleSupervisorGuidanceAckEvent(
        _ record: SupervisorGuidanceInjectionRecord
    ) -> Bool {
        let project = resolvedSupervisorProjectEntry(projectId: record.projectId)
        let projectName = project?.displayName ?? record.projectId
        let ackStatusText: String
        switch record.ackStatus {
        case .pending:
            ackStatusText = "待确认"
        case .accepted:
            ackStatusText = "已接受"
        case .deferred:
            ackStatusText = "已暂缓"
        case .rejected:
            ackStatusText = "已拒绝"
        }
        appendRecentEvent("项目 \(projectName) 指导确认：\(ackStatusText)")
        Task { @MainActor in
            await refreshSupervisorMemorySnapshot(reason: "guidance_ack")
        }

        guard record.ackStatus == .deferred || record.ackStatus == .rejected else {
            return false
        }
        guard let project else {
            return false
        }

        let normalizedNote = capped(
            record.ackNote
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .replacingOccurrences(of: "\n", with: " "),
            maxChars: 220
        )
        let workflowContext = supervisorEventLoopWorkflowContext(
            project: project,
            preferredJobId: nil,
            preferredPlanId: nil,
            preferredRequestId: nil,
            excludingStepId: nil
        )
        var lines = [
            "自动审查 coder 对 supervisor guidance 的反馈。",
            "trigger=\(SupervisorCommandTriggerSource.guidanceAck.rawValue)",
            "project_ref=\(project.displayName)",
            "project_id=\(project.projectId)",
            "review_id=\(record.reviewId)",
            "injection_id=\(record.injectionId)",
            "ack_status=\(record.ackStatus.rawValue)",
            "ack_note=\(normalizedNote.isEmpty ? "(none)" : normalizedNote)",
            "delivery_mode=\(record.deliveryMode.rawValue)",
            "intervention_mode=\(record.interventionMode.rawValue)",
            "safe_point_policy=\(record.safePointPolicy.rawValue)",
            "ack_required=\(record.ackRequired)"
        ]
        if !workflowContext.isEmpty {
            lines.append(workflowContext.trimmingCharacters(in: .whitespacesAndNewlines))
        }
        queueSupervisorEventLoopTurn(
            userMessage: lines.joined(separator: "\n"),
            triggerSource: .guidanceAck,
            dedupeKey: "guidance_ack:\(record.injectionId):\(record.ackStatus.rawValue)"
        )
        return true
    }

    func refreshSupervisorMemorySnapshotNow() {
        Task { @MainActor in
            await refreshSupervisorMemorySnapshot(reason: "manual_refresh")
        }
    }

    func retryCanonicalMemorySyncNow() {
        let startedAt = Date().timeIntervalSince1970
        let supervisorId = HubIPCClient.defaultSupervisorCanonicalID()
        let capsules = supervisorMemoryProjectDigests.compactMap { digest -> SupervisorProjectCapsule? in
            let capsule = SupervisorProjectCapsuleBuilder.build(from: digest)
            let projectId = capsule.projectId.trimmingCharacters(in: .whitespacesAndNewlines)
            return projectId.isEmpty ? nil : capsule
        }
        let scopes = canonicalMemoryRetryScopes(
            supervisorId: supervisorId,
            supervisorDisplayName: currentSupervisorIdentityProfile().name,
            capsules: capsules
        )
        let startedAtMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        let attemptToken = UUID()
        canonicalMemoryRetryAttemptToken = attemptToken
        canonicalMemoryRetryFeedback = CanonicalMemoryRetryFeedback(
            statusLine: "canonical_sync_retry: dispatching scopes=\(scopes.count) · projects=\(capsules.count)",
            detailLine: "pending: \(canonicalMemoryRetryScopeList(scopes, limit: 3))",
            metaLine: canonicalMemoryRetryMetaLine(
                attemptStartedAt: startedAt,
                lastStatusUpdatedAt: nil,
                isWaiting: true
            ),
            tone: .accent,
            attemptStartedAt: startedAt,
            lastStatusUpdatedAt: nil
        )

        HubIPCClient.syncSupervisorPortfolioSnapshot(
            supervisorPortfolioSnapshot,
            supervisorId: supervisorId,
            displayName: currentSupervisorIdentityProfile().name
        )

        for capsule in capsules {
            HubIPCClient.syncSupervisorProjectCapsule(capsule)
        }

        publishSupervisorMemoryAssemblyState(supervisorMemoryAssemblySnapshot)
        let resolvedImmediately = updateCanonicalMemoryRetryFeedback(
            attemptToken: attemptToken,
            startedAtMs: startedAtMs,
            scopes: scopes
        )
        guard !resolvedImmediately else { return }
        Task { [weak self] in
            await self?.pollCanonicalMemoryRetryFeedback(
                attemptToken: attemptToken,
                startedAtMs: startedAtMs,
                scopes: scopes,
                remainingPolls: 5
            )
        }
    }

    private struct CanonicalMemoryRetryScope {
        var scopeKind: String
        var scopeId: String
        var displayName: String
    }

    private func canonicalMemoryRetryScopes(
        supervisorId: String,
        supervisorDisplayName: String,
        capsules: [SupervisorProjectCapsule]
    ) -> [CanonicalMemoryRetryScope] {
        let deviceScope = CanonicalMemoryRetryScope(
            scopeKind: "device",
            scopeId: supervisorId.trimmingCharacters(in: .whitespacesAndNewlines),
            displayName: supervisorDisplayName.trimmingCharacters(in: .whitespacesAndNewlines)
        )
        let projectScopes = capsules.map { capsule in
            CanonicalMemoryRetryScope(
                scopeKind: "project",
                scopeId: capsule.projectId.trimmingCharacters(in: .whitespacesAndNewlines),
                displayName: capsule.projectName.trimmingCharacters(in: .whitespacesAndNewlines)
            )
        }
        return [deviceScope] + projectScopes
    }

    private func pollCanonicalMemoryRetryFeedback(
        attemptToken: UUID,
        startedAtMs: Int64,
        scopes: [CanonicalMemoryRetryScope],
        remainingPolls: Int
    ) async {
        guard remainingPolls > 0 else { return }
        try? await Task.sleep(nanoseconds: 350_000_000)
        let resolved = updateCanonicalMemoryRetryFeedback(
            attemptToken: attemptToken,
            startedAtMs: startedAtMs,
            scopes: scopes
        )
        guard !resolved else { return }
        await pollCanonicalMemoryRetryFeedback(
            attemptToken: attemptToken,
            startedAtMs: startedAtMs,
            scopes: scopes,
            remainingPolls: remainingPolls - 1
        )
    }

    @discardableResult
    private func updateCanonicalMemoryRetryFeedback(
        attemptToken: UUID,
        startedAtMs: Int64,
        scopes: [CanonicalMemoryRetryScope]
    ) -> Bool {
        guard canonicalMemoryRetryAttemptToken == attemptToken else { return true }
        let items = HubIPCClient.canonicalMemorySyncStatusSnapshot(limit: 500)?.items ?? []

        var okScopes: [CanonicalMemoryRetryScope] = []
        var failedItems: [(CanonicalMemoryRetryScope, HubIPCClient.CanonicalMemorySyncStatusItem)] = []
        var pendingScopes: [CanonicalMemoryRetryScope] = []

        for scope in scopes {
            guard let item = items.first(where: {
                $0.scopeKind == scope.scopeKind && $0.scopeId == scope.scopeId
            }) else {
                pendingScopes.append(scope)
                continue
            }
            guard item.updatedAtMs >= startedAtMs else {
                pendingScopes.append(scope)
                continue
            }
            if item.ok {
                okScopes.append(scope)
            } else {
                failedItems.append((scope, item))
            }
        }

        let resolved = pendingScopes.isEmpty
        let tone: SupervisorHeaderControlTone
        let statusLine: String
        if failedItems.isEmpty && pendingScopes.isEmpty {
            tone = .success
            statusLine = "canonical_sync_retry: ok scopes=\(okScopes.count) · projects=\(max(0, scopes.count - 1))"
        } else if !failedItems.isEmpty && pendingScopes.isEmpty {
            tone = okScopes.isEmpty ? .danger : .warning
            statusLine = "canonical_sync_retry: failed ok=\(okScopes.count) · failed=\(failedItems.count)"
        } else if failedItems.isEmpty {
            tone = .accent
            statusLine = "canonical_sync_retry: pending ok=\(okScopes.count) · waiting=\(pendingScopes.count)"
        } else {
            tone = .warning
            statusLine = "canonical_sync_retry: partial ok=\(okScopes.count) · failed=\(failedItems.count) · waiting=\(pendingScopes.count)"
        }

        let detailLine = canonicalMemoryRetryDetailLine(
            okScopes: okScopes,
            failedItems: failedItems,
            pendingScopes: pendingScopes
        )
        let lastStatusUpdatedAt: TimeInterval? = {
            let timestamps = scopes.compactMap { scope -> TimeInterval? in
                guard let item = items.first(where: {
                    $0.scopeKind == scope.scopeKind && $0.scopeId == scope.scopeId && $0.updatedAtMs >= startedAtMs
                }) else {
                    return nil
                }
                return Double(item.updatedAtMs) / 1000.0
            }
            return timestamps.max()
        }()
        let attemptStartedAt = Double(startedAtMs) / 1000.0
        canonicalMemoryRetryFeedback = CanonicalMemoryRetryFeedback(
            statusLine: statusLine,
            detailLine: detailLine,
            metaLine: canonicalMemoryRetryMetaLine(
                attemptStartedAt: attemptStartedAt,
                lastStatusUpdatedAt: lastStatusUpdatedAt,
                isWaiting: !pendingScopes.isEmpty
            ),
            tone: tone,
            attemptStartedAt: attemptStartedAt,
            lastStatusUpdatedAt: lastStatusUpdatedAt
        )
        return resolved
    }

    private func canonicalMemoryRetryDetailLine(
        okScopes: [CanonicalMemoryRetryScope],
        failedItems: [(CanonicalMemoryRetryScope, HubIPCClient.CanonicalMemorySyncStatusItem)],
        pendingScopes: [CanonicalMemoryRetryScope]
    ) -> String? {
        var parts: [String] = []

        if !failedItems.isEmpty {
            let failed = failedItems.prefix(2).map { scope, item in
                let reason = item.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "unknown"
                let detail = item.detail?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                let delivery = item.deliveryState?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                let auditRef = item.primaryAuditRef?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                let writebackRef = item.primaryWritebackRef?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                var segments = ["\(canonicalMemoryRetryScopeLabel(scope)) reason=\(reason)"]
                if !delivery.isEmpty {
                    segments.append("delivery=\(delivery)")
                }
                if !auditRef.isEmpty {
                    segments.append("audit_ref=\(auditRef)")
                }
                if !writebackRef.isEmpty {
                    segments.append("writeback_ref=\(writebackRef)")
                }
                if !detail.isEmpty {
                    segments.append("detail=\(detail)")
                }
                return segments.joined(separator: " ")
            }.joined(separator: " | ")
            parts.append("failed: \(failed)")
        }

        if !pendingScopes.isEmpty {
            parts.append("pending: \(canonicalMemoryRetryScopeList(pendingScopes, limit: 3))")
        } else if !okScopes.isEmpty {
            parts.append("ok: \(canonicalMemoryRetryScopeList(okScopes, limit: 3))")
        }

        let merged = parts.joined(separator: " || ").trimmingCharacters(in: .whitespacesAndNewlines)
        return merged.isEmpty ? nil : merged
    }

    private func canonicalMemoryRetryScopeList(
        _ scopes: [CanonicalMemoryRetryScope],
        limit: Int
    ) -> String {
        let rows = scopes.prefix(max(1, limit)).map(canonicalMemoryRetryScopeLabel)
        if rows.isEmpty { return "(none)" }
        return rows.joined(separator: ", ")
    }

    private func canonicalMemoryRetryScopeLabel(
        _ scope: CanonicalMemoryRetryScope
    ) -> String {
        let name = scope.displayName.trimmingCharacters(in: .whitespacesAndNewlines)
        if name.isEmpty {
            return "\(scope.scopeKind):\(scope.scopeId)"
        }
        return "\(scope.scopeKind):\(scope.scopeId)(\(name))"
    }

    private func canonicalMemoryRetryMetaLine(
        attemptStartedAt: TimeInterval?,
        lastStatusUpdatedAt: TimeInterval?,
        isWaiting: Bool
    ) -> String? {
        let now = Date().timeIntervalSince1970
        var parts: [String] = []

        if let attemptStartedAt, attemptStartedAt > 0 {
            parts.append("attempt: \(SupervisorEventLoopFeedPresentation.relativeTimeText(attemptStartedAt, now: now))")
        }

        if let lastStatusUpdatedAt, lastStatusUpdatedAt > 0 {
            parts.append("last_status: \(SupervisorEventLoopFeedPresentation.relativeTimeText(lastStatusUpdatedAt, now: now))")
        } else if isWaiting {
            parts.append("last_status: waiting")
        }

        let merged = parts.joined(separator: " · ").trimmingCharacters(in: .whitespacesAndNewlines)
        return merged.isEmpty ? nil : merged
    }

    private func refreshSupervisorMemorySnapshot(reason: String) async {
        let userMessage = "(supervisor_memory_panel:\(reason))"
        let memoryInfo = await buildSupervisorMemoryV1(userMessage: userMessage)
        publishSupervisorMemoryInfo(memoryInfo)
    }

    private func publishSupervisorMemoryInfo(_ memoryInfo: SupervisorMemoryBuildInfo) {
        let registry = syncSupervisorJurisdictionRegistry(with: knownProjects())
        let visibleDigests = registry.filteredDigests(memoryInfo.projectDigests)
        supervisorMemorySource = memoryInfo.source
        supervisorMemoryUpdatedAt = memoryInfo.updatedAt
        supervisorMemoryProjectDigests = visibleDigests
        supervisorMemoryPreview = memoryInfo.text
        publishSupervisorMemoryAssemblyState(memoryInfo.assemblySnapshot)
        supervisorSkillRegistrySnapshot = memoryInfo.skillRegistrySnapshot
        supervisorSkillRegistryStatusLine = memoryInfo.skillRegistrySnapshot?.statusLine ?? "skills: no focused project"
        supervisorRecentProjectActionEvents = registry.filteredEvents(supervisorRecentProjectActionEvents)
        supervisorMemoryStatusLine = "memory=\(memoryInfo.source) · projects=\(visibleDigests.count) · updated=\(Int(memoryInfo.updatedAt))"
        supervisorPortfolioSnapshot = SupervisorPortfolioSnapshotBuilder.build(from: visibleDigests)
        syncSupervisorPortfolioSnapshotIfNeeded(supervisorPortfolioSnapshot)
        syncSupervisorProjectCapsulesIfNeeded(from: visibleDigests)
    }

    private func publishSupervisorMemoryAssemblyState(
        _ snapshot: SupervisorMemoryAssemblySnapshot?
    ) {
        supervisorMemoryAssemblySnapshot = snapshot
        supervisorMemoryAssemblyStatusLine = snapshot?.statusLine ?? "assembly: unavailable"
        supervisorMemoryAssemblyReadiness = Self.evaluateSupervisorMemoryAssemblyReadiness(
            snapshot: snapshot
        )
    }

    private func syncSupervisorProjectCapsulesIfNeeded(from digests: [SupervisorMemoryProjectDigest]) {
        let visibleIDs = Set(digests.map(\.projectId))
        supervisorProjectCapsuleSyncAuditRefs = supervisorProjectCapsuleSyncAuditRefs.filter { visibleIDs.contains($0.key) }

        for digest in digests {
            let capsule = SupervisorProjectCapsuleBuilder.build(from: digest)
            guard !capsule.projectId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { continue }
            if supervisorProjectCapsuleSyncAuditRefs[capsule.projectId] == capsule.auditRef {
                continue
            }
            supervisorProjectCapsuleSyncAuditRefs[capsule.projectId] = capsule.auditRef
            HubIPCClient.syncSupervisorProjectCapsule(capsule)
        }
    }

    private func syncSupervisorPortfolioSnapshotIfNeeded(_ snapshot: SupervisorPortfolioSnapshot) {
        let supervisorId = HubIPCClient.defaultSupervisorCanonicalID()
        let fingerprint = SupervisorPortfolioSnapshotCanonicalSync.fingerprint(
            snapshot: snapshot,
            supervisorId: supervisorId
        )
        guard !fingerprint.isEmpty else { return }
        if supervisorPortfolioSnapshotSyncFingerprint == fingerprint {
            return
        }
        supervisorPortfolioSnapshotSyncFingerprint = fingerprint
        HubIPCClient.syncSupervisorPortfolioSnapshot(
            snapshot,
            supervisorId: supervisorId,
            displayName: currentSupervisorIdentityProfile().name
        )
    }

    private func buildSupervisorSystemPrompt(
        userMessage: String,
        projects: [AXProjectEntry],
        preferredModel: String?,
        memoryInfo: SupervisorMemoryBuildInfo,
        personaSlot: SupervisorPersonaSlot? = nil
    ) -> String {
        let resolvedPersona = personaSlot ?? resolvedSupervisorPersonaForPrompt(userMessage)
        let promptPreferences = currentSupervisorPromptPreferences(personaSlot: resolvedPersona)
        let turnRoutingDecision = resolveSupervisorTurnRoutingDecision(
            userMessage: userMessage,
            projects: projects
        )
        let turnContextAssembly = assembleSupervisorTurnContext(
            routingDecision: turnRoutingDecision,
            personaSlot: resolvedPersona,
            memoryText: memoryInfo.text
        )
        let memoryReadiness = memoryInfo.assemblySnapshot.map { snapshot in
            Self.evaluateSupervisorMemoryAssemblyReadiness(snapshot: snapshot)
        }
        let params = SupervisorSystemPromptParamsBuilder.build(
            identity: currentSupervisorIdentityProfile(personaSlot: resolvedPersona),
            personalProfile: currentSupervisorPersonalProfile(personaSlot: resolvedPersona),
            personalPolicy: currentSupervisorPersonalPolicy(personaSlot: resolvedPersona),
            workMode: currentSupervisorWorkMode,
            privacyMode: currentSupervisorPrivacyMode,
            personalMemorySummary: currentSupervisorPersonalMemoryPromptSummary(),
            personalFollowUpSummary: currentSupervisorPersonalFollowUpPromptSummary(),
            personalReviewSummary: currentSupervisorPersonalReviewPromptSummary(personaSlot: resolvedPersona),
            turnRoutingDecision: turnRoutingDecision,
            turnContextAssembly: turnContextAssembly,
            preferredSupervisorModelId: preferredModel,
            supervisorModelRouteSummary: contextualSupervisorModelRouteSummary(
                userMessage: userMessage,
                projects: projects
            ),
            memorySource: memoryInfo.source,
            projectCount: projects.count,
            userMessage: userMessage,
            memoryV1: memoryInfo.text,
            promptMode: .full,
            extraSystemPrompt: promptPreferences.extraSystemPromptOrNil,
            memoryReadiness: memoryReadiness,
            retrievalModelSummary: supervisorRetrievalModelSummary(),
            hubConnected: appModel?.hubConnected ?? false,
            hubRemoteConnected: appModel?.hubRemoteConnected ?? false
        )
        return sanitizeSupervisorOutboundPrompt(
            SupervisorSystemPromptBuilder().build(params)
        )
    }

    private func assembleSupervisorTurnContext(
        routingDecision: SupervisorTurnRoutingDecision,
        personaSlot: SupervisorPersonaSlot?,
        memoryText: String
    ) -> SupervisorTurnContextAssemblyResult {
        SupervisorTurnContextAssembler.assemble(
            SupervisorTurnContextAssemblyRequest(
                routingDecision: routingDecision,
                hasPersonalCapsule: !currentSupervisorPersonalMemoryPromptSummary().isEmpty ||
                    !currentSupervisorPersonalFollowUpPromptSummary().isEmpty ||
                    !currentSupervisorPersonalReviewPromptSummary(personaSlot: personaSlot).isEmpty,
                hasPortfolioBrief: memoryText.contains("[PORTFOLIO_BRIEF]"),
                hasFocusedProjectCapsule: memoryText.contains("[FOCUSED_PROJECT_ANCHOR_PACK]"),
                hasCrossLinkRefs: memoryText.contains("[CROSS_LINK_REFS]"),
                hasEvidencePack: memoryText.contains("[EVIDENCE_PACK]")
            )
        )
    }

    private func resolveSupervisorTurnRoutingDecision(
        userMessage: String,
        projects: [AXProjectEntry],
        now: Date = Date()
    ) -> SupervisorTurnRoutingDecision {
        let activePointers = supervisorFocusPointerState.activePointers(now: now)
        let pointerProjectId = activePointers.currentProjectId.flatMap { activeProjectId in
            projects.contains(where: { $0.projectId == activeProjectId }) ? activeProjectId : nil
        }
        return SupervisorTurnRouter.route(
            SupervisorTurnRoutingInput(
                userMessage: userMessage,
                projects: projects,
                personalMemory: supervisorPersonalMemoryStore.snapshot,
                crossLinks: supervisorCrossLinkStore.snapshot,
                currentProjectId: pointerProjectId ?? appModel?.selectedProjectId ?? currentTask?.projectId,
                currentPersonName: activePointers.currentPersonName,
                currentCommitmentId: activePointers.currentCommitmentId
            )
        )
    }

    private func currentSupervisorFocusPointerDeltaCursorCandidate() -> String? {
        guard let snapshot = supervisorMemoryAssemblySnapshot else { return nil }
        let updatedAtMs = Int64((snapshot.updatedAt * 1000.0).rounded())
        guard updatedAtMs > 0 else { return nil }
        return "memory_build:\(updatedAtMs)"
    }

    func renderSupervisorFailureResponse(
        error: Error,
        userMessage: String,
        personaSlot: SupervisorPersonaSlot? = nil
    ) -> String {
        let fallback = generateFallbackResponse(userMessage, personaSlot: personaSlot)

        if let resolution = paidModelAccessResolution(from: error) {
            return """
⚠️ Supervisor 当前无法调用已分配模型，已切换为本地直答兜底。

原因：\(resolution.headline)
处理建议：
1. \(primaryRepairStep(for: resolution))
2. \(secondaryRepairStep(for: resolution))

以下为本地直答结果：
\(fallback)
"""
        }

        return """
⚠️ Supervisor 当前无法调用远端模型，已切换为本地直答兜底。

原因：\(conciseSupervisorFailureReason(error))

以下为本地直答结果：
\(fallback)
"""
    }

    private func paidModelAccessResolution(from error: Error) -> XTPaidModelAccessResolution? {
        guard let hubError = error as? HubAIError,
              case let .responseDoneNotOk(failure) = hubError else {
            return nil
        }
        return XTPaidModelAccessExplainability.resolve(
            rawReasonCode: failure.reason,
            deviceName: failure.deviceName,
            modelId: failure.modelId ?? "unknown_model"
        )
    }

    private func primaryRepairStep(for resolution: XTPaidModelAccessResolution) -> String {
        switch resolution.state {
        case .allowedByDevicePolicy:
            return "当前设备策略已允许该模型，直接重试当前请求即可。"
        case .blockedPaidModelDisabled:
            return "到 Hub Settings -> Pairing & Device Trust 为这台设备开启 paid model 访问。"
        case .blockedModelNotInCustomAllowlist:
            return "到 Hub Settings -> Pairing & Device Trust 把 \(resolution.modelId) 加入该设备 allowlist。"
        case .blockedDailyBudgetExceeded:
            return "到 Hub Settings -> Models & Paid Access 提升 daily token limit，或等待下一配额窗口。"
        case .blockedSingleRequestBudgetExceeded:
            return "缩小这次请求，或到 Hub Settings -> Models & Paid Access 提升 single request token limit。"
        case .legacyGrantFlowRequired:
            return "临时放行：到 Hub Settings -> Grants & Permissions 完成一次 legacy grant。"
        }
    }

    private func secondaryRepairStep(for resolution: XTPaidModelAccessResolution) -> String {
        switch resolution.state {
        case .allowedByDevicePolicy:
            return "如果仍失败，改查 Hub 当前模型库存与桥接连通性，而不是重复授权。"
        case .blockedPaidModelDisabled, .blockedModelNotInCustomAllowlist:
            return "如果暂时不改设备策略，可先切到本地模型或已授权模型后再试。"
        case .blockedDailyBudgetExceeded, .blockedSingleRequestBudgetExceeded:
            return "如果暂时不改预算，可先切到本地模型或缩短上下文后再试。"
        case .legacyGrantFlowRequired:
            return "长期修复：到 Hub Settings -> Pairing & Device Trust 把这台设备升级到新 trust profile。"
        }
    }

    private func conciseSupervisorFailureReason(_ error: Error) -> String {
        if let localized = (error as? LocalizedError)?.errorDescription?
            .trimmingCharacters(in: .whitespacesAndNewlines),
           !localized.isEmpty {
            return firstNonEmptyLine(in: localized)
        }
        let fallback = error.localizedDescription.trimmingCharacters(in: .whitespacesAndNewlines)
        return fallback.isEmpty ? "未知错误" : firstNonEmptyLine(in: fallback)
    }

    private func firstNonEmptyLine(in text: String) -> String {
        for raw in text.split(whereSeparator: \.isNewline) {
            let line = raw.trimmingCharacters(in: .whitespacesAndNewlines)
            if !line.isEmpty {
                return line
            }
        }
        return text.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func firstNonEmptyLine(items: [String]) -> String {
        for item in items {
            let line = item.trimmingCharacters(in: .whitespacesAndNewlines)
            if !line.isEmpty {
                return line
            }
        }
        return ""
    }

    private func firstNonEmpty(_ values: String?...) -> String? {
        for value in values {
            let cleaned = (value ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            if !cleaned.isEmpty {
                return cleaned
            }
        }
        return nil
    }

    private func firstNonEmptyValue(_ preferred: String, _ fallback: String?) -> String {
        let primary = preferred.trimmingCharacters(in: .whitespacesAndNewlines)
        if !primary.isEmpty {
            return primary
        }
        return (fallback ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func firstMeaningfulDigestValue(
        _ values: [String?],
        treatContinueCurrentTaskAsPlaceholder: Bool = false,
        treatNoValueAsPlaceholder: Bool = true
    ) -> String {
        for raw in values {
            let cleaned = (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            if !isDigestPlaceholder(
                cleaned,
                treatContinueCurrentTaskAsPlaceholder: treatContinueCurrentTaskAsPlaceholder,
                treatNoValueAsPlaceholder: treatNoValueAsPlaceholder
            ) {
                return cleaned
            }
        }
        return ""
    }

    private func isDigestPlaceholder(
        _ text: String,
        treatContinueCurrentTaskAsPlaceholder: Bool = false,
        treatNoValueAsPlaceholder: Bool = true
    ) -> Bool {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.isEmpty {
            return true
        }

        let lowered = trimmed.lowercased()
        var placeholders = Set(["(暂无)", "(none)", "none", "n/a", "na"].map { $0.lowercased() })
        if treatNoValueAsPlaceholder {
            placeholders.formUnion(["(无)", "无"].map { $0.lowercased() })
        }
        if treatContinueCurrentTaskAsPlaceholder {
            placeholders.insert("继续当前任务")
        }
        return placeholders.contains(lowered)
    }

    private func hasDurableSupervisorProjectMemory(_ memory: AXMemory?) -> Bool {
        guard let memory else { return false }
        if !memory.goal.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return true
        }
        return !memory.requirements.isEmpty ||
            !memory.currentState.isEmpty ||
            !memory.decisions.isEmpty ||
            !memory.nextSteps.isEmpty ||
            !memory.openQuestions.isEmpty ||
            !memory.risks.isEmpty ||
            !memory.recommendations.isEmpty
    }

    private func processSupervisorCommands(
        _ response: String,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource = .userTurn
    ) -> String {
        var processedResponse = response
        let normalizedUserMessage = normalizedSupervisorIntentText(userMessage)
        let allowProjectCreation = triggerSource == .userTurn && isExplicitProjectCreationRequest(normalizedUserMessage)
        let allowModelAssignment = triggerSource == .userTurn && isExplicitModelAssignmentRequest(normalizedUserMessage)
        let allowGovernedOrchestration = isExplicitSupervisorWorkflowExecutionRequest(
            normalizedUserMessage,
            triggerSource: triggerSource
        )

        if !allowProjectCreation {
            processedResponse = replacingTaggedSection(
                in: processedResponse,
                tag: "CREATE_PROJECT",
                with: ""
            )
        }

        if !allowModelAssignment {
            processedResponse = replacingTaggedSection(
                in: processedResponse,
                tag: "ASSIGN_MODEL_ALL",
                with: ""
            )
            processedResponse = replacingTaggedSection(
                in: processedResponse,
                tag: "ASSIGN_MODEL",
                with: ""
            )
        }

        if !allowGovernedOrchestration {
            for tag in ["CREATE_JOB", "UPSERT_PLAN", "CALL_SKILL", "CANCEL_SKILL"] {
                processedResponse = replacingTaggedSection(
                    in: processedResponse,
                    tag: tag,
                    with: ""
                )
            }
        }

        if let projectName = firstTagContent(in: processedResponse, tag: "CREATE_PROJECT"), !projectName.isEmpty {
            let carriedExecutionIntake = activePendingSupervisorExecutionIntake()
            clearPendingSupervisorExecutionIntake()
            let actionId = appendActionLedger(
                action: "create_project",
                targetRef: projectName,
                projectId: nil,
                projectName: nil,
                role: nil,
                modelId: nil,
                status: "pending",
                reasonCode: "started",
                detail: "create project requested",
                verifiedAt: nil,
                triggerSource: triggerSource.rawValue
            )
            Task { @MainActor in
                if let result = await createProject(projectName) {
                    addSystemMessage("✅ 成功创建项目：\(result.displayName)")
                    updateActionLedger(
                        id: actionId,
                        status: "ok",
                        reasonCode: "ok",
                        detail: "created project \(result.displayName)",
                        verifiedAt: Date().timeIntervalSince1970
                    )
                } else {
                    if let carriedExecutionIntake {
                        restorePendingSupervisorExecutionIntake(carriedExecutionIntake)
                    }
                    addSystemMessage("❌ 创建项目失败")
                    updateActionLedger(
                        id: actionId,
                        status: "failed",
                        reasonCode: "user_cancelled_or_create_failed",
                        detail: "create project cancelled or failed",
                        verifiedAt: nil
                    )
                }
            }
            processedResponse = replacingTaggedSection(
                in: processedResponse,
                tag: "CREATE_PROJECT",
                with: "✅ 正在创建项目：\(projectName)"
            )
        }

        var assignAllCommand: ParsedAssignCommand?
        if let payload = firstTagContent(in: processedResponse, tag: "ASSIGN_MODEL_ALL") {
            let parsed = parseAssignCommand(tag: "ASSIGN_MODEL_ALL", payload: payload)
            if let command = parsed.command {
                assignAllCommand = command
            } else {
                let reason = parsed.error ?? "unknown"
                processedResponse = replacingTaggedSection(
                    in: processedResponse,
                    tag: "ASSIGN_MODEL_ALL",
                    with: "❌ 批量分配标签解析失败：\(reason)"
                )
                _ = appendActionLedger(
                    action: "assign_model_all",
                    targetRef: "*",
                    projectId: nil,
                    projectName: nil,
                    role: nil,
                    modelId: nil,
                    status: "failed",
                    reasonCode: "invalid_assign_model_all_format",
                    detail: reason,
                    verifiedAt: nil
                )
            }
        }

        var assignOneCommand: ParsedAssignCommand?
        if let payload = firstTagContent(in: processedResponse, tag: "ASSIGN_MODEL") {
            let parsed = parseAssignCommand(tag: "ASSIGN_MODEL", payload: payload)
            if let command = parsed.command {
                assignOneCommand = command
            } else {
                let reason = parsed.error ?? "unknown"
                processedResponse = replacingTaggedSection(
                    in: processedResponse,
                    tag: "ASSIGN_MODEL",
                    with: "❌ 单项目分配标签解析失败：\(reason)"
                )
                _ = appendActionLedger(
                    action: "assign_model",
                    targetRef: payload,
                    projectId: nil,
                    projectName: nil,
                    role: nil,
                    modelId: nil,
                    status: "failed",
                    reasonCode: "invalid_assign_model_format",
                    detail: reason,
                    verifiedAt: nil
                )
            }
        }

        if let one = assignOneCommand, let all = assignAllCommand {
            if one.projectRef == nil {
                assignOneCommand = nil
                processedResponse = replacingTaggedSection(
                    in: processedResponse,
                    tag: "ASSIGN_MODEL",
                    with: "⚠️ 跳过重复批量分配：已优先执行 ASSIGN_MODEL_ALL。"
                )
                _ = appendActionLedger(
                    action: "assign_model",
                    targetRef: "*",
                    projectId: nil,
                    projectName: nil,
                    role: one.role.rawValue,
                    modelId: one.modelId,
                    status: "skipped",
                    reasonCode: "duplicate_with_assign_model_all",
                    detail: "Skipped duplicate bulk assignment; ASSIGN_MODEL_ALL is used",
                    verifiedAt: nil
                )
            } else {
                assignAllCommand = nil
                processedResponse = replacingTaggedSection(
                    in: processedResponse,
                    tag: "ASSIGN_MODEL_ALL",
                    with: "⚠️ 跳过批量分配：与单项目分配冲突，已优先执行 ASSIGN_MODEL。"
                )
                _ = appendActionLedger(
                    action: "assign_model_all",
                    targetRef: "*",
                    projectId: nil,
                    projectName: nil,
                    role: all.role.rawValue,
                    modelId: all.modelId,
                    status: "skipped",
                    reasonCode: "conflict_with_assign_model",
                    detail: "Skipped bulk assignment because a single-project assignment is present",
                    verifiedAt: nil
                )
            }
        }

        if let all = assignAllCommand {
            let result = assignModelToAllProjects(role: all.role, modelId: all.modelId)
            processedResponse = replacingTaggedSection(
                in: processedResponse,
                tag: all.tag,
                with: result.message
            )
        }

        if let one = assignOneCommand {
            if let projectRef = one.projectRef {
                let result = assignModelToProject(projectRef: projectRef, role: one.role, modelId: one.modelId)
                processedResponse = replacingTaggedSection(
                    in: processedResponse,
                    tag: one.tag,
                    with: result.message
                )
            } else {
                let result = assignModelToAllProjects(role: one.role, modelId: one.modelId)
                processedResponse = replacingTaggedSection(
                    in: processedResponse,
                    tag: one.tag,
                    with: result.message
                )
            }
        }

        processedResponse = processCreateJobCommand(
            in: processedResponse,
            userMessage: userMessage,
            triggerSource: triggerSource
        )
        processedResponse = processUpsertPlanCommand(
            in: processedResponse,
            userMessage: userMessage,
            triggerSource: triggerSource
        )
        processedResponse = processCallSkillCommand(
            in: processedResponse,
            userMessage: userMessage,
            triggerSource: triggerSource
        )
        processedResponse = processCancelSkillCommand(
            in: processedResponse,
            userMessage: userMessage,
            triggerSource: triggerSource
        )

        return processedResponse
    }

    private func createProject(_ projectName: String) async -> AXProjectEntry? {
        let url: URL
        if let override = createProjectURLOverrideForTesting {
            guard let overriddenURL = await override(projectName) else {
                return nil
            }
            url = overriddenURL
        } else {
            let panel = NSSavePanel()
            panel.title = "创建新项目"
            panel.prompt = "创建"
            panel.nameFieldStringValue = projectName
            panel.canCreateDirectories = true
            panel.showsHiddenFiles = false
            panel.allowedContentTypes = [.folder]

            let response: NSApplication.ModalResponse
            if let window = NSApp.keyWindow {
                response = await panel.beginSheetModal(for: window)
            } else {
                response = panel.runModal()
            }
            guard response == .OK, let selectedURL = panel.url else {
                return nil
            }
            url = selectedURL
        }

        try? FileManager.default.createDirectory(at: url, withIntermediateDirectories: true)

        guard let appModel = appModel else { return nil }
        var reg = appModel.registry
        let res = AXProjectRegistryStore.upsertProject(reg, root: url)
        reg = res.0
        reg.lastSelectedProjectId = res.1.projectId
        appModel.registry = reg
        AXProjectRegistryStore.save(reg)
        appModel.selectedProjectId = res.1.projectId

        return res.1
    }

    private func assignModelToProject(projectRef: String, role: AXRole, modelId: String) -> ModelAssignmentResult {
        let normalizedRef = sanitizeProjectReference(projectRef)
        guard let appModel = appModel else {
            let message = "❌ 分配失败：Supervisor 未初始化（app_model_unavailable）"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model",
                targetRef: normalizedRef,
                projectId: nil,
                projectName: nil,
                role: role.rawValue,
                modelId: modelId,
                status: "failed",
                reasonCode: "app_model_unavailable",
                detail: "AppModel is nil",
                verifiedAt: nil
            )
            return ModelAssignmentResult(ok: false, reasonCode: "app_model_unavailable", message: message)
        }

        if let blocked = interactiveRoutingAssignmentBlock(modelId: modelId) {
            let message = "❌ 分配失败：\(blocked)"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model",
                targetRef: normalizedRef,
                projectId: nil,
                projectName: nil,
                role: role.rawValue,
                modelId: modelId,
                status: "failed",
                reasonCode: "retrieval_only_model_not_assignable",
                detail: blocked,
                verifiedAt: nil
            )
            return ModelAssignmentResult(
                ok: false,
                reasonCode: "retrieval_only_model_not_assignable",
                message: message
            )
        }

        let resolved = resolveProjectReference(normalizedRef)
        switch resolved {
        case .notFound:
            let hints = allProjects().prefix(4).map { $0.displayName }.joined(separator: "、")
            let suffix = hints.isEmpty ? "" : "。可用项目：\(hints)"
            let message = "❌ 找不到项目引用：\(normalizedRef) (project_not_found)\(suffix)"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model",
                targetRef: normalizedRef,
                projectId: nil,
                projectName: nil,
                role: role.rawValue,
                modelId: modelId,
                status: "failed",
                reasonCode: "project_not_found",
                detail: "No project matched for reference",
                verifiedAt: nil
            )
            return ModelAssignmentResult(ok: false, reasonCode: "project_not_found", message: message)

        case .ambiguous(let candidates):
            let list = candidates.prefix(4).map { "\($0.displayName)(\($0.projectId))" }.joined(separator: "、")
            let message = "⚠️ 项目引用不唯一：\(normalizedRef) (project_ambiguous)。候选：\(list)"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model",
                targetRef: normalizedRef,
                projectId: nil,
                projectName: nil,
                role: role.rawValue,
                modelId: modelId,
                status: "failed",
                reasonCode: "project_ambiguous",
                detail: "Candidates: \(list)",
                verifiedAt: nil
            )
            return ModelAssignmentResult(ok: false, reasonCode: "project_ambiguous", message: message)

        case .matched(let project):
            guard let ctx = appModel.projectContext(for: project.projectId) else {
                let message = "❌ 项目上下文不可用：\(project.displayName) (project_context_missing)"
                addSystemMessage(message)
                _ = appendActionLedger(
                    action: "assign_model",
                    targetRef: normalizedRef,
                    projectId: project.projectId,
                    projectName: project.displayName,
                    role: role.rawValue,
                    modelId: modelId,
                    status: "failed",
                    reasonCode: "project_context_missing",
                    detail: "Project context lookup failed",
                    verifiedAt: nil
                )
                return ModelAssignmentResult(ok: false, reasonCode: "project_context_missing", message: message)
            }

            guard var cfg = try? AXProjectStore.loadOrCreateConfig(for: ctx) else {
                let message = "❌ 无法加载项目配置：\(project.displayName) (config_load_failed)"
                addSystemMessage(message)
                _ = appendActionLedger(
                    action: "assign_model",
                    targetRef: normalizedRef,
                    projectId: project.projectId,
                    projectName: project.displayName,
                    role: role.rawValue,
                    modelId: modelId,
                    status: "failed",
                    reasonCode: "config_load_failed",
                    detail: "Load config failed",
                    verifiedAt: nil
                )
                return ModelAssignmentResult(ok: false, reasonCode: "config_load_failed", message: message)
            }

            let expectedModelId = normalizedModelId(modelId)
            cfg.setModelOverride(role: role, modelId: expectedModelId)

            do {
                try AXProjectStore.saveConfig(cfg, for: ctx)
            } catch {
                let message = "❌ 保存配置失败：\(project.displayName) (config_save_failed: \(error.localizedDescription))"
                addSystemMessage(message)
                _ = appendActionLedger(
                    action: "assign_model",
                    targetRef: normalizedRef,
                    projectId: project.projectId,
                    projectName: project.displayName,
                    role: role.rawValue,
                    modelId: modelId,
                    status: "failed",
                    reasonCode: "config_save_failed",
                    detail: error.localizedDescription,
                    verifiedAt: nil
                )
                return ModelAssignmentResult(ok: false, reasonCode: "config_save_failed", message: message)
            }

            guard let verify = try? AXProjectStore.loadOrCreateConfig(for: ctx) else {
                let message = "❌ 写入后复检失败：\(project.displayName) (verify_load_failed)"
                addSystemMessage(message)
                _ = appendActionLedger(
                    action: "assign_model",
                    targetRef: normalizedRef,
                    projectId: project.projectId,
                    projectName: project.displayName,
                    role: role.rawValue,
                    modelId: modelId,
                    status: "failed",
                    reasonCode: "verify_load_failed",
                    detail: "Failed to reload config for verification",
                    verifiedAt: nil
                )
                return ModelAssignmentResult(ok: false, reasonCode: "verify_load_failed", message: message)
            }

            let actualModelId = verify.modelOverride(for: role)
            guard actualModelId == expectedModelId else {
                let expected = expectedModelId ?? "auto"
                let actual = actualModelId ?? "auto"
                let message = "❌ 复检不一致：\(project.displayName) (verify_mismatch, expected=\(expected), actual=\(actual))"
                addSystemMessage(message)
                _ = appendActionLedger(
                    action: "assign_model",
                    targetRef: normalizedRef,
                    projectId: project.projectId,
                    projectName: project.displayName,
                    role: role.rawValue,
                    modelId: modelId,
                    status: "failed",
                    reasonCode: "verify_mismatch",
                    detail: "expected=\(expected), actual=\(actual)",
                    verifiedAt: nil
                )
                return ModelAssignmentResult(ok: false, reasonCode: "verify_mismatch", message: message)
            }

            let label = expectedModelId ?? "auto"
            let message = "✅ 已为项目 \(project.displayName) 设置 \(role.displayName) 模型：\(label) (id: \(project.projectId))"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model",
                targetRef: normalizedRef,
                projectId: project.projectId,
                projectName: project.displayName,
                role: role.rawValue,
                modelId: label,
                status: "ok",
                reasonCode: "ok",
                detail: "Model assignment verified",
                verifiedAt: Date().timeIntervalSince1970
            )
            return ModelAssignmentResult(ok: true, reasonCode: "ok", message: message)
        }
    }

    private func assignModelToAllProjects(role: AXRole, modelId: String) -> ModelAssignmentResult {
        guard let appModel = appModel else {
            let message = "❌ 批量分配失败：Supervisor 未初始化（app_model_unavailable）"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model_all",
                targetRef: "*",
                projectId: nil,
                projectName: nil,
                role: role.rawValue,
                modelId: modelId,
                status: "failed",
                reasonCode: "app_model_unavailable",
                detail: "AppModel is nil",
                verifiedAt: nil
            )
            return ModelAssignmentResult(ok: false, reasonCode: "app_model_unavailable", message: message)
        }

        if let blocked = interactiveRoutingAssignmentBlock(modelId: modelId) {
            let message = "❌ 批量分配失败：\(blocked)"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model_all",
                targetRef: "*",
                projectId: nil,
                projectName: nil,
                role: role.rawValue,
                modelId: modelId,
                status: "failed",
                reasonCode: "retrieval_only_model_not_assignable",
                detail: blocked,
                verifiedAt: nil
            )
            return ModelAssignmentResult(
                ok: false,
                reasonCode: "retrieval_only_model_not_assignable",
                message: message
            )
        }

        let projects = appModel.registry.projects
        if projects.isEmpty {
            let message = "⚠️ 当前没有可分配的项目"
            addSystemMessage(message)
            _ = appendActionLedger(
                action: "assign_model_all",
                targetRef: "*",
                projectId: nil,
                projectName: nil,
                role: role.rawValue,
                modelId: modelId,
                status: "failed",
                reasonCode: "no_projects",
                detail: "No projects in registry",
                verifiedAt: nil
            )
            return ModelAssignmentResult(ok: false, reasonCode: "no_projects", message: message)
        }

        let expectedModelId = normalizedModelId(modelId)
        let label = expectedModelId ?? "auto"
        var success = 0
        var failed: [String] = []

        for project in projects {
            guard let ctx = appModel.projectContext(for: project.projectId) else {
                failed.append("\(project.displayName)(project_context_missing)")
                continue
            }
            guard var cfg = try? AXProjectStore.loadOrCreateConfig(for: ctx) else {
                failed.append("\(project.displayName)(config_load_failed)")
                continue
            }
            cfg.setModelOverride(role: role, modelId: expectedModelId)
            do {
                try AXProjectStore.saveConfig(cfg, for: ctx)
                guard let verify = try? AXProjectStore.loadOrCreateConfig(for: ctx),
                      verify.modelOverride(for: role) == expectedModelId else {
                    failed.append("\(project.displayName)(verify_mismatch)")
                    continue
                }
                success += 1
            } catch {
                failed.append("\(project.displayName)(config_save_failed)")
            }
        }

        let result: ModelAssignmentResult
        if failed.isEmpty {
            let message = "✅ 已为全部 \(success) 个项目设置 \(role.displayName) 模型：\(label)"
            result = ModelAssignmentResult(ok: true, reasonCode: "ok", message: message)
        } else if success > 0 {
            let message = "⚠️ 批量分配部分成功：成功 \(success) 个，失败 \(failed.count) 个：\(failed.joined(separator: ", "))"
            result = ModelAssignmentResult(ok: false, reasonCode: "partial_failure", message: message)
        } else {
            let message = "❌ 批量分配失败：\(failed.joined(separator: ", "))"
            result = ModelAssignmentResult(ok: false, reasonCode: "all_failed", message: message)
        }

        addSystemMessage(result.message)
        _ = appendActionLedger(
            action: "assign_model_all",
            targetRef: "*",
            projectId: nil,
            projectName: nil,
            role: role.rawValue,
            modelId: label,
            status: result.ok ? "ok" : "failed",
            reasonCode: result.reasonCode,
            detail: failed.isEmpty ? "Applied to all projects" : failed.joined(separator: "; "),
            verifiedAt: Date().timeIntervalSince1970
        )
        return result
    }

    private func normalizedModelId(_ modelId: String) -> String? {
        let cleaned = modelId.trimmingCharacters(in: .whitespacesAndNewlines)
        if cleaned.isEmpty { return nil }
        if cleaned.lowercased() == "auto" { return nil }
        return cleaned
    }

    private func interactiveRoutingAssignmentBlock(modelId: String) -> String? {
        guard let normalized = normalizedModelId(modelId) else { return nil }
        let snapshot = ModelStateSnapshot(
            models: supervisorModelInventory(),
            updatedAt: appModel?.modelsState.updatedAt ?? Date().timeIntervalSince1970
        )
        guard let assessment = HubModelSelectionAdvisor.assess(
            requestedId: normalized,
            snapshot: snapshot
        ),
        let blocked = assessment.nonInteractiveExactMatch else {
            return nil
        }

        if let fallback = assessment.loadedCandidates.first?.id.trimmingCharacters(in: .whitespacesAndNewlines),
           !fallback.isEmpty {
            let reason = blocked.interactiveRoutingDisabledReason ?? ""
            return "`\(blocked.id)` 是非对话模型，不能作为角色对话模型分配。\(reason) 可先改用 `\(fallback)`。"
        }
        return "`\(blocked.id)` 是非对话模型，不能作为角色对话模型分配。\(blocked.interactiveRoutingDisabledReason ?? "")"
    }

    private func parseAssignCommand(tag: String, payload: String) -> (command: ParsedAssignCommand?, error: String?) {
        let trimmedPayload = payload.trimmingCharacters(in: .whitespacesAndNewlines)
        if tag == "ASSIGN_MODEL_ALL" {
            let parts = trimmedPayload.split(separator: "|", maxSplits: 1, omittingEmptySubsequences: false)
                .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
            guard parts.count == 2 else {
                return (nil, "应为 2 段：角色|模型ID")
            }
            guard let role = AXRole.resolveModelAssignmentToken(parts[0]) else {
                return (nil, "未知角色：\(parts[0])")
            }
            return (ParsedAssignCommand(projectRef: nil, role: role, modelId: parts[1], tag: tag), nil)
        }

        if tag == "ASSIGN_MODEL" {
            let parts = trimmedPayload.split(separator: "|", maxSplits: 2, omittingEmptySubsequences: false)
                .map { String($0).trimmingCharacters(in: .whitespacesAndNewlines) }
            guard parts.count == 3 else {
                return (nil, "应为 3 段：项目引用|角色|模型ID")
            }
            guard let role = AXRole.resolveModelAssignmentToken(parts[1]) else {
                return (nil, "未知角色：\(parts[1])")
            }
            let ref = sanitizeProjectReference(parts[0])
            let normalizedRef: String? = (ref == "*" || ref.lowercased() == "all") ? nil : ref
            return (ParsedAssignCommand(projectRef: normalizedRef, role: role, modelId: parts[2], tag: tag), nil)
        }

        return (nil, "unsupported tag: \(tag)")
    }

    private func sanitizeProjectReference(_ raw: String) -> String {
        var out = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        if out.isEmpty { return out }

        let wrappers: [(String, String)] = [
            ("[", "]"), ("【", "】"),
            ("(", ")"), ("（", "）"),
            ("“", "”"), ("\"", "\""),
            ("'", "'"), ("`", "`")
        ]
        var changed = true
        while changed {
            changed = false
            for (head, tail) in wrappers {
                if out.hasPrefix(head), out.hasSuffix(tail), out.count > (head.count + tail.count) {
                    out.removeFirst(head.count)
                    out.removeLast(tail.count)
                    out = out.trimmingCharacters(in: .whitespacesAndNewlines)
                    changed = true
                }
            }
        }

        let lower = out.lowercased()
        let prefixes = [
            "project_ref:", "project_ref：",
            "project ref:", "project ref：",
            "project_id:", "project_id：",
            "project id:", "project id：",
            "项目ref:", "项目ref：",
            "项目引用:", "项目引用：",
            "项目id:", "项目id：",
            "项目:", "项目："
        ]
        for prefix in prefixes where lower.hasPrefix(prefix) {
            out = String(out.dropFirst(prefix.count)).trimmingCharacters(in: .whitespacesAndNewlines)
            break
        }
        return out
    }

    private func syntheticProjectIdentifierKey(_ projectRef: String) -> String? {
        let trimmed = projectRef.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }

        let lowered = trimmed.lowercased()
        for prefix in ["hex:", "id:"] where lowered.hasPrefix(prefix) {
            let suffix = String(trimmed.dropFirst(prefix.count)).trimmingCharacters(in: .whitespacesAndNewlines)
            let key = normalizedLookupKey(suffix)
            if key.count >= 4 {
                return key
            }
        }
        return nil
    }

    private func supervisorTriggerContextValue(_ key: String, userMessage: String?) -> String? {
        guard let userMessage else { return nil }
        let normalizedKey = key.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        guard !normalizedKey.isEmpty else { return nil }

        for rawLine in userMessage.split(separator: "\n", omittingEmptySubsequences: false) {
            let line = rawLine.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !line.isEmpty else { continue }
            let prefix = "\(normalizedKey)="
            guard line.lowercased().hasPrefix(prefix) else { continue }
            let value = String(line.dropFirst(prefix.count)).trimmingCharacters(in: .whitespacesAndNewlines)
            return value.isEmpty ? nil : value
        }
        return nil
    }

    private func supervisorFallbackProjectReference(
        userMessage: String?,
        triggerSource: SupervisorCommandTriggerSource
    ) -> String? {
        guard triggerSource != .userTurn else { return nil }
        if let projectId = supervisorTriggerContextValue("project_id", userMessage: userMessage) {
            let sanitized = sanitizeProjectReference(projectId)
            if !sanitized.isEmpty {
                return sanitized
            }
        }
        if let projectRef = supervisorTriggerContextValue("project_ref", userMessage: userMessage) {
            let sanitized = sanitizeProjectReference(projectRef)
            if !sanitized.isEmpty {
                return sanitized
            }
        }
        return nil
    }

    private func resolvedSupervisorProjectLookup(
        projectRef: String?,
        projects: [AXProjectEntry],
        userMessage: String?,
        triggerSource: SupervisorCommandTriggerSource
    ) -> (requestedRef: String, resolution: ProjectReferenceResolution?, projectScopeMissing: Bool) {
        let rawProjectRef = sanitizeProjectReference(projectRef ?? "")
        let fallbackRef = supervisorFallbackProjectReference(
            userMessage: userMessage,
            triggerSource: triggerSource
        )

        let primaryRef: String = {
            if !rawProjectRef.isEmpty {
                return rawProjectRef
            }
            if let defaultRef = defaultProjectReferenceForDirectAssignment(projects: projects) {
                return defaultRef
            }
            return ""
        }()

        if !primaryRef.isEmpty {
            let primaryResolution = resolveProjectReference(primaryRef, in: projects)
            if case .matched = primaryResolution {
                return (primaryRef, primaryResolution, false)
            }
            if let fallbackRef,
               !fallbackRef.isEmpty,
               fallbackRef.compare(primaryRef, options: .caseInsensitive) != .orderedSame {
                let fallbackResolution = resolveProjectReference(fallbackRef, in: projects)
                if case .matched = fallbackResolution {
                    return (fallbackRef, fallbackResolution, false)
                }
            }
            return (primaryRef, primaryResolution, false)
        }

        if let fallbackRef, !fallbackRef.isEmpty {
            return (fallbackRef, resolveProjectReference(fallbackRef, in: projects), false)
        }

        return ("", nil, true)
    }

    private func resolveProjectReference(_ projectRef: String) -> ProjectReferenceResolution {
        resolveProjectReference(projectRef, in: allProjects())
    }

    private func resolveProjectReference(
        _ projectRef: String,
        in projects: [AXProjectEntry]
    ) -> ProjectReferenceResolution {
        guard !projects.isEmpty else { return .notFound }

        if let exactId = projects.first(where: { $0.projectId.compare(projectRef, options: .caseInsensitive) == .orderedSame }) {
            return .matched(exactId)
        }
        if let exactName = projects.first(where: { $0.displayName.compare(projectRef, options: .caseInsensitive) == .orderedSame }) {
            return .matched(exactName)
        }

        let key = normalizedLookupKey(projectRef)
        let syntheticIDKey = syntheticProjectIdentifierKey(projectRef)
        guard !key.isEmpty || syntheticIDKey != nil else { return .notFound }

        let scored: [(entry: AXProjectEntry, score: Int)] = projects.compactMap { entry in
            let nameKey = normalizedLookupKey(entry.displayName)
            let idKey = normalizedLookupKey(entry.projectId)
            var score = 0
            if let syntheticIDKey {
                if syntheticIDKey == idKey { score = max(score, 130) }
                if !idKey.isEmpty && idKey.hasPrefix(syntheticIDKey) { score = max(score, 125) }
            }
            if key == idKey { score = max(score, 120) }
            if key == nameKey { score = max(score, 110) }
            if !nameKey.isEmpty && nameKey.hasPrefix(key) { score = max(score, 95) }
            if !nameKey.isEmpty && nameKey.contains(key) { score = max(score, 85) }
            if !idKey.isEmpty && idKey.hasPrefix(key) { score = max(score, 80) }
            if !idKey.isEmpty && idKey.contains(key) { score = max(score, 70) }
            if score == 0 { return nil }
            return (entry, score)
        }
        .sorted { lhs, rhs in
            if lhs.score != rhs.score { return lhs.score > rhs.score }
            if lhs.entry.lastOpenedAt != rhs.entry.lastOpenedAt { return lhs.entry.lastOpenedAt > rhs.entry.lastOpenedAt }
            return lhs.entry.displayName.localizedCaseInsensitiveCompare(rhs.entry.displayName) == .orderedAscending
        }

        guard let best = scored.first else { return .notFound }
        if scored.count == 1 {
            return .matched(best.entry)
        }
        let second = scored[1]
        if best.score - second.score >= 20 {
            return .matched(best.entry)
        }
        return .ambiguous(Array(scored.prefix(4).map { $0.entry }))
    }

    private func normalizedLookupKey(_ text: String) -> String {
        let folded = text
            .folding(options: [.caseInsensitive, .diacriticInsensitive, .widthInsensitive], locale: .current)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let scalars = folded.unicodeScalars.filter { CharacterSet.alphanumerics.contains($0) }
        return String(String.UnicodeScalarView(scalars))
    }

    private func collectSupervisorProjectMemoryDigests(
        projects: [AXProjectEntry]? = nil,
        maxProjects: Int = 24
    ) -> [SupervisorMemoryProjectDigest] {
        Array((projects ?? allProjects()).prefix(maxProjects)).map(supervisorMemoryDigest)
    }

    func buildSupervisorProjectDrillDown(
        for project: AXProjectEntry,
        requestedScope: SupervisorProjectDrillDownScope = .capsuleOnly,
        recentMessageLimit: Int = 6,
        openedReason: String = "explicit_portfolio_drilldown"
    ) -> SupervisorProjectDrillDownSnapshot {
        let registry = supervisorJurisdictionRegistry
        let now = Date().timeIntervalSince1970
        guard registry.allowsProjectVisibility(project) else {
            let denied = SupervisorProjectDrillDownSnapshot.denied(
                projectId: project.projectId,
                projectName: project.displayName,
                openedReason: openedReason,
                status: .deniedProjectInvisible,
                requestedScope: requestedScope,
                denyReason: "project_not_visible_in_current_jurisdiction",
                updatedAt: now
            )
            supervisorLastProjectDrillDownSnapshot = denied
            return denied
        }
        guard registry.allowsDrillDown(projectId: project.projectId, requestedScope: requestedScope) else {
            let denied = SupervisorProjectDrillDownSnapshot.denied(
                projectId: project.projectId,
                projectName: project.displayName,
                openedReason: openedReason,
                status: .deniedScope,
                requestedScope: requestedScope,
                denyReason: "requested_scope_exceeds_jurisdiction_cap",
                updatedAt: now
            )
            supervisorLastProjectDrillDownSnapshot = denied
            return denied
        }

        let digest = supervisorMemoryDigest(project)
        let capsule = SupervisorPortfolioSnapshotBuilder.build(from: [digest], now: now).projects.first
        let ctx = AXProjectContext(root: URL(fileURLWithPath: project.rootPath, isDirectory: true))
        let specCapsule = SupervisorProjectSpecCapsuleStore.load(for: ctx)
        let decisionSnapshot = SupervisorDecisionTrackStore.load(for: ctx)
        let backgroundSnapshot = SupervisorBackgroundPreferenceTrackStore.load(for: ctx)
        let decisionRails = SupervisorDecisionRailResolver.resolve(
            projectId: project.projectId,
            decisions: decisionSnapshot.events,
            backgroundNotes: backgroundSnapshot.notes
        )
        let latestReview = SupervisorReviewNoteStore.latest(for: ctx)
        let latestGuidance = SupervisorGuidanceInjectionStore.latest(for: ctx)
        let pendingAckGuidance = SupervisorGuidanceInjectionStore.latestPendingAck(for: ctx)
        let resolvedGovernance = resolvedSupervisorProjectGovernanceState(
            projectId: project.projectId,
            ctx: ctx
        )
        let skillCallSnapshot = SupervisorProjectSkillCallStore.load(for: ctx)
        let workflow = SupervisorProjectWorkflowCanonicalSync.snapshot(
            projectId: project.projectId,
            projectName: project.displayName,
            jobSnapshot: SupervisorProjectJobStore.load(for: ctx),
            planSnapshot: SupervisorProjectPlanStore.load(for: ctx),
            skillCallSnapshot: skillCallSnapshot
        )
        let recentMessages: [AXRecentContextMessage]
        switch requestedScope {
        case .capsuleOnly:
            recentMessages = []
        case .capsulePlusRecent:
            recentMessages = Array(AXRecentContextStore.load(for: ctx).messages.suffix(max(0, recentMessageLimit))).map {
                AXRecentContextMessage(
                    role: $0.role,
                    content: capped($0.content, maxChars: 280),
                    createdAt: $0.createdAt
                )
            }
        case .rawEvidence:
            recentMessages = []
        }

        let snapshot = SupervisorProjectDrillDownSnapshot(
            updatedAt: now,
            projectId: project.projectId,
            projectName: project.displayName,
            openedReason: openedReason,
            status: .allowed,
            requestedScope: requestedScope,
            grantedScope: requestedScope,
            capsule: capsule,
            specCapsule: specCapsule,
            decisionRails: decisionRails,
            latestReview: latestReview,
            latestGuidance: latestGuidance,
            pendingAckGuidance: pendingAckGuidance,
            followUpRhythmSummary: resolvedGovernance.map {
                SupervisorReviewPolicyEngine.eventFollowUpCadenceSummary(governance: $0)
            },
            memoryCompactionRollup: digest.memoryCompactionRollup,
            workflow: workflow,
            recentMessages: recentMessages,
            denyReason: nil,
            refs: SupervisorProjectDrillDownRefsBuilder.build(
                projectId: project.projectId,
                ctx: ctx,
                requestedScope: requestedScope,
                specCapsule: specCapsule,
                decisionRails: decisionRails,
                decisionAssist: digest.decisionAssist,
                memoryCompactionRollup: digest.memoryCompactionRollup,
                latestReview: latestReview,
                latestGuidance: latestGuidance,
                pendingAckGuidance: pendingAckGuidance,
                workflow: workflow
            )
        )
        supervisorLastProjectDrillDownSnapshot = snapshot
        return snapshot
    }

    func buildSupervisorProjectDrillDown(
        projectId: String,
        requestedScope: SupervisorProjectDrillDownScope = .capsuleOnly,
        recentMessageLimit: Int = 6,
        openedReason: String = "explicit_portfolio_drilldown"
    ) -> SupervisorProjectDrillDownSnapshot {
        let projects = knownProjects()
        guard let project = projects.first(where: { $0.projectId == projectId }) else {
            let denied = SupervisorProjectDrillDownSnapshot.denied(
                projectId: projectId,
                projectName: projectId,
                openedReason: openedReason,
                status: .projectNotFound,
                requestedScope: requestedScope,
                denyReason: "project_not_found"
            )
            supervisorLastProjectDrillDownSnapshot = denied
            return denied
        }
        return buildSupervisorProjectDrillDown(
            for: project,
            requestedScope: requestedScope,
            recentMessageLimit: recentMessageLimit,
            openedReason: openedReason
        )
    }

    private func supervisorMemoryDigest(_ project: AXProjectEntry) -> SupervisorMemoryProjectDigest {
        let root = URL(fileURLWithPath: project.rootPath, isDirectory: true)
        let ctx = AXProjectContext(root: root)
        let runtime = runtimeStatus(for: project)
        let localMemory = try? AXProjectStore.loadOrCreateMemory(for: ctx)
        let recent = AXRecentContextStore.load(for: ctx)
        var governance = loadSupervisorProjectDigestGovernanceContext(projectId: project.projectId, ctx: ctx)

        let localGoal = (localMemory?.goal ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let localCurrent = firstNonEmptyLine(items: localMemory?.currentState ?? [])
        let localNext = firstNonEmptyLine(items: localMemory?.nextSteps ?? [])
        var localBlocker = firstNonEmptyLine(items: localMemory?.openQuestions ?? [])
        if localBlocker.isEmpty {
            localBlocker = firstNonEmptyLine(items: localMemory?.risks ?? [])
        }

        governance.decisionAssist = inferredSupervisorDecisionBlockerAssist(
            projectId: project.projectId,
            localBlocker: localBlocker,
            registryBlocker: project.blockerSummary,
            governance: governance
        )
        if governance.decisionAssist != nil, !governance.sourceTags.contains("decision_blocker_assist") {
            governance.sourceTags.append("decision_blocker_assist")
        }

        var state = resolvedSupervisorDigestCurrentState(
            localCurrent: localCurrent,
            registryCurrent: project.currentStateSummary,
            runtimeText: runtime.text,
            governance: governance
        )
        var next = resolvedSupervisorDigestNextStep(
            localNext: localNext,
            registryNext: project.nextStepSummary,
            governance: governance
        )
        let blocker = resolvedSupervisorDigestBlocker(
            localBlocker: localBlocker,
            registryBlocker: project.blockerSummary,
            governance: governance
        )
        let goal = resolvedSupervisorDigestGoal(
            localGoal: localGoal,
            registryDigest: project.statusDigest,
            governance: governance
        )

        let projectState = SupervisorProjectCapsuleBuilder.projectState(
            runtimeState: runtime.text,
            currentAction: state,
            blocker: blocker == "(无)" ? "" : blocker,
            nextStep: next
        )
        let compactionRollup = supervisorMemoryCompactionRollup(
            projectId: project.projectId,
            ctx: ctx,
            localMemory: localMemory,
            recent: recent,
            governance: governance,
            projectState: projectState
        )
        if state.isEmpty {
            state = supervisorMemoryCompactionStateHint(compactionRollup)
        }
        if next.isEmpty {
            next = supervisorMemoryCompactionNextStepHint(
                compactionRollup,
                projectState: projectState
            )
        }

        let source = resolvedSupervisorDigestSource(
            hasDurableLocalMemory: hasDurableSupervisorProjectMemory(localMemory),
            governance: governance,
            hasMemoryCompactionRollup: compactionRollup != nil
        )
        let updatedAt = max(
            localMemory?.updatedAt ?? 0,
            project.lastSummaryAt ?? 0,
            project.lastEventAt ?? 0,
            project.lastOpenedAt,
            governance.updatedAt
        )

        return SupervisorMemoryProjectDigest(
            projectId: project.projectId,
            displayName: project.displayName,
            runtimeState: runtime.text,
            source: source,
            goal: goal.isEmpty ? "(暂无)" : goal,
            currentState: state.isEmpty ? "(暂无)" : state,
            nextStep: next.isEmpty ? "(暂无)" : next,
            blocker: blocker.isEmpty ? "(无)" : blocker,
            updatedAt: updatedAt,
            recentMessageCount: recent.messages.count,
            missingSpecFields: governance.missingSpecFields,
            shadowedBackgroundNoteCount: governance.shadowedBackgroundNoteCount,
            weakOnlyBackgroundNoteCount: governance.weakOnlyBackgroundNoteCount,
            decisionAssist: governance.decisionAssist,
            memoryCompactionRollup: compactionRollup
        )
    }

    private func loadSupervisorProjectDigestGovernanceContext(
        projectId: String,
        ctx: AXProjectContext
    ) -> SupervisorProjectDigestGovernanceContext {
        let specCapsule = SupervisorProjectSpecCapsuleStore.load(for: ctx)
        let decisionSnapshot = SupervisorDecisionTrackStore.load(for: ctx)
        let selectedEvidenceSnapshot = SupervisorSelectedEvidencePinStore.load(for: ctx)
        let backgroundSnapshot = SupervisorBackgroundPreferenceTrackStore.load(for: ctx)
        let rails = SupervisorDecisionRailResolver.resolve(
            projectId: projectId,
            decisions: decisionSnapshot.events,
            backgroundNotes: backgroundSnapshot.notes
        )

        let hardDecisions = rails.decisionTrack.reduce(into: [SupervisorDecisionCategory: SupervisorDecisionTrackEvent]()) {
            partial, event in
            partial[event.category] = event
        }

        let preferredBackgroundNote = rails.resolutions
            .compactMap(\.preferredBackgroundNote)
            .sorted { lhs, rhs in
                if lhs.strength.rank != rhs.strength.rank {
                    return lhs.strength.rank > rhs.strength.rank
                }
                return lhs.createdAtMs > rhs.createdAtMs
            }
            .first
        let shadowedBackgroundNoteCount = rails.resolutions.reduce(0) { partial, resolution in
            partial + resolution.shadowedBackgroundNotes.count
        }
        let weakOnlyBackgroundNoteCount = rails.resolutions.reduce(0) { partial, resolution in
            partial + ((resolution.preferredBackgroundNote?.mustNotPromoteWithoutDecision == true) ? 1 : 0)
        }

        let backgroundShadowHint = preferredBackgroundNote.map { note in
            let statement = capped(firstNonEmptyLine(in: note.statement), maxChars: 80)
            return "背景偏好（弱参考）：\(note.domain.rawValue)=\(statement)"
        } ?? ""
        let resolvedGovernance = resolvedSupervisorProjectGovernanceState(
            projectId: projectId,
            ctx: ctx
        )

        let updatedAt = max(
            TimeInterval(specCapsule?.updatedAtMs ?? 0) / 1000.0,
            TimeInterval(decisionSnapshot.updatedAtMs) / 1000.0,
            TimeInterval(selectedEvidenceSnapshot.updatedAtMs) / 1000.0,
            TimeInterval(backgroundSnapshot.updatedAtMs) / 1000.0
        )

        var sourceTags: [String] = []
        if specCapsule != nil {
            sourceTags.append("spec_capsule")
        }
        if !decisionSnapshot.events.isEmpty {
            sourceTags.append("decision_track")
        }
        if !selectedEvidenceSnapshot.pins.isEmpty {
            sourceTags.append("selected_evidence")
        }
        if !backgroundSnapshot.notes.isEmpty {
            sourceTags.append("background_preference_track")
        }
        if resolvedGovernance != nil {
            sourceTags.append("runtime_governance")
        }

        return SupervisorProjectDigestGovernanceContext(
            specCapsule: specCapsule,
            missingSpecFields: specCapsule?.missingRequiredFields ?? [],
            hardDecisions: hardDecisions,
            selectedEvidencePins: selectedEvidenceSnapshot.pins,
            backgroundShadowHint: backgroundShadowHint,
            shadowedBackgroundNoteCount: shadowedBackgroundNoteCount,
            weakOnlyBackgroundNoteCount: weakOnlyBackgroundNoteCount,
            decisionAssist: nil,
            resolvedGovernance: resolvedGovernance,
            updatedAt: updatedAt,
            sourceTags: sourceTags
        )
    }

    private func resolvedSupervisorProjectGovernanceState(
        projectId: String,
        ctx: AXProjectContext
    ) -> AXProjectResolvedGovernanceState? {
        if let appModel,
           let project = appModel.registry.project(for: projectId) {
            return appModel.resolvedProjectGovernance(for: project)
        }

        let config = (try? AXProjectStore.loadOrCreateConfig(for: ctx)) ?? .default(forProjectRoot: ctx.root)
        let adaptationPolicy = AXProjectSupervisorAdaptationPolicy.default
        let strengthProfile = AXProjectAIStrengthAssessor.assess(
            ctx: ctx,
            adaptationPolicy: adaptationPolicy
        )

        return xtResolveProjectGovernance(
            projectRoot: ctx.root,
            config: config,
            projectAIStrengthProfile: strengthProfile,
            adaptationPolicy: adaptationPolicy,
            permissionReadiness: .current()
        )
    }

    private func resolvedSupervisorDigestGoal(
        localGoal: String,
        registryDigest: String?,
        governance: SupervisorProjectDigestGovernanceContext
    ) -> String {
        firstMeaningfulDigestValue(
            [
                localGoal,
                governance.specCapsule?.goal,
                registryDigest
            ]
        )
    }

    private func resolvedSupervisorDigestCurrentState(
        localCurrent: String,
        registryCurrent: String?,
        runtimeText: String,
        governance: SupervisorProjectDigestGovernanceContext
    ) -> String {
        let preferred = firstMeaningfulDigestValue([localCurrent, registryCurrent])
        if !preferred.isEmpty {
            return preferred
        }
        if !governance.missingSpecFields.isEmpty {
            return supervisorSpecGapStateHint(
                governance.missingSpecFields,
                assist: governance.decisionAssist
            )
        }
        let decisionSummary = supervisorFormalDecisionSummary(governance.hardDecisions)
        if !decisionSummary.isEmpty {
            return decisionSummary
        }
        let assistState = supervisorDecisionAssistStateHint(governance.decisionAssist)
        if !assistState.isEmpty {
            return assistState
        }
        if !governance.backgroundShadowHint.isEmpty {
            return governance.backgroundShadowHint
        }
        let milestoneHint = supervisorSpecMilestoneStateHint(governance.specCapsule)
        if !milestoneHint.isEmpty {
            return milestoneHint
        }
        return isDigestPlaceholder(runtimeText) ? "" : runtimeText
    }

    private func resolvedSupervisorDigestNextStep(
        localNext: String,
        registryNext: String?,
        governance: SupervisorProjectDigestGovernanceContext
    ) -> String {
        let preferred = firstMeaningfulDigestValue(
            [localNext, registryNext],
            treatContinueCurrentTaskAsPlaceholder: true
        )
        if !preferred.isEmpty {
            return preferred
        }
        if !governance.missingSpecFields.isEmpty {
            return supervisorSpecGapNextStepHint(
                governance.missingSpecFields,
                assist: governance.decisionAssist
            )
        }
        let assistHint = supervisorDecisionAssistNextStepHint(governance.decisionAssist)
        if !assistHint.isEmpty {
            return assistHint
        }
        let decisionHint = supervisorDecisionNextStepHint(governance.hardDecisions)
        if !decisionHint.isEmpty {
            return decisionHint
        }
        let milestoneHint = supervisorSpecMilestoneNextStepHint(governance.specCapsule)
        if !milestoneHint.isEmpty {
            return milestoneHint
        }
        let techStackHint = supervisorSpecTechStackNextStepHint(governance.specCapsule)
        if !techStackHint.isEmpty {
            return techStackHint
        }
        return ""
    }

    private func resolvedSupervisorDigestBlocker(
        localBlocker: String,
        registryBlocker: String?,
        governance: SupervisorProjectDigestGovernanceContext
    ) -> String {
        let preferred = firstMeaningfulDigestValue(
            [localBlocker, registryBlocker],
            treatNoValueAsPlaceholder: true
        )
        if !preferred.isEmpty {
            return mergedSupervisorBlockerHint(
                preferred: preferred,
                assist: governance.decisionAssist
            )
        }
        if !governance.missingSpecFields.isEmpty {
            return supervisorSpecGapBlockerHint(
                governance.missingSpecFields,
                assist: governance.decisionAssist
            )
        }
        let formalBlocker = supervisorDecisionBlockerHint(governance.hardDecisions)
        if !formalBlocker.isEmpty {
            return mergedSupervisorBlockerHint(
                preferred: formalBlocker,
                assist: governance.decisionAssist
            )
        }
        return supervisorDecisionAssistBlockerHint(governance.decisionAssist)
    }

    private func resolvedSupervisorDigestSource(
        hasDurableLocalMemory: Bool,
        governance: SupervisorProjectDigestGovernanceContext,
        hasMemoryCompactionRollup: Bool
    ) -> String {
        var parts = hasDurableLocalMemory ? ["local_project_memory", "registry"] : ["registry_summary"]
        for tag in governance.sourceTags where !parts.contains(tag) {
            parts.append(tag)
        }
        if hasMemoryCompactionRollup, !parts.contains("memory_compaction_rollup") {
            parts.append("memory_compaction_rollup")
        }
        return parts.joined(separator: "+")
    }

    private func supervisorSpecGapFieldList(_ fields: [SupervisorProjectSpecField]) -> String {
        fields.map(supervisorSpecGapFieldLabel).joined(separator: " / ")
    }

    private func supervisorSpecGapFieldLabel(_ field: SupervisorProjectSpecField) -> String {
        switch field {
        case .goal:
            return "goal"
        case .mvpDefinition:
            return "mvp_definition"
        case .nonGoals:
            return "non_goals"
        case .approvedTechStack:
            return "tech_stack"
        case .milestones:
            return "milestones"
        }
    }

    private func supervisorSpecGapStateHint(
        _ fields: [SupervisorProjectSpecField],
        assist: SupervisorDecisionBlockerAssist? = nil
    ) -> String {
        let base = "规格待补齐：\(supervisorSpecGapFieldList(fields))"
        let assistSummary = supervisorDecisionAssistStateHint(assist)
        guard !assistSummary.isEmpty else {
            return capped(base, maxChars: 120)
        }
        return capped("\(base)；\(assistSummary)", maxChars: 120)
    }

    private func supervisorSpecGapNextStepHint(
        _ fields: [SupervisorProjectSpecField],
        assist: SupervisorDecisionBlockerAssist? = nil
    ) -> String {
        let base = "补齐 formal spec 字段：\(supervisorSpecGapFieldList(fields))"
        let assistSummary = supervisorDecisionAssistNextStepHint(assist)
        guard !assistSummary.isEmpty else {
            return capped(base, maxChars: 120)
        }
        return capped("\(base)；\(assistSummary)", maxChars: 120)
    }

    private func supervisorSpecGapBlockerHint(
        _ fields: [SupervisorProjectSpecField],
        assist: SupervisorDecisionBlockerAssist? = nil
    ) -> String {
        let base = "formal_spec_missing: \(supervisorSpecGapFieldList(fields))"
        let assistSummary = supervisorDecisionAssistBlockerHint(assist)
        guard !assistSummary.isEmpty else {
            return capped(base, maxChars: 120)
        }
        return capped("\(base) | \(assistSummary)", maxChars: 120)
    }

    private func supervisorDecisionHintOrder() -> [SupervisorDecisionCategory] {
        [.approvalResult, .scopeFreeze, .techStack, .riskPosture]
    }

    private func supervisorFormalDecisionSummary(
        _ hardDecisions: [SupervisorDecisionCategory: SupervisorDecisionTrackEvent]
    ) -> String {
        let items = supervisorDecisionHintOrder().compactMap { category -> String? in
            guard let event = hardDecisions[category] else { return nil }
            let statement = capped(firstNonEmptyLine(in: event.statement), maxChars: 56)
            return "\(category.rawValue)=\(statement)"
        }
        guard !items.isEmpty else { return "" }
        return capped("已批准决策：\(items.prefix(2).joined(separator: "；"))", maxChars: 160)
    }

    private func supervisorDecisionNextStepHint(
        _ hardDecisions: [SupervisorDecisionCategory: SupervisorDecisionTrackEvent]
    ) -> String {
        for category in supervisorDecisionHintOrder() {
            guard let event = hardDecisions[category] else { continue }
            let statement = capped(firstNonEmptyLine(in: event.statement), maxChars: 72)
            switch category {
            case .approvalResult:
                if supervisorDecisionIndicatesBlocker(event) {
                    return "处理已批准 approval_result：\(statement)"
                }
                return "按已批准 approval_result 继续：\(statement)"
            case .scopeFreeze:
                return "按已批准 scope_freeze 收口：\(statement)"
            case .techStack:
                return "按已批准 tech_stack 推进：\(statement)"
            case .riskPosture:
                return "按已批准 risk_posture 执行：\(statement)"
            default:
                return "按已批准决策推进：\(statement)"
            }
        }
        return ""
    }

    private func supervisorDecisionBlockerHint(
        _ hardDecisions: [SupervisorDecisionCategory: SupervisorDecisionTrackEvent]
    ) -> String {
        for category in supervisorDecisionHintOrder() {
            guard let event = hardDecisions[category], supervisorDecisionIndicatesBlocker(event) else { continue }
            let statement = capped(firstNonEmptyLine(in: event.statement), maxChars: 84)
            return "formal_\(category.rawValue): \(statement)"
        }
        return ""
    }

    private func supervisorDecisionIndicatesBlocker(_ event: SupervisorDecisionTrackEvent) -> Bool {
        let lowered = event.statement.lowercased()
        return [
            "deny",
            "denied",
            "rejected",
            "blocked",
            "blocking",
            "no_go",
            "no-go",
            "hold",
            "requires authorization",
            "requires approval",
            "等待授权",
            "阻塞",
            "驳回"
        ].contains { lowered.contains($0) }
    }

    private func inferredSupervisorDecisionBlockerAssist(
        projectId: String,
        localBlocker: String,
        registryBlocker: String?,
        governance: SupervisorProjectDigestGovernanceContext
    ) -> SupervisorDecisionBlockerAssist? {
        let preferredBlocker = firstMeaningfulDigestValue(
            [localBlocker, registryBlocker],
            treatNoValueAsPlaceholder: true
        )
        let fallbackFormalBlocker = supervisorDecisionBlockerHint(governance.hardDecisions)
        let normalized = normalizedSupervisorIntentText(
            !preferredBlocker.isEmpty
                ? preferredBlocker
                : (!fallbackFormalBlocker.isEmpty ? fallbackFormalBlocker : inferredSupervisorSpecGapAssistSeed(governance))
        )
        let category = inferredSupervisorDecisionBlockerCategory(
            normalized: normalized,
            governance: governance
        )

        let candidateText = !preferredBlocker.isEmpty
            ? preferredBlocker
            : (!fallbackFormalBlocker.isEmpty ? fallbackFormalBlocker : inferredSupervisorSpecGapAssistSeed(governance))
        guard !candidateText.isEmpty else { return nil }

        let riskLevel = inferredSupervisorDecisionBlockerRiskLevel(
            normalized: normalized,
            category: category
        )
        let reversible = inferredSupervisorDecisionBlockerReversible(
            normalized: normalized,
            category: category
        )
        let touchesSecurity = category == .security || containsAny(
            normalized,
            ["security", "权限", "grant", "授权", "secret", "token", "credential", "安全"]
        )
        let touchesReleaseScope = category == .releaseScope || containsAny(
            normalized,
            ["release scope", "release", "发版", "go/no-go", "上线范围", "门禁", "release gate"]
        )
        let requiresHubAuthorization = touchesSecurity || touchesReleaseScope || containsAny(
            normalized,
            ["approval", "authorize", "授权", "审批", "grant_required", "paid", "付费", "prod", "production"]
        )

        let assist = SupervisorDecisionBlockerAssistEngine.build(
            context: SupervisorDecisionBlockerContext(
                projectId: projectId,
                blockerId: "digest-\(category.rawValue)",
                category: category,
                reversible: reversible,
                riskLevel: riskLevel,
                touchesSecurity: touchesSecurity,
                touchesReleaseScope: touchesReleaseScope,
                requiresHubAuthorization: requiresHubAuthorization,
                explicitApprovalGranted: false,
                allowAutoAdoptWhenPolicyAllows: false,
                evidenceRefs: governanceAssistEvidenceRefs(governance)
            )
        )

        if assist.templateCandidates.isEmpty && !assist.failClosed {
            return nil
        }
        return assist
    }

    private func inferredSupervisorSpecGapAssistSeed(
        _ governance: SupervisorProjectDigestGovernanceContext
    ) -> String {
        if governance.missingSpecFields.contains(.approvedTechStack) {
            return "missing approved tech stack"
        }
        return ""
    }

    private func inferredSupervisorDecisionBlockerCategory(
        normalized: String,
        governance: SupervisorProjectDigestGovernanceContext
    ) -> SupervisorDecisionBlockerCategory {
        if containsAny(normalized, ["delete", "删除", "wipe", "drop", "purge", "reset", "migrate", "migration", "销毁", "不可逆", "irreversible"]) {
            return .irreversibleOperation
        }
        if containsAny(normalized, ["release scope", "release", "发版", "上线", "go/no-go", "release gate", "发布范围"]) {
            return .releaseScope
        }
        if containsAny(normalized, ["security", "权限", "grant", "授权", "secret", "token", "credential", "安全"]) {
            return .security
        }
        if governance.missingSpecFields.contains(.approvedTechStack) || containsAny(
            normalized,
            ["tech stack", "技术栈", "语言", "框架", "stack", "选型"]
        ) {
            return .techStack
        }
        if containsAny(
            normalized,
            ["test stack", "test framework", "测试框架", "swift testing", "xctest", "jest", "pytest", "测试工具"]
        ) {
            return .testStack
        }
        if containsAny(
            normalized,
            ["scaffold", "脚手架", "目录结构", "project structure", "boilerplate", "template repo", "模板工程"]
        ) {
            return .scaffold
        }
        if containsAny(
            normalized,
            ["doc template", "文档模板", "readme", "release notes", "说明模板", "documentation template", "spec template"]
        ) {
            return .docTemplate
        }
        return .other
    }

    private func inferredSupervisorDecisionBlockerRiskLevel(
        normalized: String,
        category: SupervisorDecisionBlockerCategory
    ) -> SupervisorDecisionBlockerRiskLevel {
        switch category {
        case .irreversibleOperation:
            return .critical
        case .security, .releaseScope:
            return .high
        case .techStack, .scaffold, .testStack, .docTemplate:
            return .low
        case .other:
            if containsAny(normalized, ["prod", "production", "paid", "付费", "上线"]) {
                return .high
            }
            return .medium
        }
    }

    private func inferredSupervisorDecisionBlockerReversible(
        normalized: String,
        category: SupervisorDecisionBlockerCategory
    ) -> Bool {
        switch category {
        case .techStack, .scaffold, .testStack, .docTemplate:
            return true
        case .security, .releaseScope, .irreversibleOperation:
            return false
        case .other:
            return !containsAny(
                normalized,
                ["delete", "删除", "wipe", "drop", "purge", "销毁", "不可逆", "irreversible"]
            )
        }
    }

    private func governanceAssistEvidenceRefs(
        _ governance: SupervisorProjectDigestGovernanceContext
    ) -> [String] {
        var refs: [String] = []
        if let specCapsule = governance.specCapsule {
            refs.append(contentsOf: specCapsule.sourceRefs)
        }
        refs.append(contentsOf: governance.hardDecisions.values.flatMap(\.evidenceRefs))
        refs.append(contentsOf: governance.hardDecisions.values.map(\.auditRef))
        return orderedUniqueSupervisorRefs(refs)
    }

    private func supervisorDecisionAssistStateHint(_ assist: SupervisorDecisionBlockerAssist?) -> String {
        guard let assist else { return "" }
        if assist.failClosed {
            return "默认建议已生成但保持 fail-closed：\(assist.blockerCategory.rawValue)"
        }
        let option = assist.recommendedOption ?? assist.templateCandidates.first ?? assist.blockerCategory.rawValue
        return "默认建议待确认：\(option)（\(assist.approvalState.rawValue)）"
    }

    private func supervisorDecisionAssistNextStepHint(_ assist: SupervisorDecisionBlockerAssist?) -> String {
        guard let assist else { return "" }
        if assist.failClosed {
            return capped(
                "该决策需显式审批：\(assist.blockerCategory.rawValue)，当前只允许 \(assist.governanceMode.rawValue)",
                maxChars: 110
            )
        }
        let option = assist.recommendedOption ?? assist.templateCandidates.first ?? assist.blockerCategory.rawValue
        return capped(
            "审阅待定默认建议：\(option)，确认后再走 governed adoption",
            maxChars: 110
        )
    }

    private func supervisorDecisionAssistBlockerHint(_ assist: SupervisorDecisionBlockerAssist?) -> String {
        guard let assist else { return "" }
        if assist.failClosed {
            return "decision_requires_approval:\(assist.blockerCategory.rawValue)"
        }
        let option = assist.recommendedOption ?? assist.templateCandidates.first ?? assist.blockerCategory.rawValue
        return "default_proposal_pending:\(assist.blockerCategory.rawValue)=\(option)"
    }

    private func mergedSupervisorBlockerHint(
        preferred: String,
        assist: SupervisorDecisionBlockerAssist?
    ) -> String {
        let trimmed = preferred.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return supervisorDecisionAssistBlockerHint(assist) }
        let assistHint = supervisorDecisionAssistBlockerHint(assist)
        guard !assistHint.isEmpty else { return capped(trimmed, maxChars: 120) }
        return capped("\(trimmed) | \(assistHint)", maxChars: 120)
    }

    private func supervisorMemoryCompactionRollup(
        projectId: String,
        ctx: AXProjectContext,
        localMemory: AXMemory?,
        recent: AXRecentContext,
        governance: SupervisorProjectDigestGovernanceContext,
        projectState: SupervisorPortfolioProjectState
    ) -> SupervisorMemoryCompactionRollup? {
        let nowMs = max(0, Int64(Date().timeIntervalSince1970 * 1_000))
        let nodes = supervisorMemoryCompactionNodes(
            ctx: ctx,
            localMemory: localMemory,
            recent: recent,
            governance: governance
        )
        guard !nodes.isEmpty else { return nil }

        let plan = SupervisorMemoryCompactionPolicy.makePlan(
            SupervisorMemoryCompactionPolicyInput(
                projectId: projectId,
                projectState: supervisorCompactionProjectState(projectState),
                nowMs: nowMs,
                nodes: nodes
            )
        )
        guard plan.archiveCandidate || !plan.rollupNodes.isEmpty || !plan.archiveNodes.isEmpty else {
            return nil
        }
        return try? SupervisorArchiveRollup.build(from: plan, updatedAtMs: nowMs)
    }

    private func supervisorMemoryCompactionNodes(
        ctx: AXProjectContext,
        localMemory: AXMemory?,
        recent: AXRecentContext,
        governance: SupervisorProjectDigestGovernanceContext
    ) -> [SupervisorMemoryNode] {
        var nodes: [SupervisorMemoryNode] = []

        func appendNoiseNodes(
            _ items: [String],
            kind: SupervisorMemoryNodeKind,
            prefix: String,
            timestampMs: Int64,
            activeFirst: Bool = false
        ) {
            for (index, raw) in items.enumerated() {
                let summary = firstNonEmptyLine(in: raw)
                guard !summary.isEmpty else { continue }
                nodes.append(
                    SupervisorMemoryNode(
                        id: "\(prefix)-\(index)",
                        kind: kind,
                        createdAtMs: timestampMs,
                        lastTouchedAtMs: timestampMs,
                        summary: capped(summary, maxChars: 180),
                        refs: [],
                        pinned: false,
                        active: activeFirst && index == 0
                    )
                )
            }
        }

        if let localMemory {
            let memoryMs = max(0, Int64((localMemory.updatedAt * 1_000.0).rounded()))
            let goal = localMemory.goal.trimmingCharacters(in: .whitespacesAndNewlines)
            if !goal.isEmpty {
                nodes.append(
                    SupervisorMemoryNode(
                        id: "goal",
                        kind: .workingSet,
                        createdAtMs: memoryMs,
                        lastTouchedAtMs: memoryMs,
                        summary: capped(goal, maxChars: 180),
                        refs: [],
                        pinned: true,
                        active: true
                    )
                )
            }
            appendNoiseNodes(localMemory.currentState, kind: .workingSet, prefix: "current", timestampMs: memoryMs, activeFirst: true)
            appendNoiseNodes(localMemory.nextSteps, kind: .workingSet, prefix: "next", timestampMs: memoryMs, activeFirst: true)
            appendNoiseNodes(localMemory.openQuestions, kind: .observation, prefix: "open-question", timestampMs: memoryMs)
            appendNoiseNodes(localMemory.risks, kind: .observation, prefix: "risk", timestampMs: memoryMs)
            appendNoiseNodes(localMemory.recommendations, kind: .observation, prefix: "recommendation", timestampMs: memoryMs)
            appendNoiseNodes(localMemory.decisions, kind: .actionLog, prefix: "legacy-decision", timestampMs: memoryMs)
        }

        let recentRef = AXRecentContextStore.jsonURL(for: ctx).path
        for (index, message) in recent.messages.enumerated() {
            let summary = firstNonEmptyLine(in: message.content)
            guard !summary.isEmpty else { continue }
            let timestampMs = max(0, Int64((message.createdAt * 1_000.0).rounded()))
            let rolePrefix = message.role.trimmingCharacters(in: .whitespacesAndNewlines)
            nodes.append(
                SupervisorMemoryNode(
                    id: "recent-\(index)",
                    kind: .actionLog,
                    createdAtMs: timestampMs,
                    lastTouchedAtMs: timestampMs,
                    summary: capped("\(rolePrefix): \(summary)", maxChars: 180),
                    refs: [recentRef],
                    pinned: false,
                    active: index >= max(0, recent.messages.count - 2)
                )
            )
        }

        for event in governance.hardDecisions.values.sorted(by: { lhs, rhs in
            if lhs.updatedAtMs == rhs.updatedAtMs {
                return lhs.decisionId < rhs.decisionId
            }
            return lhs.updatedAtMs < rhs.updatedAtMs
        }) {
            nodes.append(
                SupervisorMemoryNode(
                    id: "decision-\(event.decisionId)",
                    kind: .decision,
                    createdAtMs: event.createdAtMs,
                    lastTouchedAtMs: event.updatedAtMs,
                    summary: capped(firstNonEmptyLine(in: event.statement), maxChars: 180),
                    refs: orderedUniqueSupervisorRefs(event.evidenceRefs + [event.auditRef]),
                    decisionId: event.decisionId,
                    milestoneId: nil,
                    pinned: true,
                    active: false
                )
            )
        }

        if let specCapsule = governance.specCapsule {
            for milestone in specCapsule.milestoneMap {
                nodes.append(
                    SupervisorMemoryNode(
                        id: "milestone-\(milestone.milestoneId)",
                        kind: .milestone,
                        createdAtMs: specCapsule.updatedAtMs,
                        lastTouchedAtMs: specCapsule.updatedAtMs,
                        summary: capped(milestone.title, maxChars: 180),
                        refs: orderedUniqueSupervisorRefs(specCapsule.sourceRefs),
                        decisionId: nil,
                        milestoneId: milestone.milestoneId,
                        pinned: milestone.status == .blocked,
                        active: milestone.status == .active
                    )
                )
            }
            if !specCapsule.sourceRefs.isEmpty {
                nodes.append(
                    SupervisorMemoryNode(
                        id: "spec-audit",
                        kind: .audit,
                        createdAtMs: specCapsule.updatedAtMs,
                        lastTouchedAtMs: specCapsule.updatedAtMs,
                        summary: "spec capsule sources",
                        refs: orderedUniqueSupervisorRefs(specCapsule.sourceRefs),
                        pinned: true,
                        active: false
                    )
                )
            }
        }

        return nodes
    }

    private func supervisorCompactionProjectState(
        _ state: SupervisorPortfolioProjectState
    ) -> SupervisorProjectCapsuleState {
        switch state {
        case .active:
            return .active
        case .blocked:
            return .blocked
        case .awaitingAuthorization:
            return .awaitingAuthorization
        case .completed:
            return .completed
        case .idle:
            return .idle
        }
    }

    private func supervisorMemoryCompactionStateHint(
        _ rollup: SupervisorMemoryCompactionRollup?
    ) -> String {
        guard let rollup, !rollup.rollupSummary.isEmpty else { return "" }
        return capped("记忆收口：\(rollup.rollupSummary)", maxChars: 120)
    }

    private func supervisorMemoryCompactionNextStepHint(
        _ rollup: SupervisorMemoryCompactionRollup?,
        projectState: SupervisorPortfolioProjectState
    ) -> String {
        guard let rollup else { return "" }
        if projectState == .completed && rollup.archiveCandidate {
            return capped(
                "审阅 archive rollup：关键 decision/milestone/gate refs 已保留，可按 archive 模式收口",
                maxChars: 120
            )
        }
        if !rollup.rolledUpNodeIds.isEmpty {
            return capped(
                "继续围绕 active facts 推进；旧 observation 已转为 rollup 摘要",
                maxChars: 120
            )
        }
        return ""
    }

    private func orderedUniqueSupervisorRefs(_ refs: [String]) -> [String] {
        var seen = Set<String>()
        var ordered: [String] = []
        for ref in refs {
            let trimmed = ref.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty, seen.insert(trimmed).inserted else { continue }
            ordered.append(trimmed)
        }
        return ordered
    }

    private func supervisorSpecMilestoneStateHint(_ specCapsule: SupervisorProjectSpecCapsule?) -> String {
        guard let milestone = specCapsule?.milestoneMap.first(where: { $0.status == .active }) ??
                specCapsule?.milestoneMap.first else {
            return ""
        }
        return capped("当前规格里程碑：\(milestone.title)", maxChars: 100)
    }

    private func supervisorSpecMilestoneNextStepHint(_ specCapsule: SupervisorProjectSpecCapsule?) -> String {
        guard let milestone = specCapsule?.milestoneMap.first(where: { $0.status == .active }) ??
                specCapsule?.milestoneMap.first else {
            return ""
        }
        return capped("推进规格里程碑：\(milestone.title)", maxChars: 100)
    }

    private func supervisorSpecTechStackNextStepHint(_ specCapsule: SupervisorProjectSpecCapsule?) -> String {
        guard let specCapsule, !specCapsule.approvedTechStack.isEmpty else { return "" }
        let summary = specCapsule.approvedTechStack.prefix(3).joined(separator: ", ")
        return capped("按规格技术栈推进：\(summary)", maxChars: 100)
    }

    private func generateProjectList(from digests: [SupervisorMemoryProjectDigest]) -> String {
        if digests.isEmpty {
            return "(暂无项目)"
        }
        return digests.map { digest in
            """
            - \(digest.displayName)
              运行态: \(digest.runtimeState)
              记忆来源: \(digest.source)
              目标/摘要: \(digest.goal)
              当前状态: \(digest.currentState)
              下一步: \(digest.nextStep)
              阻塞: \(digest.blocker)
              recent_messages: \(digest.recentMessageCount)
            """
        }.joined(separator: "\n")
    }

    private func generateAvailableModels() -> String {
        let models = modelManager.availableModels
        if models.isEmpty {
            return "(暂无可用模型)"
        }
        return models.map { model in
            var lines = [
                "- \(model.name)",
                "  ID: \(model.id)",
                "  后端: \(model.backend)",
                "  \(model.defaultLoadConfigDisplayLine)"
            ]
            if let localLoadConfigLimitLine = model.localLoadConfigLimitLine {
                lines.append("  \(localLoadConfigLimitLine)")
            }
            lines.append("  状态: \(model.state == .loaded ? "已加载" : "可用")")
            return lines.joined(separator: "\n")
        }.joined(separator: "\n")
    }

    private func generateFallbackResponse(
        _ userMessage: String,
        personaSlot: SupervisorPersonaSlot? = nil
    ) -> String {
        let projects = allProjects()

        if shouldRunDoctorCommand(userMessage) {
            let report = runSupervisorDoctorPreflight(reason: "fallback_doctor_command", emitSystemMessage: false)
            return renderDoctorSummary(report)
        } else if shouldRunSecretsDryRunCommand(userMessage) {
            let report = runSupervisorDoctorPreflight(reason: "fallback_secrets_dry_run", emitSystemMessage: false)
            return renderSecretsDryRunSummary(report)
        } else if shouldShowXTReadyIncidentEventsStatusCommand(userMessage) {
            return renderXTReadyIncidentEventsStatus()
        } else if shouldExportXTReadyIncidentEventsCommand(userMessage) {
            let result = exportXTReadyIncidentEventsReport()
            return renderXTReadyIncidentExportSummary(result)
        }

        if let directReply = directSupervisorReplyIfApplicable(
            userMessage,
            projects: projects,
            personaSlot: personaSlot
        ) {
            return directReply
        } else if let directAction = directSupervisorActionIfApplicable(userMessage, projects: projects) {
            return directAction
        } else if let synchronousBriefGuard = synchronousSupervisorBriefGuardReplyIfApplicable(
            userMessage,
            projects: projects
        ) {
            return synchronousBriefGuard
        } else if userMessage.contains("进度") || userMessage.contains("状态") {
            return generateProgressReport(projects)
        } else if userMessage.contains("卡点") || userMessage.contains("问题") {
            return generateBlockerReport(projects)
        } else if userMessage.contains("下一步") || userMessage.contains("建议") {
            return generateNextStepSuggestions(projects)
        } else if userMessage.contains("优先") || userMessage.contains("排序") {
            return generatePriorityRecommendation(projects)
        } else {
            return generateGeneralResponse(userMessage, projects, personaSlot: personaSlot)
        }
    }

    private func isIdentityQuestion(_ normalized: String) -> Bool {
        let tokens = [
            "你是谁",
            "你是啥",
