    private func isNaturalSupervisorBriefRequest(
        _ normalized: String,
        projectSelectionSource: String?
    ) -> Bool {
        let strongSignals = [
            "汇报",
            "简报",
            "brief",
            "summary",
            "状态",
            "进度",
            "进展",
            "卡点",
            "卡在哪",
            "阻塞",
            "下一步",
            "建议",
            "先做哪个",
