    private func isExplicitProjectCreationRequest(_ normalized: String) -> Bool {
        let tokens = [
            "创建项目",
            "新建项目",
            "建个项目",
            "建一个项目",
            "建立项目",
            "按默认方案建项目",
            "按默认方案创建项目",
            "直接建项目",
            "直接创建项目",
            "create project",
            "new project"
        ]
        return tokens.contains { normalized.contains($0) }
    }

    private func isExplicitModelAssignmentRequest(_ normalized: String) -> Bool {
        let directTokens = [
            "分配模型",
            "批量分配模型",
            "统一分配模型",
            "设置模型",
            "换模型",
            "切模型",
            "set model",
            "assign model"
        ]
        if directTokens.contains(where: { normalized.contains($0) }) {
            return true
        }

        let roleTokens = [
            "coder",
            "coarse",
            "refine",
            "reviewer",
            "advisor",
            "开发者",
            "粗编",
            "粗稿",
            "初稿",
            "精编",
            "精修",
            "审查",
            "审阅",
            "评审",
            "顾问"
        ]
        let changeTokens = [
            "改成",
            "改为",
            "换成",
            "换为",
            "换到",
            "切到",
            "切换到",
            "设为",
            "设置为",
            "指定",
            "指定为",
            "调整为",
            "用"
        ]
        let modelTokens = ["模型", "model", "auto"]
        let scopeTokens = ["项目", "当前项目", "这个项目", "该项目", "所有项目", "全部项目"]

        let hasRole = roleTokens.contains(where: { normalized.contains($0) })
        let hasChange = changeTokens.contains(where: { normalized.contains($0) })
        let hasModel = modelTokens.contains(where: { normalized.contains($0) })
        let hasScope = scopeTokens.contains(where: { normalized.contains($0) })
        let hasVersionLikeToken = normalized.range(
            of: #"\b[a-z]*[0-9]+(?:\.[0-9]+)+(?:[a-z0-9._/-]*)\b"#,
            options: .regularExpression
        ) != nil
        return hasChange && (hasRole || hasScope) && (hasModel || hasVersionLikeToken)
    }

    private func isExplicitSupervisorWorkflowExecutionRequest(
        _ normalized: String,
        triggerSource: SupervisorCommandTriggerSource
    ) -> Bool {
        if triggerSource != .userTurn {
            return true
        }

        if isExplicitSupervisorContinuationIntent(normalized) {
            return true
        }

        let directTokens = [
            "创建任务",
            "新建任务",
            "建个任务",
            "建一个任务",
            "create job",
            "创建job",
            "新增job",
            "更新计划",
            "创建计划",
            "执行计划",
            "调用技能",
            "调用skill",
            "call skill",
            "取消技能",
            "取消skill",
            "cancel skill",
            "停止技能",
            "执行这个技能",
            "写入文件",
            "写个文件",
            "修改文件",
            "应用补丁",
            "打补丁",
            "write file",
            "apply patch",
            "自动处理",
            "自动执行",
            "自动继续",
            "继续执行",
            "启动自动化",
            "launch run",
            "开始跑"
        ]
        if directTokens.contains(where: { normalized.contains($0) }) {
            return true
        }

        let orchestrationNouns = [
            "任务",
            "job",
            "计划",
            "plan",
            "技能",
            "skill",
            "运行",
            "执行"
        ]
        let executionVerbs = [
            "创建",
            "新建",
            "建立",
            "更新",
            "执行",
            "运行",
            "启动",
            "开始",
            "取消",
            "停止",
            "终止",
            "调",
            "调用",
            "create",
            "run",
            "start",
            "cancel",
            "execute",
            "call"
        ]
        let hasNoun = orchestrationNouns.contains(where: { normalized.contains($0) })
        let hasVerb = executionVerbs.contains(where: { normalized.contains($0) })
        return hasNoun && hasVerb
    }

    private func isExplicitSupervisorContinuationIntent(_ normalized: String) -> Bool {
        let trimmed = normalized.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return false }

        let compact = trimmed.replacingOccurrences(of: " ", with: "")
        let exact = compact.trimmingCharacters(
            in: CharacterSet.punctuationCharacters.union(.symbols)
        )
        if ["继续", "推进", "下一步"].contains(exact) {
            return true
        }

        let directTokens = [
            "继续推进",
            "继续执行",
            "自动继续",
            "自动推进",
            "按当前记忆继续推进",
            "按当前记忆继续",
            "继续这个项目",
            "继续当前项目",
            "继续该项目",
            "继续这个任务",
            "继续当前任务",
            "推进这个项目",
            "推进当前项目",
            "推进该项目",
            "继续下一步",
            "开始下一步"
        ]
        if directTokens.contains(where: { compact.contains($0) }) {
            return true
        }

        let continuationVerbs = ["继续", "推进", "接着", "下一步", "followup", "continue"]
        let scopeTokens = [
            "项目",
            "当前项目",
            "这个项目",
            "该项目",
            "任务",
            "当前任务",
            "这个任务",
            "workflow",
            "plan",
            "记忆",
            "上下文"
        ]
        let hasVerb = continuationVerbs.contains(where: { compact.contains($0) })
        let hasScope = scopeTokens.contains(where: { compact.contains($0) })
        return hasVerb && hasScope
    }

    private func processCreateJobCommand(
        in text: String,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource
    ) -> String {
        guard let payload = firstTagContent(in: text, tag: "CREATE_JOB"), !payload.isEmpty else {
            return text
        }

        switch decodeSupervisorJSONPayload(payload, as: SupervisorCreateJobPayload.self) {
        case .success(let command):
            let result = createSupervisorJob(
                from: command,
                userMessage: userMessage,
                triggerSource: triggerSource
            )
            _ = appendActionLedger(
                action: "create_job",
                targetRef: (command.projectRef ?? "").trimmingCharacters(in: .whitespacesAndNewlines),
                projectId: result.projectId,
                projectName: result.projectName,
                role: nil,
                modelId: nil,
                status: result.ok ? "ok" : "failed",
                reasonCode: result.reasonCode,
                detail: result.message,
                verifiedAt: result.ok ? Date().timeIntervalSince1970 : nil,
                triggerSource: triggerSource.rawValue
            )
            return replacingTaggedSection(
                in: text,
                tag: "CREATE_JOB",
                with: result.message
            )
        case .failure(let error):
            let reason = error.message
            _ = appendActionLedger(
                action: "create_job",
                targetRef: "(invalid_json)",
                projectId: nil,
                projectName: nil,
                role: nil,
                modelId: nil,
                status: "failed",
                reasonCode: "invalid_create_job_format",
                detail: reason,
                verifiedAt: nil,
                triggerSource: triggerSource.rawValue
            )
            return replacingTaggedSection(
                in: text,
                tag: "CREATE_JOB",
                with: "❌ CREATE_JOB 标签解析失败：\(reason)"
            )
        }
    }

