    private func decodeSupervisorJSONPayload<T: Decodable>(
        _ payload: String,
        as type: T.Type
    ) -> Result<T, SupervisorJSONPayloadDecodeError> {
        guard let data = payload.data(using: .utf8) else {
            return .failure(SupervisorJSONPayloadDecodeError(message: "payload 不是合法 UTF-8 文本"))
        }
        let decoder = JSONDecoder()
        do {
            return .success(try decoder.decode(type, from: data))
        } catch {
            return .failure(
                SupervisorJSONPayloadDecodeError(
                    message: "body 必须是单个 JSON object：\(error.localizedDescription)"
                )
            )
        }
    }

    private func decodeSupervisorJSONObject(
        _ payload: String
    ) -> Result<[String: Any], SupervisorJSONPayloadDecodeError> {
        guard let data = payload.data(using: .utf8) else {
            return .failure(SupervisorJSONPayloadDecodeError(message: "payload 不是合法 UTF-8 文本"))
        }
        do {
            let object = try JSONSerialization.jsonObject(with: data)
            guard let dictionary = object as? [String: Any] else {
                return .failure(SupervisorJSONPayloadDecodeError(message: "body 必须是单个 JSON object"))
            }
            return .success(dictionary)
        } catch {
            return .failure(
                SupervisorJSONPayloadDecodeError(
                    message: "body 必须是单个 JSON object：\(error.localizedDescription)"
                )
            )
        }
    }

    private func createSupervisorJob(
        from payload: SupervisorCreateJobPayload,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource,
        emitSystemMessage: Bool = true
    ) -> (ok: Bool, reasonCode: String, message: String, projectId: String?, projectName: String?, jobId: String?) {
        let goal = payload.goal.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !goal.isEmpty else {
            let message = "❌ CREATE_JOB 失败：goal 不能为空（goal_missing）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "goal_missing", message, nil, nil, nil)
        }

        let scope: SupervisorProjectScopeResolution
        switch resolveSupervisorProjectScope(
            projectRef: payload.projectRef,
            commandName: "CREATE_JOB",
            userMessage: userMessage,
            triggerSource: triggerSource
        ) {
        case .failure(let failure):
            if emitSystemMessage { addSystemMessage(failure.message) }
            return (false, failure.reasonCode, failure.message, failure.projectId, failure.projectName, nil)
        case .success(let resolved):
            scope = resolved
        }

        let now = Date()
        let nowMs = Int64((now.timeIntervalSince1970 * 1000.0).rounded())
        let jobId = "job-\(nowMs)-\(String(UUID().uuidString.lowercased().prefix(8)))"
        let auditRef = "audit-xt-supervisor-job-\(String(jobId.suffix(12)))"
        let source = SupervisorJobSource.parse(payload.source, fallback: triggerSource.defaultJobSource)
        let owner = (payload.currentOwner ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let record = SupervisorJobRecord(
            schemaVersion: SupervisorJobRecord.currentSchemaVersion,
            jobId: jobId,
            projectId: scope.project.projectId,
            goal: goal,
            priority: SupervisorJobPriority.parse(payload.priority),
            status: .queued,
            source: source,
            currentOwner: owner.isEmpty ? "supervisor" : owner,
            activePlanId: "",
            createdAtMs: nowMs,
            updatedAtMs: nowMs,
            auditRef: auditRef
        )

        do {
            try SupervisorProjectJobStore.append(record, for: scope.ctx)
        } catch {
            let message = "❌ CREATE_JOB 失败：任务落盘失败（job_store_write_failed: \(error.localizedDescription))"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "job_store_write_failed", message, scope.project.projectId, scope.project.displayName, nil)
        }

        AXProjectStore.appendRawLog(
            [
                "type": "supervisor_job",
                "action": "create",
                "schema_version": SupervisorJobRecord.currentSchemaVersion,
                "job_id": record.jobId,
                "project_id": record.projectId,
                "goal": record.goal,
                "priority": record.priority.rawValue,
                "status": record.status.rawValue,
                "source": record.source.rawValue,
                "current_owner": record.currentOwner,
                "trigger_source": triggerSource.rawValue,
                "audit_ref": record.auditRef,
                "timestamp_ms": record.updatedAtMs
            ],
            for: scope.ctx
        )
        currentTask = SupervisorTask(
            id: record.jobId,
            projectId: record.projectId,
            title: record.goal,
            status: record.status.rawValue,
            createdAt: now.timeIntervalSince1970
        )
        syncSupervisorProjectWorkflowCanonical(
            ctx: scope.ctx,
            project: scope.project
        )

        let message = "✅ 已为项目 \(scope.project.displayName) 创建任务：\(record.goal)（priority=\(record.priority.rawValue)）"
        if emitSystemMessage { addSystemMessage(message) }
        return (true, "ok", message, scope.project.projectId, scope.project.displayName, record.jobId)
    }

    private func upsertSupervisorPlan(
        from payload: SupervisorUpsertPlanPayload,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource,
        emitSystemMessage: Bool = true
    ) -> (ok: Bool, reasonCode: String, message: String, projectId: String?, projectName: String?) {
        let planId = payload.planId.trimmingCharacters(in: .whitespacesAndNewlines)
        let jobId = payload.jobId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !planId.isEmpty else {
            let message = "❌ UPSERT_PLAN 失败：plan_id 不能为空（plan_id_missing）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "plan_id_missing", message, nil, nil)
        }
        guard !jobId.isEmpty else {
            let message = "❌ UPSERT_PLAN 失败：job_id 不能为空（job_id_missing）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "job_id_missing", message, nil, nil)
        }
        guard !payload.steps.isEmpty else {
            let message = "❌ UPSERT_PLAN 失败：steps 不能为空（steps_missing）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "steps_missing", message, nil, nil)
        }

        let scope: SupervisorProjectScopeResolution
        switch resolveSupervisorProjectScope(
            projectRef: payload.projectRef,
            commandName: "UPSERT_PLAN",
            userMessage: userMessage,
            triggerSource: triggerSource
        ) {
        case .failure(let failure):
            if emitSystemMessage { addSystemMessage(failure.message) }
            return (false, failure.reasonCode, failure.message, failure.projectId, failure.projectName)
        case .success(let resolved):
            scope = resolved
        }

        let jobSnapshot = SupervisorProjectJobStore.load(for: scope.ctx)
        guard var job = jobSnapshot.jobs.first(where: { $0.jobId == jobId }) else {
            let message = "❌ UPSERT_PLAN 失败：找不到 job_id \(jobId)（job_not_found）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "job_not_found", message, scope.project.projectId, scope.project.displayName)
        }

        guard job.projectId == scope.project.projectId else {
            let message = "❌ UPSERT_PLAN 失败：job 与当前 project scope 不一致（job_project_scope_mismatch）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "job_project_scope_mismatch", message, scope.project.projectId, scope.project.displayName)
        }

        let now = Date()
        let nowMs = Int64((now.timeIntervalSince1970 * 1000.0).rounded())
        let previousPlanSnapshot = SupervisorProjectPlanStore.load(for: scope.ctx)
        let existingPlan = previousPlanSnapshot.plans.first(where: { $0.planId == planId })
        let owner = (payload.currentOwner ?? job.currentOwner)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let resolvedGovernance = resolvedSupervisorProjectGovernanceState(
            projectId: scope.project.projectId,
            ctx: scope.ctx
        )
        let supervisorAdaptation = resolvedGovernance?.supervisorAdaptation
        let effectiveWorkOrderDepth = supervisorAdaptation?.effectiveWorkOrderDepth ?? .none
        let allowConciseExecutionReadyPlan = supervisorExecutionReadyPlanCanStayConcise(
            payload.steps,
            adaptation: supervisorAdaptation
        )
        let registrySnapshot = AXSkillsLibrary.supervisorSkillRegistrySnapshot(
            projectId: scope.project.projectId,
            projectName: scope.project.displayName,
            hubBaseDir: HubPaths.baseDir()
        )
        var planNormalizationNotes: [String] = []
        var previousStepID: String?
        var steps: [SupervisorPlanStepRecord] = []

        for (index, step) in payload.steps.enumerated() {
            let title = step.title.trimmingCharacters(in: .whitespacesAndNewlines)
            let stepId = step.stepId.trimmingCharacters(in: .whitespacesAndNewlines)
            let resolvedTitle = title.isEmpty ? "step-\(index + 1)" : title
            var seenDependencies = Set<String>()
            var dependsOn = (step.dependsOn ?? []).compactMap { raw -> String? in
                let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
                guard !trimmed.isEmpty else { return nil }
                guard seenDependencies.insert(trimmed).inserted else { return nil }
                return trimmed
            }
            if effectiveWorkOrderDepth == .stepLockedRescue,
               dependsOn.isEmpty,
               let previousStepID,
               !previousStepID.isEmpty,
               index > 0 {
                dependsOn = [previousStepID]
                planNormalizationNotes.append("auto_chain:\(stepId.isEmpty ? resolvedTitle : stepId)->\(previousStepID)")
            }

            let currentOwner = (step.currentOwner ?? owner).trimmingCharacters(in: .whitespacesAndNewlines)
            let rawDetail = (step.detail ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let detailNormalization = normalizedSupervisorPlanStepDetail(
                rawDetail: rawDetail,
                resolvedTitle: resolvedTitle,
                payloadStep: step,
                dependsOn: dependsOn,
                effectiveWorkOrderDepth: effectiveWorkOrderDepth,
                allowConciseExecutionReadyPlan: allowConciseExecutionReadyPlan
            )
            let detail = detailNormalization.detail
            if let normalizationNote = detailNormalization.normalizationNote {
                planNormalizationNotes.append(
                    "\(normalizationNote):\(stepId.isEmpty ? resolvedTitle : stepId)"
                )
            }
            let requestedSkillId = (step.skillId ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            let normalizedSkillId = effectiveSupervisorSkillID(
                requestedSkillId: requestedSkillId,
                projectId: scope.project.projectId,
                projectName: scope.project.displayName,
                registrySnapshot: registrySnapshot
            )
            if !requestedSkillId.isEmpty, requestedSkillId != normalizedSkillId {
                planNormalizationNotes.append(
                    "preferred_builtin_skill:\(stepId.isEmpty ? resolvedTitle : stepId)->\(normalizedSkillId)"
                )
            }

            let record = SupervisorPlanStepRecord(
                schemaVersion: SupervisorPlanStepRecord.currentSchemaVersion,
                stepId: stepId,
                title: resolvedTitle,
                kind: SupervisorPlanStepKind.parse(step.kind),
                status: SupervisorPlanStepStatus.parse(step.status),
                skillId: normalizedSkillId,
                currentOwner: currentOwner.isEmpty
                    ? "supervisor"
                    : currentOwner,
                detail: detail,
                dependsOn: dependsOn.isEmpty ? nil : dependsOn,
                timeoutMs: step.timeoutMs.map { max(0, $0) },
                maxRetries: step.maxRetries.map { max(0, $0) },
                failurePolicy: SupervisorPlanStepFailurePolicy.parse(step.failurePolicy),
                orderIndex: index,
                updatedAtMs: nowMs
            )
            steps.append(record)
            if !stepId.isEmpty {
                previousStepID = stepId
            }
        }
        guard steps.allSatisfy({ !$0.stepId.isEmpty }) else {
            let message = "❌ UPSERT_PLAN 失败：steps.step_id 不能为空（step_id_missing）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "step_id_missing", message, scope.project.projectId, scope.project.displayName)
        }
        if effectiveWorkOrderDepth == .stepLockedRescue, steps.count < 2 {
            let message = "❌ UPSERT_PLAN 失败：当前项目处于 step_locked_rescue，计划至少需要 2 个步骤（step_locked_rescue_requires_multiple_steps）"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "step_locked_rescue_requires_multiple_steps", message, scope.project.projectId, scope.project.displayName)
        }

        let planStatus = derivedPlanStatus(from: steps)
        let plan = SupervisorPlanRecord(
            schemaVersion: SupervisorPlanRecord.currentSchemaVersion,
            planId: planId,
            jobId: jobId,
            projectId: scope.project.projectId,
            status: planStatus,
            currentOwner: owner.isEmpty ? "supervisor" : owner,
            steps: steps,
            createdAtMs: existingPlan?.createdAtMs ?? nowMs,
            updatedAtMs: nowMs,
            auditRef: existingPlan?.auditRef ?? "audit-xt-supervisor-plan-\(String(planId.suffix(12)))"
        )

        do {
            try SupervisorProjectPlanStore.upsert(plan, for: scope.ctx)
        } catch {
            let message = "❌ UPSERT_PLAN 失败：计划落盘失败（plan_store_write_failed: \(error.localizedDescription))"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "plan_store_write_failed", message, scope.project.projectId, scope.project.displayName)
        }

        job.activePlanId = plan.planId
        job.status = derivedJobStatus(from: plan)
        job.currentOwner = plan.currentOwner
        job.updatedAtMs = nowMs
        do {
            try SupervisorProjectJobStore.upsert(job, for: scope.ctx)
        } catch {
            let message = "❌ UPSERT_PLAN 失败：任务状态更新失败（job_store_write_failed: \(error.localizedDescription))"
            if emitSystemMessage { addSystemMessage(message) }
            return (false, "job_store_write_failed", message, scope.project.projectId, scope.project.displayName)
        }

        AXProjectStore.appendRawLog(
            [
                "type": "supervisor_plan",
                "action": existingPlan == nil ? "create" : "upsert",
                "schema_version": SupervisorPlanRecord.currentSchemaVersion,
                "plan_id": plan.planId,
                "job_id": plan.jobId,
                "project_id": plan.projectId,
                "status": plan.status.rawValue,
                "step_count": plan.steps.count,
                "effective_supervisor_tier": supervisorAdaptation?.effectiveSupervisorTier.rawValue ?? "",
                "effective_work_order_depth": effectiveWorkOrderDepth.rawValue,
                "project_ai_strength_band": supervisorAdaptation?.projectAIStrengthProfile?.strengthBand.rawValue ?? AXProjectAIStrengthBand.unknown.rawValue,
                "project_ai_strength_confidence": supervisorAdaptation?.projectAIStrengthProfile?.confidence ?? 0,
                "project_ai_strength_audit_ref": supervisorAdaptation?.projectAIStrengthProfile?.auditRef ?? "",
                "plan_normalization_notes": planNormalizationNotes,
                "trigger_source": triggerSource.rawValue,
                "audit_ref": plan.auditRef,
                "timestamp_ms": plan.updatedAtMs
            ],
            for: scope.ctx
        )
        currentTask = SupervisorTask(
            id: job.jobId,
            projectId: job.projectId,
            title: job.goal,
            status: job.status.rawValue,
            createdAt: Double(job.createdAtMs) / 1000.0
        )
        syncSupervisorProjectWorkflowCanonical(
            ctx: scope.ctx,
            project: scope.project
        )

        let normalizationSuffix = planNormalizationNotes.isEmpty
            ? ""
            : "；auto_normalized=\(capped(planNormalizationNotes.joined(separator: ", "), maxChars: 120))"
        let message = "✅ 已为项目 \(scope.project.displayName) 写入计划：\(plan.planId)（job=\(plan.jobId), steps=\(plan.steps.count), depth=\(effectiveWorkOrderDepth.rawValue)）\(normalizationSuffix)"
        if emitSystemMessage { addSystemMessage(message) }
        return (true, "ok", message, scope.project.projectId, scope.project.displayName)
    }

    private func normalizedSupervisorPlanStepDetail(
        rawDetail: String,
        resolvedTitle: String,
        payloadStep: SupervisorUpsertPlanStepPayload,
        dependsOn: [String],
        effectiveWorkOrderDepth: AXProjectSupervisorWorkOrderDepth,
        allowConciseExecutionReadyPlan: Bool
    ) -> (detail: String, normalizationNote: String?) {
        guard rawDetail.isEmpty else {
            return (rawDetail, nil)
        }

        if effectiveWorkOrderDepth == .stepLockedRescue {
            return (resolvedTitle, "detail_from_title")
        }

        guard effectiveWorkOrderDepth >= .executionReady else {
            return ("", nil)
        }

        if allowConciseExecutionReadyPlan,
           supervisorExecutionReadyStepCanStayConcise(
                payloadStep: payloadStep,
                resolvedTitle: resolvedTitle,
                dependsOn: dependsOn
           ) {
            return ("", nil)
        }

        return (resolvedTitle, "detail_from_title")
    }

    private func supervisorExecutionReadyPlanCanStayConcise(
        _ steps: [SupervisorUpsertPlanStepPayload],
        adaptation: AXProjectSupervisorAdaptationSnapshot?
    ) -> Bool {
        guard adaptation?.effectiveWorkOrderDepth == .executionReady else { return false }
        guard let strengthBand = adaptation?.projectAIStrengthProfile?.strengthBand,
              strengthBand >= .capable else {
            return false
        }
        guard !steps.isEmpty else { return false }

        let specificStepCount = steps.filter {
            supervisorExecutionReadyStepTitleLooksSpecific($0.title)
        }.count
        guard specificStepCount == steps.count else { return false }

        return steps.count >= 2 || steps.contains { step in
            supervisorExecutionReadyStepCarriesStructuredSignal(step)
        }
    }

    private func supervisorExecutionReadyStepCanStayConcise(
        payloadStep: SupervisorUpsertPlanStepPayload,
        resolvedTitle: String,
        dependsOn: [String]
    ) -> Bool {
        guard supervisorExecutionReadyStepTitleLooksSpecific(resolvedTitle) else { return false }

        if !dependsOn.isEmpty {
            return true
        }

        if supervisorExecutionReadyStepCarriesStructuredSignal(payloadStep) {
            return true
        }

        let kind = SupervisorPlanStepKind.parse(payloadStep.kind)
        return kind != .unknown
    }

    private func supervisorExecutionReadyStepCarriesStructuredSignal(
        _ step: SupervisorUpsertPlanStepPayload
    ) -> Bool {
        let skillId = (step.skillId ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let failurePolicy = (step.failurePolicy ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let dependsOn = (step.dependsOn ?? []).contains {
            !$0.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        }
        return !skillId.isEmpty ||
            dependsOn ||
            step.timeoutMs != nil ||
            step.maxRetries != nil ||
            !failurePolicy.isEmpty
    }

    private func supervisorExecutionReadyStepTitleLooksSpecific(
        _ rawTitle: String
    ) -> Bool {
        let trimmed = rawTitle.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.count >= 5 else { return false }

        let lowered = trimmed.lowercased()
        let genericExact = Set([
            "step",
            "todo",
            "task",
            "next step",
            "follow up",
            "follow-up",
            "继续推进",
            "继续当前路径",
            "补计划",
            "处理问题",
            "修一下",
            "做一下",
        ])
        if genericExact.contains(lowered) {
            return false
        }
        if lowered.hasPrefix("step ") || lowered.hasPrefix("todo ") || lowered.hasPrefix("task ") {
            return false
        }
        return true
    }

    private struct SupervisorProjectScopeResolution {
        var project: AXProjectEntry
        var ctx: AXProjectContext
    }

    private struct SupervisorWorkflowStepResolution {
        var project: AXProjectEntry
        var ctx: AXProjectContext
        var job: SupervisorJobRecord
        var plan: SupervisorPlanRecord
        var stepIndex: Int
        var step: SupervisorPlanStepRecord
    }

    private struct SupervisorSkillCallResolution {
        var project: AXProjectEntry
        var ctx: AXProjectContext
        var record: SupervisorSkillCallRecord
    }

    private struct SupervisorMappedSkillDispatch {
        var toolCall: ToolCall
        var toolName: String
    }

    private struct SupervisorCommandResolutionFailure: Error {
        var reasonCode: String
        var message: String
        var projectId: String?
        var projectName: String?
    }

    private struct SupervisorSkillMappingFailure: Error {
        var reasonCode: String
    }

    private func resolveSupervisorProjectScope(
        projectRef: String?,
        commandName: String,
        userMessage: String? = nil,
        triggerSource: SupervisorCommandTriggerSource = .userTurn
    ) -> Result<SupervisorProjectScopeResolution, SupervisorCommandResolutionFailure> {
        guard let appModel else {
            return .failure(
                SupervisorCommandResolutionFailure(
                    reasonCode: "app_model_unavailable",
                    message: "❌ \(commandName) 失败：Supervisor 未初始化（app_model_unavailable）",
                    projectId: nil,
                    projectName: nil
                )
            )
        }

        let projects = projectsForTriggerSource(triggerSource)
        let lookup = resolvedSupervisorProjectLookup(
            projectRef: projectRef,
            projects: projects,
            userMessage: userMessage,
            triggerSource: triggerSource
        )
        if lookup.projectScopeMissing {
            return .failure(
                SupervisorCommandResolutionFailure(
                    reasonCode: "project_scope_missing",
                    message: "❌ \(commandName) 失败：当前项目范围不唯一，请补 project_ref（project_scope_missing）",
                    projectId: nil,
                    projectName: nil
                )
            )
        }

        let project: AXProjectEntry
        switch lookup.resolution ?? .notFound {
        case .matched(let matched):
            project = matched
        case .notFound:
            let hints = projects.prefix(4).map { $0.displayName }.joined(separator: "、")
            let suffix = hints.isEmpty ? "" : "。可用项目：\(hints)"
            return .failure(
                SupervisorCommandResolutionFailure(
                    reasonCode: "project_not_found",
                    message: "❌ \(commandName) 失败：找不到项目引用 \(lookup.requestedRef.isEmpty ? "(empty)" : lookup.requestedRef)（project_not_found）\(suffix)",
                    projectId: nil,
                    projectName: nil
                )
            )
        case .ambiguous(let candidates):
            let list = candidates.prefix(4).map { "\($0.displayName)(\($0.projectId))" }.joined(separator: "、")
            return .failure(
                SupervisorCommandResolutionFailure(
                    reasonCode: "project_ambiguous",
                    message: "❌ \(commandName) 失败：项目引用不唯一（project_ambiguous）。候选：\(list)",
                    projectId: nil,
                    projectName: nil
                )
            )
        }

        guard let ctx = appModel.projectContext(for: project.projectId) else {
            return .failure(
                SupervisorCommandResolutionFailure(
                    reasonCode: "project_context_missing",
                    message: "❌ \(commandName) 失败：项目上下文不可用（project_context_missing）",
                    projectId: project.projectId,
                    projectName: project.displayName
                )
            )
        }
        return .success(SupervisorProjectScopeResolution(project: project, ctx: ctx))
    }

    private func resolveSupervisorWorkflowStep(
        projectRef: String?,
        jobId: String,
        stepId: String,
        skillId: String,
        commandName: String,
        userMessage: String? = nil,
        triggerSource: SupervisorCommandTriggerSource = .userTurn
    ) -> Result<SupervisorWorkflowStepResolution, SupervisorCommandResolutionFailure> {
        switch resolveSupervisorProjectScope(
            projectRef: projectRef,
            commandName: commandName,
            userMessage: userMessage,
            triggerSource: triggerSource
        ) {
        case .failure(let failure):
            return .failure(failure)
        case .success(let scope):
            guard let job = SupervisorProjectJobStore.load(for: scope.ctx).jobs.first(where: { $0.jobId == jobId }) else {
                return .failure(
                    SupervisorCommandResolutionFailure(
                        reasonCode: "job_not_found",
                        message: "❌ \(commandName) 失败：找不到 job_id \(jobId)（job_not_found）",
                        projectId: scope.project.projectId,
                        projectName: scope.project.displayName
                    )
                )
            }

            let plans = SupervisorProjectPlanStore.load(for: scope.ctx).plans
                .filter { $0.jobId == jobId }
                .sorted { lhs, rhs in
                    let leftActive = lhs.planId == job.activePlanId ? 0 : 1
                    let rightActive = rhs.planId == job.activePlanId ? 0 : 1
                    if leftActive != rightActive {
                        return leftActive < rightActive
                    }
                    if lhs.updatedAtMs != rhs.updatedAtMs {
                        return lhs.updatedAtMs > rhs.updatedAtMs
                    }
                    return lhs.planId > rhs.planId
                }
            guard let plan = plans.first(where: { plan in
                plan.steps.contains(where: { $0.stepId == stepId })
            }) else {
                return .failure(
                    SupervisorCommandResolutionFailure(
                        reasonCode: "step_not_found",
                        message: "❌ \(commandName) 失败：找不到 step_id \(stepId)（step_not_found）",
                        projectId: scope.project.projectId,
                        projectName: scope.project.displayName
                    )
                )
            }
            guard let stepIndex = plan.steps.firstIndex(where: { $0.stepId == stepId }) else {
                return .failure(
                    SupervisorCommandResolutionFailure(
                        reasonCode: "step_not_found",
                        message: "❌ \(commandName) 失败：找不到 step_id \(stepId)（step_not_found）",
                        projectId: scope.project.projectId,
                        projectName: scope.project.displayName
                    )
                )
            }
            let step = plan.steps[stepIndex]
            let expectedSkillId = step.skillId.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines)
            if !expectedSkillId.isEmpty,
               !supervisorWorkflowSkillIDsAreCompatible(
                    expectedSkillId: expectedSkillId,
                    requestedSkillId: skillId
               ) {
                return .failure(
                    SupervisorCommandResolutionFailure(
                        reasonCode: "step_skill_mismatch",
                        message: "❌ \(commandName) 失败：step 绑定 skill_id=\(expectedSkillId)，与请求 skill_id=\(skillId) 不一致（step_skill_mismatch）",
                        projectId: scope.project.projectId,
                        projectName: scope.project.displayName
                    )
                )
            }
            return .success(
                SupervisorWorkflowStepResolution(
                    project: scope.project,
                    ctx: scope.ctx,
                    job: job,
                    plan: plan,
                    stepIndex: stepIndex,
                    step: step
                )
            )
        }
    }

    private func locateSupervisorSkillCall(
        requestId: String,
        projectRef: String?,
        commandName: String,
        userMessage: String? = nil,
        triggerSource: SupervisorCommandTriggerSource = .userTurn
    ) -> Result<SupervisorSkillCallResolution, SupervisorCommandResolutionFailure> {
        guard let appModel else {
            return .failure(
                SupervisorCommandResolutionFailure(
                    reasonCode: "app_model_unavailable",
                    message: "❌ \(commandName) 失败：Supervisor 未初始化（app_model_unavailable）",
                    projectId: nil,
                    projectName: nil
                )
            )
        }

        let normalizedRequestId = requestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedRequestId.isEmpty else {
            return .failure(
                SupervisorCommandResolutionFailure(
                    reasonCode: "request_id_missing",
                    message: "❌ \(commandName) 失败：request_id 不能为空（request_id_missing）",
                    projectId: nil,
                    projectName: nil
                )
            )
        }

        let hasExplicitScope = !(projectRef?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true)
        let hasFallbackScope = supervisorFallbackProjectReference(
            userMessage: userMessage,
            triggerSource: triggerSource
        ) != nil
        if hasExplicitScope || hasFallbackScope {
            switch resolveSupervisorProjectScope(
                projectRef: projectRef,
                commandName: commandName,
                userMessage: userMessage,
                triggerSource: triggerSource
            ) {
            case .failure(let failure):
                return .failure(failure)
            case .success(let scope):
                let snapshot = SupervisorProjectSkillCallStore.load(for: scope.ctx)
                guard let record = snapshot.calls.first(where: { $0.requestId == normalizedRequestId }) else {
                    return .failure(
                        SupervisorCommandResolutionFailure(
                            reasonCode: "request_not_found",
                            message: "❌ \(commandName) 失败：找不到 request_id \(normalizedRequestId)（request_not_found）",
                            projectId: scope.project.projectId,
                            projectName: scope.project.displayName
                        )
                    )
                }
                return .success(SupervisorSkillCallResolution(project: scope.project, ctx: scope.ctx, record: record))
            }
        }

        let projects = projectsForTriggerSource(triggerSource)
        for project in projects {
            guard let ctx = appModel.projectContext(for: project.projectId) else { continue }
            let snapshot = SupervisorProjectSkillCallStore.load(for: ctx)
            if let record = snapshot.calls.first(where: { $0.requestId == normalizedRequestId }) {
                return .success(SupervisorSkillCallResolution(project: project, ctx: ctx, record: record))
            }
        }

        return .failure(
            SupervisorCommandResolutionFailure(
                reasonCode: "request_not_found",
                message: "❌ \(commandName) 失败：找不到 request_id \(normalizedRequestId)（request_not_found）",
                projectId: nil,
                projectName: nil
            )
        )
    }

    private func callSupervisorSkill(
        from payload: SupervisorCallSkillPayload,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource
    ) -> (ok: Bool, reasonCode: String, message: String, projectId: String?, projectName: String?) {
        let jobId = payload.jobId.trimmingCharacters(in: .whitespacesAndNewlines)
        let stepId = payload.stepId.trimmingCharacters(in: .whitespacesAndNewlines)
        let requestedSkillId = payload.skillId.trimmingCharacters(in: .whitespacesAndNewlines)
        let canonicalRequestedSkillId = AXSkillsLibrary.canonicalSupervisorSkillID(requestedSkillId)
        guard !jobId.isEmpty else {
            let message = "❌ CALL_SKILL 失败：job_id 不能为空（job_id_missing）"
            addSystemMessage(message)
            return (false, "job_id_missing", message, nil, nil)
        }
        guard !stepId.isEmpty else {
            let message = "❌ CALL_SKILL 失败：step_id 不能为空（step_id_missing）"
            addSystemMessage(message)
            return (false, "step_id_missing", message, nil, nil)
        }
        guard !canonicalRequestedSkillId.isEmpty else {
            let message = "❌ CALL_SKILL 失败：skill_id 不能为空（skill_id_missing）"
            addSystemMessage(message)
            return (false, "skill_id_missing", message, nil, nil)
        }

        let workflow: SupervisorWorkflowStepResolution
        switch resolveSupervisorWorkflowStep(
            projectRef: payload.projectRef,
            jobId: jobId,
            stepId: stepId,
            skillId: requestedSkillId,
            commandName: "CALL_SKILL",
            userMessage: userMessage,
            triggerSource: triggerSource
        ) {
        case .failure(let failure):
            addSystemMessage(failure.message)
            return (false, failure.reasonCode, failure.message, failure.projectId, failure.projectName)
        case .success(let resolved):
            workflow = resolved
        }

        guard let registrySnapshot = AXSkillsLibrary.supervisorSkillRegistrySnapshot(
            projectId: workflow.project.projectId,
            projectName: workflow.project.displayName,
            hubBaseDir: HubPaths.baseDir()
        ) else {
            let message = "❌ CALL_SKILL 失败：Hub skill registry 当前不可用（skill_registry_unavailable）"
            addSystemMessage(message)
            return (false, "skill_registry_unavailable", message, workflow.project.projectId, workflow.project.displayName)
        }
        warmResolvedSkillsCacheIfPossible(for: workflow.project)
        let effectiveSkillId = effectiveSupervisorSkillID(
            requestedSkillId: requestedSkillId,
            projectId: workflow.project.projectId,
            projectName: workflow.project.displayName,
            registrySnapshot: registrySnapshot
        )
        let payloadObject = normalizedSupervisorSkillPayload(
            requestedSkillId: requestedSkillId,
            effectiveSkillId: effectiveSkillId,
            payload: payload.payload ?? [:]
        )
        let routedRequestedSkillId = requestedSkillId == effectiveSkillId ? nil : requestedSkillId
        let routingResolution = SupervisorSkillRoutingCompatibilityHint.routingResolution(
            requestedSkillId: routedRequestedSkillId,
            effectiveSkillId: effectiveSkillId,
            payload: payloadObject,
            registryItems: registrySnapshot.items
        )
        let displaySkill = supervisorSkillDisplaySummary(
            requestedSkillId: routedRequestedSkillId,
            effectiveSkillId: effectiveSkillId,
            payload: payloadObject
        )
        guard let registryItem = registrySnapshot.items.first(where: {
            AXSkillsLibrary.canonicalSupervisorSkillID($0.skillId) == effectiveSkillId
        }) else {
            let message = "❌ CALL_SKILL 失败：技能 \(displaySkill) 不在当前 project scope 的 Hub registry 中（skill_not_registered）"
            addSystemMessage(message)
            return (false, "skill_not_registered", message, workflow.project.projectId, workflow.project.displayName)
        }

        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        let requestId = "skill-\(nowMs)-\(String(UUID().uuidString.lowercased().prefix(8)))"
        let owner = workflow.step.currentOwner.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? (workflow.job.currentOwner.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? "supervisor" : workflow.job.currentOwner)
            : workflow.step.currentOwner

        let mapped: SupervisorMappedSkillDispatch
        switch mapSupervisorSkillToToolCall(
            skillId: effectiveSkillId,
            payload: payloadObject,
            requestId: requestId,
            projectId: workflow.project.projectId,
            projectName: workflow.project.displayName,
            registryItem: registryItem
        ) {
        case .success(let dispatch):
            mapped = dispatch
        case .failure(let failure):
            let blockedSummary = supervisorSkillMappingFailureSummary(failure)
            let blockedDenyCode = failure.reasonCode == "unsupported_skill_id"
                ? "skill_mapping_missing"
                : failure.reasonCode
            var blocked = SupervisorSkillCallRecord(
                schemaVersion: SupervisorSkillCallRecord.currentSchemaVersion,
                requestId: requestId,
                projectId: workflow.project.projectId,
                jobId: workflow.job.jobId,
                planId: workflow.plan.planId,
                stepId: workflow.step.stepId,
                skillId: effectiveSkillId,
                requestedSkillId: routedRequestedSkillId,
                routingReasonCode: routingResolution?.reasonCode,
                routingExplanation: routingResolution?.explanation,
                toolName: "",
                status: .blocked,
                payload: payloadObject,
                currentOwner: owner,
                resultSummary: blockedSummary,
                denyCode: blockedDenyCode,
                resultEvidenceRef: nil,
                requiredCapability: nil,
                grantRequestId: nil,
                grantId: nil,
                createdAtMs: nowMs,
                updatedAtMs: nowMs,
                auditRef: "audit-xt-supervisor-skill-\(String(requestId.suffix(12)))"
            )
            blocked.resultEvidenceRef = SupervisorSkillResultEvidenceStore.write(
                record: blocked,
                toolCall: nil,
                rawOutput: nil,
                triggerSource: triggerSource.rawValue,
                ctx: workflow.ctx
            )
            try? SupervisorProjectSkillCallStore.upsert(blocked, for: workflow.ctx)
            _ = updateSupervisorWorkflowStepState(
                ctx: workflow.ctx,
                project: workflow.project,
                jobId: workflow.job.jobId,
                planId: workflow.plan.planId,
                stepId: workflow.step.stepId,
                status: .blocked,
                detail: blocked.resultSummary,
                owner: blocked.currentOwner,
                updatedAtMs: nowMs
            )
            appendSupervisorSkillCallRawLog(
                action: "blocked",
                record: blocked,
                toolCall: nil,
                triggerSource: triggerSource,
                ctx: workflow.ctx
            )
            appendSupervisorSkillResultRawLog(
                record: blocked,
                toolCall: nil,
                rawOutput: nil,
                triggerSource: triggerSource,
                ctx: workflow.ctx
            )
            appendRecentEvent("skill_result: \(workflow.project.displayName) -> \(blocked.skillId) \(blocked.status.rawValue)")
            let message = supervisorSkillMappingFailureMessage(displaySkill: displaySkill, failure: failure)
            addSystemMessage(message)
            return (false, blockedDenyCode, message, workflow.project.projectId, workflow.project.displayName)
        }

        let requiredCapability = supervisorRequiredHubCapability(for: mapped.toolCall)
        let projectConfig = (try? AXProjectStore.loadOrCreateConfig(for: workflow.ctx))
            ?? .default(forProjectRoot: workflow.ctx.root)
        let requiresGrant = registryItem.requiresGrant || requiredCapability != nil
        let canBypassLocalGrantWait =
            requiredCapability == nil &&
            xtProjectGovernedAutoApprovalConfigured(
                projectRoot: workflow.ctx.root,
                config: projectConfig
            ) &&
            !ToolPolicy.isAlwaysConfirm(call: mapped.toolCall)
        let requiresWaitingAuthorization =
            requiresGrant &&
            !supervisorToolCallHasExplicitGrant(mapped.toolCall) &&
            !canBypassLocalGrantWait
        let awaitingResultSummary: String = {
            guard requiresWaitingAuthorization else { return "queued governed dispatch" }
            if let requiredCapability, !requiredCapability.isEmpty {
                return XTHubGrantPresentation.awaitingStateSummary(
                    capability: requiredCapability,
                    modelId: "",
                    grantRequestId: nil
                )
            }
            return "waiting for local governed approval"
        }()
        let awaitingDenyCode: String = {
            guard requiresWaitingAuthorization else { return "" }
            if let requiredCapability, !requiredCapability.isEmpty {
                return "grant_required"
            }
            return "local_approval_required"
        }()
        var record = SupervisorSkillCallRecord(
            schemaVersion: SupervisorSkillCallRecord.currentSchemaVersion,
            requestId: requestId,
            projectId: workflow.project.projectId,
            jobId: workflow.job.jobId,
            planId: workflow.plan.planId,
            stepId: workflow.step.stepId,
            skillId: effectiveSkillId,
            requestedSkillId: routedRequestedSkillId,
            routingReasonCode: routingResolution?.reasonCode,
            routingExplanation: routingResolution?.explanation,
            toolName: mapped.toolName,
            status: requiresWaitingAuthorization ? .awaitingAuthorization : .queued,
            payload: payloadObject,
            currentOwner: owner,
            resultSummary: awaitingResultSummary,
            denyCode: awaitingDenyCode,
            resultEvidenceRef: nil,
            requiredCapability: requiredCapability,
            grantRequestId: nil,
            grantId: nil,
            createdAtMs: nowMs,
            updatedAtMs: nowMs,
            auditRef: "audit-xt-supervisor-skill-\(String(requestId.suffix(12)))"
        )
        record.resultEvidenceRef = SupervisorSkillResultEvidenceStore.write(
            record: record,
            toolCall: mapped.toolCall,
            rawOutput: nil,
            triggerSource: triggerSource.rawValue,
            ctx: workflow.ctx
        )

        do {
            try SupervisorProjectSkillCallStore.upsert(record, for: workflow.ctx)
        } catch {
            let message = "❌ CALL_SKILL 失败：技能调用落盘失败（skill_call_store_write_failed: \(error.localizedDescription))"
            addSystemMessage(message)
            return (false, "skill_call_store_write_failed", message, workflow.project.projectId, workflow.project.displayName)
        }

        _ = updateSupervisorWorkflowStepState(
            ctx: workflow.ctx,
            project: workflow.project,
            jobId: workflow.job.jobId,
            planId: workflow.plan.planId,
            stepId: workflow.step.stepId,
            status: requiresWaitingAuthorization ? .awaitingAuthorization : .running,
            detail: record.resultSummary,
            owner: record.currentOwner,
            updatedAtMs: nowMs
        )
        appendSupervisorSkillCallRawLog(
            action: requiresWaitingAuthorization ? "awaiting_authorization" : "dispatch",
            record: record,
            toolCall: mapped.toolCall,
            triggerSource: triggerSource,
            ctx: workflow.ctx
        )
        appendSupervisorSkillResultRawLog(
            record: record,
            toolCall: mapped.toolCall,
            rawOutput: nil,
            triggerSource: triggerSource,
            ctx: workflow.ctx
        )

        if requiresWaitingAuthorization {
            appendRecentEvent("skill_result: \(workflow.project.displayName) -> \(record.skillId) \(record.status.rawValue)")
            if let requiredCapability,
               supervisorHubGrantPreflightEnabled {
                let requestedSeconds = supervisorRequestedGrantWindowSeconds(payload: payloadObject)
                let reason = supervisorGrantReason(
                    project: workflow.project,
                    job: workflow.job,
                    skillId: effectiveSkillId,
                    capability: requiredCapability
                )
                let task = Task { [weak self] in
                    guard let self else { return }
                    await self.requestSupervisorHubGrantForSkillCall(
                        requestId: requestId,
                        project: workflow.project,
                        ctx: workflow.ctx,
                        toolCall: mapped.toolCall,
                        requiredCapability: requiredCapability,
                        requestedSeconds: requestedSeconds,
                        reason: reason
                    )
                }
                supervisorSkillExecutionTasks[requestId] = task
                let message = "⏸️ 已为项目 \(workflow.project.displayName) 登记技能调用：\(displaySkill)（\(userFacingRequestIdentifier(requestId))），正在向 Hub 申请\(grantCapabilityText(capability: requiredCapability, modelId: ""))授权。"
                addSystemMessage(message)
                return (true, "awaiting_authorization", message, workflow.project.projectId, workflow.project.displayName)
            }

            let message: String
            if let requiredCapability, !requiredCapability.isEmpty {
                message = "⏸️ 已为项目 \(workflow.project.displayName) 登记技能调用：\(displaySkill)（\(userFacingRequestIdentifier(requestId))），正在向 Hub 申请\(grantCapabilityText(capability: requiredCapability, modelId: ""))授权。"
            } else {
                message = "⏸️ 已为项目 \(workflow.project.displayName) 登记技能调用：\(displaySkill)（\(userFacingRequestIdentifier(requestId))），当前需要本地审批后才能继续。"
            }
            addSystemMessage(message)
            return (true, "awaiting_authorization", message, workflow.project.projectId, workflow.project.displayName)
        }

        let task = Task { [weak self] in
            guard let self else { return }
            await self.executeSupervisorSkillCall(
                requestId: requestId,
                project: workflow.project,
                ctx: workflow.ctx,
                toolCall: mapped.toolCall,
                triggerSource: triggerSource
            )
        }
        supervisorSkillExecutionTasks[requestId] = task

        let message = "✅ 已为项目 \(workflow.project.displayName) 排队技能调用：\(displaySkill)（\(userFacingRequestIdentifier(requestId))）"
        addSystemMessage(message)
        return (true, "ok", message, workflow.project.projectId, workflow.project.displayName)
    }

    private func cancelSupervisorSkill(
        from payload: SupervisorCancelSkillPayload,
        userMessage: String,
        triggerSource: SupervisorCommandTriggerSource
    ) -> (ok: Bool, reasonCode: String, message: String, projectId: String?, projectName: String?) {
        let requestId = payload.requestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !requestId.isEmpty else {
            let message = "❌ CANCEL_SKILL 失败：request_id 不能为空（request_id_missing）"
            addSystemMessage(message)
            return (false, "request_id_missing", message, nil, nil)
        }

        let resolved: SupervisorSkillCallResolution
        switch locateSupervisorSkillCall(
            requestId: requestId,
            projectRef: payload.projectRef,
            commandName: "CANCEL_SKILL",
            userMessage: userMessage,
            triggerSource: triggerSource
        ) {
        case .failure(let failure):
            addSystemMessage(failure.message)
            return (false, failure.reasonCode, failure.message, failure.projectId, failure.projectName)
        case .success(let call):
            resolved = call
        }

        if [.completed, .failed, .blocked, .canceled].contains(resolved.record.status) {
            let message = "ℹ️ \(userFacingRequestIdentifier(requestId)) 已处于终态（状态：\(resolved.record.status.rawValue)），无需重复取消。"
            addSystemMessage(message)
            return (true, "already_terminal", message, resolved.project.projectId, resolved.project.displayName)
        }

        var record = resolved.record
        record.status = .canceled
        record.resultSummary = capped(
            (payload.reason ?? "canceled by supervisor").trimmingCharacters(in: .whitespacesAndNewlines),
            maxChars: 320
        )
        record.denyCode = ""
        record.updatedAtMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        record.resultEvidenceRef = SupervisorSkillResultEvidenceStore.write(
            record: record,
            toolCall: resolvedSupervisorToolCallForRecord(record),
            rawOutput: nil,
            triggerSource: triggerSource.rawValue,
            ctx: resolved.ctx
        ) ?? record.resultEvidenceRef
        do {
            try SupervisorProjectSkillCallStore.upsert(record, for: resolved.ctx)
        } catch {
            let message = "❌ CANCEL_SKILL 失败：技能调用状态更新失败（skill_call_store_write_failed: \(error.localizedDescription))"
            addSystemMessage(message)
            return (false, "skill_call_store_write_failed", message, resolved.project.projectId, resolved.project.displayName)
        }

        _ = updateSupervisorWorkflowStepState(
            ctx: resolved.ctx,
            project: resolved.project,
            jobId: record.jobId,
            planId: record.planId,
            stepId: record.stepId,
            status: .canceled,
            detail: record.resultSummary,
            owner: record.currentOwner,
            updatedAtMs: record.updatedAtMs
        )
        appendSupervisorSkillCallRawLog(
            action: "cancel",
            record: record,
            toolCall: nil,
            triggerSource: triggerSource,
            ctx: resolved.ctx
        )
        appendSupervisorSkillResultRawLog(
            record: record,
            toolCall: nil,
            rawOutput: nil,
            triggerSource: triggerSource,
            ctx: resolved.ctx
        )
        appendRecentEvent("skill_result: \(resolved.project.displayName) -> \(record.skillId) \(record.status.rawValue)")

        supervisorSkillExecutionTasks.removeValue(forKey: requestId)?.cancel()
        let message = "✅ 已取消项目 \(resolved.project.displayName) 的技能调用：\(supervisorSkillDisplaySummary(record))（\(userFacingRequestIdentifier(requestId))）"
        addSystemMessage(message)
        return (true, "ok", message, resolved.project.projectId, resolved.project.displayName)
    }

    private func supervisorRequiredHubCapability(for toolCall: ToolCall) -> String? {
        switch toolCall.tool {
        case .web_fetch, .web_search, .browser_read:
            return "web.fetch"
        case .deviceBrowserControl:
            if let action = toolCall.args["action"]?.stringValue?
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .lowercased(),
               action == "extract" {
                return "web.fetch"
            }
            return nil
        case .summarize:
            if let url = toolCall.args["url"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
               !url.isEmpty {
                return "web.fetch"
            }
            return nil
        default:
            return nil
        }
    }

    private func supervisorToolCallHasExplicitGrant(_ toolCall: ToolCall) -> Bool {
        for key in ["grant_id", "grant_request_id"] {
            guard let value = toolCall.args[key]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !value.isEmpty else {
                continue
            }
            return true
        }
        return false
    }

    private func supervisorRequestedGrantWindowSeconds(payload: [String: JSONValue]) -> Int {
        if let raw = payload["timeout_sec"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
           let timeout = Double(raw),
           timeout.isFinite,
           timeout > 0 {
            return max(120, min(3_600, Int(timeout.rounded(.up)) * 4))
        }
        return 900
    }

    private func supervisorGrantReason(
        project: AXProjectEntry,
        job: SupervisorJobRecord,
        skillId: String,
        capability: String
    ) -> String {
        let goal = job.goal.trimmingCharacters(in: .whitespacesAndNewlines)
        if goal.isEmpty {
            return "supervisor skill \(skillId) for project \(project.displayName) requires \(capability)"
        }
        return "supervisor skill \(skillId) for project \(project.displayName): \(goal)"
    }

    private func requestSupervisorHubGrantForSkillCall(
        requestId: String,
        project: AXProjectEntry,
        ctx: AXProjectContext,
        toolCall: ToolCall,
        requiredCapability: String,
        requestedSeconds: Int,
        reason: String
    ) async {
        if isSupervisorSkillCanceled(requestId: requestId, ctx: ctx) {
            supervisorSkillExecutionTasks.removeValue(forKey: requestId)
            return
        }

        let access: HubIPCClient.NetworkAccessResult
        if let override = supervisorNetworkAccessRequestOverride {
            access = await override(ctx.root, requestedSeconds, reason)
        } else {
            access = await HubIPCClient.requestNetworkAccess(
                root: ctx.root,
                seconds: requestedSeconds,
                reason: reason
            )
        }

        if isSupervisorSkillCanceled(requestId: requestId, ctx: ctx) {
            supervisorSkillExecutionTasks.removeValue(forKey: requestId)
            return
        }

        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        let normalizedGrantRequestId = access.grantRequestId?.trimmingCharacters(in: .whitespacesAndNewlines)
        let fallbackSeconds = max(120, access.remainingSeconds ?? requestedSeconds)

        switch access.state {
        case .enabled, .autoApproved:
            let activatedGrantId = await ToolExecutor.activateHighRiskGrantForSupervisor(
                projectRoot: ctx.root,
                capability: requiredCapability,
                grantRequestId: normalizedGrantRequestId,
                fallbackSeconds: fallbackSeconds
            )
            let resumeGrantId = (activatedGrantId?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false)
                ? activatedGrantId!.trimmingCharacters(in: .whitespacesAndNewlines)
                : (normalizedGrantRequestId ?? "")
            let resumeToolCall = injectSupervisorGrant(
                into: toolCall,
                grantId: resumeGrantId,
                capability: requiredCapability
            )
            let resumedRecord = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: .queued,
                stepStatus: .pending,
                resultSummary: "grant approved; resuming governed dispatch",
                denyCode: "",
                requiredCapability: requiredCapability,
                grantRequestId: normalizedGrantRequestId,
                grantId: resumeGrantId.isEmpty ? nil : resumeGrantId,
                updatedAtMs: nowMs,
                triggerSource: .grantResolution,
                toolCall: resumeToolCall
            )
            let executeTask = Task { [weak self] in
                guard let self else { return }
                await self.executeSupervisorSkillCall(
                    requestId: requestId,
                    project: project,
                    ctx: ctx,
                    toolCall: resumeToolCall,
                    allowPreviouslyApprovedAuthorization: true,
                    triggerSource: .grantResolution
                )
            }
            supervisorSkillExecutionTasks[requestId] = executeTask
            let displaySkill = resumedRecord.map(supervisorSkillDisplaySummary) ?? "技能调用"
            addSystemMessage(
                "✅ 已为项目 \(project.displayName) 取得 Hub 授权并恢复技能调用：\(displaySkill)（\(userFacingRequestIdentifier(requestId))）"
            )
            return

        case .queued:
            _ = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: .awaitingAuthorization,
                stepStatus: .awaitingAuthorization,
                resultSummary: XTHubGrantPresentation.awaitingStateSummary(
                    capability: requiredCapability,
                    modelId: "",
                    grantRequestId: normalizedGrantRequestId
                ),
                denyCode: "grant_required",
                requiredCapability: requiredCapability,
                grantRequestId: normalizedGrantRequestId,
                grantId: nil,
                updatedAtMs: nowMs,
                triggerSource: .grantResolution,
                toolCall: toolCall
            )
            if let normalizedGrantRequestId, !normalizedGrantRequestId.isEmpty {
                addSystemMessage("⏸️ 已向 Hub 提交授权请求（\(userFacingGrantIdentifier(normalizedGrantRequestId))）。")
            }
            await refreshSchedulerSnapshot(force: true)
            supervisorSkillExecutionTasks.removeValue(forKey: requestId)

        case .denied:
            if let blocked = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: .blocked,
                stepStatus: .blocked,
                resultSummary: XTHubGrantPresentation.deniedStateSummary(
                    capability: requiredCapability,
                    modelId: "",
                    deniedByUser: false
                ),
                denyCode: access.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "grant_denied",
                requiredCapability: requiredCapability,
                grantRequestId: normalizedGrantRequestId,
                grantId: nil,
                updatedAtMs: nowMs,
                triggerSource: .grantResolution,
                toolCall: toolCall
            ) {
                scheduleSupervisorGrantResolutionFollowUp(
                    record: blocked,
                    project: project,
                    reasonCode: blocked.denyCode,
                    summary: blocked.resultSummary
                )
            }
            supervisorSkillExecutionTasks.removeValue(forKey: requestId)

        case .failed:
            if let blocked = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: .blocked,
                stepStatus: .blocked,
                resultSummary: access.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                    ? "Hub 授权请求失败：\(access.reasonCode!.trimmingCharacters(in: .whitespacesAndNewlines))"
                    : "Hub 授权请求失败",
                denyCode: access.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "grant_request_failed",
                requiredCapability: requiredCapability,
                grantRequestId: normalizedGrantRequestId,
                grantId: nil,
                updatedAtMs: nowMs,
                triggerSource: .grantResolution,
                toolCall: toolCall
            ) {
                scheduleSupervisorGrantResolutionFollowUp(
                    record: blocked,
                    project: project,
                    reasonCode: blocked.denyCode,
                    summary: blocked.resultSummary
                )
            }
            supervisorSkillExecutionTasks.removeValue(forKey: requestId)
        }
    }

    private func injectSupervisorGrant(
        into toolCall: ToolCall,
        grantId: String,
        capability: String
    ) -> ToolCall {
        guard !grantId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            return toolCall
        }
        guard capability.lowercased().contains("web.fetch") else {
            return toolCall
        }
        var args = toolCall.args
        args["grant_id"] = .string(grantId.trimmingCharacters(in: .whitespacesAndNewlines))
        return ToolCall(id: toolCall.id, tool: toolCall.tool, args: args)
    }

    private func resumeSupervisorSkillCallsAfterGrantAction(
        grant: SupervisorPendingGrant,
        approve: Bool,
        result: HubIPCClient.PendingGrantActionResult
    ) async {
        let projectId = grant.projectId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !projectId.isEmpty else { return }
        guard let project = knownProjects().first(where: { $0.projectId == projectId }),
              let ctx = appModel?.projectContext(for: projectId) else {
            return
        }

        let capability = grant.capability.trimmingCharacters(in: .whitespacesAndNewlines)
        let grantRequestId = grant.grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines)
        let snapshot = SupervisorProjectSkillCallStore.load(for: ctx)
        let matches = snapshot.calls.filter { record in
            guard record.status == .awaitingAuthorization else { return false }
            if !grantRequestId.isEmpty,
               record.grantRequestId?.trimmingCharacters(in: .whitespacesAndNewlines) == grantRequestId {
                return true
            }
            guard record.projectId == projectId else { return false }
            return record.requiredCapability?.trimmingCharacters(in: .whitespacesAndNewlines) == capability
        }
        guard !matches.isEmpty else { return }

        if !approve {
            let updatedAtMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
            for record in matches {
                if let blocked = applySupervisorSkillCallStatus(
                    requestId: record.requestId,
                    ctx: ctx,
                    project: project,
                    status: .blocked,
                    stepStatus: .blocked,
                    resultSummary: XTHubGrantPresentation.deniedStateSummary(
                        capability: capability.isEmpty ? (record.requiredCapability ?? "") : capability,
                        modelId: "",
                        deniedByUser: true
                    ),
                    denyCode: "grant_denied",
                    requiredCapability: capability.isEmpty ? record.requiredCapability : capability,
                    grantRequestId: grantRequestId.isEmpty ? record.grantRequestId : grantRequestId,
                    grantId: nil,
                    updatedAtMs: updatedAtMs,
                    triggerSource: .grantResolution,
                    toolCall: nil
                ) {
                    scheduleSupervisorGrantResolutionFollowUp(
                        record: blocked,
                        project: project,
                        reasonCode: blocked.denyCode,
                        summary: blocked.resultSummary
                    )
                }
            }
            return
        }

        guard result.ok else { return }
        let resolvedGrantId = [
            result.grantId,
            result.grantRequestId,
            grant.grantRequestId
        ]
        .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
        .first(where: { !$0.isEmpty }) ?? ""

        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        let fallbackSeconds: Int = {
            guard let expiresAtMs = result.expiresAtMs, expiresAtMs > 0 else {
                return max(120, grant.requestedTtlSec > 0 ? grant.requestedTtlSec : 900)
            }
            let remaining = Int(((expiresAtMs / 1000.0) - Date().timeIntervalSince1970).rounded(.up))
            return max(120, remaining)
        }()

        if !resolvedGrantId.isEmpty, !capability.isEmpty {
            _ = await ToolExecutor.activateHighRiskGrantForSupervisor(
                projectRoot: ctx.root,
                capability: capability,
                grantRequestId: resolvedGrantId,
                fallbackSeconds: fallbackSeconds
            )
        }

        for record in matches {
            switch mapSupervisorSkillToToolCall(
                skillId: record.skillId,
                payload: record.payload,
                requestId: record.requestId,
                projectId: project.projectId,
                projectName: project.displayName
            ) {
            case .failure:
                if let blocked = applySupervisorSkillCallStatus(
                    requestId: record.requestId,
                    ctx: ctx,
                    project: project,
                    status: .blocked,
                    stepStatus: .blocked,
                    resultSummary: "skill mapping unavailable during grant resume",
                    denyCode: "skill_mapping_missing",
                    requiredCapability: capability.isEmpty ? record.requiredCapability : capability,
                    grantRequestId: grantRequestId.isEmpty ? record.grantRequestId : grantRequestId,
                    grantId: resolvedGrantId.isEmpty ? record.grantId : resolvedGrantId,
                    updatedAtMs: nowMs,
                    triggerSource: .grantResolution,
                    toolCall: nil
                ) {
                    scheduleSupervisorGrantResolutionFollowUp(
                        record: blocked,
                        project: project,
                        reasonCode: blocked.denyCode,
                        summary: blocked.resultSummary
                    )
                }

            case .success(let mapped):
                let resumedToolCall = injectSupervisorGrant(
                    into: mapped.toolCall,
                    grantId: resolvedGrantId,
                    capability: capability.isEmpty ? (record.requiredCapability ?? "") : capability
                )
                let resumedRecord = applySupervisorSkillCallStatus(
                    requestId: record.requestId,
                    ctx: ctx,
                    project: project,
                    status: .queued,
                    stepStatus: .pending,
                    resultSummary: "grant approved; resuming governed dispatch",
                    denyCode: "",
                    requiredCapability: capability.isEmpty ? record.requiredCapability : capability,
                    grantRequestId: grantRequestId.isEmpty ? record.grantRequestId : grantRequestId,
                    grantId: resolvedGrantId.isEmpty ? record.grantId : resolvedGrantId,
                    updatedAtMs: nowMs,
                    triggerSource: .grantResolution,
                    toolCall: resumedToolCall
                )

                let task = Task { [weak self] in
                    guard let self else { return }
                    await self.executeSupervisorSkillCall(
                        requestId: record.requestId,
                        project: project,
                        ctx: ctx,
                        toolCall: resumedToolCall,
                        allowPreviouslyApprovedAuthorization: true,
                        triggerSource: .grantResolution
                    )
                }
                supervisorSkillExecutionTasks[record.requestId] = task
                let displaySkill = resumedRecord.map(supervisorSkillDisplaySummary) ?? "技能调用"
                addSystemMessage(
                    "✅ 已为项目 \(project.displayName) 取得 Hub 授权并恢复技能调用：\(displaySkill)（\(userFacingRequestIdentifier(record.requestId))）"
                )
            }
        }
    }

    private func executeSupervisorSkillCall(
        requestId: String,
        project: AXProjectEntry,
        ctx: AXProjectContext,
        toolCall: ToolCall,
        allowPreviouslyApprovedAuthorization: Bool = false,
        triggerSource: SupervisorCommandTriggerSource
    ) async {
        defer { supervisorSkillExecutionTasks.removeValue(forKey: requestId) }

        if isSupervisorSkillCanceled(requestId: requestId, ctx: ctx) {
            return
        }

        let config = (try? AXProjectStore.loadOrCreateConfig(for: ctx)) ?? .default(forProjectRoot: ctx.root)
        let decision = await xtToolAuthorizationDecision(
            call: toolCall,
            config: config,
            projectRoot: ctx.root
        )

        if isSupervisorSkillCanceled(requestId: requestId, ctx: ctx) {
            return
        }

        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        if decision.isDenied {
            let blockedSummary = xtToolAuthorizationDeniedSummaryText(
                call: toolCall,
                decision: decision
            )
            if let blocked = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: .blocked,
                stepStatus: .blocked,
                resultSummary: blockedSummary,
                denyCode: decision.denyCode,
                policySource: decision.policySource,
                policyReason: decision.policyReason,
                updatedAtMs: nowMs,
                triggerSource: triggerSource,
                toolCall: toolCall
            ) {
                scheduleSupervisorSkillCallbackFollowUp(
                    record: blocked,
                    project: project,
                    ctx: ctx,
                    status: .blocked,
                    reason: blocked.resultSummary
                )
            }
            return
        }

        if decision.needsApproval, !allowPreviouslyApprovedAuthorization {
            _ = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: .awaitingAuthorization,
                stepStatus: .awaitingAuthorization,
                resultSummary: decision.policyReason.isEmpty ? "tool confirmation required" : "tool confirmation required: \(decision.policyReason)",
                denyCode: "",
                policySource: decision.policySource,
                policyReason: decision.policyReason,
                updatedAtMs: nowMs,
                triggerSource: triggerSource,
                toolCall: toolCall
            )
            return
        }

        _ = applySupervisorSkillCallStatus(
            requestId: requestId,
            ctx: ctx,
            project: project,
            status: .running,
            stepStatus: .running,
            resultSummary: "executing \(toolCall.tool.rawValue)",
            denyCode: "",
            updatedAtMs: nowMs,
            triggerSource: triggerSource,
            toolCall: toolCall
        )

        do {
            let result: ToolResult
            if let override = supervisorToolExecutorOverride {
                result = try await override(toolCall, ctx.root)
            } else {
                result = try await ToolExecutor.execute(call: toolCall, projectRoot: ctx.root)
            }
            if isSupervisorSkillCanceled(requestId: requestId, ctx: ctx) {
                return
            }
            AXProjectStore.appendToolLog(
                action: toolCall.tool.rawValue,
                input: foundationJSONObject(from: toolCall.args),
                output: result.output,
                ok: result.ok,
                for: ctx
            )
            let finalStatus = result.ok ? SupervisorSkillCallStatus.completed : .failed
            let resultPolicyContext: (denyCode: String, policySource: String, policyReason: String) = result.ok
                ? (denyCode: "", policySource: "", policyReason: "")
                : supervisorToolResultPolicyContext(from: result.output)
            if let updated = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: finalStatus,
                stepStatus: result.ok ? .completed : .failed,
                resultSummary: summarizedSupervisorSkillOutput(
                    result.output,
                    ok: result.ok,
                    toolCall: toolCall
                ),
                denyCode: resultPolicyContext.denyCode,
                policySource: resultPolicyContext.policySource,
                policyReason: resultPolicyContext.policyReason,
                rawOutput: result.output,
                updatedAtMs: Int64((Date().timeIntervalSince1970 * 1000.0).rounded()),
                triggerSource: triggerSource,
                toolCall: toolCall
            ) {
                scheduleSupervisorSkillCallbackFollowUp(
                    record: updated,
                    project: project,
                    ctx: ctx,
                    status: finalStatus,
                    reason: updated.resultSummary
                )
            }
        } catch {
            if isSupervisorSkillCanceled(requestId: requestId, ctx: ctx) {
                return
            }
            if let failed = applySupervisorSkillCallStatus(
                requestId: requestId,
                ctx: ctx,
                project: project,
                status: .failed,
                stepStatus: .failed,
                resultSummary: capped(String(describing: error), maxChars: 320),
                denyCode: "tool_execution_failed",
                rawOutput: String(describing: error),
                updatedAtMs: Int64((Date().timeIntervalSince1970 * 1000.0).rounded()),
                triggerSource: triggerSource,
                toolCall: toolCall
            ) {
                scheduleSupervisorSkillCallbackFollowUp(
                    record: failed,
                    project: project,
                    ctx: ctx,
                    status: .failed,
                    reason: failed.resultSummary
                )
            }
        }
    }

    private func resolvedSupervisorToolCallForRecord(_ record: SupervisorSkillCallRecord) -> ToolCall? {
        let requestId = record.requestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !requestId.isEmpty else { return nil }
        let mapped: SupervisorMappedSkillDispatch
        switch mapSupervisorSkillToToolCall(
            skillId: record.skillId,
            payload: record.payload,
            requestId: requestId,
            projectId: record.projectId,
            projectName: nil
        ) {
        case .failure:
            return nil
        case .success(let dispatch):
            mapped = dispatch
        }

        let capability = record.requiredCapability?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let candidateGrantId = [
            record.grantId,
            record.grantRequestId
        ]
        .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
        .first(where: { !$0.isEmpty }) ?? ""
        if candidateGrantId.isEmpty || capability.isEmpty {
            return mapped.toolCall
        }
        return injectSupervisorGrant(
            into: mapped.toolCall,
            grantId: candidateGrantId,
            capability: capability
        )
    }

    @discardableResult
    private func applySupervisorSkillCallStatus(
        requestId: String,
        ctx: AXProjectContext,
        project: AXProjectEntry,
        status: SupervisorSkillCallStatus,
        stepStatus: SupervisorPlanStepStatus,
        resultSummary: String,
        denyCode: String,
        policySource: String? = nil,
        policyReason: String? = nil,
        rawOutput: String? = nil,
        requiredCapability: String? = nil,
        grantRequestId: String? = nil,
        grantId: String? = nil,
        updatedAtMs: Int64,
        triggerSource: SupervisorCommandTriggerSource,
        toolCall: ToolCall?
    ) -> SupervisorSkillCallRecord? {
        let snapshot = SupervisorProjectSkillCallStore.load(for: ctx)
        guard var record = snapshot.calls.first(where: { $0.requestId == requestId }) else { return nil }
        record.status = status
        record.resultSummary = capped(resultSummary, maxChars: 320)
        record.denyCode = denyCode.trimmingCharacters(in: .whitespacesAndNewlines)
        record.policySource = normalizedSupervisorSkillPolicyScalar(policySource)
        record.policyReason = normalizedSupervisorSkillPolicyScalar(policyReason)
        if let requiredCapability, !requiredCapability.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            record.requiredCapability = requiredCapability.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        if let grantRequestId, !grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            record.grantRequestId = grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        if let grantId, !grantId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            record.grantId = grantId.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        record.updatedAtMs = updatedAtMs
        record.resultEvidenceRef = SupervisorSkillResultEvidenceStore.write(
            record: record,
            toolCall: toolCall,
            rawOutput: rawOutput,
            triggerSource: triggerSource.rawValue,
            ctx: ctx
        ) ?? record.resultEvidenceRef
        try? SupervisorProjectSkillCallStore.upsert(record, for: ctx)
        _ = updateSupervisorWorkflowStepState(
            ctx: ctx,
            project: project,
            jobId: record.jobId,
            planId: record.planId,
            stepId: record.stepId,
            status: stepStatus,
            detail: record.resultSummary,
            owner: record.currentOwner,
            updatedAtMs: updatedAtMs
        )
        appendSupervisorSkillCallRawLog(
            action: status.rawValue,
            record: record,
            toolCall: toolCall,
            triggerSource: triggerSource,
            ctx: ctx
        )
        appendSupervisorSkillResultRawLog(
            record: record,
            toolCall: toolCall,
            rawOutput: rawOutput,
            triggerSource: triggerSource,
            ctx: ctx
        )
        if status != .running && status != .queued {
            appendRecentEvent("skill_result: \(project.displayName) -> \(record.skillId) \(status.rawValue)")
        }
        return record
    }

    private func normalizedSupervisorSkillPolicyScalar(_ raw: String?) -> String? {
        let trimmed = (raw ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : trimmed
    }

    @discardableResult
    private func updateSupervisorWorkflowStepState(
        ctx: AXProjectContext,
        project: AXProjectEntry,
        jobId: String,
        planId: String,
        stepId: String,
        status: SupervisorPlanStepStatus,
        detail: String,
        owner: String?,
        updatedAtMs: Int64
    ) -> Bool {
        let planSnapshot = SupervisorProjectPlanStore.load(for: ctx)
        guard var plan = planSnapshot.plans.first(where: { $0.planId == planId })
            ?? planSnapshot.plans.first(where: { $0.jobId == jobId && $0.steps.contains(where: { $0.stepId == stepId }) }) else {
            return false
        }
        guard let stepIndex = plan.steps.firstIndex(where: { $0.stepId == stepId }) else { return false }
        let jobSnapshot = SupervisorProjectJobStore.load(for: ctx)
        guard var job = jobSnapshot.jobs.first(where: { $0.jobId == jobId }) else { return false }

        plan.steps[stepIndex].status = status
        plan.steps[stepIndex].detail = capped(detail, maxChars: 320)
        if let owner, !owner.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            plan.steps[stepIndex].currentOwner = owner
            job.currentOwner = owner
        }
        plan.steps[stepIndex].updatedAtMs = updatedAtMs
        plan.updatedAtMs = updatedAtMs
        plan.status = derivedPlanStatus(from: plan.steps)
        job.activePlanId = plan.planId
        job.status = derivedJobStatus(from: plan)
        job.updatedAtMs = updatedAtMs

        do {
            try SupervisorProjectPlanStore.upsert(plan, for: ctx)
            try SupervisorProjectJobStore.upsert(job, for: ctx)
        } catch {
            return false
        }

        currentTask = SupervisorTask(
            id: job.jobId,
            projectId: job.projectId,
            title: job.goal,
            status: job.status.rawValue,
            createdAt: Double(job.createdAtMs) / 1000.0
        )
        syncSupervisorProjectWorkflowCanonical(ctx: ctx, project: project)
        return true
    }

    private func mapSupervisorSkillToToolCall(
        skillId: String,
        payload: [String: JSONValue],
        requestId: String,
        projectId: String? = nil,
        projectName: String? = nil,
        registryItem: SupervisorSkillRegistryItem? = nil
    ) -> Result<SupervisorMappedSkillDispatch, SupervisorSkillMappingFailure> {
        let canonicalSkillId = AXSkillsLibrary.canonicalSupervisorSkillID(skillId)
        let effectiveSkillId = effectiveSupervisorSkillID(
            requestedSkillId: canonicalSkillId,
            projectId: projectId,
            projectName: projectName,
            registryItem: registryItem
        )
        let effectivePayload = normalizedSupervisorSkillPayload(
            requestedSkillId: canonicalSkillId,
            effectiveSkillId: effectiveSkillId,
            payload: payload
        )
        let effectiveRegistryItem: SupervisorSkillRegistryItem? = {
            let canonicalRegistryItemId = AXSkillsLibrary.canonicalSupervisorSkillID(registryItem?.skillId ?? "")
            if canonicalRegistryItemId == effectiveSkillId {
                return registryItem
            }
            return resolvedSupervisorRegistryItem(
                skillId: effectiveSkillId,
                projectId: projectId,
                projectName: projectName
            ) ?? registryItem
        }()

        switch effectiveSkillId.lowercased() {
        case "repo.git.status":
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .git_status, args: [:]),
                toolName: ToolName.git_status.rawValue
            ))
        case "repo.git.diff":
            var args: [String: JSONValue] = [:]
            if let cached = effectivePayload["cached"] {
                args["cached"] = cached
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .git_diff, args: args),
                toolName: ToolName.git_diff.rawValue
            ))
        case "repo.git.commit":
            return mappedSupervisorGitCommitDispatch(
                payload: payload,
                requestId: requestId
            )
        case "repo.git.push":
            return mappedSupervisorGitPushDispatch(
                payload: payload,
                requestId: requestId
            )
        case "repo.git.apply", "repo.patch.apply", "repo.git.patch.apply":
            guard let patch = payload["patch"]?.stringValue,
                  !patch.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.patch_missing"))
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .git_apply, args: ["patch": .string(patch)]),
                toolName: ToolName.git_apply.rawValue
            ))
        case "repo.search", "repo.grep":
            guard let pattern = payload["pattern"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !pattern.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.pattern_missing"))
            }
            var args: [String: JSONValue] = ["pattern": .string(pattern)]
            if let path = effectivePayload["path"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
               !path.isEmpty {
                args["path"] = .string(path)
            }
            if let glob = effectivePayload["glob"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
               !glob.isEmpty {
                args["glob"] = .string(glob)
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .search, args: args),
                toolName: ToolName.search.rawValue
            ))
        case "repo.write.file", "repo.write", "repo.file.write":
            return mappedSupervisorRepoWriteFileDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "repo.delete.path", "repo.delete.file", "repo.delete":
            return mappedSupervisorRepoDeletePathDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "repo.move.path", "repo.rename.path", "repo.move", "repo.rename":
            return mappedSupervisorRepoMovePathDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "repo.read.file", "repo.read", "repo.file.read":
            guard let path = effectivePayload["path"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !path.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.path_missing"))
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .read_file, args: ["path": .string(path)]),
                toolName: ToolName.read_file.rawValue
            ))
        case "repo.list.dir", "repo.list", "repo.dir.list":
            let path = effectivePayload["path"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "."
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .list_dir, args: ["path": .string(path.isEmpty ? "." : path)]),
                toolName: ToolName.list_dir.rawValue
            ))
        case "project.snapshot", "project_snapshot":
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .project_snapshot, args: [:]),
                toolName: ToolName.project_snapshot.rawValue
            ))
        case "memory.snapshot", "memory_snapshot":
            var args: [String: JSONValue] = [:]
            if let mode = payload["mode"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
               !mode.isEmpty {
                args["mode"] = .string(mode)
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .memory_snapshot, args: args),
                toolName: ToolName.memory_snapshot.rawValue
            ))
        case "bridge.status", "bridge_status":
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .bridge_status, args: [:]),
                toolName: ToolName.bridge_status.rawValue
            ))
        case "find-skills", "skills.search", "skills_search":
            if let registryDriven = mappedSupervisorGovernedDispatch(
                skillId: effectiveSkillId,
                payload: effectivePayload,
                requestId: requestId,
                projectId: projectId,
                projectName: projectName,
                registryItem: effectiveRegistryItem
            ) {
                return registryDriven
            }
            guard let query = effectivePayload["query"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !query.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.query_missing"))
            }
            var args: [String: JSONValue] = ["query": .string(query)]
            if let sourceFilter = firstNonEmptyString(
                effectivePayload["source_filter"]?.stringValue,
                effectivePayload["source"]?.stringValue
            )?.trimmingCharacters(in: .whitespacesAndNewlines),
               !sourceFilter.isEmpty {
                args["source_filter"] = .string(sourceFilter)
            }
            if let projectId = effectivePayload["project_id"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
               !projectId.isEmpty {
                args["project_id"] = .string(projectId)
            }
            if let limit = effectivePayload["limit"] ?? effectivePayload["max_results"] {
                args["limit"] = limit
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .skills_search, args: args),
                toolName: ToolName.skills_search.rawValue
            ))
        case "agent-browser", "agent_browser", "agent.browser":
            if let registryDriven = mappedSupervisorGovernedDispatch(
                skillId: effectiveSkillId,
                payload: effectivePayload,
                requestId: requestId,
                projectId: projectId,
                projectName: projectName,
                registryItem: effectiveRegistryItem
            ) {
                return registryDriven
            }
            return mappedSupervisorAgentBrowserDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "self-improving-agent", "self_improving_agent", "agent.retrospective", "agent_retrospective":
            if let registryDriven = mappedSupervisorGovernedDispatch(
                skillId: effectiveSkillId,
                payload: effectivePayload,
                requestId: requestId,
                projectId: projectId,
                projectName: projectName,
                registryItem: effectiveRegistryItem
            ) {
                return registryDriven
            }
            return mappedSupervisorSelfImprovingAgentDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "browser.open", "browser.navigate", "browser_open", "browser_navigate":
            guard let url = effectivePayload["url"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !url.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_missing"))
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: [
                        "action": .string("open_url"),
                        "url": .string(url)
                    ]
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "browser.runtime.inspect", "browser_runtime.inspect":
            var args: [String: JSONValue] = ["action": .string("snapshot")]
            if let url = effectivePayload["url"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
               !url.isEmpty {
                args["url"] = .string(url)
            }
            if let sessionId = effectivePayload["session_id"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
               !sessionId.isEmpty {
                args["session_id"] = .string(sessionId)
            }
            guard args["url"] != nil || args["session_id"] != nil else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_or_session_id_missing"))
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .deviceBrowserControl, args: args),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "browser.runtime.smoke", "browser_runtime.smoke":
            let url = effectivePayload["url"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "https://example.com"
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: [
                        "action": .string("open_url"),
                        "url": .string(url)
                    ]
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "web.fetch", "web_fetch":
            guard let url = effectivePayload["url"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !url.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_missing"))
            }
            var args: [String: JSONValue] = ["url": .string(url)]
            for key in ["grant_id", "timeout_sec", "max_bytes"] {
                if let value = effectivePayload[key] {
                    args[key] = value
                }
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .web_fetch, args: args),
                toolName: ToolName.web_fetch.rawValue
            ))
        case "web.search", "web_search":
            guard let query = effectivePayload["query"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !query.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.query_missing"))
            }
            var args: [String: JSONValue] = ["query": .string(query)]
            for key in ["grant_id", "timeout_sec", "max_results", "max_bytes"] {
                if let value = effectivePayload[key] {
                    args[key] = value
                }
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .web_search, args: args),
                toolName: ToolName.web_search.rawValue
            ))
        case "browser.read", "browser_read":
            guard let url = effectivePayload["url"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !url.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_missing"))
            }
            var args: [String: JSONValue] = ["url": .string(url)]
            for key in ["grant_id", "timeout_sec", "max_bytes"] {
                if let value = effectivePayload[key] {
                    args[key] = value
                }
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .browser_read, args: args),
                toolName: ToolName.browser_read.rawValue
            ))
        case "summarize", "document.summarize", "document_summarize":
            if let registryDriven = mappedSupervisorGovernedDispatch(
                skillId: effectiveSkillId,
                payload: effectivePayload,
                requestId: requestId,
                projectId: projectId,
                projectName: projectName,
                registryItem: effectiveRegistryItem
            ) {
                return registryDriven
            }
            return mappedSupervisorSummarizeDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "supervisor-voice", "supervisor.voice", "supervisor_voice":
            if let registryDriven = mappedSupervisorGovernedDispatch(
                skillId: "supervisor-voice",
                payload: effectivePayload,
                requestId: requestId,
                projectId: projectId,
                projectName: projectName,
                registryItem: effectiveRegistryItem
            ) {
                return registryDriven
            }
            return mappedSupervisorVoicePlaybackDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "repo.test.run", "repo.test", "repo.verify.run":
            return mappedSupervisorRepoCommandDispatch(
                payload: effectivePayload,
                requestId: requestId,
                profile: .test
            )
        case "repo.build.run", "repo.build":
            return mappedSupervisorRepoCommandDispatch(
                payload: effectivePayload,
                requestId: requestId,
                profile: .build
            )
        case "repo.pr.create", "repo.pull_request.create", "repo.pull-request.create":
            return mappedSupervisorPRCreateDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "repo.ci.read", "ci.read":
            return mappedSupervisorCIReadDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "repo.ci.trigger", "ci.trigger":
            return mappedSupervisorCITriggerDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "process.start":
            return mappedSupervisorProcessStartDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "process.status":
            return mappedSupervisorProcessStatusDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "process.logs":
            return mappedSupervisorProcessLogsDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "process.stop":
            return mappedSupervisorProcessStopDispatch(
                payload: effectivePayload,
                requestId: requestId
            )
        case "coder.run.command", "coder.run", "coder_run.command", "coder_run":
            guard let command = effectivePayload["command"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !command.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.command_missing"))
            }
            var args: [String: JSONValue] = ["command": .string(command)]
            if let timeout = effectivePayload["timeout_sec"] {
                args["timeout_sec"] = timeout
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .run_command, args: args),
                toolName: ToolName.run_command.rawValue
            ))
        default:
            if let registryDriven = mappedSupervisorGovernedDispatch(
                skillId: effectiveSkillId,
                payload: effectivePayload,
                requestId: requestId,
                projectId: projectId,
                projectName: projectName,
                registryItem: effectiveRegistryItem
            ) {
                return registryDriven
            }
            return .failure(SupervisorSkillMappingFailure(reasonCode: "unsupported_skill_id"))
        }
    }

    private func mappedSupervisorGovernedDispatch(
        skillId: String,
        payload: [String: JSONValue],
        requestId: String,
        projectId: String?,
        projectName: String?,
        registryItem: SupervisorSkillRegistryItem?
    ) -> Result<SupervisorMappedSkillDispatch, SupervisorSkillMappingFailure>? {
        let normalizedSkillId = skillId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedSkillId.isEmpty else { return nil }
        let item = registryItem ?? resolvedSupervisorRegistryItem(
            skillId: normalizedSkillId,
            projectId: projectId,
            projectName: projectName
        )
        if let variantResult = mappedSupervisorGovernedDispatchVariant(
            item: item,
            payload: payload,
            requestId: requestId
        ) {
            return variantResult
        }
        guard let dispatch = item?.governedDispatch else { return nil }
        return mappedSupervisorGovernedDispatch(
            dispatch: dispatch,
            payload: payload,
            requestId: requestId,
            actionOverride: nil
        )
    }

    private func mappedSupervisorGovernedDispatchVariant(
        item: SupervisorSkillRegistryItem?,
        payload: [String: JSONValue],
        requestId: String
    ) -> Result<SupervisorMappedSkillDispatch, SupervisorSkillMappingFailure>? {
        guard let item, !item.governedDispatchVariants.isEmpty else { return nil }
        let requestedAction = firstNonEmptyString(
            payload["action"]?.stringValue,
            payload["operation"]?.stringValue,
            payload["mode"]?.stringValue
        )?
        .trimmingCharacters(in: .whitespacesAndNewlines)
        .lowercased() ?? ""
        guard !requestedAction.isEmpty else { return nil }

        guard let variant = item.governedDispatchVariants.first(where: { variant in
            variant.actions.contains {
                $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == requestedAction
            }
        }) else {
            return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.action_unsupported"))
        }

        let actionOverride: (key: String, value: String)? = {
            let cleanedKey = variant.actionArg.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !cleanedKey.isEmpty else { return nil }
            let mapped = variant.actionMap.first(where: {
                $0.key.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == requestedAction
            })?.value.trimmingCharacters(in: .whitespacesAndNewlines)
            let resolved = {
                let token = mapped ?? ""
                return token.isEmpty ? requestedAction : token
            }()
            guard !resolved.isEmpty else { return nil }
            return (cleanedKey, resolved)
        }()

        return mappedSupervisorGovernedDispatch(
            dispatch: variant.dispatch,
            payload: payload,
            requestId: requestId,
            actionOverride: actionOverride
        )
    }

    private func mappedSupervisorGovernedDispatch(
        dispatch: SupervisorGovernedSkillDispatch,
        payload: [String: JSONValue],
        requestId: String,
        actionOverride: (key: String, value: String)?
    ) -> Result<SupervisorMappedSkillDispatch, SupervisorSkillMappingFailure> {

        let toolToken = dispatch.tool.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !toolToken.isEmpty,
              let toolName = ToolName.allCases.first(where: { $0.rawValue == toolToken }) else {
            return .failure(SupervisorSkillMappingFailure(reasonCode: "governed_dispatch_tool_invalid"))
        }

        var args = dispatch.fixedArgs
        if let actionOverride {
            args[actionOverride.key] = .string(actionOverride.value)
        }
        let canonicalKeys = Set(dispatch.passthroughArgs).union(dispatch.argAliases.keys)
        for canonicalKey in canonicalKeys.sorted() {
            if let value = resolvedGovernedDispatchPayloadValue(
                payload: payload,
                canonicalKey: canonicalKey,
                aliases: dispatch.argAliases[canonicalKey] ?? []
            ) {
                args[canonicalKey] = value
            }
        }

        for group in dispatch.requiredAny {
            let presentCount = group.filter { governedDispatchHasValue(args[$0]) }.count
            guard presentCount > 0 else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: governedDispatchMissingReasonCode(for: group)))
            }
        }

        for group in dispatch.exactlyOneOf {
            let presentCount = group.filter { governedDispatchHasValue(args[$0]) }.count
            guard presentCount == 1 else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: governedDispatchExclusiveReasonCode(for: group, presentCount: presentCount)))
            }
        }

        return .success(SupervisorMappedSkillDispatch(
            toolCall: ToolCall(id: requestId, tool: toolName, args: args),
            toolName: toolName.rawValue
        ))
    }

    private func resolvedSupervisorRegistryItem(
        skillId: String,
        projectId: String?,
        projectName: String?
    ) -> SupervisorSkillRegistryItem? {
        guard let projectId = firstNonEmptyString(projectId) else { return nil }
        let canonicalSkillId = AXSkillsLibrary.canonicalSupervisorSkillID(skillId)
        guard !canonicalSkillId.isEmpty else { return nil }
        let snapshot = AXSkillsLibrary.supervisorSkillRegistrySnapshot(
            projectId: projectId,
            projectName: firstNonEmptyString(projectName),
            hubBaseDir: HubPaths.baseDir()
        )
        return snapshot?.items.first {
            AXSkillsLibrary.canonicalSupervisorSkillID($0.skillId) == canonicalSkillId
        }
    }

    private func effectiveSupervisorSkillID(
        requestedSkillId: String,
        projectId: String?,
        projectName: String?,
        registrySnapshot: SupervisorSkillRegistrySnapshot? = nil,
        registryItem: SupervisorSkillRegistryItem? = nil
    ) -> String {
        let canonicalSkillId = AXSkillsLibrary.canonicalSupervisorSkillID(requestedSkillId)
        guard !canonicalSkillId.isEmpty else { return "" }
        return preferredSupervisorBuiltinSkillID(
            requestedSkillId: canonicalSkillId,
            projectId: projectId,
            projectName: projectName,
            registrySnapshot: registrySnapshot,
            registryItem: registryItem
        ) ?? canonicalSkillId
    }

    private func normalizedSupervisorSkillPayload(
        requestedSkillId: String,
        effectiveSkillId: String,
        payload: [String: JSONValue]
    ) -> [String: JSONValue] {
        guard AXSkillsLibrary.canonicalSupervisorSkillID(effectiveSkillId) == "guarded-automation" else {
            return payload
        }
        guard firstNonEmptyString(
            payload["action"]?.stringValue,
            payload["operation"]?.stringValue,
            payload["mode"]?.stringValue
        ) == nil else {
            return payload
        }
        guard let inferredAction = inferredGuardedAutomationAction(for: requestedSkillId) else {
            return payload
        }
        var normalized = payload
        normalized["action"] = .string(inferredAction)
        return normalized
    }

    private func inferredGuardedAutomationAction(for requestedSkillId: String) -> String? {
        switch AXSkillsLibrary.canonicalSupervisorSkillID(requestedSkillId).lowercased() {
        case "browser.open", "browser_open":
            return "open"
        case "browser.navigate", "browser_navigate":
            return "navigate"
        case "browser.runtime.inspect", "browser_runtime.inspect":
            return "snapshot"
        default:
            return nil
        }
    }

    private func preferredSupervisorBuiltinSkillID(
        requestedSkillId: String,
        projectId: String?,
        projectName: String?,
        registrySnapshot: SupervisorSkillRegistrySnapshot? = nil,
        registryItem: SupervisorSkillRegistryItem? = nil
    ) -> String? {
        let canonicalSkillId = AXSkillsLibrary.canonicalSupervisorSkillID(requestedSkillId)
        guard preferredBuiltinSkillCompatibilityToken(for: canonicalSkillId) == "governed_browser_automation" else {
            return nil
        }

        let snapshot = registrySnapshot ?? AXSkillsLibrary.supervisorSkillRegistrySnapshot(
            projectId: projectId ?? "",
            projectName: firstNonEmptyString(projectName),
            hubBaseDir: HubPaths.baseDir()
        )
        let preferredBuiltinId = "guarded-automation"
        let canonicalRegistryItemId = AXSkillsLibrary.canonicalSupervisorSkillID(registryItem?.skillId ?? "")
        if canonicalRegistryItemId == preferredBuiltinId {
            return preferredBuiltinId
        }
        guard snapshot?.items.contains(where: {
            AXSkillsLibrary.canonicalSupervisorSkillID($0.skillId) == preferredBuiltinId
        }) == true else {
            return nil
        }
        return preferredBuiltinId
    }

    private func supervisorWorkflowSkillIDsAreCompatible(
        expectedSkillId: String,
        requestedSkillId: String
    ) -> Bool {
        let canonicalExpected = AXSkillsLibrary.canonicalSupervisorSkillID(expectedSkillId)
        let canonicalRequested = AXSkillsLibrary.canonicalSupervisorSkillID(requestedSkillId)
        guard !canonicalExpected.isEmpty, !canonicalRequested.isEmpty else { return false }
        if canonicalExpected == canonicalRequested {
            return true
        }
        return supervisorWorkflowSkillCompatibilityToken(canonicalExpected)
            == supervisorWorkflowSkillCompatibilityToken(canonicalRequested)
    }

    private func supervisorWorkflowSkillCompatibilityToken(_ canonicalSkillId: String) -> String {
        preferredBuiltinSkillCompatibilityToken(for: canonicalSkillId)
    }

    private func preferredBuiltinSkillCompatibilityToken(for canonicalSkillId: String) -> String {
        switch canonicalSkillId {
        case "agent-browser", "guarded-automation", "browser.open", "browser_open", "browser.navigate", "browser_navigate", "browser.runtime.inspect", "browser_runtime.inspect":
            return "governed_browser_automation"
        default:
            return canonicalSkillId
        }
    }

    private func resolvedGovernedDispatchPayloadValue(
        payload: [String: JSONValue],
        canonicalKey: String,
        aliases: [String]
    ) -> JSONValue? {
        let candidates = [canonicalKey] + aliases
        for candidate in candidates {
            let key = candidate.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !key.isEmpty else { continue }
            guard let value = payload[key], governedDispatchHasValue(value) else { continue }
            return value
        }
        return nil
    }

    private func governedDispatchHasValue(_ value: JSONValue?) -> Bool {
        guard let value else { return false }
        switch value {
        case .null:
            return false
        case .string(let string):
            return !string.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        case .array(let array):
            return !array.isEmpty
        case .object(let object):
            return !object.isEmpty
        case .number, .bool:
            return true
        }
    }

    private func governedDispatchMissingReasonCode(for group: [String]) -> String {
        let normalized = group
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() }
            .filter { !$0.isEmpty }
        if normalized.count == 1, let first = normalized.first {
            return "payload.\(first)_missing"
        }
        return "payload.required_args_missing"
    }

    private func governedDispatchExclusiveReasonCode(for group: [String], presentCount: Int) -> String {
        let normalized = group
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() }
            .filter { !$0.isEmpty }
        let sourceGroup = Set(["url", "path", "text"])
        if Set(normalized) == sourceGroup {
            return presentCount == 0 ? "payload.source_missing" : "payload.multiple_sources"
        }
        if normalized.count == 1, let first = normalized.first {
            return "payload.\(first)_missing"
        }
        return presentCount == 0 ? "payload.required_args_missing" : "payload.mutually_exclusive_args"
    }

