    private func mappedSupervisorAgentBrowserDispatch(
        payload: [String: JSONValue],
        requestId: String
    ) -> Result<SupervisorMappedSkillDispatch, SupervisorSkillMappingFailure> {
        let requestedAction = firstNonEmptyString(
            payload["action"]?.stringValue,
            payload["operation"]?.stringValue,
            payload["mode"]?.stringValue
        )?
        .trimmingCharacters(in: .whitespacesAndNewlines)
        .lowercased() ?? ""
        let url = payload["url"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let sessionId = payload["session_id"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""

        let action: String
        if requestedAction.isEmpty {
            if !url.isEmpty {
                action = "open_url"
            } else if !sessionId.isEmpty {
                action = "snapshot"
            } else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.action_missing"))
            }
        } else {
            action = requestedAction
        }

        switch action {
        case "open", "open_url", "navigate", "goto", "visit":
            guard !url.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_missing"))
            }
            let runtimeAction = action == "navigate" || action == "goto" || action == "visit"
                ? "navigate"
                : "open_url"
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: mappedSupervisorAgentBrowserRuntimeArgs(
                        payload: payload,
                        action: runtimeAction
                    )
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "snapshot", "inspect":
            guard !url.isEmpty || !sessionId.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_or_session_id_missing"))
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: mappedSupervisorAgentBrowserRuntimeArgs(
                        payload: payload,
                        action: "snapshot"
                    )
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "extract":
            guard !url.isEmpty || !sessionId.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_or_session_id_missing"))
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: mappedSupervisorAgentBrowserRuntimeArgs(
                        payload: payload,
                        action: "extract"
                    )
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "read", "read_page", "read-page", "fetch":
            guard !url.isEmpty else {
                return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.url_missing"))
            }
            var args: [String: JSONValue] = ["url": .string(url)]
            for key in ["grant_id", "timeout_sec", "max_bytes"] {
                if let value = payload[key] {
                    args[key] = value
                }
            }
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(id: requestId, tool: .browser_read, args: args),
                toolName: ToolName.browser_read.rawValue
            ))
        case "click", "tap":
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: mappedSupervisorAgentBrowserRuntimeArgs(
                        payload: payload,
                        action: "click"
                    )
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "type", "fill", "input", "enter":
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: mappedSupervisorAgentBrowserRuntimeArgs(
                        payload: payload,
                        action: "type"
                    )
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        case "upload", "attach":
            return .success(SupervisorMappedSkillDispatch(
                toolCall: ToolCall(
                    id: requestId,
                    tool: .deviceBrowserControl,
                    args: mappedSupervisorAgentBrowserRuntimeArgs(
                        payload: payload,
                        action: "upload"
                    )
                ),
                toolName: ToolName.deviceBrowserControl.rawValue
            ))
        default:
            return .failure(SupervisorSkillMappingFailure(reasonCode: "payload.action_unsupported"))
        }
    }

    private func mappedSupervisorAgentBrowserRuntimeArgs(
        payload: [String: JSONValue],
        action: String
    ) -> [String: JSONValue] {
        var args: [String: JSONValue] = ["action": .string(action)]
        for key in [
            "url",
            "session_id",
            "selector",
            "field_role",
            "text",
            "content",
            "value",
            "secret_item_id",
            "secret_scope",
            "secret_name",
            "secret_project_id",
            "path",
            "grant_id",
            "timeout_sec",
            "max_bytes",
        ] {
            if let value = payload[key] {
                args[key] = value
            }
        }
        return args
    }

    private func mappedSupervisorSelfImprovingAgentDispatch(
        payload: [String: JSONValue],
        requestId: String
    ) -> Result<SupervisorMappedSkillDispatch, SupervisorSkillMappingFailure> {
        var args: [String: JSONValue] = [
            "mode": .string(XTMemoryUseMode.supervisorOrchestration.rawValue),
            "retrospective": .bool(true)
        ]

        if let focus = firstNonEmptyString(
            payload["focus"]?.stringValue,
            payload["goal"]?.stringValue,
            payload["topic"]?.stringValue
        )?.trimmingCharacters(in: .whitespacesAndNewlines),
           !focus.isEmpty {
            args["focus"] = .string(focus)
        }

        if let value = payload["limit"] ?? payload["max_results"] ?? payload["top_n"] {
            args["limit"] = value
        }

        for key in [
            "project_id",
            "include_doctor",
            "include_incidents",
            "include_skill_calls",
            "include_plan",
            "include_memory",
        ] {
            if let value = payload[key] {
                args[key] = value
            }
        }

        return .success(SupervisorMappedSkillDispatch(
            toolCall: ToolCall(id: requestId, tool: .memory_snapshot, args: args),
            toolName: ToolName.memory_snapshot.rawValue
        ))
    }

    private func supervisorValidatedRepoCommand(
        _ raw: String,
        profile: XTGovernedRepoCommandProfile
    ) -> String? {
        xtValidateGovernedRepoCommand(raw, profile: profile)
    }

    private func firstNonEmptyString(_ values: String?...) -> String? {
        for value in values {
            let trimmed = (value ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty {
                return trimmed
            }
        }
        return nil
    }

    private func supervisorSkillMappingFailureSummary(_ failure: SupervisorSkillMappingFailure) -> String {
        switch failure.reasonCode {
        case "payload.command_not_allowed":
            return "repo command rejected by governed allowlist"
        case "payload.command_missing":
            return "payload.command missing"
        case "payload.action_missing":
            return "payload.action missing"
        case "payload.action_unsupported":
            return "unsupported browser action requested"
        case "payload.content_missing":
            return "payload.content missing"
        case "payload.patch_missing":
            return "payload.patch missing"
        case "payload.path_missing":
            return "payload.path missing"
        case "payload.query_missing":
            return "payload.query missing"
        case "payload.source_missing":
            return "payload source missing"
        case "payload.multiple_sources":
            return "multiple payload sources provided"
        case "payload.url_missing":
            return "payload.url missing"
        case "payload.url_or_session_id_missing":
            return "payload.url or payload.session_id missing"
        default:
            return "skill mapping unavailable"
        }
    }

    private func supervisorSkillMappingFailureMessage(
        displaySkill: String,
        failure: SupervisorSkillMappingFailure
    ) -> String {
        switch failure.reasonCode {
        case "unsupported_skill_id":
            return "❌ CALL_SKILL 失败：技能 \(displaySkill) 还没有接到受治理 runtime（skill_mapping_missing）"
        case "payload.command_not_allowed":
            return "❌ CALL_SKILL 失败：技能 \(displaySkill) 请求的命令不在受治理 allowlist 内（payload.command_not_allowed）"
        default:
            return "❌ CALL_SKILL 失败：技能 \(displaySkill) payload 校验失败（\(failure.reasonCode)）"
        }
    }

    private func appendSupervisorSkillCallRawLog(
        action: String,
        record: SupervisorSkillCallRecord,
        toolCall: ToolCall?,
        triggerSource: SupervisorCommandTriggerSource,
        ctx: AXProjectContext
    ) {
        var row: [String: Any] = [
            "type": "supervisor_skill_call",
            "action": action,
            "schema_version": SupervisorSkillCallRecord.currentSchemaVersion,
            "request_id": record.requestId,
            "project_id": record.projectId,
            "job_id": record.jobId,
            "plan_id": record.planId,
            "step_id": record.stepId,
            "skill_id": record.skillId,
            "tool_name": record.toolName,
            "status": record.status.rawValue,
            "current_owner": record.currentOwner,
            "trigger_source": triggerSource.rawValue,
            "audit_ref": record.auditRef,
            "timestamp_ms": record.updatedAtMs
        ]
        if !record.resultSummary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            row["result_summary"] = record.resultSummary
        }
        if let requestedSkillId = record.requestedSkillId?.trimmingCharacters(in: .whitespacesAndNewlines),
           !requestedSkillId.isEmpty {
            row["requested_skill_id"] = requestedSkillId
        }
        if let routingReasonCode = record.routingReasonCode?.trimmingCharacters(in: .whitespacesAndNewlines),
           !routingReasonCode.isEmpty {
            row["routing_reason_code"] = routingReasonCode
        }
        if let routingExplanation = record.routingExplanation?.trimmingCharacters(in: .whitespacesAndNewlines),
           !routingExplanation.isEmpty {
            row["routing_explanation"] = routingExplanation
        }
        if !record.denyCode.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            row["deny_code"] = record.denyCode
        }
        if let policySource = record.policySource?.trimmingCharacters(in: .whitespacesAndNewlines),
           !policySource.isEmpty {
            row["policy_source"] = policySource
        }
        if let policyReason = record.policyReason?.trimmingCharacters(in: .whitespacesAndNewlines),
           !policyReason.isEmpty {
            row["policy_reason"] = policyReason
        }
        if let resultEvidenceRef = record.resultEvidenceRef?.trimmingCharacters(in: .whitespacesAndNewlines),
           !resultEvidenceRef.isEmpty {
            row["result_evidence_ref"] = resultEvidenceRef
        }
        if let capability = record.requiredCapability?.trimmingCharacters(in: .whitespacesAndNewlines),
           !capability.isEmpty {
            row["required_capability"] = capability
        }
        if let grantRequestId = record.grantRequestId?.trimmingCharacters(in: .whitespacesAndNewlines),
           !grantRequestId.isEmpty {
            row["grant_request_id"] = grantRequestId
        }
        if let grantId = record.grantId?.trimmingCharacters(in: .whitespacesAndNewlines),
           !grantId.isEmpty {
            row["grant_id"] = grantId
        }
        if let toolCall {
            row["tool"] = toolCall.tool.rawValue
            row["tool_args"] = foundationJSONObject(from: toolCall.args)
        }
        AXProjectStore.appendRawLog(row, for: ctx)
    }

    private func appendSupervisorSkillResultRawLog(
        record: SupervisorSkillCallRecord,
        toolCall: ToolCall?,
        rawOutput: String?,
        triggerSource: SupervisorCommandTriggerSource,
        ctx: AXProjectContext
    ) {
        var row: [String: Any] = [
            "type": "supervisor_skill_result",
            "schema_version": SupervisorSkillResultEvidence.currentSchemaVersion,
            "request_id": record.requestId,
            "project_id": record.projectId,
            "job_id": record.jobId,
            "plan_id": record.planId,
            "step_id": record.stepId,
            "skill_id": record.skillId,
            "tool_name": record.toolName,
            "status": record.status.rawValue,
            "result_summary": record.resultSummary,
            "deny_code": record.denyCode,
            "trigger_source": triggerSource.rawValue,
            "audit_ref": record.auditRef,
            "updated_at_ms": record.updatedAtMs
        ]
        if let resultEvidenceRef = record.resultEvidenceRef?.trimmingCharacters(in: .whitespacesAndNewlines),
           !resultEvidenceRef.isEmpty {
            row["result_evidence_ref"] = resultEvidenceRef
            let normalizedOutput = (rawOutput ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
            if !normalizedOutput.isEmpty {
                row["raw_output_ref"] = "\(resultEvidenceRef)#raw_output"
                row["raw_output_chars"] = normalizedOutput.count
            }
        }
        if let uiReviewAgentEvidenceRef = supervisorUIReviewAgentEvidenceRef(from: rawOutput) {
            row["ui_review_agent_evidence_ref"] = uiReviewAgentEvidenceRef
        }
        if let requestedSkillId = record.requestedSkillId?.trimmingCharacters(in: .whitespacesAndNewlines),
           !requestedSkillId.isEmpty {
            row["requested_skill_id"] = requestedSkillId
        }
        if let routingReasonCode = record.routingReasonCode?.trimmingCharacters(in: .whitespacesAndNewlines),
           !routingReasonCode.isEmpty {
            row["routing_reason_code"] = routingReasonCode
        }
        if let routingExplanation = record.routingExplanation?.trimmingCharacters(in: .whitespacesAndNewlines),
           !routingExplanation.isEmpty {
            row["routing_explanation"] = routingExplanation
        }
        if let policySource = record.policySource?.trimmingCharacters(in: .whitespacesAndNewlines),
           !policySource.isEmpty {
            row["policy_source"] = policySource
        }
        if let policyReason = record.policyReason?.trimmingCharacters(in: .whitespacesAndNewlines),
           !policyReason.isEmpty {
            row["policy_reason"] = policyReason
        }
        if let capability = record.requiredCapability?.trimmingCharacters(in: .whitespacesAndNewlines),
           !capability.isEmpty {
            row["required_capability"] = capability
        }
        if let toolCall {
            row["tool"] = toolCall.tool.rawValue
            row["tool_args"] = foundationJSONObject(from: toolCall.args)
        }
        appendGovernanceTruthSnapshot(to: &row, rawOutput: rawOutput)
        AXProjectStore.appendRawLog(row, for: ctx)
    }

    private func supervisorUIReviewAgentEvidenceRef(
        from output: String?
    ) -> String? {
        guard let summary = structuredToolSummaryObject(from: output) else { return nil }
        let candidate = [
            summary["ui_review_agent_evidence_ref"]?.stringValue,
            summary["browser_runtime_ui_review_agent_evidence_ref"]?.stringValue
        ]
        .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
        .first(where: { !$0.isEmpty })
        return candidate
    }

    private func appendGovernanceTruthSnapshot(
        to row: inout [String: Any],
        rawOutput: String?
    ) {
        guard let summary = structuredToolSummaryObject(from: rawOutput) else { return }
        for (key, value) in XTGovernanceTruthPresentation.snapshotFields(from: summary) {
            row[key] = foundationValue(from: value)
        }
    }

    private func structuredToolSummaryObject(
        from output: String?
    ) -> [String: JSONValue]? {
        let normalizedOutput = (output ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedOutput.isEmpty else { return nil }
        let parsed = ToolExecutor.parseStructuredToolOutput(normalizedOutput)
        guard case .object(let summary)? = parsed.summary else { return nil }
        return summary
    }

    private func supervisorUIReviewAgentEvidenceRef(
        requestId: String,
        ctx: AXProjectContext
    ) -> String? {
        let normalizedRequestId = requestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedRequestId.isEmpty,
              let evidence = SupervisorSkillResultEvidenceStore.load(requestId: normalizedRequestId, for: ctx) else {
            return nil
        }
        return [
            evidence.uiReviewAgentEvidenceRef,
            supervisorUIReviewAgentEvidenceRef(from: evidence.rawOutput),
            supervisorUIReviewAgentEvidenceRef(from: evidence.rawOutputPreview)
        ]
        .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
        .first(where: { !$0.isEmpty })
    }

    private func supervisorUIReviewAgentEvidenceSnapshot(
        requestId: String,
        ctx: AXProjectContext
    ) -> XTUIReviewAgentEvidenceSnapshot? {
        guard let ref = supervisorUIReviewAgentEvidenceRef(requestId: requestId, ctx: ctx) else {
            return nil
        }
        return XTUIReviewAgentEvidenceStore.load(ref: ref, for: ctx)
    }

    private func supervisorSkillCallbackUIReviewExtraLines(
        requestId: String,
        ctx: AXProjectContext
    ) -> [String] {
        guard let ref = supervisorUIReviewAgentEvidenceRef(requestId: requestId, ctx: ctx),
              let snapshot = XTUIReviewAgentEvidenceStore.load(ref: ref, for: ctx) else {
            return []
        }

        let issueCodes = snapshot.issueCodes.isEmpty
            ? "(none)"
            : snapshot.issueCodes.joined(separator: ",")
        var lines = [
            "ui_review_agent_evidence_ref=\(ref)",
            "ui_review_verdict=\(snapshot.verdict.rawValue)",
            "ui_review_confidence=\(snapshot.confidence.rawValue)",
            "ui_review_objective_ready=\(snapshot.objectiveReady)",
            "ui_review_sufficient_evidence=\(snapshot.sufficientEvidence)",
            "ui_review_issue_codes=\(issueCodes)",
            "ui_review_summary=\(capped(snapshot.summary, maxChars: 220))"
        ]
        if let guidance = SupervisorUIReviewRepairPlanner.guidance(for: snapshot) {
            lines.append("ui_review_repair_action=\(guidance.actionCode)")
            lines.append("ui_review_repair_focus=\(guidance.focusArea)")
            lines.append("ui_review_repair_summary=\(capped(guidance.summary, maxChars: 220))")
            lines.append("ui_review_repair_prompt=\(capped(guidance.prompt, maxChars: 260))")
        }
        if let trend = snapshot.trend.first(where: { $0.lowercased().contains("status=") }) {
            lines.append("ui_review_trend=\(trend)")
        }
        if supervisorShouldRouteToUIReview(snapshot) {
            lines.append("next_safe_action=open_ui_review")
        }
        return lines
    }

    private func supervisorShouldRouteToUIReview(
        requestId: String,
        ctx: AXProjectContext
    ) -> Bool {
        guard let snapshot = supervisorUIReviewAgentEvidenceSnapshot(requestId: requestId, ctx: ctx) else {
            return false
        }
        return supervisorShouldRouteToUIReview(snapshot)
    }

    private func supervisorShouldRouteToUIReview(
        _ snapshot: XTUIReviewAgentEvidenceSnapshot
    ) -> Bool {
        if snapshot.verdict != .ready {
            return true
        }
        if !snapshot.objectiveReady || !snapshot.sufficientEvidence {
            return true
        }

        let issueCodes = Set(
            snapshot.issueCodes.map {
                $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            }
        )
        if issueCodes.contains("critical_action_not_visible") ||
            issueCodes.contains("interactive_target_missing") {
            return true
        }

        return snapshot.trend.contains(where: {
            $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased().contains("status=regressed")
        })
    }

    private func supervisorToolResultPolicyContext(
        from output: String
    ) -> (denyCode: String, policySource: String, policyReason: String) {
        let parsed = ToolExecutor.parseStructuredToolOutput(output)
        guard case .object(let summary)? = parsed.summary else {
            return ("", "", "")
        }
        let denyCode = normalizedSupervisorSkillPolicyScalar(summary["deny_code"]?.stringValue) ?? ""
        let policySource = normalizedSupervisorSkillPolicyScalar(summary["policy_source"]?.stringValue) ?? ""
        let runtimeSurfacePolicyReason = normalizedSupervisorSkillPolicyScalar(
            summary["runtime_surface_policy_reason"]?.stringValue
        ) ?? ""
        let policyReason = !runtimeSurfacePolicyReason.isEmpty
            ? runtimeSurfacePolicyReason
            : (normalizedSupervisorSkillPolicyScalar(summary["policy_reason"]?.stringValue) ?? "")
        return (denyCode, policySource, policyReason)
    }

    private func summarizedSupervisorSkillOutput(
        _ output: String,
        ok: Bool,
        toolCall: ToolCall? = nil
    ) -> String {
        let trimmed = output.trimmingCharacters(in: .whitespacesAndNewlines)
        if let toolCall {
            let toolResult = ToolResult(
                id: toolCall.id,
                tool: toolCall.tool,
                ok: ok,
                output: output
            )
            if let specialized = ToolResultHumanSummary.specializedSummary(for: toolResult) {
                return capped(
                    "\(toolCall.tool.rawValue) \(ok ? "completed" : "failed"): \(specialized)",
                    maxChars: 320
                )
            }
            switch toolCall.tool {
            case .write_file:
                let path = toolCall.args["path"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if ok, trimmed == "ok" {
                    return capped("write_file completed: \(path)", maxChars: 320)
                }
                if !trimmed.isEmpty {
                    return capped("write_file \(ok ? "completed" : "failed"): \(path)\n\(trimmed)", maxChars: 320)
                }
            case .delete_path:
                let path = toolCall.args["path"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if ok, trimmed.hasPrefix("{") || trimmed.hasPrefix("delete_path") {
                    return capped("delete_path completed: \(path)", maxChars: 320)
                }
                if !trimmed.isEmpty {
                    return capped("delete_path \(ok ? "completed" : "failed"): \(path)\n\(trimmed)", maxChars: 320)
                }
            case .move_path:
                let fromPath = toolCall.args["from"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                let toPath = toolCall.args["to"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if ok, trimmed.hasPrefix("{") || trimmed.hasPrefix("move_path") {
                    return capped("move_path completed: \(fromPath) -> \(toPath)", maxChars: 320)
                }
                if !trimmed.isEmpty {
                    return capped("move_path \(ok ? "completed" : "failed"): \(fromPath) -> \(toPath)\n\(trimmed)", maxChars: 320)
                }
            case .run_command:
                let command = toolCall.args["command"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if ok, trimmed.hasPrefix("exit: 0") {
                    return capped("run_command completed: \(command)", maxChars: 320)
                }
                if !trimmed.isEmpty {
                    return capped("run_command \(ok ? "completed" : "failed"): \(command)\n\(trimmed)", maxChars: 320)
                }
            case .git_commit:
                let message = toolCall.args["message"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if !trimmed.isEmpty {
                    return capped("git_commit \(ok ? "completed" : "failed"): \(message)\n\(trimmed)", maxChars: 320)
                }
            case .git_push:
                let remote = toolCall.args["remote"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(default)"
                let branch = toolCall.args["branch"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(default)"
                if !trimmed.isEmpty {
                    return capped("git_push \(ok ? "completed" : "failed"): \(remote) \(branch)\n\(trimmed)", maxChars: 320)
                }
            case .process_start:
                let processId = firstNonEmptyString(
                    toolCall.args["process_id"]?.stringValue,
                    toolCall.args["name"]?.stringValue
                ) ?? "(none)"
                if !trimmed.isEmpty {
                    return capped("process_start \(ok ? "completed" : "failed"): \(processId)\n\(trimmed)", maxChars: 320)
                }
            case .process_status:
                let processId = toolCall.args["process_id"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "all"
                if !trimmed.isEmpty {
                    return capped("process_status \(ok ? "completed" : "failed"): \(processId)\n\(trimmed)", maxChars: 320)
                }
            case .process_logs:
                let processId = toolCall.args["process_id"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if !trimmed.isEmpty {
                    return capped("process_logs \(ok ? "completed" : "failed"): \(processId)\n\(trimmed)", maxChars: 320)
                }
            case .process_stop:
                let processId = toolCall.args["process_id"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if !trimmed.isEmpty {
                    return capped("process_stop \(ok ? "completed" : "failed"): \(processId)\n\(trimmed)", maxChars: 320)
                }
            case .pr_create:
                let title = toolCall.args["title"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(fill)"
                if !trimmed.isEmpty {
                    return capped("pr_create \(ok ? "completed" : "failed"): \(title)\n\(trimmed)", maxChars: 320)
                }
            case .ci_read:
                let workflow = toolCall.args["workflow"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(all)"
                if !trimmed.isEmpty {
                    return capped("ci_read \(ok ? "completed" : "failed"): \(workflow)\n\(trimmed)", maxChars: 320)
                }
            case .ci_trigger:
                let workflow = toolCall.args["workflow"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                if !trimmed.isEmpty {
                    return capped("ci_trigger \(ok ? "completed" : "failed"): \(workflow)\n\(trimmed)", maxChars: 320)
                }
            case .git_apply:
                let patchChars = toolCall.args["patch"]?.stringValue?.count ?? 0
                if ok, trimmed.hasPrefix("exit: 0") {
                    return capped("git_apply completed: patch_chars=\(patchChars)", maxChars: 320)
                }
                if !trimmed.isEmpty {
                    return capped("git_apply \(ok ? "completed" : "failed"): patch_chars=\(patchChars)\n\(trimmed)", maxChars: 320)
                }
            case .skills_search:
                let query = toolCall.args["query"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                let parsed = ToolExecutor.parseStructuredToolOutput(output)
                if case .object(let summary)? = parsed.summary,
                   case .number(let count)? = summary["results_count"] {
                    return capped("skills.search completed: \(query) (\(Int(count)) results)", maxChars: 320)
                }
                if !trimmed.isEmpty {
                    return capped("skills.search \(ok ? "completed" : "failed"): \(query)\n\(trimmed)", maxChars: 320)
                }
            case .agentImportRecord:
                let stagingId = toolCall.args["staging_id"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "(none)"
                let parsed = ToolExecutor.parseStructuredToolOutput(output)
                if case .object(let summary)? = parsed.summary,
                   case .string(let vetterStatus)? = summary["vetter_status"] {
                    let warnCount = {
                        if case .number(let value)? = summary["vetter_warn_count"] {
                            return Int(value)
                        }
                        return 0
                    }()
                    let criticalCount = {
                        if case .number(let value)? = summary["vetter_critical_count"] {
                            return Int(value)
                        }
                        return 0
                    }()
                    return capped(
                        "agent.import.record \(ok ? "completed" : "failed"): \(stagingId) vetter=\(vetterStatus) c\(criticalCount)/w\(warnCount)",
                        maxChars: 320
                    )
                }
                if !trimmed.isEmpty {
                    return capped("agent.import.record \(ok ? "completed" : "failed"): \(stagingId)\n\(trimmed)", maxChars: 320)
                }
            case .summarize:
                let source = firstNonEmptyString(
                    toolCall.args["url"]?.stringValue,
                    toolCall.args["path"]?.stringValue,
                    toolCall.args["text"]?.stringValue
                ) ?? "(inline)"
                if !trimmed.isEmpty {
                    return capped("summarize \(ok ? "completed" : "failed"): \(source)\n\(trimmed)", maxChars: 320)
                }
            case .supervisorVoicePlayback:
                let action = toolCall.args["action"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "status"
                if !trimmed.isEmpty {
                    return capped("supervisor.voice.playback \(ok ? "completed" : "failed"): \(action)\n\(trimmed)", maxChars: 320)
                }
            case .memory_snapshot:
                let parsed = ToolExecutor.parseStructuredToolOutput(output)
                if case .object(let summary)? = parsed.summary,
                   case .string(let profile)? = summary["analysis_profile"],
                   profile == "self_improvement" {
                    let focus = summary["focus"]?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                    let label = focus.isEmpty ? "self_improvement" : "self_improvement: \(focus)"
                    if case .number(let count)? = summary["recommendation_count"] {
                        return capped("\(label) \(ok ? "completed" : "failed"): \(Int(count)) recommendations", maxChars: 320)
                    }
                    return capped("\(label) \(ok ? "completed" : "failed")", maxChars: 320)
                }
            default:
                break
            }
        }
        guard !trimmed.isEmpty else {
            return ok ? "tool execution completed" : "tool execution failed"
        }
        return capped(trimmed, maxChars: 320)
    }

    private func isSupervisorSkillCanceled(requestId: String, ctx: AXProjectContext) -> Bool {
        SupervisorProjectSkillCallStore.load(for: ctx).calls.first(where: { $0.requestId == requestId })?.status == .canceled
    }

    private func foundationJSONObject(from object: [String: JSONValue]) -> [String: Any] {
        object.reduce(into: [String: Any]()) { partial, item in
            partial[item.key] = foundationValue(from: item.value)
        }
    }

    private func foundationValue(from value: JSONValue) -> Any {
        switch value {
        case .string(let string):
            return string
        case .number(let number):
            return number
        case .bool(let bool):
            return bool
        case .object(let object):
            return foundationJSONObject(from: object)
        case .array(let array):
            return array.map { foundationValue(from: $0) }
        case .null:
            return NSNull()
        }
    }

    private func derivedPlanStatus(from steps: [SupervisorPlanStepRecord]) -> SupervisorPlanStatus {
        let statuses = steps.map(\.status)
        if statuses.isEmpty || statuses.allSatisfy({ $0 == .pending }) {
            return .planning
        }
        if statuses.contains(.awaitingAuthorization) {
            return .awaitingAuthorization
        }
        if statuses.contains(.blocked) {
            return .blocked
        }
        if statuses.allSatisfy({ $0 == .completed }) {
            return .completed
        }
        if statuses.contains(.failed) {
            return .failed
        }
        if statuses.allSatisfy({ $0 == .canceled }) {
            return .canceled
        }
        return .active
    }

    private func derivedJobStatus(from plan: SupervisorPlanRecord) -> SupervisorJobStatus {
        switch plan.status {
        case .planning:
            return .planning
        case .active:
            return .running
        case .blocked:
            return .blocked
        case .awaitingAuthorization:
            return .awaitingAuthorization
        case .completed:
            return .completed
        case .failed:
            return .failed
        case .canceled:
            return .canceled
        }
    }

