        let goal = intake.track == "网页版"
            ? "交付一个最小可运行的网页版本：\(project.displayName)"
            : "交付一个最小可运行的版本：\(project.displayName)"
        let doneDefinition: String
        let approvedTechStack: [String]
        switch intake.track {
