                ),
                SupervisorUpsertPlanStepPayload(
                    stepId: "step-002",
                    title: "搭建最小可运行骨架",
                    kind: SupervisorPlanStepKind.launchRun.rawValue,
                    status: SupervisorPlanStepStatus.pending.rawValue,
                    skillId: nil,
                    currentOwner: "coder",
