        _ governance: SupervisorProjectDigestGovernanceContext
    ) -> String {
        guard let resolved = governance.resolvedGovernance else {
            return "(none)"
        }
        let adaptation = resolved.supervisorAdaptation
        return focusedSupervisorJoinedValueList(
