    private func resolveSupervisorPersonaSelection(
        for userMessage: String,
        applySideEffects: Bool
    ) -> SupervisorPersonaSelection {
        let registry = currentSupervisorPersonaRegistry()
        let fallbackPersona = currentSupervisorExecutionPersona(registry: registry)
        let resolution = SupervisorPersonaResolver().resolve(
            userMessage: userMessage,
            registry: registry,
            fallbackPersonaID: fallbackPersona.personaID,
            updatedAtMs: Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        )
        if applySideEffects {
            applySupervisorPersonaResolution(resolution)
        }
        return SupervisorPersonaSelection(
            executionPersona: resolution.persona,
            resolution: resolution
        )
    }

    private func resolveSupervisorPersonaSelectionForWakePhrase(
        _ phrase: String,
        applySideEffects: Bool,
        timestamp: Double = Date().timeIntervalSince1970
    ) -> SupervisorPersonaSelection {
        let registry = currentSupervisorPersonaRegistry()
        let fallbackPersona = currentSupervisorExecutionPersona(registry: registry)
        let resolution = SupervisorPersonaResolver().resolveWakePhrase(
            phrase: phrase,
            registry: registry,
            fallbackPersonaID: fallbackPersona.personaID,
            updatedAtMs: Int64((timestamp * 1000.0).rounded())
        )
        if applySideEffects {
            applySupervisorPersonaResolution(resolution)
        }
        return SupervisorPersonaSelection(
            executionPersona: resolution.persona,
            resolution: resolution
        )
    }

    private func applySupervisorPersonaResolution(_ resolution: SupervisorPersonaResolution) {
        guard let invocation = resolution.invocation else {
            refreshSupervisorPersonaStatusLine(resolution: resolution)
            return
        }

        switch invocation.applyScope {
        case .turn:
            break
        case .session:
            supervisorSessionPersonaIDOverride = resolution.persona.personaID
        case .persistedDefault:
            supervisorSessionPersonaIDOverride = nil
            guard let appModel else { break }
            var registry = appModel.settingsStore.settings.supervisorPersonaRegistry
            registry = registry.setting(defaultPersonaID: resolution.persona.personaID)
            registry = registry.setting(activePersonaID: resolution.persona.personaID)
            appModel.settingsStore.settings = appModel.settingsStore.settings.setting(
                supervisorPersonaRegistry: registry
            )
            appModel.settingsStore.save()
        }

        refreshSupervisorPersonaStatusLine(resolution: resolution)
    }

    private func refreshSupervisorPersonaStatusLine(
        resolution: SupervisorPersonaResolution? = nil
    ) {
        let registry = currentSupervisorPersonaRegistry()
        if let override = supervisorSessionPersonaIDOverride,
           registry.slot(for: override) == nil {
            supervisorSessionPersonaIDOverride = nil
        }

        if let resolution {
            if let invocation = resolution.invocation {
                supervisorPersonaStatusLine = "persona: \(resolution.persona.displayName) [\(invocation.applyScope.rawValue), \(invocation.matchSource.rawValue)]"
            } else {
                supervisorPersonaStatusLine = resolution.debugSummary
            }
            return
        }

        let currentPersona = currentSupervisorExecutionPersona(registry: registry)
        let scope = supervisorSessionPersonaIDOverride == nil ? "default" : "session"
        supervisorPersonaStatusLine = "persona: \(currentPersona.displayName) (\(scope))"
    }

    private func directSupervisorPersonaRoutingReplyIfApplicable(
        _ userMessage: String,
        personaSlot: SupervisorPersonaSlot
    ) -> String? {
        let normalized = normalizedSupervisorIntentText(userMessage)
        let scope = SupervisorPersonaResolver().resolve(
            userMessage: userMessage,
            registry: currentSupervisorPersonaRegistry(),
            fallbackPersonaID: personaSlot.personaID
        ).invocation?.applyScope
        guard let scope else { return nil }
        guard scope != .turn else { return nil }
        guard looksLikePurePersonaRoutingCommand(normalized) else { return nil }

        switch scope {
        case .session:
            return "接下来这个会话我会用 \(personaSlot.displayName) 的 persona 来回答；默认 persona 不变。"
        case .persistedDefault:
            return "已把默认 supervisor persona 切到 \(personaSlot.displayName)。后续未点名时会优先用这个 persona。"
        case .turn:
            return nil
        }
    }

    private func looksLikePurePersonaRoutingCommand(_ normalized: String) -> Bool {
        containsAny(
            normalized,
            [
                "接下来用", "这段对话用", "先切到", "切换到", "以后默认", "默认用",
                "设为默认", "设置为默认", "make default", "set default", "switch to",
                "talk as", "use for this chat", "use in this session"
            ]
        ) && !containsAny(
            normalized,
            [
                "进度", "状态", "卡点", "问题", "建议", "下一步", "做什么", "帮我",
                "告诉我", "why", "what", "who", "审查", "review", "continue", "推进"
            ]
        )
    }

    private func recordSupervisorReplyExecution(
        mode: SupervisorReplyExecutionMode,
        actualModelId: String?,
        requestedModelId: String? = nil,
        failureReasonCode: String? = nil
    ) {
        lastSupervisorReplyExecutionMode = mode.rawValue
        let trimmedActual = actualModelId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let trimmedRequested = requestedModelId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let normalizedFailure = normalizedSupervisorFailureReasonCode(failureReasonCode)
        switch mode {
        case .remoteModel:
            lastSupervisorActualModelId = trimmedActual
            lastSupervisorRequestedModelId = trimmedRequested
            lastSupervisorRemoteFailureReasonCode = ""
        case .hubDowngradedToLocal:
            lastSupervisorActualModelId = trimmedActual
            lastSupervisorRequestedModelId = trimmedRequested
            lastSupervisorRemoteFailureReasonCode = normalizedFailure.isEmpty
                ? "downgrade_to_local"
                : normalizedFailure
        case .idle:
            lastSupervisorActualModelId = ""
            lastSupervisorRequestedModelId = ""
            lastSupervisorRemoteFailureReasonCode = ""
        case .localFallbackAfterRemoteError:
            lastSupervisorActualModelId = trimmedActual
            if !trimmedRequested.isEmpty {
                lastSupervisorRequestedModelId = trimmedRequested
            }
            lastSupervisorRemoteFailureReasonCode = normalizedFailure
        case .localPreflight, .localDirectReply, .localDirectAction, .hubBriefProjection:
            break
        }
    }

    private func lastSupervisorActualInvocationSummary() -> String {
        let actualModelId = lastSupervisorActualModelId.trimmingCharacters(in: .whitespacesAndNewlines)
        let requestedModelId = lastSupervisorRequestedModelId.trimmingCharacters(in: .whitespacesAndNewlines)
        let failureReason = displayedSupervisorFailureReason(lastSupervisorRemoteFailureReasonCode)
        if let mismatch = currentSupervisorModelMismatchSummary(),
           !actualModelId.isEmpty {
            return "最近一次实际执行没有按当前配置模型命中；实际执行的是：\(actualModelId)\n\n\(mismatch)"
        }
        switch SupervisorReplyExecutionMode(rawValue: lastSupervisorReplyExecutionMode) ?? .idle {
        case .remoteModel:
            if actualModelId.isEmpty {
                if !requestedModelId.isEmpty {
                    return "最近一次 Supervisor 远端调用已经发生，首选模型是 \(requestedModelId)，但运行层没有回传明确的 model_id。"
                }
                return "最近一次远端调用已经发生，但运行层没有回传明确的 model_id。"
            }
            return "最近一次 Supervisor 远端调用实际返回的 model_id 是：\(actualModelId)"
        case .hubDowngradedToLocal:
            if actualModelId.isEmpty {
                if !requestedModelId.isEmpty, !failureReason.isEmpty {
                    return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但 Hub 在执行阶段因 \(failureReason) 把请求降到了本地执行；没有拿到可确认的实际 model_id。"
                }
                if !requestedModelId.isEmpty {
                    return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但 Hub 在执行阶段把请求降到了本地执行；没有拿到可确认的实际 model_id。"
                }
                return "最近一次 Supervisor 远端调用没有直接命中远端模型，而是被 Hub 在执行阶段降到了本地执行。"
            }
            if !requestedModelId.isEmpty, !failureReason.isEmpty {
                return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但 Hub 在执行阶段因 \(failureReason) 把请求降到了本地模型 \(actualModelId)。"
            }
            if !requestedModelId.isEmpty {
                return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但 Hub 在执行阶段把请求降到了本地模型 \(actualModelId)。"
            }
            return "最近一次 Supervisor 远端调用没有直接命中远端模型，而是被 Hub 在执行阶段降到了本地模型 \(actualModelId)。"
        case .localPreflight:
            return "最近一次回复属于本地预检路径，没有远端模型调用。"
        case .localDirectReply:
            return "最近一次回复属于本地直答路径，没有远端模型调用。"
        case .localDirectAction:
            return "最近一次回复属于本地直行动作路径，没有远端模型调用。"
        case .hubBriefProjection:
            return "最近一次回复属于 Hub brief 投影视图，没有远端模型调用。"
        case .localFallbackAfterRemoteError:
            if actualModelId.isEmpty {
                if !requestedModelId.isEmpty, !failureReason.isEmpty {
                    return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但因 \(failureReason) 失败，随后走了本地兜底；没有拿到可确认的实际 model_id。"
                }
                if !requestedModelId.isEmpty {
                    return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但这轮失败后走了本地兜底；没有拿到可确认的实际 model_id。"
                }
                return "最近一次尝试调用远端模型时失败，随后走了本地兜底；没有拿到可确认的实际 model_id。"
            }
            if !requestedModelId.isEmpty, !failureReason.isEmpty {
                return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，运行层返回的 actual model_id 是 \(actualModelId)，但该轮最终因 \(failureReason) 被本地兜底接管。"
            }
            if !requestedModelId.isEmpty {
                return "最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但这轮最终回复被本地回退接管；实际拿到的 model_id 是：\(actualModelId)"
            }
            return "最近一次已经触发过远端调用，但这轮最终回复被本地回退接管；实际拿到的 model_id 是：\(actualModelId)"
        case .idle:
            return "当前还没有可用的调用记录。"
        }
    }

    private func currentSupervisorModelVerificationSummary() -> String {
        let actualModelId = lastSupervisorActualModelId.trimmingCharacters(in: .whitespacesAndNewlines)
        let requestedModelId = lastSupervisorRequestedModelId.trimmingCharacters(in: .whitespacesAndNewlines)
        let failureReason = displayedSupervisorFailureReason(lastSupervisorRemoteFailureReasonCode)
        if currentSupervisorModelMismatchSummary() != nil, !actualModelId.isEmpty {
            return "未按配置模型执行。当前已记录到一次成功回复，但实际模型与当前配置不一致。"
        }
        switch SupervisorReplyExecutionMode(rawValue: lastSupervisorReplyExecutionMode) ?? .idle {
        case .remoteModel:
            if actualModelId.isEmpty {
                if !requestedModelId.isEmpty {
                    return "已触发过 Supervisor 远端调用，首选模型是 \(requestedModelId)，但运行层没有回传明确 model_id，属于已调用未精确核验。"
                }
                return "已触发过远端调用，但运行层没有回传明确 model_id，属于已调用未精确核验。"
            }
            return "已验证。最近一次可确认的远端实际 model_id 是 \(actualModelId)。"
        case .hubDowngradedToLocal:
            if !requestedModelId.isEmpty, !failureReason.isEmpty {
                return "未验证成功。最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但 Hub 在执行阶段因 \(failureReason) 把请求降到了本地。"
            }
            if actualModelId.isEmpty {
                return "未验证成功。最近一次 Supervisor 远端调用没有真正命中远端模型，而是被 Hub 在执行阶段降到了本地。"
            }
            return "未验证成功。最近一次 Supervisor 远端调用没有真正命中远端模型，而是被 Hub 在执行阶段降到了本地模型 \(actualModelId)。"
        case .localFallbackAfterRemoteError:
            if !requestedModelId.isEmpty, !failureReason.isEmpty {
                return "未验证成功。最近一次 Supervisor 远端尝试首选 \(requestedModelId)，但因 \(failureReason) 失败并由本地兜底接管。"
            }
            if actualModelId.isEmpty {
                return "未验证成功。系统尝试过远端调用，但本地回退接管了最终回复，而且没有拿到可确认的实际 model_id。"
            }
            return "部分验证。远端曾被触发，且拿到 model_id=\(actualModelId)，但那轮最终回复被本地回退接管。"
        case .localPreflight, .localDirectReply, .localDirectAction, .hubBriefProjection, .idle:
            return "未验证。当前只能确认已配置好远端首选路由，但还没有一轮可确认的成功远端调用记录。"
        }
    }

    private func supervisorRemoteFailureContext(
        for error: Error,
        preferredModelId: String?
    ) -> (requestedModelId: String?, failureReasonCode: String?) {
        if let hubError = error as? HubAIError {
            switch hubError {
            case .responseDoneNotOk(let failure):
                return (
                    requestedModelId: failure.modelId?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                        ? failure.modelId
                        : preferredModelId,
                    failureReasonCode: failure.reason
                )
            case .responseTimeout:
                return (preferredModelId, "response_timeout")
            case .grpcRouteUnavailable:
                return (preferredModelId, "grpc_route_unavailable")
            case .runtimeNotRunning:
                return (preferredModelId, "runtime_not_running")
            case .requestWriteFailed:
                return (preferredModelId, "request_write_failed")
            }
        }
        return (preferredModelId, "remote_error")
    }

    private func normalizedSupervisorFailureReasonCode(_ raw: String?) -> String {
        guard let raw else { return "" }
        return raw
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
            .replacingOccurrences(of: "-", with: "_")
            .replacingOccurrences(of: " ", with: "_")
    }

    private func displayedSupervisorFailureReason(_ raw: String) -> String {
        let normalized = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        switch normalized {
        case "":
            return ""
        case "model_not_found", "remote_model_not_found":
            return "model_not_found"
        case "downgrade_to_local":
            return "downgrade_to_local"
        case "response_timeout":
            return "response_timeout"
        case "grpc_route_unavailable":
            return "grpc_route_unavailable"
        case "runtime_not_running":
            return "runtime_not_running"
        case "request_write_failed":
            return "request_write_failed"
        case "sanitized_remote_response":
            return "远端回复未通过 Supervisor 输出约束"
        case "empty_remote_response":
            return "远端回复为空"
        default:
            return normalized
        }
    }

    private func currentSupervisorModelMismatchSummary() -> String? {
        let configured = currentPreferredModelID(for: .supervisor)?
            .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let expected = resolvedPreferredSupervisorModelID(configuredModelId: configured)?
            .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let actual = lastSupervisorActualModelId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !expected.isEmpty, !actual.isEmpty else { return nil }
        guard normalizedModelIdentity(expected) != normalizedModelIdentity(actual) else { return nil }
        let configuredLabel = {
            guard !configured.isEmpty else { return expected }
            guard !expected.isEmpty, normalizedModelIdentity(configured) != normalizedModelIdentity(expected) else {
                return configured
            }
            return "\(configured)（当前对话实际请求 \(expected)）"
        }()
        switch HubAIClient.transportMode() {
        case .grpc:
            return """
当前配置首选是 \(configuredLabel)，但最近一次实际执行是 \(actual)。
XT 当前已经是 grpc-only，所以这次不一致基本不是 XT 本地 auto fallback；更可能是 Hub 端触发了 downgrade_to_local，或 Hub 的 remote_export gate 主动把 paid 请求降到了本地模型。
下一步不要再看 XT 路由设置，直接去 Hub 侧查 `ai.generate.downgraded_to_local` / `remote_export_blocked` 审计。
"""
        case .auto:
            return """
当前配置首选是 \(configuredLabel)，但最近一次实际执行是 \(actual)。
这通常表示远端 paid 路由没有真正命中，而是发生了 XT 自动回退到本地模型，或 Hub 端触发了 downgrade_to_local。
如果你要强制验证 paid GPT，请先把 Hub transport 切到 `/hub route grpc`，这样远端不可用时会直接报错，不会静默掉回本地。
"""
        case .fileIPC:
            return """
当前配置首选是 \(configuredLabel)，但最近一次实际执行是 \(actual)。
XT 当前 transport 是 fileIPC，所以这轮本来就不会强制走远端 paid GPT；请先在 Supervisor 里执行 `/hub route grpc`，再重新验证。
"""
        }
    }

    private func strictSupervisorRemoteModelMismatchResponse(
        preferredModelId: String?,
        actualModelId: String?
    ) -> String? {
        guard HubAIClient.transportMode() == .grpc else { return nil }
        let configured = preferredModelId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let actual = actualModelId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !configured.isEmpty, !actual.isEmpty else { return nil }
        guard normalizedModelIdentity(configured) != normalizedModelIdentity(actual) else { return nil }

        return """
❌ Supervisor 已拒绝接受本次回复：当前配置首选是 \(configured)，但这轮实际执行返回的是 \(actual)。

XT 当前 transport 是 grpc-only，这不属于 XT 本地 auto fallback；更可能是 Hub 端触发了 `downgrade_to_local`，或 `remote_export_blocked` 把 paid 请求降到了本地模型。
为了避免“界面选了 GPT，但实际 quietly 用本地模型继续执行”，这轮结果已按 fail-closed 丢弃。

下一步：
1. 到 Hub 审计里查 `ai.generate.downgraded_to_local`
2. 查同 request_id 对应的 `remote_export_blocked` deny_code
3. 修完 Hub export gate 后，再重试当前请求
"""
    }

    private func normalizedModelIdentity(_ raw: String) -> String {
        raw
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
            .replacingOccurrences(of: "（已加载，名称：", with: "")
            .replacingOccurrences(of: ")", with: "")
            .replacingOccurrences(of: "）", with: "")
    }

    private func currentHubTransportSummary() -> String {
        let mode = HubAIClient.transportMode()
        let decision = HubRouteStateMachine.resolve(mode: mode, hasRemoteProfile: true)
        return "\(mode.rawValue) - \(supervisorRouteDecisionText(decision))"
    }

    private func supervisorModelInventory() -> [HubModel] {
        if let models = appModel?.modelsState.models, !models.isEmpty {
            return models
        }
        if !modelManager.availableModels.isEmpty {
            return modelManager.availableModels
        }
        return []
    }

    private func resolvedPreferredSupervisorModelID(configuredModelId: String? = nil) -> String? {
        let configured = configuredModelId?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
            ? configuredModelId
            : currentPreferredModelID(for: .supervisor)
        let snapshot = ModelStateSnapshot(
            models: supervisorModelInventory(),
            updatedAt: appModel?.modelsState.updatedAt ?? Date().timeIntervalSince1970
        )
        return HubAIClient.sanitizedInteractiveGenerateModelID(
            configured,
            snapshot: snapshot,
            taskType: "supervisor"
        )
    }

    private func supervisorRetrievalModelSummary() -> String? {
        let retrievalModels = supervisorModelInventory().filter(\.isEmbeddingModel)
        guard !retrievalModels.isEmpty else { return nil }

        let ordered = retrievalModels.sorted { lhs, rhs in
            if lhs.state != rhs.state { return lhs.state == .loaded }
            return lhs.id.localizedCaseInsensitiveCompare(rhs.id) == .orderedAscending
        }

        let listed = ordered.prefix(3).map { model in
            "\(model.id) (\(model.state == .loaded ? "loaded" : "available"))"
        }
        guard !listed.isEmpty else { return nil }
        let suffix = ordered.count > listed.count ? " +\(ordered.count - listed.count) more" : ""
        return listed.joined(separator: ", ") + suffix
    }

    private func currentSupervisorModelRouteSummary() -> String {
        currentConfiguredSupervisorModelRouteSummary()
    }

    private func contextualSupervisorModelRouteSummary(
        userMessage: String,
        projects: [AXProjectEntry]
    ) -> String {
        let configuredSummary = currentConfiguredSupervisorModelRouteSummary()
        let trimmed = userMessage.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return configuredSummary }

        guard let routeContext = resolvedSupervisorModelRouteContext(
            userMessage: trimmed,
            projects: projects
        ) else {
            return configuredSummary
        }
        let intentSummary = currentSupervisorTaskIntentSummary(for: routeContext)
        return "\(configuredSummary) | \(intentSummary)"
    }

    private func currentConfiguredSupervisorModelRouteSummary() -> String {
        guard let preferred = currentPreferredModelID(for: .supervisor) else {
            return "未绑定固定 model id，当前按默认 Hub 路由执行。"
        }
        if let matched = supervisorModelInventory().first(where: {
            $0.id.compare(preferred, options: .caseInsensitive) == .orderedSame
        }) {
            if !matched.isSelectableForInteractiveRouting {
                let disabledReason = matched.interactiveRoutingDisabledReason ?? "当前 Supervisor 对话不会直接使用这个模型。"
                if let resolved = resolvedPreferredSupervisorModelID(configuredModelId: preferred),
                   !resolved.isEmpty {
                    return "\(matched.id)（非对话模型，名称：\(matched.name)；\(disabledReason) 当前 Supervisor 对话会改用 \(resolved)）"
                }
                return "\(matched.id)（非对话模型，名称：\(matched.name)；\(disabledReason) 当前 Supervisor 对话会回到默认 Hub 路由）"
            }
            let stateText: String
            switch matched.state {
            case .loaded:
                stateText = "已加载"
            case .available:
                stateText = "可用"
            case .sleeping:
                stateText = "休眠"
            }
            return "\(matched.id)（\(stateText)，名称：\(matched.name)）"
        }
        return "\(preferred)（当前 Hub 模型清单里暂未看到这个 id）"
    }

    private func supervisorRouteDiagnosisText() -> String {
        let configured = currentPreferredModelID(for: .supervisor)?
            .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let actualModelId = lastSupervisorActualModelId.trimmingCharacters(in: .whitespacesAndNewlines)
        let requestedModelId = lastSupervisorRequestedModelId.trimmingCharacters(in: .whitespacesAndNewlines)
        let failureReason = displayedSupervisorFailureReason(lastSupervisorRemoteFailureReasonCode)
        let mode = SupervisorReplyExecutionMode(rawValue: lastSupervisorReplyExecutionMode) ?? .idle
        let mismatch = currentSupervisorModelMismatchSummary()

        var lines: [String] = [
            "Supervisor route diagnose",
            "配置来源：\(configured.isEmpty ? "default auto（没有固定 model id）" : "global assignment（Supervisor 全局配置）")",
            "当前配置：\(configured.isEmpty ? "auto" : currentConfiguredSupervisorModelRouteSummary())",
            "当前 Hub transport：\(currentHubTransportSummary())",
            "最近一次执行模式：\(mode.rawValue)",
            "",
            "最近一次 Supervisor 真实记录：",
            supervisorExecutionDiagnosisSummary(
                requestedModelId: requestedModelId,
                actualModelId: actualModelId,
                failureReason: failureReason
            ),
            "",
            "当前验证状态：",
            currentSupervisorModelVerificationSummary(),
            "",
            "判定：",
            supervisorRouteDiagnosisConclusion(
                configuredModelId: configured,
                mode: mode,
                mismatchSummary: mismatch,
                failureReason: failureReason
            ),
            "",
            "提示：Supervisor 不读取 project override，也不使用 project route memory；它只看自己的全局 assignment 和当前 Hub transport。"
        ]

        if let mismatch, !mismatch.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            lines.insert("当前差异提示：\n\(mismatch)", at: 10)
            lines.insert("", at: 11)
        }

        return lines.joined(separator: "\n")
    }

    private func supervisorExecutionDiagnosisSummary(
        requestedModelId: String,
        actualModelId: String,
        failureReason: String
    ) -> String {
        let lines: [String] = [
            "- requested_model=\(requestedModelId.isEmpty ? "(none)" : requestedModelId)",
            "- actual_model=\(actualModelId.isEmpty ? "(none)" : actualModelId)",
            "- failure_reason=\(failureReason.isEmpty ? "(none)" : failureReason)"
        ]
        return lines.joined(separator: "\n")
    }

    private func supervisorRouteDiagnosisConclusion(
        configuredModelId: String,
        mode: SupervisorReplyExecutionMode,
        mismatchSummary: String?,
        failureReason: String
    ) -> String {
        switch HubAIClient.transportMode() {
        case .fileIPC:
            return "XT 当前 transport 是 fileIPC，所以 Supervisor 这轮本来就不会强制走远端。先切 `/hub route auto` 或 `/hub route grpc` 再验证。"
        case .grpc:
            if mode == .hubDowngradedToLocal {
                return "XT 当前已经是 grpc-only；最近这一轮不是 XT 本地 auto fallback，而是 Hub 在执行阶段把远端请求降到了本地。直接去 Hub 审计查 `ai.generate.downgraded_to_local` / `remote_export_blocked`。"
            }
            if let mismatchSummary, !mismatchSummary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                return mismatchSummary
            }
            if mode == .localFallbackAfterRemoteError {
                return "XT 当前已经是 grpc-only；如果这时仍出现本地接管，优先查 Hub 端的 downgrade_to_local 或 remote_export_blocked。"
            }
            if configuredModelId.isEmpty {
                return "Supervisor 当前没有固定 model id，但 XT 这层也没有 project route memory 之类的额外锁。"
            }
            return "从 XT 这层看，Supervisor 没有被本地锁住；如果后续还是没命中 GPT，更可能是 Hub 侧策略或远端配置问题。"
        case .auto:
            if mode == .hubDowngradedToLocal {
                if !failureReason.isEmpty {
                    return "最近一次 Supervisor 没有真正命中远端，而是被 Hub 在执行阶段降到了本地；当前 reason=\(failureReason)。如果你要 fail-closed 验证，请切 `/hub route grpc`。"
                }
                return "最近一次 Supervisor 没有真正命中远端，而是被 Hub 在执行阶段降到了本地。如果你要 fail-closed 验证，请切 `/hub route grpc`。"
            }
            if mode == .localFallbackAfterRemoteError {
                if !failureReason.isEmpty {
                    return "最近一次 Supervisor 远端失败后走了本地兜底，当前 reason=\(failureReason)。在 auto 模式下，这既可能是 XT auto fallback，也可能是 Hub 自己降级；想 fail-closed 验证请切 `/hub route grpc`。"
                }
                return "最近一次 Supervisor 远端失败后走了本地兜底。在 auto 模式下，这既可能是 XT auto fallback，也可能是 Hub 自己降级；想 fail-closed 验证请切 `/hub route grpc`。"
            }
            if let mismatchSummary, !mismatchSummary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                return mismatchSummary
            }
            if configuredModelId.isEmpty {
                return "Supervisor 当前没有固定 model id，XT 只会按默认 Hub 路由尝试。"
            }
            return "从 XT 这层看，Supervisor 当前没有 project 级别的额外路由干预；如果你看到异常分叉，优先对比 Project chat 那边是否有项目级 override 或 route memory 锁定。"
        }
    }

    private func resolvedRouteIntentProject(
        for userMessage: String,
        projects: [AXProjectEntry]
    ) -> AXProjectEntry? {
        let explicitRef = extractProjectReferenceForDirectAssignment(userMessage, projects: projects)
        let fallbackRef = defaultProjectReferenceForDirectAssignment(projects: projects)

        for candidate in [explicitRef, fallbackRef] {
            guard let candidate, !candidate.isEmpty else { continue }
            if case .matched(let project) = resolveProjectReference(candidate, in: projects) {
                return project
            }
        }
        return nil
    }

    private func loadRouteIntentProjectConfig(for project: AXProjectEntry) -> AXProjectConfig? {
        let root = URL(fileURLWithPath: project.rootPath, isDirectory: true)
        let ctx = AXProjectContext(root: root)
        return try? AXProjectStore.loadOrCreateConfig(for: ctx)
    }

    private func resolvedSupervisorModelRouteContext(
        userMessage: String,
        projects: [AXProjectEntry]
    ) -> SupervisorModelRouteContext? {
        let trimmed = userMessage.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }

        let routeProject = resolvedRouteIntentProject(for: trimmed, projects: projects)
        let projectConfig = routeProject.flatMap { loadRouteIntentProjectConfig(for: $0) }
        let routeDecision = inferredSupervisorRouteDecision(
            for: trimmed,
            project: routeProject,
            projectConfig: projectConfig
        )
        return SupervisorModelRouteContext(
            projectName: routeProject?.displayName,
            decision: routeDecision
        )
    }

    private func inferredSupervisorRouteDecision(
        for userMessage: String,
        project: AXProjectEntry?,
        projectConfig: AXProjectConfig?
    ) -> SupervisorModelRouteDecision {
        let normalized = normalizedSupervisorIntentText(userMessage)
        let input = SupervisorTaskRoleClassifier.Input(
            taskTags: inferredSupervisorRouteTaskTags(from: normalized),
            risk: inferredSupervisorRouteRisk(from: normalized),
            sideEffect: inferredSupervisorRouteSideEffect(from: normalized),
            codeExecution: inferredSupervisorRouteCodeExecution(from: normalized)
        )
        let projectID = project?.projectId ?? "supervisor"
        return SupervisorModelRoutePolicy.default(projectID: projectID)
            .routeDecision(for: input, projectConfig: projectConfig)
    }

    private func inferredSupervisorRouteTaskTags(from normalized: String) -> [String] {
        var tags: [String] = []

        func appendTag(_ tag: String) {
            guard !tag.isEmpty, !tags.contains(tag) else { return }
            tags.append(tag)
        }

        if containsAny(normalized, ["范围", "scope", "freeze", "冻结", "规格", "spec", "里程碑", "milestone"]) {
            appendTag("scope_freeze")
        }
        if containsAny(normalized, ["goal", "mvp", "non goal", "non-goal", "技术栈", "tech stack", "模块", "规格胶囊", "spec capsule"]) {
            appendTag("spec_capsule")
        }
        if containsAny(normalized, ["卡住", "卡在哪", "阻塞", "blocked", "决策", "decision", "选型"]) {
            appendTag("decision_blocker")
        }
        if containsAny(normalized, ["写代码", "代码", "编码", "编程", "实现", "开发", "feature", "patch"]) {
            appendTag("codegen")
        }
        if containsAny(normalized, ["重构", "重写", "refactor", "整理代码"]) {
            appendTag("refactor")
        }
        if containsAny(normalized, ["修复", "fix", "bug", "runtime", "编译错误", "build error", "报错"]) {
            appendTag("runtime_fix")
        }
        if containsAny(normalized, ["review", "审查", "审阅", "评审", "检查代码"]) {
            appendTag("review")
        }
        if containsAny(normalized, ["回归", "regression", "qa", "测试一下", "验收"]) {
            appendTag("regression")
        }
        if containsAny(normalized, ["gate", "checklist", "收口", "门禁"]) {
            appendTag("gate_review")
        }
        if containsAny(normalized, ["文档", "docs", "readme", "说明文档"]) {
            appendTag("docs")
        }
        if containsAny(normalized, ["release notes", "release note", "发版说明", "发布说明", "更新日志", "changelog"]) {
            appendTag("release_notes")
        }
        if containsAny(normalized, ["spec freeze writeup", "scope note", "冻结说明", "口径说明"]) {
            appendTag("spec_freeze_writeup")
        }
        if containsAny(normalized, ["runbook", "操作手册", "故障手册"]) {
            appendTag("runbook")
        }
        if containsAny(normalized, ["rollout", "上线", "部署", "发布到"]) {
            appendTag("rollout")
        }
        if containsAny(normalized, ["probe", "doctor", "诊断", "排查", "健康检查", "runtime probe"]) {
            appendTag("runtime_probe")
        }
        if containsAny(normalized, ["operator", "人工处理", "手工操作", "执行一下"]) {
            appendTag("operator_action")
        }

        if let explicitRole = firstExplicitRoleMention(in: normalized) {
            switch explicitRole {
            case .coder, .coarse, .refine:
                appendTag("codegen")
            case .reviewer:
                appendTag("review")
            case .advisor:
                appendTag("scope_freeze")
            case .supervisor:
                appendTag("operator_action")
            }
        }

        return tags
    }

    private func inferredSupervisorRouteRisk(from normalized: String) -> SupervisorTaskRisk {
        if containsAny(normalized, ["delete", "删除", "wipe", "drop db", "销毁", "不可逆", "irreversible"]) {
            return .critical
        }
        if containsAny(normalized, ["授权", "grant", "权限", "安全", "security", "付费", "paid", "上线", "部署", "rollout", "production", "prod", "迁移", "connector", "联网"]) {
            return .high
        }
        if containsAny(normalized, ["review", "审查", "审阅", "回归", "regression", "qa", "probe", "doctor", "诊断"]) {
            return .medium
        }
        return .low
    }

    private func inferredSupervisorRouteSideEffect(from normalized: String) -> SupervisorTaskSideEffect {
        if containsAny(normalized, ["delete", "删除", "wipe", "drop db", "销毁", "不可逆", "irreversible"]) {
            return .irreversible
        }
        if containsAny(normalized, ["上线", "部署", "rollout", "发布到", "connector", "联网", "browser", "web fetch"]) {
            return .externalWrite
        }
        if containsAny(normalized, ["probe", "doctor", "诊断", "排查", "日志", "log", "health", "审计", "audit"]) {
            return .externalRead
        }
        if containsAny(normalized, ["写代码", "代码", "编码", "编程", "实现", "开发", "修复", "fix", "bug", "重构", "refactor", "patch", "编译"]) {
            return .localMutation
        }
        return .none
    }

    private func inferredSupervisorRouteCodeExecution(from normalized: String) -> Bool {
        containsAny(
            normalized,
            ["写代码", "代码", "编码", "编程", "实现", "开发", "修复", "fix", "bug", "重构", "refactor", "patch", "编译", "build"]
        )
    }

    private func currentSupervisorTaskIntentSummary(
        for context: SupervisorModelRouteContext
    ) -> String {
        let decision = context.decision
        let preferredClasses = decision.preferredModelClasses.map(\.rawValue).joined(separator: ", ")
        let matchedSignals = decision.explainability.matchedSignals.isEmpty
            ? ["fail_closed_default:\(decision.role.rawValue)"]
            : decision.explainability.matchedSignals
        var parts = [
            "task-intent role=\(decision.role.rawValue)",
            "signals=[\(matchedSignals.joined(separator: ", "))]",
            "preferred_classes=[\(preferredClasses)]",
            "grant=\(decision.grantPolicy.rawValue)",
            "hub_gate=\(decision.hubPolicyRequired ? "required" : "not_required")",
            "why_role=\(capped(decision.explainability.whyRole, maxChars: 120))",
            "why_classes=\(capped(decision.explainability.whyPreferredModelClasses, maxChars: 140))"
        ]

        let projectName = context.projectName?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !projectName.isEmpty {
            parts.append("project=\(projectName)")
        }
        if !decision.projectModelHints.isEmpty {
            parts.append("project_hints=[\(decision.projectModelHints.joined(separator: ", "))]")
        }
        parts.append("hub_resolves_concrete_model=true")
        return parts.joined(separator: "; ")
    }

    private func parseDirectModelAssignmentIntent(
        _ userMessage: String,
        projects: [AXProjectEntry],
        role: AXRole,
        usedDefaultRole: Bool,
        resolvedModelId: String,
        sourceModelToken: String
    ) -> DirectModelAssignmentIntent? {
        let normalized = normalizedSupervisorIntentText(userMessage)
        let appliesToAllProjects = normalized.contains("所有项目") || normalized.contains("全部项目")

        let projectRef = appliesToAllProjects
            ? nil
            : extractProjectReferenceForDirectAssignment(userMessage, projects: projects)
        return DirectModelAssignmentIntent(
            appliesToAllProjects: appliesToAllProjects,
            projectRef: projectRef,
            role: role,
            usedDefaultRole: usedDefaultRole,
            modelId: resolvedModelId,
            sourceModelToken: sourceModelToken
        )
    }

    private func firstExplicitRoleMention(in normalized: String) -> AXRole? {
        let aliases: [(String, AXRole)] = [
            ("reviewer", .reviewer), ("advisor", .advisor), ("coarse", .coarse), ("refine", .refine), ("coder", .coder),
            ("开发者", .coder), ("开发", .coder), ("编程", .coder), ("编码", .coder),
            ("粗编", .coarse), ("粗稿", .coarse), ("初稿", .coarse),
            ("精编", .refine), ("精修", .refine), ("润色", .refine),
            ("审查", .reviewer), ("审阅", .reviewer), ("评审", .reviewer),
            ("顾问", .advisor)
        ]
        for (token, role) in aliases.sorted(by: { $0.0.count > $1.0.count }) where normalized.contains(token) {
            return role
        }
        return nil
    }

    private func extractRequestedModelToken(from userMessage: String) -> String? {
        let patterns = [
            #"(?:改成|改为|换成|换为|换到|切到|切换到|设为|设置为|指定为|调整为)\s*[“"']?([^“"'\n。！!？?]+)"#,
            #"(?:用|使用)\s*[“"']?([^“"'\n。！!？?]+)"#
        ]
        for pattern in patterns {
            if let captured = firstRegexCapture(in: userMessage, pattern: pattern) {
                let cleaned = sanitizeRequestedModelToken(captured)
                if !cleaned.isEmpty {
                    return cleaned
                }
            }
        }
        return nil
    }

    private func sanitizeRequestedModelToken(_ raw: String) -> String {
        var out = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        while out.hasPrefix("模型") || out.hasPrefix("model") || out.hasPrefix("为") {
            if out.hasPrefix("模型") {
                out.removeFirst("模型".count)
            } else if out.hasPrefix("model") {
                out.removeFirst("model".count)
            } else if out.hasPrefix("为") {
                out.removeFirst("为".count)
            }
            out = out.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        let suffixes = ["吧", "一下", "试试", "看看", "谢谢"]
        for suffix in suffixes where out.hasSuffix(suffix) {
            out = String(out.dropLast(suffix.count)).trimmingCharacters(in: .whitespacesAndNewlines)
        }
        return out.trimmingCharacters(in: CharacterSet(charactersIn: "\"'“”‘’.,，。!！?？"))
    }

    private func resolveRequestedModelToken(_ token: String) -> ModelTokenResolution {
        let trimmed = token.trimmingCharacters(in: .whitespacesAndNewlines)
        let lowered = trimmed.lowercased()
        if ["auto", "default", "none", "clear", "自动"].contains(lowered) {
            return .auto
        }

        let inventory = supervisorModelInventory()
        guard !inventory.isEmpty else {
            if lowered.contains("/") || lowered.contains("gpt") || lowered.contains("claude") || lowered.contains("gemini") {
                return .resolved(trimmed)
            }
            return .inventoryUnavailable
        }

        let compactQuery = compactModelLookupKey(trimmed)
        let versionFragments = versionLikeFragments(in: trimmed.lowercased())
        let scored: [(model: HubModel, score: Int)] = inventory.compactMap { model in
            let idLower = model.id.lowercased()
            let nameLower = model.name.lowercased()
            let compactID = compactModelLookupKey(model.id)
            let compactName = compactModelLookupKey(model.name)
            var score = 0

            if idLower == lowered { score = max(score, 300) }
            if nameLower == lowered { score = max(score, 290) }
            if !compactQuery.isEmpty && compactID == compactQuery { score = max(score, 270) }
            if !compactQuery.isEmpty && compactName == compactQuery { score = max(score, 260) }
            if idLower.contains(lowered) { score = max(score, 230) }
            if nameLower.contains(lowered) { score = max(score, 220) }
            if !compactQuery.isEmpty && compactID.contains(compactQuery) { score = max(score, 210) }
            if !compactQuery.isEmpty && compactName.contains(compactQuery) { score = max(score, 200) }
            if versionFragments.contains(where: { fragment in
                idLower.contains(fragment) || nameLower.contains(fragment)
            }) {
                score = max(score, 240)
            }
            if score == 0 { return nil }
            return (model, score)
        }
        .sorted { lhs, rhs in
            if lhs.score != rhs.score { return lhs.score > rhs.score }
            if lhs.model.state != rhs.model.state { return lhs.model.state == .loaded }
            return lhs.model.id.localizedCaseInsensitiveCompare(rhs.model.id) == .orderedAscending
        }

        guard let best = scored.first else { return .notFound }
        if scored.count == 1 {
            return .resolved(best.model.id)
        }
        let second = scored[1]
        if best.score - second.score >= 20 {
            return .resolved(best.model.id)
        }
        return .ambiguous(Array(scored.prefix(4).map(\.model)))
    }

    private func compactModelLookupKey(_ text: String) -> String {
        text
            .folding(options: [.caseInsensitive, .diacriticInsensitive, .widthInsensitive], locale: .current)
            .unicodeScalars
            .filter { CharacterSet.alphanumerics.contains($0) }
            .map(String.init)
            .joined()
    }

    private func versionLikeFragments(in text: String) -> [String] {
        let pattern = #"[0-9]+(?:\.[0-9]+)+"#
        guard let regex = try? NSRegularExpression(pattern: pattern) else { return [] }
        let range = NSRange(text.startIndex..<text.endIndex, in: text)
        return regex.matches(in: text, options: [], range: range).compactMap { match in
            guard let range = Range(match.range, in: text) else { return nil }
            return String(text[range])
        }
    }

    private func extractProjectReferenceForDirectAssignment(
        _ userMessage: String,
        projects: [AXProjectEntry]
    ) -> String? {
        let normalized = normalizedSupervisorIntentText(userMessage)
        if normalized.contains("当前项目") || normalized.contains("这个项目") || normalized.contains("该项目") {
            return defaultProjectReferenceForDirectAssignment(projects: projects)
        }

        let patterns = [
            #"(?:把|给|将)\s*(.+?)(?:这个项目|该项目|项目)"#,
            #"(?:把|给|将)\s*(.+?)\s*的\s*(?:开发者|开发|coder|coarse|refine|reviewer|advisor|审查|审阅|评审|顾问|粗编|精修)?\s*模型"#
        ]
        for pattern in patterns {
            if let captured = firstRegexCapture(in: userMessage, pattern: pattern) {
                let cleaned = sanitizeDirectProjectHint(captured)
                if !cleaned.isEmpty {
                    return cleaned
                }
            }
        }
        return nil
    }

    private func sanitizeDirectProjectHint(_ raw: String) -> String {
        var out = raw.trimmingCharacters(in: .whitespacesAndNewlines)
        let prefixes = ["把", "给", "将"]
        for prefix in prefixes where out.hasPrefix(prefix) {
            out.removeFirst(prefix.count)
            out = out.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        let fillers = ["这个", "该", "当前", "一下"]
        for filler in fillers {
            out = out.replacingOccurrences(of: filler, with: "")
        }
        return sanitizeProjectReference(out)
    }

    private func defaultProjectReferenceForDirectAssignment(projects: [AXProjectEntry]) -> String? {
        if let selectedProjectID = appModel?.selectedProjectId,
           selectedProjectID != AXProjectRegistry.globalHomeId,
           let selected = projects.first(where: { $0.projectId == selectedProjectID }) {
            return selected.displayName
        }
        if projects.count == 1 {
            return projects[0].displayName
        }
        return nil
    }

    private func firstRegexCapture(in text: String, pattern: String) -> String? {
        guard let regex = try? NSRegularExpression(pattern: pattern, options: [.caseInsensitive]) else {
            return nil
        }
        let range = NSRange(text.startIndex..<text.endIndex, in: text)
        guard let match = regex.firstMatch(in: text, options: [], range: range),
              match.numberOfRanges > 1,
              let captureRange = Range(match.range(at: 1), in: text) else {
            return nil
        }
        return String(text[captureRange])
    }

    private func regexMatches(in text: String, pattern: String) -> [String] {
        guard let regex = try? NSRegularExpression(pattern: pattern, options: [.caseInsensitive]) else {
            return []
        }
        let range = NSRange(text.startIndex..<text.endIndex, in: text)
        return regex.matches(in: text, options: [], range: range).compactMap { match in
            guard let matchRange = Range(match.range, in: text) else { return nil }
            return String(text[matchRange])
        }
    }

    private func containsAny(_ text: String, _ needles: [String]) -> Bool {
        needles.contains { text.contains($0) }
    }

    private func normalizedContainsAny(_ normalized: String, _ needles: [String]) -> Bool {
        needles.contains { needle in
            normalized.contains(normalizedLookupKey(needle))
        }
    }

    private func idleDurationText(_ seconds: TimeInterval) -> String {
        if seconds < 90 { return "刚刚无更新" }
        let mins = Int(seconds / 60)
        if mins < 60 { return "\(mins) 分钟无更新" }
        let hours = Int(round(Double(mins) / 60.0))
        if hours < 48 { return "\(hours) 小时无更新" }
        let days = Int(round(Double(hours) / 24.0))
        return "\(days) 天无更新"
    }

    private func addAssistantMessage(_ text: String) {
        _ = appendSupervisorAssistantMessage(text)
    }

    private func addSystemMessage(_ text: String) {
        recordRuntimeActivity(text)
        let message = SupervisorMessage(
            id: UUID().uuidString,
            role: .system,
            content: text,
            isVoice: false,
            timestamp: Date().timeIntervalSince1970
        )
        messages.append(message)
    }

    private func applyVoicePlaybackActivity(_ activity: VoicePlaybackActivity) {
        voicePlaybackActivity = activity

        guard activity.state != .idle else { return }
        guard activity != lastRecordedVoicePlaybackActivity else { return }

        lastRecordedVoicePlaybackActivity = activity
        guard let summary = activity.runtimeLogSummaryLine else { return }
        recordRuntimeActivity(summary)
        let auditLine = activity.auditLine.trimmingCharacters(in: .whitespacesAndNewlines)
        if !auditLine.isEmpty {
            recordRuntimeActivity(auditLine)
        }
    }

    private func recordHeartbeatEntry(
        reason: String,
        projectCount: Int,
        changed: Bool,
        content: String,
        focusActionURL: String?
    ) {
        heartbeatHistory.insert(
            HeartbeatFeedEntry(
                id: UUID().uuidString,
                createdAt: Date().timeIntervalSince1970,
                reason: reason,
                projectCount: projectCount,
                changed: changed,
                content: content,
                focusActionURL: focusActionURL
            ),
            at: 0
        )
        if heartbeatHistory.count > heartbeatHistoryMaxEntries {
            heartbeatHistory.removeLast(heartbeatHistory.count - heartbeatHistoryMaxEntries)
        }
    }

    private func recordRuntimeActivity(_ text: String) {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return }
        runtimeActivityEntries.insert(
            RuntimeActivityEntry(
                id: UUID().uuidString,
                createdAt: Date().timeIntervalSince1970,
                text: trimmed
            ),
            at: 0
        )
        if runtimeActivityEntries.count > runtimeActivityMaxEntries {
            runtimeActivityEntries.removeLast(runtimeActivityEntries.count - runtimeActivityMaxEntries)
        }
    }

    private func pushSupervisorIncidentNotification(_ incident: SupervisorLaneIncident) {
        let dedupeKey = supervisorIncidentNotificationDedupeKey(incident)
        guard shouldMirrorSupervisorIncidentNotificationToHub(incident) else {
            HubIPCClient.removeNotification(dedupeKey: dedupeKey)
            return
        }
        let linkedGrant = selectPendingGrant(for: incident.projectID)
        let projectToken = incident.projectID?.uuidString
        let actionURL = supervisorActionURL(
            projectId: projectToken,
            grantRequestId: linkedGrant?.grantRequestId,
            capability: linkedGrant?.capability
        )
        guard shouldMirrorNotificationToHub(actionURL: actionURL) else {
            HubIPCClient.removeNotification(dedupeKey: dedupeKey)
            return
        }
        let title = "🚧 Lane 需要处理：\(incident.incidentCode)"
        let body = """
lane=\(incident.laneID)
action=\(incident.proposedAction.rawValue)
deny=\(incident.denyCode)
latency=\(incident.takeoverLatencyMs ?? -1)ms
audit=\(incident.auditRef)
"""

        HubIPCClient.pushNotification(
            source: "X-Terminal",
            title: title,
            body: body,
            dedupeKey: dedupeKey,
            actionURL: actionURL,
            unread: true
        )
    }

    private func supervisorIncidentNotificationDedupeKey(
        _ incident: SupervisorLaneIncident
    ) -> String {
        "x_terminal_supervisor_incident_\(incident.id)"
    }

    private func shouldMirrorSupervisorIncidentNotificationToHub(
        _ incident: SupervisorLaneIncident
    ) -> Bool {
        let suppressedCodes = Set([
            LaneBlockedReason.grantPending.rawValue,
            LaneBlockedReason.awaitingInstruction.rawValue,
        ])
        let candidates = [
            incident.incidentCode,
            incident.denyCode,
        ].map {
            $0.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        return !candidates.contains { suppressedCodes.contains($0) }
    }

    private func appendSupervisorIncident(_ incident: SupervisorLaneIncident) {
        supervisorIncidentLedger.append(incident)
        if supervisorIncidentLedger.count > 240 {
            supervisorIncidentLedger.removeFirst(supervisorIncidentLedger.count - 240)
        }
        HubIPCClient.appendSupervisorIncidentAudit(
            incidentID: incident.id,
            laneID: incident.laneID,
            taskID: incident.taskID,
            projectID: incident.projectID,
            incidentCode: incident.incidentCode,
            eventType: incident.eventType,
            denyCode: incident.denyCode,
            proposedAction: incident.proposedAction.rawValue,
            severity: incident.severity.rawValue,
            category: incident.category.rawValue,
            detectedAtMs: incident.detectedAtMs,
            handledAtMs: incident.handledAtMs,
            takeoverLatencyMs: incident.takeoverLatencyMs,
            auditRef: incident.auditRef,
            detail: incident.detail,
            status: incident.status.rawValue
        )
        autoExportXTReadyIncidentEventsIfNeeded()
    }

    @discardableResult
    private func applySupervisorLaneHealthSnapshot(_ snapshot: SupervisorLaneHealthSnapshot) -> Bool {
        supervisorLaneHealthSnapshot = snapshot
        supervisorLaneHealthStatusLine = laneHealthStatusLine(summary: snapshot.summary)

        let fingerprint = snapshot.fingerprint
        let changed = fingerprint != lastLaneHealthFingerprint
        if changed {
            lastLaneHealthFingerprint = fingerprint
            maybePushLaneHealthNotification(snapshot)
        }
        return changed
    }

    private func laneHealthStatusLine(summary: LaneHealthSummary) -> String {
        if summary.total == 0 {
            return "lane health: idle"
        }
        return "lane health: total=\(summary.total), running=\(summary.running), blocked=\(summary.blocked), stalled=\(summary.stalled), failed=\(summary.failed)"
    }

    private func maybePushLaneHealthNotification(_ snapshot: SupervisorLaneHealthSnapshot) {
        let summary = snapshot.summary
        guard summary.failed > 0 || summary.stalled > 0 else { return }

        let hotspots = snapshot.lanes
            .filter { $0.status == .failed || $0.status == .stalled }
            .prefix(3)
            .map { lane in
                "\(lane.laneID):\(lane.status.rawValue)/\(lane.blockedReason?.rawValue ?? "none")"
            }
            .joined(separator: ";")

        let body = """
running=\(summary.running)
blocked=\(summary.blocked)
stalled=\(summary.stalled)
failed=\(summary.failed)
hotspots=\(hotspots.isEmpty ? "none" : hotspots)
"""
        let dedupeKey = "x_terminal_supervisor_lane_health_\(summary.failed)_\(summary.stalled)_\(hotspots)"
        let actionURL = supervisorActionURL(projectId: nil)
        guard shouldMirrorNotificationToHub(actionURL: actionURL) else {
            HubIPCClient.removeNotification(dedupeKey: dedupeKey)
            return
        }

        HubIPCClient.pushNotification(
            source: "X-Terminal",
            title: "🫀 Lane 健康巡检告警",
            body: body,
            dedupeKey: dedupeKey,
            actionURL: actionURL,
            unread: true
        )
    }

    private func autoExportXTReadyIncidentEventsIfNeeded() {
        guard isXTReadyIncidentAutoExportEnabled else {
            xtReadyIncidentEventsAutoExportStatus = "disabled"
            return
        }

        let now = Date().timeIntervalSince1970
        guard now - lastXTReadyIncidentAutoExportAt >= xtReadyIncidentAutoExportMinIntervalSec else {
            return
        }
        lastXTReadyIncidentAutoExportAt = now

        _ = exportXTReadyIncidentEventsReport()
    }

    private var isXTReadyIncidentAutoExportEnabled: Bool {
        let raw = (ProcessInfo.processInfo.environment["XTERMINAL_AUTO_EXPORT_XT_READY_INCIDENT_EVENTS"] ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        if raw.isEmpty {
            return true
        }
        return !["0", "false", "off", "no", "n"].contains(raw)
    }

    static func buildXTReadyIncidentEvents(
        from incidents: [SupervisorLaneIncident],
        limit: Int = 120
    ) -> [XTReadyIncidentEvent] {
        let required = Set(xtReadyRequiredIncidentCodes)
        return incidents
            .filter { required.contains($0.incidentCode) && $0.status == .handled }
            .sorted { lhs, rhs in
                let lt = lhs.handledAtMs ?? lhs.detectedAtMs
                let rt = rhs.handledAtMs ?? rhs.detectedAtMs
                if lt != rt {
                    return lt < rt
                }
                if lhs.incidentCode != rhs.incidentCode {
                    return lhs.incidentCode < rhs.incidentCode
                }
                return lhs.laneID < rhs.laneID
            }
            .suffix(max(1, limit))
            .map { incident in
                XTReadyIncidentEvent(
                    eventType: incident.eventType,
                    incidentCode: incident.incidentCode,
                    laneID: incident.laneID,
                    detectedAtMs: incident.detectedAtMs,
                    handledAtMs: incident.handledAtMs ?? incident.detectedAtMs,
                    denyCode: incident.denyCode,
                    auditEventType: "supervisor.incident.handled",
                    auditRef: incident.auditRef,
                    takeoverLatencyMs: incident.takeoverLatencyMs
                )
            }
    }

    static func missingXTReadyIncidentCodes(
        in events: [XTReadyIncidentEvent]
    ) -> [String] {
        let existing = Set(events.map(\.incidentCode))
        return xtReadyRequiredIncidentCodes.filter { !existing.contains($0) }
    }

    static func evaluateXTReadyIncidentReadiness(
        events: [XTReadyIncidentEvent]
    ) -> XTReadyIncidentReadiness {
        var issues: [String] = []

        for incidentCode in xtReadyRequiredIncidentCodes {
            guard let selected = selectBestXTReadyIncidentEvent(
                incidentCode: incidentCode,
                events: events
            ) else {
                issues.append("\(incidentCode):missing_incident")
                continue
            }

            let expectedEventType = xtReadyExpectedEventTypes[incidentCode] ?? ""
            if !expectedEventType.isEmpty, selected.eventType != expectedEventType {
                issues.append("\(incidentCode):event_type_mismatch")
            }
            if selected.denyCode != incidentCode {
                issues.append("\(incidentCode):deny_code_mismatch")
            }
            if selected.auditRef.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                issues.append("\(incidentCode):audit_ref_missing")
            }
            guard let latency = resolvedTakeoverLatencyMs(for: selected) else {
                issues.append("\(incidentCode):takeover_latency_missing")
                continue
            }
            if latency > xtReadyMaxTakeoverLatencyMs {
                issues.append("\(incidentCode):takeover_latency_exceeded")
            }
        }

        return XTReadyIncidentReadiness(
            ready: issues.isEmpty,
            issues: issues
        )
    }

    static func evaluateSupervisorMemoryAssemblyReadiness(
        snapshot: SupervisorMemoryAssemblySnapshot?
    ) -> SupervisorMemoryAssemblyReadiness {
        SupervisorMemoryAssemblyDiagnostics.evaluate(
            snapshot: snapshot,
            canonicalSyncSnapshot: HubIPCClient.canonicalMemorySyncStatusSnapshot(limit: 120)
        )
    }

    private static func xtReadyStrictIssueCodes(
        incidentReadiness: XTReadyIncidentReadiness,
        memoryReadiness: SupervisorMemoryAssemblyReadiness,
        hubRuntimeDiagnosis: XTHubRuntimeDiagnosisSnapshot? = nil
    ) -> [String] {
        var issues = incidentReadiness.issues + memoryReadiness.issueCodes.map { "memory:\($0)" }
        if let hubIssue = hubRuntimeDiagnosis?.strictIssueCode {
            issues.append("hub_runtime:\(hubIssue)")
        }
        return issues
    }

    private static func xtReadyHubRuntimeDiagnosisSnapshot(
        baseDir: URL = HubPaths.baseDir()
    ) -> XTHubRuntimeDiagnosisSnapshot? {
        let report = XHubDoctorOutputStore.loadHubReport(baseDir: baseDir)
        let localServiceSnapshot = XHubDoctorOutputStore.loadHubLocalServiceSnapshot(baseDir: baseDir)
        let localRuntimeMonitorSnapshot = XHubDoctorOutputStore.loadHubLocalRuntimeMonitorSnapshot(baseDir: baseDir)
        let recoveryGuidance = XHubDoctorOutputStore.loadHubLocalServiceRecoveryGuidance(baseDir: baseDir)

        let reportDiagnosis = report.flatMap { xtReadyHubRuntimeDiagnosisSnapshot(from: $0) }
        let snapshotDiagnosis = localServiceSnapshot.flatMap { xtReadyHubRuntimeDiagnosisSnapshot(from: $0) }
        let guidanceDiagnosis = recoveryGuidance.flatMap { xtReadyHubRuntimeDiagnosisSnapshot(from: $0) }

        let baseDiagnosis: XTHubRuntimeDiagnosisSnapshot?
        if let report, let localServiceSnapshot,
           localServiceSnapshot.generatedAtMs > report.generatedAtMs {
            baseDiagnosis = snapshotDiagnosis ?? reportDiagnosis
        } else {
            baseDiagnosis = reportDiagnosis ?? snapshotDiagnosis
        }
        let diagnosis = xtReadyMergedHubRuntimeDiagnosis(baseDiagnosis, guidance: guidanceDiagnosis)
        return xtReadyMergeHubRuntimeMonitorDetails(
            diagnosis,
            monitor: localRuntimeMonitorSnapshot
        )
    }

    private static func xtReadyHubRuntimeDiagnosisSnapshot(
        from report: XHubDoctorOutputReport
    ) -> XTHubRuntimeDiagnosisSnapshot? {
        let failureCode = report.currentFailureCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let primaryCheck = xtReadyHubRuntimePrimaryCheck(
            in: report,
            failureCode: failureCode
        )
        let headline = (
            primaryCheck?.headline.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                ? primaryCheck?.headline
                : report.summary.headline
        )?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let nextStep = (
            primaryCheck?.nextStep.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                ? primaryCheck?.nextStep
                : report.nextSteps.first?.instruction
        )?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""

        return XTHubRuntimeDiagnosisSnapshot(
            overallState: report.overallState.rawValue,
            readyForFirstTask: report.readyForFirstTask,
            failureCode: failureCode,
            headline: headline,
            detailLines: xtReadyHubRuntimeDetailLines(primaryCheck),
            nextStep: nextStep,
            repairDestinationRef: (
                primaryCheck?.repairDestinationRef?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                    ? primaryCheck?.repairDestinationRef
                    : report.nextSteps.first?.destinationRef
            )?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "",
            generatedAtMs: report.generatedAtMs
        )
    }

    private static func xtReadyHubRuntimeDiagnosisSnapshot(
        from snapshot: XHubLocalServiceSnapshotReport
    ) -> XTHubRuntimeDiagnosisSnapshot? {
        guard snapshot.doctorProjection != nil
                || snapshot.primaryIssue != nil
                || !snapshot.providers.isEmpty else {
            return nil
        }

        let projection = snapshot.doctorProjection
        let primaryIssue = snapshot.primaryIssue
        let projectionFailureCode = projection?.currentFailureCode.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let projectionHeadline = projection?.headline.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let projectionNextStep = projection?.nextStep.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let primaryFailureCode = primaryIssue?.reasonCode.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let primaryHeadline = primaryIssue?.headline.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let primaryNextStep = primaryIssue?.nextStep.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let overallState = projection?.overallState.rawValue
            ?? (snapshot.runtimeAlive ? XHubDoctorOverallState.degraded.rawValue : XHubDoctorOverallState.blocked.rawValue)
        let failureCode = projectionFailureCode.isEmpty ? primaryFailureCode : projectionFailureCode
        let headline = projectionHeadline.isEmpty ? primaryHeadline : projectionHeadline
        let nextStep = projectionNextStep.isEmpty ? primaryNextStep : projectionNextStep

        return XTHubRuntimeDiagnosisSnapshot(
            overallState: overallState,
            readyForFirstTask: projection?.readyForFirstTask ?? false,
            failureCode: failureCode,
            headline: headline,
            detailLines: snapshot.preferredDetailLines(),
            nextStep: nextStep,
            repairDestinationRef: projection?.repairDestinationRef.trimmingCharacters(in: .whitespacesAndNewlines) ?? "",
            generatedAtMs: snapshot.generatedAtMs
        )
    }

    private static func xtReadyHubRuntimeDiagnosisSnapshot(
        from guidance: XHubLocalServiceRecoveryGuidanceReport
    ) -> XTHubRuntimeDiagnosisSnapshot? {
        let failureCode = guidance.primaryFailureCode
        let actionCategory = guidance.actionCategory.trimmingCharacters(in: .whitespacesAndNewlines)
        let installHint = guidance.installHint.trimmingCharacters(in: .whitespacesAndNewlines)
        guard guidance.guidancePresent
                || guidance.primaryIssue != nil
                || !failureCode.isEmpty
                || !actionCategory.isEmpty
                || !installHint.isEmpty else {
            return nil
        }

        let providerCheckStatus = XHubDoctorCheckStatus(
            rawValue: guidance.providerCheckStatus.trimmingCharacters(in: .whitespacesAndNewlines)
        )
        let overallState: String
        if guidance.providerCheckBlocking {
            overallState = XHubDoctorOverallState.blocked.rawValue
        } else {
            switch providerCheckStatus {
            case .pass:
                overallState = failureCode.isEmpty ? XHubDoctorOverallState.ready.rawValue : XHubDoctorOverallState.degraded.rawValue
            case .warn, .fail:
                overallState = XHubDoctorOverallState.degraded.rawValue
            case .skip, .none:
                overallState = guidance.runtimeAlive
                    ? XHubDoctorOverallState.degraded.rawValue
                    : XHubDoctorOverallState.blocked.rawValue
            }
        }

        let primaryIssue = guidance.primaryIssue
        let headline = (
            primaryIssue?.headline.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
                ? primaryIssue?.headline
                : installHint
        )?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let primaryNextStep = primaryIssue?.nextStep.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let recommendedAction = guidance.topRecommendedActionSummary.trimmingCharacters(in: .whitespacesAndNewlines)
        let nextStep = !primaryNextStep.isEmpty
            ? primaryNextStep
            : (!recommendedAction.isEmpty ? recommendedAction : installHint)
        let readyForFirstTask = !guidance.providerCheckBlocking
            && failureCode.isEmpty
            && providerCheckStatus == .pass
            && guidance.readyProviderCount > 0

        return XTHubRuntimeDiagnosisSnapshot(
            overallState: overallState,
            readyForFirstTask: readyForFirstTask,
            failureCode: failureCode,
            headline: headline,
            detailLines: guidance.preferredDetailLines(),
            nextStep: nextStep,
            actionCategory: actionCategory,
            installHint: installHint,
            recommendedAction: recommendedAction,
            supportFAQSummary: guidance.topSupportFAQSummary,
            repairDestinationRef: guidance.repairDestinationRef.trimmingCharacters(in: .whitespacesAndNewlines),
            generatedAtMs: guidance.generatedAtMs
        )
    }

    private static func xtReadyMergedHubRuntimeDiagnosis(
        _ base: XTHubRuntimeDiagnosisSnapshot?,
        guidance: XTHubRuntimeDiagnosisSnapshot?
    ) -> XTHubRuntimeDiagnosisSnapshot? {
        guard let guidance else { return base }
        guard var merged = base else { return guidance }

        let mergedFailureCode = merged.failureCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let guidanceFailureCode = guidance.failureCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let codesMatch = !guidanceFailureCode.isEmpty
            && (mergedFailureCode.isEmpty || mergedFailureCode == guidanceFailureCode)
        let guidanceIsNewerOrSame = guidance.generatedAtMs >= merged.generatedAtMs
        let shouldApplyGuidance = guidanceIsNewerOrSame || codesMatch || mergedFailureCode.isEmpty
        guard shouldApplyGuidance else { return merged }

        if mergedFailureCode.isEmpty, !guidanceFailureCode.isEmpty {
            merged.failureCode = guidanceFailureCode
        }
        if merged.headline.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !guidance.headline.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            merged.headline = guidance.headline
        }
        if merged.nextStep.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !guidance.nextStep.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            merged.nextStep = guidance.nextStep
        }
        if merged.detailLines.isEmpty, !guidance.detailLines.isEmpty {
            merged.detailLines = guidance.detailLines
        }
        if merged.actionCategory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !guidance.actionCategory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            merged.actionCategory = guidance.actionCategory
        }
        if merged.installHint.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !guidance.installHint.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            merged.installHint = guidance.installHint
        }
        if merged.recommendedAction.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !guidance.recommendedAction.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            merged.recommendedAction = guidance.recommendedAction
        }
        if merged.supportFAQSummary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !guidance.supportFAQSummary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            merged.supportFAQSummary = guidance.supportFAQSummary
        }
        if merged.repairDestinationRef.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !guidance.repairDestinationRef.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            merged.repairDestinationRef = guidance.repairDestinationRef
        }
        merged.generatedAtMs = max(merged.generatedAtMs, guidance.generatedAtMs)
        return merged
    }

    private static func xtReadyMergeHubRuntimeMonitorDetails(
        _ diagnosis: XTHubRuntimeDiagnosisSnapshot?,
        monitor: XHubLocalRuntimeMonitorSnapshotReport?
    ) -> XTHubRuntimeDiagnosisSnapshot? {
        guard var diagnosis else { return nil }
        guard let monitor else { return diagnosis }

        let monitorLines = monitor.preferredDetailLines(limit: 2)
        let monitorLoadConfigLine = monitor.preferredLoadConfigLine()?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if diagnosis.loadConfigSummaryLine.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
           !monitorLoadConfigLine.isEmpty {
            diagnosis.loadConfigSummaryLine = monitorLoadConfigLine
        }
        guard !monitorLines.isEmpty else {
            diagnosis.generatedAtMs = max(diagnosis.generatedAtMs, monitor.generatedAtMs)
            return diagnosis
        }

        var mergedLines = diagnosis.detailLines
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        for line in monitorLines where !mergedLines.contains(line) {
            mergedLines.append(line)
        }
        diagnosis.detailLines = Array(mergedLines.prefix(4))
        diagnosis.generatedAtMs = max(diagnosis.generatedAtMs, monitor.generatedAtMs)
        return diagnosis
    }

    private static func xtReadyHubRuntimePrimaryCheck(
        in report: XHubDoctorOutputReport,
        failureCode: String
    ) -> XHubDoctorOutputCheckResult? {
        if !failureCode.isEmpty,
           let failureCheck = report.checks.first(where: { $0.checkID == failureCode }) {
            return failureCheck
        }
        if let blocking = report.checks.first(where: \.blocking) {
            return blocking
        }
        if let degraded = report.checks.first(where: { $0.status == .warn || $0.status == .fail }) {
            return degraded
        }
        return report.checks.first
    }

    private static func xtReadyHubRuntimeDetailLines(
        _ primaryCheck: XHubDoctorOutputCheckResult?
    ) -> [String] {
        guard let primaryCheck,
              primaryCheck.status != .pass else {
            return []
        }

        let normalized = primaryCheck.detailLines
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        guard !normalized.isEmpty else { return [] }

        let preferred = normalized.filter { line in
            line.hasPrefix("ready_providers=")
                || line.hasPrefix("provider_count=")
                || line.hasPrefix("managed_service_provider_count=")
                || line.hasPrefix("managed_service_ready_count=")
                || line.contains("service_state=")
                || line.contains("runtime_reason=")
                || line.contains("endpoint=")
                || line.contains("execution_mode=")
                || line.contains("loaded_instances=")
                || line.contains("queued=")
        }

        let detailPool = preferred.isEmpty ? normalized : preferred
        let readyProvidersLine = detailPool.first(where: { $0.hasPrefix("ready_providers=") })
        let providerLine = detailPool.first(where: { $0.contains("service_state=") || $0.contains("endpoint=") })
        var prioritized: [String] = []
        if let readyProvidersLine {
            prioritized.append(readyProvidersLine)
        }
        if let providerLine, !prioritized.contains(providerLine) {
            prioritized.append(providerLine)
        }
        for line in detailPool where !prioritized.contains(line) {
            prioritized.append(line)
        }
        return Array(prioritized.prefix(2))
    }

    private static func xtReadyAutoExportStatus(
        ok: Bool,
        reason: String,
        strictIssues: [String]
    ) -> String {
        guard ok else {
            return "failed:\(reason)"
        }
        guard strictIssues.isEmpty else {
            return "strict_risk:\(strictIssues.joined(separator: ","))"
        }
        return "ok"
    }

    func exportXTReadyIncidentEventsReport(
        outputURL: URL? = nil,
        limit: Int = 120
    ) -> XTReadyIncidentEventsExportResult {
        let rows = Self.buildXTReadyIncidentEvents(from: supervisorIncidentLedger, limit: limit)
        let missing = Self.missingXTReadyIncidentCodes(in: rows)
        let readiness = Self.evaluateXTReadyIncidentReadiness(events: rows)
        let memoryReadiness = Self.evaluateSupervisorMemoryAssemblyReadiness(
            snapshot: supervisorMemoryAssemblySnapshot
        )
        let hubRuntimeDiagnosis = Self.xtReadyHubRuntimeDiagnosisSnapshot()
        let strictIssues = Self.xtReadyStrictIssueCodes(
            incidentReadiness: readiness,
            memoryReadiness: memoryReadiness,
            hubRuntimeDiagnosis: hubRuntimeDiagnosis
        )
        let mirrorState = Self.supervisorDurableCandidateMirrorExportState(
            snapshot: supervisorMemoryAssemblySnapshot
        )
        let destination = outputURL ?? defaultXTReadyIncidentEventsReportURL()
        let summary = XTReadyIncidentSummary(
            highRiskLaneWithoutGrant: 0,
            unauditedAutoResolution: 0,
            highRiskBypassCount: 0,
            blockedEventMissRate: 0,
            nonMessageIngressPolicyCoverage: rows.isEmpty ? 0 : 1,
            memoryAssemblyReady: memoryReadiness.ready,
            memoryAssemblyIssueCount: memoryReadiness.issues.count,
            memoryAssemblyRequestedProfile: supervisorMemoryAssemblySnapshot?.requestedProfile ?? "",
            memoryAssemblyResolvedProfile: supervisorMemoryAssemblySnapshot?.resolvedProfile ?? "",
            memoryAssemblyTruncatedLayerCount: supervisorMemoryAssemblySnapshot?.truncatedLayers.count ?? 0,
            durableCandidateMirrorStatus: mirrorState.status.rawValue,
            durableCandidateMirrorTarget: mirrorState.target,
            durableCandidateMirrorAttempted: mirrorState.attempted,
            durableCandidateMirrorErrorCode: mirrorState.errorCode,
            durableCandidateLocalStoreRole: mirrorState.localStoreRole
        )
        let payload = XTReadyIncidentEventsPayload(
            runId: "xt_ready_runtime_\(Int64((Date().timeIntervalSince1970 * 1000).rounded()))",
            schemaVersion: "xt_ready_incident_events.v1",
            generatedAtMs: Int64((Date().timeIntervalSince1970 * 1000).rounded()),
            source: "supervisor_manager",
            summary: summary,
            events: rows
        )

        do {
            try Self.writeXTReadyIncidentEventsPayload(payload, to: destination)
            let result = XTReadyIncidentEventsExportResult(
                ok: true,
                outputPath: destination.path,
                exportedEventCount: rows.count,
                missingIncidentCodes: missing,
                reason: "ok"
            )
            xtReadyIncidentEventsReportPath = result.outputPath
            xtReadyIncidentEventsAutoExportStatus = Self.xtReadyAutoExportStatus(
                ok: result.ok,
                reason: result.reason,
                strictIssues: strictIssues
            )
            return result
        } catch {
            let result = XTReadyIncidentEventsExportResult(
                ok: false,
                outputPath: destination.path,
                exportedEventCount: rows.count,
                missingIncidentCodes: missing,
                reason: "write_failed:\(error.localizedDescription)"
            )
            xtReadyIncidentEventsReportPath = result.outputPath
            xtReadyIncidentEventsAutoExportStatus = Self.xtReadyAutoExportStatus(
                ok: result.ok,
                reason: result.reason,
                strictIssues: strictIssues
            )
            return result
        }
    }

    private static func writeXTReadyIncidentEventsPayload(
        _ payload: XTReadyIncidentEventsPayload,
        to destination: URL
    ) throws {
        let encoder = JSONEncoder()
        encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
        let data = try encoder.encode(payload)
        try FileManager.default.createDirectory(
            at: destination.deletingLastPathComponent(),
            withIntermediateDirectories: true
        )

        do {
            try writeXTReadyIncidentReportData(data, to: destination, options: .atomic)
        } catch {
            guard looksLikeXTReadyIncidentReportDiskSpaceExhaustion(error),
                  FileManager.default.fileExists(atPath: destination.path) else {
                throw error
            }
            try writeXTReadyIncidentReportData(data, to: destination, options: [])
        }
    }

    private static func writeXTReadyIncidentReportData(
        _ data: Data,
        to destination: URL,
        options: Data.WritingOptions
    ) throws {
        if let override = withXTReadyIncidentReportWriteTestingLock({
            xtReadyIncidentReportWriteAttemptOverrideForTesting
        }) {
            try override(data, destination, options)
            return
        }
        try data.write(to: destination, options: options)
    }

    private static func looksLikeXTReadyIncidentReportDiskSpaceExhaustion(_ error: Error) -> Bool {
        let nsError = error as NSError
        if nsError.domain == NSCocoaErrorDomain, nsError.code == NSFileWriteOutOfSpaceError {
            return true
        }
        if nsError.domain == NSPOSIXErrorDomain, nsError.code == 28 {
            return true
        }
        if let underlying = nsError.userInfo[NSUnderlyingErrorKey] as? Error {
            return looksLikeXTReadyIncidentReportDiskSpaceExhaustion(underlying)
        }
        return false
    }

    @discardableResult
    private static func withXTReadyIncidentReportWriteTestingLock<T>(_ body: () -> T) -> T {
        xtReadyIncidentReportWriteTestingLock.lock()
        defer { xtReadyIncidentReportWriteTestingLock.unlock() }
        return body()
    }

    @discardableResult
    private static func withSupervisorVoiceSkillActionTestingLock<T>(_ body: () -> T) -> T {
        supervisorVoiceSkillActionTestingLock.lock()
        defer { supervisorVoiceSkillActionTestingLock.unlock() }
        return body()
    }

    func xtReadyIncidentExportSnapshot(limit: Int = 120) -> XTReadyIncidentExportSnapshot {
        let rows = Self.buildXTReadyIncidentEvents(from: supervisorIncidentLedger, limit: limit)
        let missing = Self.missingXTReadyIncidentCodes(in: rows)
        let incidentReadiness = Self.evaluateXTReadyIncidentReadiness(events: rows)
        let memoryReadiness = Self.evaluateSupervisorMemoryAssemblyReadiness(
            snapshot: supervisorMemoryAssemblySnapshot
        )
        let hubRuntimeDiagnosis = Self.xtReadyHubRuntimeDiagnosisSnapshot()
        let strictIssues = Self.xtReadyStrictIssueCodes(
            incidentReadiness: incidentReadiness,
            memoryReadiness: memoryReadiness,
            hubRuntimeDiagnosis: hubRuntimeDiagnosis
        )
        let mirrorState = Self.supervisorDurableCandidateMirrorExportState(
            snapshot: supervisorMemoryAssemblySnapshot
        )
        let defaultPath = defaultXTReadyIncidentEventsReportURL().path
        return XTReadyIncidentExportSnapshot(
            autoExportEnabled: isXTReadyIncidentAutoExportEnabled,
            ledgerIncidentCount: supervisorIncidentLedger.count,
            requiredIncidentEventCount: rows.count,
            missingIncidentCodes: missing,
            memoryAssemblyReady: memoryReadiness.ready,
            memoryAssemblyIssues: memoryReadiness.issueCodes,
            memoryAssemblyDetailLines: Self.xtReadyMemoryAssemblyDetailLines(
                memoryReadiness,
                snapshot: supervisorMemoryAssemblySnapshot
            ),
            memoryAssemblyStatusLine: memoryReadiness.statusLine,
            durableCandidateMirrorStatus: mirrorState.status,
            durableCandidateMirrorTarget: mirrorState.target,
            durableCandidateMirrorAttempted: mirrorState.attempted,
            durableCandidateMirrorErrorCode: mirrorState.errorCode,
            durableCandidateLocalStoreRole: mirrorState.localStoreRole,
            strictE2EReady: strictIssues.isEmpty,
            strictE2EIssues: strictIssues,
            hubRuntimeDiagnosis: hubRuntimeDiagnosis,
            status: xtReadyIncidentEventsAutoExportStatus,
            reportPath: xtReadyIncidentEventsReportPath.isEmpty ? defaultPath : xtReadyIncidentEventsReportPath
        )
    }

    private static func xtReadyMemoryAssemblyDetailLines(
        _ memoryReadiness: SupervisorMemoryAssemblyReadiness,
        snapshot: SupervisorMemoryAssemblySnapshot?
    ) -> [String] {
        var lines: [String] = memoryReadiness.issues.prefix(2).compactMap { issue in
            let detailParts = issue.detail
                .components(separatedBy: .newlines)
                .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
                .filter { !$0.isEmpty }
            guard !detailParts.isEmpty else { return nil }
            return "\(issue.code): \(detailParts.prefix(2).joined(separator: " | "))"
        }
        if let snapshot,
           shouldSurfaceMemoryAssemblySnapshotDetails(snapshot) {
            lines.append(contentsOf: prioritizedMemoryAssemblySnapshotDetailLines(snapshot))
        }
        return Array(lines.prefix(4))
    }

    private static func supervisorDurableCandidateMirrorExportState(
        snapshot: SupervisorMemoryAssemblySnapshot?
    ) -> (
        status: SupervisorDurableCandidateMirrorStatus,
        target: String?,
        attempted: Bool,
        errorCode: String?,
        localStoreRole: String
    ) {
        guard let snapshot else {
            return (
                status: .notNeeded,
                target: nil,
                attempted: false,
                errorCode: nil,
                localStoreRole: XTSupervisorDurableCandidateMirror.localStoreRole
            )
        }
        return (
            status: snapshot.durableCandidateMirrorStatus,
            target: snapshot.durableCandidateMirrorTarget,
            attempted: snapshot.durableCandidateMirrorAttempted,
            errorCode: snapshot.durableCandidateMirrorErrorCode,
            localStoreRole: snapshot.durableCandidateLocalStoreRole
        )
    }

    private static func shouldSurfaceMemoryAssemblySnapshotDetails(
        _ snapshot: SupervisorMemoryAssemblySnapshot
    ) -> Bool {
        snapshot.rawWindowSource != "xt_cache"
            || snapshot.lowSignalDroppedMessages > 0
            || !snapshot.continuityFloorSatisfied
            || snapshot.rollingDigestPresent
            || !snapshot.lowSignalDropSampleLines.isEmpty
            || snapshot.durableCandidateMirrorAttempted
            || snapshot.durableCandidateMirrorStatus != .notNeeded
            || snapshot.localPersonalMemoryWriteIntent != nil
            || snapshot.localCrossLinkWriteIntent != nil
            || snapshot.localPersonalReviewWriteIntent != nil
    }

    private static func prioritizedMemoryAssemblySnapshotDetailLines(
        _ snapshot: SupervisorMemoryAssemblySnapshot
    ) -> [String] {
        let drillDownLines = snapshot.continuityDrillDownLines
        let continuityLine = drillDownLines.first { $0.hasPrefix("continuity ") }
        let mirrorLine = drillDownLines.first { $0.hasPrefix("durable_candidate_mirror ") }
        let localWriteLine = drillDownLines.first { $0.hasPrefix("xt_local_store_writes ") }
        let traceLine = drillDownLines.first { line in
            !line.hasPrefix("continuity ")
                && !line.hasPrefix("durable_candidate_mirror ")
                && !line.hasPrefix("xt_local_store_writes ")
                && !line.hasPrefix("low_signal_samples:")
        }
        let lowSignalLine = drillDownLines.first { $0.hasPrefix("low_signal_samples:") }

        var lines: [String] = []
        func append(_ line: String?) {
            guard let trimmed = line?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !trimmed.isEmpty,
                  !lines.contains(trimmed) else {
                return
            }
            lines.append(trimmed)
        }

        append(continuityLine)
        append(mirrorLine)
        append(localWriteLine)
        append(traceLine)
        append(lowSignalLine)

        for line in drillDownLines {
            append(line)
        }
        return lines
    }

    private static func selectBestXTReadyIncidentEvent(
        incidentCode: String,
        events: [XTReadyIncidentEvent]
    ) -> XTReadyIncidentEvent? {
        let expectedEventType = xtReadyExpectedEventTypes[incidentCode] ?? ""
        let candidates = events.filter { $0.incidentCode == incidentCode }
        guard !candidates.isEmpty else { return nil }
        return candidates.max { lhs, rhs in
            let lScore = scoreXTReadyIncidentEvent(lhs, incidentCode: incidentCode, expectedEventType: expectedEventType)
            let rScore = scoreXTReadyIncidentEvent(rhs, incidentCode: incidentCode, expectedEventType: expectedEventType)
            if lScore != rScore {
                return lScore < rScore
            }
            if lhs.handledAtMs != rhs.handledAtMs {
                return lhs.handledAtMs < rhs.handledAtMs
            }
            return lhs.detectedAtMs < rhs.detectedAtMs
        }
    }

    private static func scoreXTReadyIncidentEvent(
        _ event: XTReadyIncidentEvent,
        incidentCode: String,
        expectedEventType: String
    ) -> Int {
        var score = 0
        if event.incidentCode == incidentCode { score += 2 }
        if event.denyCode == incidentCode { score += 2 }
        if !expectedEventType.isEmpty, event.eventType == expectedEventType { score += 2 }
        if !event.auditRef.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty { score += 2 }
        if let latency = resolvedTakeoverLatencyMs(for: event) {
            score += 1
            if latency <= xtReadyMaxTakeoverLatencyMs {
                score += 1
            }
        }
        return score
    }

    private static func resolvedTakeoverLatencyMs(
        for event: XTReadyIncidentEvent
    ) -> Int64? {
        if let direct = event.takeoverLatencyMs, direct >= 0 {
            return direct
        }
        if event.handledAtMs >= event.detectedAtMs {
            return event.handledAtMs - event.detectedAtMs
        }
        return nil
    }

    private func defaultXTReadyIncidentEventsReportURL() -> URL {
        let env = (ProcessInfo.processInfo.environment["XTERMINAL_XT_READY_INCIDENT_EVENTS_PATH"] ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if !env.isEmpty {
            let expanded = NSString(string: env).expandingTildeInPath
            return URL(fileURLWithPath: expanded)
        }
        let root = SupervisorDoctorChecker.defaultWorkspaceRoot()
        return root.appendingPathComponent(".axcoder/reports/xt_ready_incident_events.runtime.json")
    }

