    }

    private func selectPendingGrant(for projectID: UUID?) -> SupervisorPendingGrant? {
        let projectToken = projectID?.uuidString.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !projectToken.isEmpty {
            if let exact = pendingHubGrants.first(where: {
                $0.projectId.trimmingCharacters(in: .whitespacesAndNewlines) == projectToken
            }) {
                return exact
            }
        }
        return pendingHubGrants.first
    }

    private func performPendingSupervisorSkillApprovalAction(
        _ approval: SupervisorPendingSkillApproval,
        approve: Bool
    ) {
        performLocalSupervisorSkillAuthorizationAction(
            requestId: approval.requestId,
            projectRef: approval.projectId,
            approve: approve,
            commandName: approve ? "APPROVE_SUPERVISOR_SKILL" : "DENY_SUPERVISOR_SKILL",
            lookupTriggerSource: .approvalResolution
        )
    }

    private func performLocalSupervisorSkillAuthorizationAction(
        requestId: String,
        projectRef: String,
        approve: Bool,
        commandName: String,
        lookupTriggerSource: SupervisorCommandTriggerSource = .userTurn
    ) {
        let normalizedRequestId = requestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedRequestId.isEmpty else { return }

        let resolution: SupervisorSkillCallResolution
        switch locateSupervisorSkillCall(
            requestId: normalizedRequestId,
            projectRef: projectRef,
            commandName: commandName,
            triggerSource: lookupTriggerSource
        ) {
        case .failure(let failure):
            addSystemMessage(failure.message)
            rebuildPendingSupervisorSkillApprovalViewState()
            return
        case .success(let resolved):
            resolution = resolved
        }

        guard resolution.record.status == .awaitingAuthorization else {
            rebuildPendingSupervisorSkillApprovalViewState()
            return
        }

        let capability = resolution.record.requiredCapability?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard capability.isEmpty else {
            addSystemMessage("ℹ️ \(userFacingRequestIdentifier(normalizedRequestId)) 当前正在等待 Hub 授权，请在 Hub 授权面板处理。")
            rebuildPendingSupervisorSkillApprovalViewState()
            return
        }

        if approve {
            resumeSupervisorSkillCallAfterLocalApproval(resolution)
        } else {
            blockSupervisorSkillCallAfterLocalApprovalDenial(resolution)
        }
    }

    private func enqueueSupervisorSkillRetry(
        _ resolution: SupervisorSkillCallResolution
    ) {
        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        let retryRequestId = "retry-\(nowMs)-\(String(UUID().uuidString.lowercased().prefix(8)))"
        var retried = resolution.record
        retried.requestId = retryRequestId
        retried.status = .queued
        retried.resultSummary = ""
        retried.denyCode = ""
        retried.policySource = nil
        retried.policyReason = nil
        retried.resultEvidenceRef = nil
        retried.grantRequestId = nil
        retried.grantId = nil
        retried.createdAtMs = nowMs
        retried.updatedAtMs = nowMs
        retried.auditRef = "audit-xt-supervisor-skill-\(String(retryRequestId.suffix(12)))"

        guard let toolCall = resolvedSupervisorToolCallForRecord(retried) else {
            retried.status = .blocked
            retried.resultSummary = "retry failed: skill mapping unavailable"
            retried.denyCode = "skill_mapping_missing"
            retried.resultEvidenceRef = SupervisorSkillResultEvidenceStore.write(
                record: retried,
                toolCall: nil,
                rawOutput: nil,
                triggerSource: SupervisorCommandTriggerSource.userTurn.rawValue,
                ctx: resolution.ctx
            )
            try? SupervisorProjectSkillCallStore.upsert(retried, for: resolution.ctx)
            _ = updateSupervisorWorkflowStepState(
                ctx: resolution.ctx,
                project: resolution.project,
                jobId: retried.jobId,
                planId: retried.planId,
                stepId: retried.stepId,
                status: .blocked,
                detail: retried.resultSummary,
                owner: retried.currentOwner,
                updatedAtMs: nowMs
            )
            appendSupervisorSkillCallRawLog(
                action: "blocked",
                record: retried,
                toolCall: nil,
                triggerSource: .userTurn,
                ctx: resolution.ctx
            )
            appendSupervisorSkillResultRawLog(
                record: retried,
                toolCall: nil,
                rawOutput: nil,
                triggerSource: .userTurn,
                ctx: resolution.ctx
            )
            scheduleSupervisorSkillCallbackFollowUp(
                record: retried,
                project: resolution.project,
                ctx: resolution.ctx,
                status: .blocked,
                reason: retried.resultSummary
            )
            addSystemMessage("❌ 无法重试项目 \(resolution.project.displayName) 的技能调用：\(supervisorSkillDisplaySummary(resolution.record))（\(userFacingRequestIdentifier(resolution.record.requestId))）")
            return
        }

        let registryItem = resolvedSupervisorRegistryItem(
            skillId: retried.skillId,
            projectId: resolution.project.projectId,
            projectName: resolution.project.displayName
        )
        let requiredCapability = supervisorRequiredHubCapability(for: toolCall)
        let projectConfig = (try? AXProjectStore.loadOrCreateConfig(for: resolution.ctx))
            ?? .default(forProjectRoot: resolution.ctx.root)
        let requiresGrant = registryItem?.requiresGrant == true || requiredCapability != nil
        let canBypassLocalGrantWait =
            requiredCapability == nil &&
            xtProjectGovernedAutoApprovalConfigured(
                projectRoot: resolution.ctx.root,
                config: projectConfig
            ) &&
            !ToolPolicy.isAlwaysConfirm(call: toolCall)
        let requiresWaitingAuthorization =
            requiresGrant &&
            !supervisorToolCallHasExplicitGrant(toolCall) &&
            !canBypassLocalGrantWait
        let awaitingResultSummary: String = {
            guard requiresWaitingAuthorization else { return "queued governed dispatch" }
            if let requiredCapability, !requiredCapability.isEmpty {
                return XTHubGrantPresentation.awaitingStateSummary(
                    capability: requiredCapability,
                    modelId: "",
                    grantRequestId: nil
                )
            }
            return "waiting for local governed approval"
        }()
        let awaitingDenyCode: String = {
            guard requiresWaitingAuthorization else { return "" }
            if let requiredCapability, !requiredCapability.isEmpty {
                return "grant_required"
            }
            return "local_approval_required"
        }()

        retried.requiredCapability = requiredCapability
        retried.status = requiresWaitingAuthorization ? .awaitingAuthorization : .queued
        retried.resultSummary = awaitingResultSummary
        retried.denyCode = awaitingDenyCode
        retried.resultEvidenceRef = SupervisorSkillResultEvidenceStore.write(
            record: retried,
            toolCall: toolCall,
            rawOutput: nil,
            triggerSource: SupervisorCommandTriggerSource.userTurn.rawValue,
            ctx: resolution.ctx
        )

        do {
            try SupervisorProjectSkillCallStore.upsert(retried, for: resolution.ctx)
        } catch {
            addSystemMessage(
                "❌ 重试技能调用落盘失败（skill_call_store_write_failed: \(error.localizedDescription)）"
            )
            return
        }

        _ = updateSupervisorWorkflowStepState(
            ctx: resolution.ctx,
            project: resolution.project,
            jobId: retried.jobId,
            planId: retried.planId,
            stepId: retried.stepId,
            status: requiresWaitingAuthorization ? .awaitingAuthorization : .pending,
            detail: retried.resultSummary,
            owner: retried.currentOwner,
            updatedAtMs: nowMs
        )
        appendSupervisorSkillCallRawLog(
            action: requiresWaitingAuthorization ? "awaiting_authorization" : "dispatch",
            record: retried,
            toolCall: toolCall,
            triggerSource: .userTurn,
            ctx: resolution.ctx
        )
        appendSupervisorSkillResultRawLog(
            record: retried,
            toolCall: toolCall,
            rawOutput: nil,
            triggerSource: .userTurn,
            ctx: resolution.ctx
        )

        if requiresWaitingAuthorization {
            appendRecentEvent("skill_result: \(resolution.project.displayName) -> \(retried.skillId) \(retried.status.rawValue)")
            if let requiredCapability,
               supervisorHubGrantPreflightEnabled {
                let requestedSeconds = supervisorRequestedGrantWindowSeconds(payload: retried.payload)
                let reason = "retry supervisor skill \(retried.skillId) for project \(resolution.project.displayName) requires \(requiredCapability)"
                let task = Task { [weak self] in
                    guard let self else { return }
                    await self.requestSupervisorHubGrantForSkillCall(
                        requestId: retryRequestId,
                        project: resolution.project,
                        ctx: resolution.ctx,
                        toolCall: toolCall,
                        requiredCapability: requiredCapability,
                        requestedSeconds: requestedSeconds,
                        reason: reason
                    )
                }
                supervisorSkillExecutionTasks[retryRequestId] = task
                addSystemMessage("⏸️ 已为项目 \(resolution.project.displayName) 重新登记技能调用：\(supervisorSkillDisplaySummary(retried))（\(userFacingRequestIdentifier(retryRequestId))），正在向 Hub 申请\(grantCapabilityText(capability: requiredCapability, modelId: ""))授权。")
                return
            }

            let message: String
            if let requiredCapability, !requiredCapability.isEmpty {
                message = "⏸️ 已为项目 \(resolution.project.displayName) 重新登记技能调用：\(supervisorSkillDisplaySummary(retried))（\(userFacingRequestIdentifier(retryRequestId))），正在向 Hub 申请\(grantCapabilityText(capability: requiredCapability, modelId: ""))授权。"
            } else {
                message = "⏸️ 已为项目 \(resolution.project.displayName) 重新登记技能调用：\(supervisorSkillDisplaySummary(retried))（\(userFacingRequestIdentifier(retryRequestId))），当前需要本地审批后才能继续。"
            }
            addSystemMessage(message)
            return
        }

        let task = Task { [weak self] in
            guard let self else { return }
            await self.executeSupervisorSkillCall(
                requestId: retryRequestId,
                project: resolution.project,
                ctx: resolution.ctx,
                toolCall: toolCall,
                triggerSource: .userTurn
            )
        }
        supervisorSkillExecutionTasks[retryRequestId] = task
        addSystemMessage("✅ 已为项目 \(resolution.project.displayName) 重新排队技能调用：\(supervisorSkillDisplaySummary(retried))（\(userFacingRequestIdentifier(retryRequestId))）")
    }

    private func resumeSupervisorSkillCallAfterLocalApproval(
        _ resolution: SupervisorSkillCallResolution
    ) {
        guard let toolCall = resolvedSupervisorToolCallForRecord(resolution.record) else {
            let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
            if let blocked = applySupervisorSkillCallStatus(
                requestId: resolution.record.requestId,
                ctx: resolution.ctx,
                project: resolution.project,
                status: .blocked,
                stepStatus: .blocked,
                resultSummary: "local approval resume failed: skill mapping unavailable",
                denyCode: "skill_mapping_missing",
                updatedAtMs: nowMs,
                triggerSource: .approvalResolution,
                toolCall: nil
            ) {
                scheduleSupervisorApprovalResolutionFollowUp(
                    record: blocked,
                    project: resolution.project,
                    reasonCode: blocked.denyCode,
                    summary: blocked.resultSummary
                )
            }
            addSystemMessage("❌ 无法恢复项目 \(resolution.project.displayName) 的技能调用：\(supervisorSkillDisplaySummary(resolution.record))（\(userFacingRequestIdentifier(resolution.record.requestId))）")
            return
        }

        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        _ = applySupervisorSkillCallStatus(
            requestId: resolution.record.requestId,
            ctx: resolution.ctx,
            project: resolution.project,
            status: .queued,
            stepStatus: .pending,
            resultSummary: "local approval approved; resuming governed dispatch",
            denyCode: "",
            updatedAtMs: nowMs,
            triggerSource: .approvalResolution,
            toolCall: toolCall
        )

        let task = Task { [weak self] in
            guard let self else { return }
            await self.executeSupervisorSkillCall(
                requestId: resolution.record.requestId,
                project: resolution.project,
                ctx: resolution.ctx,
                toolCall: toolCall,
                allowPreviouslyApprovedAuthorization: true,
                triggerSource: .approvalResolution
            )
        }
        supervisorSkillExecutionTasks[resolution.record.requestId] = task
        addSystemMessage("✅ 已批准项目 \(resolution.project.displayName) 的技能调用：\(supervisorSkillDisplaySummary(resolution.record))（\(userFacingRequestIdentifier(resolution.record.requestId))）")
    }

    private func blockSupervisorSkillCallAfterLocalApprovalDenial(
        _ resolution: SupervisorSkillCallResolution
    ) {
        let nowMs = Int64((Date().timeIntervalSince1970 * 1000.0).rounded())
        let toolCall = resolvedSupervisorToolCallForRecord(resolution.record)
        if let blocked = applySupervisorSkillCallStatus(
            requestId: resolution.record.requestId,
            ctx: resolution.ctx,
            project: resolution.project,
            status: .blocked,
            stepStatus: .blocked,
            resultSummary: "local approval denied by user",
            denyCode: "local_approval_denied",
            updatedAtMs: nowMs,
            triggerSource: .approvalResolution,
            toolCall: toolCall
        ) {
            scheduleSupervisorApprovalResolutionFollowUp(
                record: blocked,
                project: resolution.project,
                reasonCode: blocked.denyCode,
                summary: blocked.resultSummary
            )
        }
        addSystemMessage("⛔️ 已拒绝项目 \(resolution.project.displayName) 的技能调用：\(supervisorSkillDisplaySummary(resolution.record))（\(userFacingRequestIdentifier(resolution.record.requestId))）")
    }

    private func performPendingHubGrantAction(
        _ grant: SupervisorPendingGrant,
        approve: Bool
    ) {
        let grantId = grant.grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !grantId.isEmpty else { return }
        guard !pendingHubGrantActionsInFlight.contains(grantId) else { return }

        pendingHubGrantActionsInFlight.insert(grantId)
        let projectId = grant.projectId.trimmingCharacters(in: .whitespacesAndNewlines)

        Task { [weak self] in
            guard let self else { return }

            let result: HubIPCClient.PendingGrantActionResult
            if approve {
                let ttlOverride = grant.requestedTtlSec > 0 ? grant.requestedTtlSec : nil
                let tokenOverride = grant.requestedTokenCap > 0 ? grant.requestedTokenCap : nil
                result = await self.approvePendingHubGrantRequest(
                    grantRequestId: grantId,
                    projectId: projectId.isEmpty ? nil : projectId,
                    requestedTtlSec: ttlOverride,
                    requestedTokenCap: tokenOverride,
                    note: "x_terminal_supervisor_quick_approve"
                )
            } else {
                result = await self.denyPendingHubGrantRequest(
                    grantRequestId: grantId,
                    projectId: projectId.isEmpty ? nil : projectId,
                    reason: "user_denied_from_supervisor"
                )
            }

            await self.completePendingHubGrantAction(
                grantId: grantId,
                grant: grant,
                approve: approve,
                result: result
            )
        }
    }

    private func approvePendingHubGrantRequest(
        grantRequestId: String,
        projectId: String?,
        requestedTtlSec: Int?,
        requestedTokenCap: Int?,
        note: String
    ) async -> HubIPCClient.PendingGrantActionResult {
        if let override = approvePendingHubGrantRequestOverride {
            return await override(
                grantRequestId,
                projectId,
                requestedTtlSec,
                requestedTokenCap,
                note
            )
        }
        return await HubIPCClient.approvePendingGrantRequest(
            grantRequestId: grantRequestId,
            projectId: projectId,
            requestedTtlSec: requestedTtlSec,
            requestedTokenCap: requestedTokenCap,
            note: note
        )
    }

    private func denyPendingHubGrantRequest(
        grantRequestId: String,
        projectId: String?,
        reason: String
    ) async -> HubIPCClient.PendingGrantActionResult {
        if let override = denyPendingHubGrantRequestOverride {
            return await override(
                grantRequestId,
                projectId,
                reason
            )
        }
        return await HubIPCClient.denyPendingGrantRequest(
            grantRequestId: grantRequestId,
            projectId: projectId,
            reason: reason
        )
    }

    private func completePendingHubGrantAction(
        grantId: String,
        grant: SupervisorPendingGrant,
        approve: Bool,
        result: HubIPCClient.PendingGrantActionResult
    ) async {
        pendingHubGrantActionsInFlight.remove(grantId)

        if result.ok {
            pendingHubGrants.removeAll { $0.grantRequestId == grantId }
            let action = approve ? "通过" : "拒绝"
            let summary = pendingGrantSummaryLine(
                grant,
                includeGrantToken: true,
                includeScope: true,
                includeReason: false
            )
            addSystemMessage("已\(action) Hub 授权：\(summary)")
            await resumeSupervisorSkillCallsAfterGrantAction(
                grant: grant,
                approve: approve,
                result: result
            )
        } else {
            let action = approve ? "通过" : "拒绝"
            let reason = result.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "unknown"
            let summary = pendingGrantSummaryLine(
                grant,
                includeGrantToken: true,
                includeScope: false,
                includeReason: false
            )
            addSystemMessage("Hub 授权\(action)失败：\(summary)（reason=\(reason)）")
        }

        await refreshSchedulerSnapshot(force: true)
    }

    private func applyVoiceAuthorizationResolution(
        _ resolution: SupervisorVoiceAuthorizationResolution,
        request: SupervisorVoiceAuthorizationRequest?,
        preserveActiveChallengeOnFailClosed: Bool,
        forceCancel: Bool = false
    ) {
        let previousChallengeId = activeVoiceChallenge?.challengeId
            .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let previousRequestId = activeVoiceAuthorizationRequest?.requestId
            .trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        voiceAuthorizationResolution = resolution
        let preserveMobileConfirmation = shouldPreserveVoiceAuthorizationMobileConfirmationLatch(
            resolution: resolution,
            request: request,
            previousChallengeId: previousChallengeId,
            previousRequestId: previousRequestId
        )

        switch resolution.state {
        case .pending, .escalatedToMobile:
            if resolution.state == .pending || !preserveMobileConfirmation {
                setVoiceAuthorizationMobileConfirmed(
                    false,
                    source: resolution.state == .pending ? "voice_authorization_pending" : "voice_authorization_escalated",
                    emitSystemMessage: false
                )
            }
            activeVoiceAuthorizationRequest = request
            activeVoiceChallenge = resolution.challenge
        case .verified, .denied:
            setVoiceAuthorizationMobileConfirmed(
                false,
                source: resolution.state == .verified ? "voice_authorization_verified" : "voice_authorization_denied",
                emitSystemMessage: false
            )
            activeVoiceAuthorizationRequest = nil
            activeVoiceChallenge = nil
        case .failClosed:
            if forceCancel || !preserveActiveChallengeOnFailClosed || !preserveMobileConfirmation {
                setVoiceAuthorizationMobileConfirmed(
                    false,
                    source: forceCancel ? "voice_authorization_cancelled" : "voice_authorization_fail_closed",
                    emitSystemMessage: false
                )
            }
            if forceCancel || !preserveActiveChallengeOnFailClosed {
                activeVoiceAuthorizationRequest = nil
                activeVoiceChallenge = nil
            } else if let request {
                activeVoiceAuthorizationRequest = request
                activeVoiceChallenge = resolution.challenge ?? activeVoiceChallenge
            }
        }

        let challengeId = resolution.challengeId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let challengeToken = challengeId.isEmpty ? "n/a" : challengeId
        let reasonToken = resolution.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines)
        let denyToken = resolution.denyCode?.trimmingCharacters(in: .whitespacesAndNewlines)

        let eventText: String
        let messageText: String
        switch resolution.state {
        case .pending:
            eventText = "voice authorization challenge issued: \(challengeToken)"
            messageText = "语音授权挑战已发起（challenge=\(challengeToken)）"
        case .escalatedToMobile:
            eventText = "voice authorization escalated to mobile: \(challengeToken)"
            messageText = "语音授权已升级到移动端确认（challenge=\(challengeToken)）"
        case .verified:
            eventText = "voice authorization verified: \(challengeToken)"
            messageText = "语音授权已验证通过（challenge=\(challengeToken)）"
        case .denied:
            let deny = denyToken ?? "denied"
            eventText = "voice authorization denied: \(challengeToken) -> \(deny)"
            messageText = "语音授权被拒绝（challenge=\(challengeToken)，deny=\(deny)）"
        case .failClosed:
            let reason = reasonToken ?? "unknown"
            eventText = "voice authorization fail-closed: \(challengeToken) -> \(reason)"
            if forceCancel, reason == "user_cancelled" {
                messageText = "已取消语音授权挑战（challenge=\(challengeToken)）"
            } else {
                messageText = "语音授权失败闭锁（challenge=\(challengeToken)，reason=\(reason)）"
            }
        }

        appendRecentEvent(eventText)
        addSystemMessage(messageText)
        speakSupervisorVoiceAuthorizationUpdate(
            resolution: resolution,
            challengeToken: challengeToken
        )
    }

    private func shouldPreserveVoiceAuthorizationMobileConfirmationLatch(
        resolution: SupervisorVoiceAuthorizationResolution,
        request: SupervisorVoiceAuthorizationRequest?,
        previousChallengeId: String,
        previousRequestId: String
    ) -> Bool {
        let nextChallengeId = (resolution.challengeId ?? resolution.challenge?.challengeId ?? "")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let nextRequestId = (request?.requestId ?? resolution.requestId)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !previousChallengeId.isEmpty,
              !nextChallengeId.isEmpty,
              !previousRequestId.isEmpty,
              !nextRequestId.isEmpty else {
            return false
        }
        return previousChallengeId == nextChallengeId && previousRequestId == nextRequestId
    }

    private func shouldPreserveActiveVoiceAuthorizationStateAfterFailClosed(
        _ resolution: SupervisorVoiceAuthorizationResolution,
        preserveRequested: Bool
    ) -> Bool {
        guard preserveRequested, resolution.state == .failClosed else { return false }
        switch HubRouteStateMachine.normalizedReasonToken(resolution.reasonCode) {
        case "challenge_expired",
             "challenge_missing",
             "replay_detected",
             "voice_authorization_not_started",
             "request_id_empty",
             "template_id_empty",
             "challenge_id_empty",
             "verify_nonce_empty",
             "user_cancelled":
            return false
        default:
            return true
        }
    }

    private func applyVoiceAuthorizationRuntimeSideEffects(
        _ resolution: SupervisorVoiceAuthorizationResolution,
        request: SupervisorVoiceAuthorizationRequest?,
        forceCancel: Bool
    ) async {
        guard !forceCancel else { return }
        guard resolution.state == .verified else { return }
        if await applyVerifiedPendingGrantVoiceAuthorization(request: request) {
            return
        }
        guard isCurrentGuardedOneShotVoiceAuthorization(request) else { return }
        guard let intakeRequest = oneShotIntakeRequest,
              let planDecision = oneShotAdaptivePoolPlan,
              oneShotRunState?.state == .awaitingGrant else {
            return
        }

        let resumedRunState = oneShotRunStateStore.transition(
            to: .launching,
            owner: .supervisor,
            activePools: planDecision.poolPlan.map(\.poolID),
            activeLanes: planDecision.poolPlan.flatMap(\.laneIDs),
            topBlocker: "none",
            nextDirectedTarget: "Supervisor",
            userVisibleSummary: "voice authorization verified; guarded one-shot launch resumed",
            evidenceRefs: OneShotControlPlaneSnapshot.defaultEvidenceRefs(),
            auditRef: intakeRequest.auditRef
        )
        oneShotRunState = resumedRunState
        appendRecentEvent("guarded one-shot launch resumed after voice authorization")
        addSystemMessage("高风险 one-shot 语音授权已通过，正在接入真实启动链路。")

        let outcome = await executePreparedOneShotLaunch(
            request: intakeRequest,
            planDecision: planDecision
        )
        applyGuardedOneShotLaunchResumeOutcome(
            outcome,
            request: intakeRequest,
            planDecision: planDecision
        )
    }

    private func finalizeVoicePendingGrantActionContext(
        resolution: SupervisorVoiceAuthorizationResolution,
        request: SupervisorVoiceAuthorizationRequest?,
        forceCancel: Bool,
        preserveActiveChallengeOnFailClosed: Bool
    ) {
        guard let context = activeVoicePendingGrantAction else { return }
        let requestId = request?.requestId.trimmingCharacters(in: .whitespacesAndNewlines)
            ?? resolution.requestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !requestId.isEmpty, context.requestId == requestId else { return }

        switch resolution.state {
        case .pending, .escalatedToMobile:
            return
        case .verified, .denied:
            activeVoicePendingGrantAction = nil
        case .failClosed:
            if forceCancel ||
                !preserveActiveChallengeOnFailClosed ||
                activeVoiceChallenge == nil ||
                activeVoiceAuthorizationRequest == nil {
                activeVoicePendingGrantAction = nil
            }
        }
    }

    private func applyVerifiedPendingGrantVoiceAuthorization(
        request: SupervisorVoiceAuthorizationRequest?
    ) async -> Bool {
        guard let request,
              let context = activeVoicePendingGrantAction,
              context.requestId == request.requestId else {
            return false
        }

        let grant = context.grant
        let grantId = grant.grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !grantId.isEmpty else {
            let replyText = "语音授权已验证，但授权单号为空，我没有执行对应的 Hub 授权。"
            let spokenOutcome = speakSupervisorVoiceReply(replyText)
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: request.actionText,
                    responseText: replyText,
                    triggerSource: .grantResolution,
                    triggeredByVoice: true,
                    spokenOutcome: spokenOutcome,
                    replySource: "pending_grant_missing_id",
                    personaSlot: nil,
                    lifecycle: .nonReviewAssistantReply
                )
            )
            return true
        }

        guard !pendingHubGrantActionsInFlight.contains(grantId) else {
            let replyText = "语音授权已验证，但《\(grant.projectName)》这笔 Hub 授权仍在处理中（授权单号：\(grantId)）。"
            let spokenOutcome = speakSupervisorVoiceReply(replyText)
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: request.actionText,
                    responseText: replyText,
                    triggerSource: .grantResolution,
                    triggeredByVoice: true,
                    spokenOutcome: spokenOutcome,
                    replySource: "pending_grant_inflight",
                    personaSlot: nil,
                    lifecycle: .nonReviewAssistantReply
                )
            )
            return true
        }

        pendingHubGrantActionsInFlight.insert(grantId)
        let projectId = grant.projectId.trimmingCharacters(in: .whitespacesAndNewlines)
        let result: HubIPCClient.PendingGrantActionResult
        if context.approve {
            let ttlOverride = grant.requestedTtlSec > 0 ? grant.requestedTtlSec : nil
            let tokenOverride = grant.requestedTokenCap > 0 ? grant.requestedTokenCap : nil
            result = await approvePendingHubGrantRequest(
                grantRequestId: grantId,
                projectId: projectId.isEmpty ? nil : projectId,
                requestedTtlSec: ttlOverride,
                requestedTokenCap: tokenOverride,
                note: "x_terminal_supervisor_voice_grant_approve:\(request.requestId)"
            )
        } else {
            result = await denyPendingHubGrantRequest(
                grantRequestId: grantId,
                projectId: projectId.isEmpty ? nil : projectId,
                reason: "voice_authorized_supervisor_denial:\(request.requestId)"
            )
        }

        await completePendingHubGrantAction(
            grantId: grantId,
            grant: grant,
            approve: context.approve,
            result: result
        )

        let followUp = await voicePendingGrantPostActionReply(
            grant: grant,
            approve: context.approve,
            result: result
        )
        completeSupervisorAssistantTurn(
            SupervisorAfterTurnLifecycleContext(
                userMessage: request.actionText,
                responseText: followUp.text,
                triggerSource: .grantResolution,
                triggeredByVoice: true,
                spokenOutcome: followUp.spokenOutcome,
                replySource: "pending_grant_follow_up",
                personaSlot: nil,
                lifecycle: .nonReviewAssistantReply
            )
        )
        return true
    }

    private func voicePendingGrantPostActionReply(
        grant: SupervisorPendingGrant,
        approve: Bool,
        result: HubIPCClient.PendingGrantActionResult
    ) async -> SupervisorVoicePendingGrantReply {
        let grantId = grant.grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines)
        if !result.ok {
            let replyText = XTHubGrantPresentation.voiceDecisionFailureReply(
                projectName: grant.projectName,
                intent: approve ? .approve : .deny,
                capability: grant.capability,
                modelId: grant.modelId,
                grantRequestId: grantId,
                reasonCode: result.reasonCode
            )
            return SupervisorVoicePendingGrantReply(
                text: replyText,
                spokenOutcome: speakSupervisorVoiceReply(replyText)
            )
        }

        let request = HubIPCClient.SupervisorBriefProjectionRequestPayload(
            requestId: "voice_grant_follow_up_\(Int(Date().timeIntervalSince1970 * 1000))_\(UUID().uuidString.lowercased())",
            projectId: grant.projectId,
            runId: nil,
            missionId: nil,
            projectionKind: "progress_brief",
            trigger: "critical_path_changed",
            includeTtsScript: true,
            includeCardSummary: true,
            maxEvidenceRefs: 4
        )
        let fetcher = supervisorBriefProjectionRequestOverride
            ?? { payload in
                await HubIPCClient.requestSupervisorBriefProjection(payload)
            }
        let projectionResult = await fetcher(request)
        if projectionResult.ok, let projection = projectionResult.projection {
            let replyText = renderSupervisorBriefProjectionVoiceReply(
                projection,
                projectName: grant.projectName
            )
            let script = projectionVoiceScript(from: projection)
            let spokenOutcome: SupervisorSpeechSynthesizer.Outcome
            if script.isEmpty {
                spokenOutcome = speakSupervisorVoiceReply(replyText)
            } else {
                let job = SupervisorVoiceTTSJob(
                    trigger: .authorization,
                    priority: .normal,
                    script: script,
                    dedupeKey: "voice-grant-followup:\(projectionVoiceDedupeKey(from: projection))"
                )
                spokenOutcome = dispatchSupervisorVoiceJob(
                    job,
                    preferences: currentVoicePreferences(),
                    source: "pending_grant_follow_up",
                    suppressRapidSameSourceRepeat: false,
                    cancelPendingHeartbeat: true
                )
            }
            return SupervisorVoicePendingGrantReply(
                text: replyText,
                spokenOutcome: spokenOutcome
            )
        }

        let capabilityText = grantCapabilityText(capability: grant.capability, modelId: grant.modelId)
        let replyText: String
        if approve {
            replyText = "已批准 \(grant.projectName) 的 \(capabilityText) Hub 授权。我会继续推进，并在路径变化时继续汇报。"
        } else {
            replyText = "已拒绝 \(grant.projectName) 的 \(capabilityText) Hub 授权。我会继续保持阻断，并等待新的指示。"
        }
        return SupervisorVoicePendingGrantReply(
            text: replyText,
            spokenOutcome: speakSupervisorVoiceReply(replyText)
        )
    }

    @discardableResult
    private func appendSupervisorAssistantMessage(
        _ text: String,
        timestamp: Date = Date()
    ) -> String? {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }
        messages.append(
            SupervisorMessage(
                id: UUID().uuidString,
                role: .assistant,
                content: trimmed,
                isVoice: false,
                timestamp: timestamp.timeIntervalSince1970
            )
        )
        return trimmed
    }

    @discardableResult
    func appendLocalAssistantNotice(
        _ text: String,
        timestamp: Date = Date()
    ) -> String? {
        appendSupervisorAssistantMessage(text, timestamp: timestamp)
    }

    private func isCurrentGuardedOneShotVoiceAuthorization(
        _ request: SupervisorVoiceAuthorizationRequest?
    ) -> Bool {
        guard let request,
              let intakeRequest = oneShotIntakeRequest else {
            return false
        }
        let expectedRequestID = oneShotVoiceAuthorizationRequestID(
            requestID: intakeRequest.requestID,
            authorizationTypes: intakeRequest.requiresHumanAuthorizationTypes
        )
        guard request.requestId == expectedRequestID else { return false }
        let projectID = request.projectId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !projectID.isEmpty, projectID == intakeRequest.projectID else {
            return false
        }
        return true
    }

    private func executePreparedOneShotLaunch(
        request: SupervisorOneShotIntakeRequest,
        planDecision: AdaptivePoolPlanDecision
    ) async -> GuardedOneShotLaunchResumeOutcome {
        guard let buildResult = oneShotPreparedSplitBuildResult else {
            return .failedClosed(reason: "guarded_one_shot_split_plan_missing")
        }

        if let executor = preparedOneShotLaunchExecutorForTesting {
            return await executor(request, planDecision, buildResult)
        }

        guard let supervisor = appModel?.supervisor else {
            return .failedClosed(reason: "supervisor_model_unavailable")
        }

        guard supervisor.orchestrator != nil else {
            return .failedClosed(reason: "supervisor_orchestrator_unavailable")
        }
        let orchestrator = supervisor.orchestrator!
        _ = await ensureOneShotAnchorProject(
            in: supervisor,
            request: request,
            planDecision: planDecision
        )
        _ = orchestrator.adoptPreparedSplitProposal(
            buildResult,
            auditDetail: "guarded one-shot prepared proposal adopted after voice authorization"
        )

        if buildResult.validation.hasBlockingIssues {
            let reason = buildResult.validation.blockingIssues.first?.code ?? "split_proposal_blocked"
            return .blocked(reason: reason, report: nil)
        }

        guard let promptResult = orchestrator.confirmActiveSplitProposal(globalContext: request.userGoal) else {
            let reason = normalizedOneShotFailureReason(
                orchestrator.splitFlowErrorMessage,
                fallback: "prompt_contract_confirmation_failed"
            )
            return .blocked(reason: reason, report: nil)
        }

        if promptResult.status != .ready || promptResult.lintResult.hasBlockingErrors {
            let lintReason = promptResult.lintResult.blockingIssues.first?.code
            let reason = normalizedOneShotFailureReason(lintReason, fallback: "prompt_contract_blocked")
            return .blocked(reason: reason, report: nil)
        }

        guard let launchReport = await orchestrator.executeActiveSplitProposal() else {
            let reason = normalizedOneShotFailureReason(
                orchestrator.splitFlowErrorMessage,
                fallback: "lane_launch_execution_failed"
            )
            return .blocked(reason: reason, report: nil)
        }

        if !launchReport.launchedLaneIDs.isEmpty {
            return .launched(launchReport)
        }

        let blockedReason = primaryBlockedReason(from: launchReport)
        return .blocked(reason: blockedReason, report: launchReport)
    }

    private func ensureOneShotAnchorProject(
        in supervisor: SupervisorModel,
        request: SupervisorOneShotIntakeRequest,
        planDecision: AdaptivePoolPlanDecision
    ) async -> ProjectModel {
        if let existing = supervisor.activeProjects.first(where: { $0.name == "Root" }) {
            existing.taskDescription = request.userGoal
            existing.status = .running
            applyOneShotAnchorExecutionProfile(to: existing, planDecision: planDecision)
            return existing
        }

        if let existing = supervisor.activeProjects.first(where: {
            $0.status == .running || $0.status == .pending
        }) {
            existing.taskDescription = request.userGoal
            if existing.status == .pending {
                existing.status = .running
            }
            applyOneShotAnchorExecutionProfile(to: existing, planDecision: planDecision)
            return existing
        }

        let root = ProjectModel(
            name: "Root",
            taskDescription: request.userGoal,
            taskIcon: "point.3.connected.trianglepath.dotted",
            status: .running,
            modelName: oneShotAnchorModelName(for: planDecision),
            executionTier: planDecision.riskSurface >= .high ? .a4OpenClaw : .a3DeliverAuto,
            supervisorInterventionTier: planDecision.riskSurface == .low ? .s2PeriodicReview : .s3StrategicCoach,
            budget: Budget(
                daily: planDecision.riskSurface >= .high ? 40.0 : 20.0,
                monthly: planDecision.riskSurface >= .high ? 1200.0 : 600.0
            )
        )
        applyOneShotAnchorExecutionProfile(to: root, planDecision: planDecision)
        supervisor.activeProjects.append(root)
        await supervisor.onProjectCreated(root)
        return root
    }

    private func applyOneShotAnchorExecutionProfile(
        to project: ProjectModel,
        planDecision: AdaptivePoolPlanDecision
    ) {
        let capability: ModelCapability
        let executionTier: AXProjectExecutionTier
        let supervisorTier: AXProjectSupervisorInterventionTier
        let modelName: String

        switch planDecision.riskSurface {
        case .critical:
            capability = .expert
            executionTier = .a4OpenClaw
            supervisorTier = .s4TightSupervision
            modelName = "one-shot-anchor-critical"
        case .high:
            capability = .advanced
            executionTier = .a4OpenClaw
            supervisorTier = .s3StrategicCoach
            modelName = "one-shot-anchor-high"
        case .medium:
            capability = .advanced
            executionTier = .a3DeliverAuto
            supervisorTier = .s3StrategicCoach
            modelName = "one-shot-anchor-medium"
        case .low:
            capability = .intermediate
            executionTier = .a3DeliverAuto
            supervisorTier = .s2PeriodicReview
            modelName = "one-shot-anchor-low"
        }

        let governance = AXProjectGovernanceBundle.recommended(
            for: executionTier,
            supervisorInterventionTier: supervisorTier
        )
        project.updateGovernance(
            executionTier: governance.executionTier,
            supervisorInterventionTier: governance.supervisorInterventionTier,
            reviewPolicyMode: governance.reviewPolicyMode,
            progressHeartbeatSeconds: governance.schedule.progressHeartbeatSeconds,
            reviewPulseSeconds: governance.schedule.reviewPulseSeconds,
            brainstormReviewSeconds: governance.schedule.brainstormReviewSeconds,
            eventDrivenReviewEnabled: governance.schedule.eventDrivenReviewEnabled,
            eventReviewTriggers: governance.schedule.eventReviewTriggers
        )
        project.currentModel = ModelInfo(
            id: modelName,
            name: modelName,
            displayName: modelName,
            type: .hubPaid,
            capability: capability,
            speed: capability == .expert ? .slow : .medium,
            costPerMillionTokens: capability == .expert ? 5.0 : 3.0,
            memorySize: nil,
            suitableFor: ["one-shot", "supervisor_anchor"],
            badge: nil,
            badgeColor: nil
        )
    }

    private func oneShotAnchorModelName(for planDecision: AdaptivePoolPlanDecision) -> String {
        switch planDecision.riskSurface {
        case .critical:
            return "one-shot-anchor-critical"
        case .high:
            return "one-shot-anchor-high"
        case .medium:
            return "one-shot-anchor-medium"
        case .low:
            return "one-shot-anchor-low"
        }
    }

    private func applyGuardedOneShotLaunchResumeOutcome(
        _ outcome: GuardedOneShotLaunchResumeOutcome,
        request: SupervisorOneShotIntakeRequest,
        planDecision: AdaptivePoolPlanDecision
    ) {
        switch outcome {
        case .launched(let report):
            let blockedCount = report.blockedLaneReasons.count
            let deferredCount = report.deferredLaneIDs.count
            let summary = "one-shot launch started: launched=\(report.launchedLaneIDs.count), blocked=\(blockedCount), deferred=\(deferredCount)"
            oneShotRunState = oneShotRunStateStore.transition(
                to: .running,
                owner: .supervisor,
                activePools: planDecision.poolPlan.map(\.poolID),
                activeLanes: report.launchedLaneIDs.isEmpty ? planDecision.poolPlan.flatMap(\.laneIDs) : report.launchedLaneIDs,
                topBlocker: "none",
                nextDirectedTarget: "Supervisor",
                userVisibleSummary: summary,
                evidenceRefs: OneShotControlPlaneSnapshot.defaultEvidenceRefs(),
                auditRef: request.auditRef
            )
            appendRecentEvent(summary)
            addSystemMessage("one-shot 已进入真实执行（launched=\(report.launchedLaneIDs.count)，blocked=\(blockedCount)，deferred=\(deferredCount)）。")

        case .blocked(let reason, let report):
            let blockedCount = report?.blockedLaneReasons.count ?? 0
            let summary = "one-shot launch blocked: \(reason)"
            oneShotRunState = oneShotRunStateStore.transition(
                to: .blocked,
                owner: .supervisor,
                activePools: planDecision.poolPlan.map(\.poolID),
                activeLanes: planDecision.poolPlan.flatMap(\.laneIDs),
                topBlocker: reason,
                nextDirectedTarget: "Supervisor",
                userVisibleSummary: summary,
                evidenceRefs: OneShotControlPlaneSnapshot.defaultEvidenceRefs(),
                auditRef: request.auditRef
            )
            appendRecentEvent(summary)
            addSystemMessage("one-shot 启动仍被阻塞（reason=\(reason)，blocked=\(blockedCount)）。")

        case .failedClosed(let reason):
            let summary = "failed closed: \(reason)"
            oneShotRunState = oneShotRunStateStore.transition(
                to: .failedClosed,
                owner: .supervisor,
                activePools: planDecision.poolPlan.map(\.poolID),
                activeLanes: planDecision.poolPlan.flatMap(\.laneIDs),
                topBlocker: reason,
                nextDirectedTarget: "Supervisor",
                userVisibleSummary: summary,
                evidenceRefs: OneShotControlPlaneSnapshot.defaultEvidenceRefs(),
                auditRef: request.auditRef
            )
            appendRecentEvent("one-shot launch failed closed: \(reason)")
            addSystemMessage("one-shot 启动失败闭锁（reason=\(reason)）。")
        }
    }

    private func normalizedOneShotFailureReason(_ raw: String?, fallback: String) -> String {
        let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !trimmed.isEmpty else { return fallback }
        let singleLine = trimmed.replacingOccurrences(of: "\n", with: " ")
        let sanitized = singleLine
            .components(separatedBy: .whitespacesAndNewlines)
            .filter { !$0.isEmpty }
            .joined(separator: "_")
        return sanitized.isEmpty ? fallback : sanitized.lowercased()
    }

    private func primaryBlockedReason(from report: LaneLaunchReport) -> String {
        let candidates = report.blockedLaneReasons
            .values
            .map { normalizedOneShotFailureReason($0, fallback: "lane_launch_blocked") }
            .sorted()
        return candidates.first ?? "lane_launch_blocked"
    }

    private func makeVoiceAuthorizationManagerFailureResolution(
        requestId: String,
        projectId: String?,
        templateId: String,
        riskTier: LaneRiskTier,
        reasonCode: String,
        challenge: HubIPCClient.VoiceGrantChallengeSnapshot?
    ) -> SupervisorVoiceAuthorizationResolution {
        let normalizedTemplate = templateId.trimmingCharacters(in: .whitespacesAndNewlines)
        let fallbackTemplate = normalizedTemplate.isEmpty ? "voice.grant.v1" : normalizedTemplate
        let requiresMobileConfirm = challenge?.requiresMobileConfirm ?? (riskTier >= .high)
        let allowVoiceOnly = challenge?.allowVoiceOnly ?? (riskTier < .high)
        let policyRef = [
            "schema=\(SupervisorVoiceAuthorizationResolution.currentSchemaVersion)",
            "state=\(SupervisorVoiceAuthorizationResolution.State.failClosed.rawValue)",
            "risk_tier=\(riskTier.rawValue)",
            "requires_mobile_confirm=\(requiresMobileConfirm ? "true" : "false")",
            "allow_voice_only=\(allowVoiceOnly ? "true" : "false")",
            "reason_code=\(reasonCode)"
        ].joined(separator: ";")

        let nextAction: String = {
            switch reasonCode {
            case "voice_authorization_not_started":
                return "issue a new voice challenge before attempting verify"
            case "voice_authorization_inflight":
                return "wait for the current voice authorization round to finish"
            case "user_cancelled":
                return "reissue the challenge if authorization is still required"
            case "hub_env_missing":
                return "repair Hub pairing/runtime profile before retrying voice authorization"
            default:
                return "hold the gated action and repair the voice authorization path first"
            }
        }()

        return SupervisorVoiceAuthorizationResolution(
            schemaVersion: SupervisorVoiceAuthorizationResolution.currentSchemaVersion,
            state: .failClosed,
            ok: false,
            requestId: requestId.trimmingCharacters(in: .whitespacesAndNewlines),
            projectId: {
                let token = projectId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                return token.isEmpty ? nil : token
            }(),
            templateId: fallbackTemplate,
            riskTier: riskTier.rawValue,
            challengeId: challenge?.challengeId,
            challenge: challenge,
            verified: false,
            requiresMobileConfirm: requiresMobileConfirm,
            allowVoiceOnly: allowVoiceOnly,
            denyCode: nil,
            reasonCode: reasonCode,
            transcriptHash: nil,
            semanticMatchScore: nil,
            policyRef: policyRef,
            nextAction: nextAction
        )
    }

    private func pushHubHeartbeatNotification(
        timeText: String,
        reason: String,
        projectCount: Int,
        changed: Bool,
        blockerCount: Int,
        blockerSignal: BlockerSignal,
        focusActionURL: String?,
        topSummary: String,
        queueSummary: String,
        permissionSummary: String,
        governanceRepairSummary: String,
        progressSummary: String,
        nextStepSummary: String,
        queuePendingCount: Int,
        permissionPendingCount: Int,
        governanceRepairCount: Int,
        routeAttentionSignal: HeartbeatRouteAttentionSignal?
    ) {
        let presentation = buildHeartbeatNotificationPresentation(
            timeText: timeText,
            reason: reason,
            projectCount: projectCount,
            changed: changed,
            blockerCount: blockerCount,
            blockerSignal: blockerSignal,
            topSummary: topSummary,
            queueSummary: queueSummary,
            permissionSummary: permissionSummary,
            governanceRepairSummary: governanceRepairSummary,
            progressSummary: progressSummary,
            nextStepSummary: nextStepSummary,
            queuePendingCount: queuePendingCount,
            permissionPendingCount: permissionPendingCount,
            governanceRepairCount: governanceRepairCount,
            focusActionURL: focusActionURL,
            routeDiagnoseShouldAlert: routeAttentionSignal?.shouldAlertOnTimer
        )
        guard presentation.unread else {
            HubIPCClient.removeNotification(dedupeKey: heartbeatNotificationDedupeKey)
            return
        }
        guard shouldMirrorNotificationToHub(actionURL: focusActionURL) else {
            HubIPCClient.removeNotification(dedupeKey: heartbeatNotificationDedupeKey)
            return
        }
        HubIPCClient.pushNotification(
            source: "X-Terminal",
            title: presentation.title,
            body: presentation.body,
            dedupeKey: heartbeatNotificationDedupeKey,
            actionURL: focusActionURL,
            unread: presentation.unread
        )
    }

    private func buildHeartbeatNotificationPresentation(
        timeText: String,
        reason: String,
        projectCount: Int,
        changed: Bool,
        blockerCount: Int,
        blockerSignal: BlockerSignal,
        topSummary: String,
        queueSummary: String,
        permissionSummary: String,
        governanceRepairSummary: String,
        progressSummary: String,
        nextStepSummary: String,
        queuePendingCount: Int,
        permissionPendingCount: Int,
        governanceRepairCount: Int,
        focusActionURL: String?,
        routeDiagnoseShouldAlert: Bool? = nil
    ) -> HeartbeatNotificationPresentation {
        let memoryReadinessLine = supervisorMemoryReadinessBriefTextLine()
        let voiceReadinessSignal = heartbeatVoiceReadinessSignal()
        let routeDiagnoseAction = heartbeatNotificationHasRouteDiagnoseAction(focusActionURL)
        let governanceRepairAction = heartbeatNotificationHasGovernanceRepairAction(focusActionURL)
        let routeDiagnoseHighlight = routeDiagnoseAction
            ? heartbeatRouteDiagnoseHighlight(nextStepSummary: nextStepSummary)
            : nil
        let governanceRepairHighlight = governanceRepairAction
            ? heartbeatGovernanceRepairHighlight(
                governanceRepairSummary: governanceRepairSummary,
                nextStepSummary: nextStepSummary
            )
            : nil
        let title: String
        let unread: Bool
        if blockerCount > 0, blockerSignal.escalated {
            title = "🚨 Supervisor 升级提醒：\(blockerCount) 个阻塞已持续 \(blockerSignal.streak) 次心跳"
            unread = true
        } else if !progressSummary.isEmpty {
            title = "🚀 Supervisor 心跳：已主动推进项目"
            unread = true
        } else if blockerCount > 0, blockerSignal.streak <= 1 {
            title = "🚧 Supervisor 心跳：检测到 \(blockerCount) 个阻塞"
            unread = true
        } else if blockerCount > 0 {
            title = "🚧 Supervisor 心跳：阻塞持续（静默）"
            unread = false
        } else if permissionPendingCount > 0 {
            title = "🛂 Supervisor 心跳：\(permissionPendingCount) 个权限申请待处理"
            unread = true
        } else if governanceRepairCount > 0 {
            title = "🛠️ Supervisor 心跳：\(governanceRepairCount) 个治理修复待处理"
            unread = true
        } else if let voiceReadinessSignal {
            title = voiceReadinessSignal.readyForFirstTask
                ? "🎙️ Supervisor 心跳：语音首个任务已就绪，但仍有修复项"
                : "🎙️ Supervisor 心跳：语音链路待修复"
            unread = !voiceReadinessSignal.readyForFirstTask || changed
        } else if queuePendingCount > 0 {
            title = "⏳ Supervisor 心跳：\(queuePendingCount) 个项目排队中"
            unread = changed
        } else if routeDiagnoseAction {
            if let routeDiagnoseShouldAlert {
                title = routeDiagnoseShouldAlert
                    ? "🧭 Supervisor 心跳：模型路由异常，点我直接诊断"
                    : "🧭 Supervisor 心跳：模型路由仍需关注（静默）"
                unread = routeDiagnoseShouldAlert
            } else {
                title = "🧭 Supervisor 心跳：模型路由异常，点我直接诊断"
                unread = true
            }
        } else if memoryReadinessLine != nil {
            title = "⚠️ Supervisor 心跳：战略记忆供给不足"
            unread = true
        } else if changed {
            title = "Supervisor 心跳：项目有更新（静默）"
            unread = false
        } else {
            title = "Supervisor 心跳：状态稳定（静默）"
            unread = false
        }

        var blockerLines: [String] = []
        blockerLines.append(blockerCount > 0 ? "阻塞项目数：\(blockerCount)" : "阻塞项目数：0")
        if blockerCount > 0 {
            blockerLines.append("阻塞连续心跳：\(max(1, blockerSignal.streak)) 次")
            if blockerSignal.escalated {
                blockerLines.append("升级状态：已触发升级提醒")
            } else if blockerSignal.cooldownRemainingSec > 0 {
                let mins = max(1, Int(ceil(Double(blockerSignal.cooldownRemainingSec) / 60.0)))
                blockerLines.append("升级冷却中：约 \(mins) 分钟后可再次升级提醒")
            }
        }
        var bodyLines = [
            "时间：\(timeText)",
            "原因：\(reason)",
            "项目总数：\(projectCount)",
            blockerLines.joined(separator: "\n"),
            "排队项目数：\(queuePendingCount)",
            "待授权项目数：\(permissionPendingCount)",
            "待治理修复项目数：\(governanceRepairCount)"
        ]
        if routeDiagnoseAction {
            bodyLines.append("操作提示：")
            bodyLines.append("点开这条提醒会直接进入项目聊天，并自动展开一条路由诊断摘要（等价于先去项目里看 `/route diagnose`）。")
            if let routeDiagnoseHighlight {
                bodyLines.append("优先建议：")
                bodyLines.append(routeDiagnoseHighlight)
            }
        } else if governanceRepairAction {
            bodyLines.append("操作提示：")
            bodyLines.append("点开这条提醒会直接进入项目治理设置，并定位到对应的治理子页。")
            if let governanceRepairHighlight {
                bodyLines.append("优先建议：")
                bodyLines.append(governanceRepairHighlight)
            }
        } else if let voiceReadinessSignal {
            bodyLines.append("操作提示：")
            bodyLines.append("点开这条提醒会直接进入语音运行时相关设置或诊断页。")
            bodyLines.append("优先建议：")
            bodyLines.append(voiceReadinessSignal.nextStep)
        }
        if let memoryReadinessLine {
            bodyLines.append("战略纠偏状态：")
            bodyLines.append(memoryReadinessLine)
        }
        bodyLines.append(contentsOf: [
            "主动推进：",
            progressSummary.isEmpty ? "（本轮无需介入）" : progressSummary,
            "重点看板：",
            topSummary,
            "排队态势：",
            queueSummary.isEmpty ? "（无）" : queueSummary,
            "权限申请：",
            permissionSummary.isEmpty ? "（无）" : permissionSummary,
            "治理修复：",
            governanceRepairSummary.isEmpty ? "（无）" : governanceRepairSummary,
            "语音就绪：",
            voiceReadinessSignal?.overallSummary ?? "（无）",
            "Coder 下一步建议：",
            nextStepSummary.isEmpty ? "（暂无）" : nextStepSummary
        ])
        return HeartbeatNotificationPresentation(
            title: title,
            body: bodyLines.joined(separator: "\n"),
            unread: unread
        )
    }

    private func heartbeatNotificationHasRouteDiagnoseAction(
        _ focusActionURL: String?
    ) -> Bool {
        let raw = focusActionURL?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !raw.isEmpty,
              let url = URL(string: raw),
              let route = XTDeepLinkParser.parse(url) else {
            return false
        }

        switch route {
        case let .project(projectRoute):
            return projectRoute.focusTarget == .routeDiagnose
        default:
            return false
        }
    }

    private func heartbeatNotificationHasGovernanceRepairAction(
        _ focusActionURL: String?
    ) -> Bool {
        let raw = focusActionURL?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard !raw.isEmpty,
              let url = URL(string: raw),
              let route = XTDeepLinkParser.parse(url) else {
            return false
        }

        switch route {
        case let .project(projectRoute):
            return projectRoute.governanceDestination != nil
        default:
            return false
        }
    }

    private func heartbeatRouteDiagnoseHighlight(
        nextStepSummary: String
    ) -> String? {
        let lines = nextStepSummary
            .split(separator: "\n", omittingEmptySubsequences: true)
            .map {
                $0.trimmingCharacters(in: .whitespacesAndNewlines)
                    .replacingOccurrences(
                        of: #"^\d+\.\s*"#,
                        with: "",
                        options: .regularExpression
                    )
            }
            .filter { !$0.isEmpty }

        if let routeLine = lines.first(where: { $0.contains("模型路由：") || $0.contains("/route diagnose") }) {
            return routeLine
        }
        return nil
    }

    private func heartbeatGovernanceRepairHighlight(
        governanceRepairSummary: String,
        nextStepSummary: String
    ) -> String? {
        let summaryLines = governanceRepairSummary
            .split(separator: "\n", omittingEmptySubsequences: true)
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        if let first = summaryLines.first {
            return first
        }

        let lines = nextStepSummary
            .split(separator: "\n", omittingEmptySubsequences: true)
            .map {
                $0.trimmingCharacters(in: .whitespacesAndNewlines)
                    .replacingOccurrences(
                        of: #"^\d+\.\s*"#,
                        with: "",
                        options: .regularExpression
                    )
            }
            .filter { !$0.isEmpty }

        if let governanceLine = lines.first(where: {
            $0.contains("治理修复：") || $0.contains("Execution Tier") || $0.contains("Project Governance")
        }) {
            return governanceLine
        }
        return nil
    }

    private func speakSupervisorHeartbeatUpdate(
        reason: String,
        changed: Bool,
        projects: [AXProjectEntry],
        blockerProjects: [(projectId: String, blocker: String)],
        blockerSignal: BlockerSignal,
        permissionSignals: [ProjectPermissionSignal],
        governanceRepairSignals: [ProjectGovernanceRepairSignal],
        queueSignals: [ProjectQueueSignal],
        progressActions: [HeartbeatAutoProgressAction],
        nextStepSummary: String,
        routeAttentionSignal: HeartbeatRouteAttentionSignal?
    ) {
        let fallbackJob = heartbeatVoiceJob(
            reason: reason,
            changed: changed,
            projects: projects,
            blockerProjects: blockerProjects,
            blockerSignal: blockerSignal,
            permissionSignals: permissionSignals,
            governanceRepairSignals: governanceRepairSignals,
            queueSignals: queueSignals,
            progressActions: progressActions,
            nextStepSummary: nextStepSummary,
            routeAttentionSignal: routeAttentionSignal
        )
        let request = heartbeatProjectionRequest(
            reason: reason,
            changed: changed,
            projects: projects,
            blockerProjects: blockerProjects,
            blockerSignal: blockerSignal,
            permissionSignals: permissionSignals,
            governanceRepairSignals: governanceRepairSignals,
            queueSignals: queueSignals,
            progressActions: progressActions,
            nextStepSummary: nextStepSummary
        )
        let dispatchGeneration = beginHeartbeatVoiceDispatch()

        guard backgroundSupervisorServicesEnabled || supervisorBriefProjectionRequestOverride != nil else {
            guard let fallbackJob else { return }
            _ = dispatchSupervisorVoiceJob(
                fallbackJob,
                preferences: currentVoicePreferences(),
                source: "heartbeat",
                suppressRapidSameSourceRepeat: true,
                cancelPendingHeartbeat: false
            )
            return
        }

        guard let request else {
            guard let fallbackJob else { return }
            _ = dispatchSupervisorVoiceJob(
                fallbackJob,
                preferences: currentVoicePreferences(),
                source: "heartbeat",
                suppressRapidSameSourceRepeat: true,
                cancelPendingHeartbeat: false
            )
            return
        }

        heartbeatVoiceDispatchTask = Task { @MainActor [weak self] in
            guard let self else { return }
            defer { self.finishHeartbeatVoiceDispatchIfCurrent(dispatchGeneration) }
            guard !Task.isCancelled,
                  self.isCurrentHeartbeatVoiceDispatch(dispatchGeneration) else {
                return
            }
            if let projectionResolution = await self.heartbeatProjectionVoiceResolution(
                request: request,
                blockerSignal: blockerSignal,
                projects: projects
            ) {
                let job: SupervisorVoiceTTSJob
                let detail: String
                switch projectionResolution {
                case .projection(let projectionJob):
                    job = projectionJob
                    detail = "projection"
                case .unavailable(let unavailableJob):
                    job = unavailableJob
                    detail = "projection_unavailable"
                }
                guard !Task.isCancelled,
                      self.isCurrentHeartbeatVoiceDispatch(dispatchGeneration) else {
                    self.appendRecentEvent("stale heartbeat voice projection dropped")
                    self.recordVoiceDispatchActivity(
                        state: "dropped",
                        source: "heartbeat",
                        job: job,
                        reasonCode: "stale_generation",
                        detail: detail
                    )
                    return
                }
                _ = self.dispatchSupervisorVoiceJob(
                    job,
                    preferences: self.currentVoicePreferences(),
                    source: "heartbeat",
                    suppressRapidSameSourceRepeat: true,
                    cancelPendingHeartbeat: false
                )
                return
            }
            guard let fallbackJob else { return }
            guard !Task.isCancelled,
                  self.isCurrentHeartbeatVoiceDispatch(dispatchGeneration) else {
                self.appendRecentEvent("stale heartbeat voice fallback dropped")
                self.recordVoiceDispatchActivity(
                    state: "dropped",
                    source: "heartbeat",
                    job: fallbackJob,
                    reasonCode: "stale_generation",
                    detail: "fallback"
                )
                return
            }
            _ = self.dispatchSupervisorVoiceJob(
                fallbackJob,
                preferences: self.currentVoicePreferences(),
                source: "heartbeat",
                suppressRapidSameSourceRepeat: true,
                cancelPendingHeartbeat: false
            )
        }
    }

    @discardableResult
    private func speakSupervisorVoiceReply(
        _ text: String,
        personaSlot: SupervisorPersonaSlot? = nil
    ) -> SupervisorSpeechSynthesizer.Outcome {
        let script = conciseVoiceReplyScript(text)
        guard !script.isEmpty else { return .suppressed("empty_script") }
        let dedupeKey = "voice-reply:\(capped(script.joined(separator: "|"), maxChars: 96))"
        let job = SupervisorVoiceTTSJob(
            trigger: .userQueryReply,
            priority: .normal,
            script: script,
            dedupeKey: dedupeKey
        )
        return dispatchSupervisorVoiceJob(
            job,
            preferences: currentVoicePreferences(personaSlot: personaSlot),
            source: "user_query_reply",
            suppressRapidSameSourceRepeat: false,
            cancelPendingHeartbeat: true
        )
    }

    private func supervisorPendingGrantVoiceReplyIfApplicable(
        _ text: String
    ) async -> SupervisorVoicePendingGrantReply? {
        guard activeSupervisorMemoryFactFollowUp() == nil else { return nil }
        guard !looksLikeSupervisorNaturalMemoryPatchFacts(text) else { return nil }
        let projects = allProjects()
        if shouldPreferPendingSupervisorSkillApprovalOverGrantVoiceAction(
            text,
            projects: projects
        ) {
            return nil
        }
        guard let approve = pendingGrantVoiceDecision(in: text) else { return nil }
        if pendingHubGrants.isEmpty {
            await refreshSchedulerSnapshot(force: true)
        }

        let selection = resolvePendingHubGrantForVoiceAction(text, projects: projects)
        if let replyText = selection.reply {
            return SupervisorVoicePendingGrantReply(
                text: replyText,
                spokenOutcome: speakSupervisorVoiceReply(replyText)
            )
        }
        guard let grant = selection.grant else { return nil }
        rememberPendingHubGrantVoiceContext(grant)

        let request = makeVoiceAuthorizationRequestForPendingHubGrantAction(
            grant: grant,
            approve: approve
        )
        if let activeRequest = activeVoiceAuthorizationRequest,
           activeRequest.requestId == request.requestId,
           let existingResolution = voiceAuthorizationResolution,
           activeVoiceChallenge != nil {
            let replyText = renderPendingGrantVoiceAuthorizationReply(
                resolution: existingResolution,
                grant: grant,
                approve: approve,
                challengeAlreadyActive: true
            )
            return SupervisorVoicePendingGrantReply(
                text: replyText,
                spokenOutcome: .spoken
            )
        }

        activeVoicePendingGrantAction = SupervisorVoicePendingGrantActionContext(
            requestId: request.requestId,
            grant: grant,
            approve: approve
        )
        let resolution = await startVoiceAuthorization(request)
        let replyText = renderPendingGrantVoiceAuthorizationReply(
            resolution: resolution,
            grant: grant,
            approve: approve,
            challengeAlreadyActive: false
        )
        return SupervisorVoicePendingGrantReply(
            text: replyText,
            spokenOutcome: .spoken
        )
    }

    private func shouldPreferPendingSupervisorSkillApprovalOverGrantVoiceAction(
        _ text: String,
        projects: [AXProjectEntry]
    ) -> Bool {
        guard pendingSupervisorSkillApprovalDecision(in: text) != nil else { return false }
        let selection = resolvePendingSupervisorSkillApprovalForDirectAction(
            text,
            projects: projects
        )
        return selection.approval != nil || selection.reply != nil
    }

    private func handleActiveVoiceAuthorizationVoiceInputIfApplicable(
        _ text: String
    ) async -> Bool {
        guard activeVoiceChallenge != nil,
              let request = activeVoiceAuthorizationRequest else {
            return false
        }

        if shouldCancelActiveVoiceAuthorization(from: text) {
            cancelVoiceAuthorization()
            let replyText = "已取消当前语音授权。"
            let spokenOutcome = speakSupervisorVoiceReply(replyText)
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: text,
                    responseText: replyText,
                    triggerSource: .userTurn,
                    triggeredByVoice: true,
                    spokenOutcome: spokenOutcome,
                    replySource: "voice_auth_cancel",
                    personaSlot: nil,
                    lifecycle: .nonReviewAssistantReply
                )
            )
            return true
        }

        if shouldRepeatActiveVoiceAuthorizationPrompt(for: text) {
            let replyText = renderActiveVoiceAuthorizationPrompt(request: request)
            let spokenOutcome = speakSupervisorVoiceReply(replyText)
            completeSupervisorAssistantTurn(
                SupervisorAfterTurnLifecycleContext(
                    userMessage: text,
                    responseText: replyText,
                    triggerSource: .userTurn,
                    triggeredByVoice: true,
                    spokenOutcome: spokenOutcome,
                    replySource: "voice_auth_repeat_prompt",
                    personaSlot: nil,
                    lifecycle: .nonReviewAssistantReply
                )
            )
            return true
        }

        let requiresMobileConfirm = voiceAuthorizationResolution?.requiresMobileConfirm ?? false
        let isPendingGrantVerification = isCurrentPendingGrantVoiceAuthorization(request)
        let mobileConfirmed = inferredMobileConfirmationState(
            from: text,
            requiresMobileConfirm: requiresMobileConfirm
        )
        if mobileConfirmed {
            setVoiceAuthorizationMobileConfirmed(
                true,
                source: "voice_input",
                emitSystemMessage: false
            )
            if isStandaloneMobileConfirmationUtterance(
                text,
                requiresMobileConfirm: requiresMobileConfirm
            ) {
                let replyText = "已记录移动端确认；现在继续说授权短语即可。"
                let spokenOutcome = speakSupervisorVoiceReply(replyText)
                completeSupervisorAssistantTurn(
                    SupervisorAfterTurnLifecycleContext(
                        userMessage: text,
                        responseText: replyText,
                        triggerSource: .userTurn,
                        triggeredByVoice: true,
                        spokenOutcome: spokenOutcome,
                        replySource: "voice_auth_mobile_confirmed",
                        personaSlot: nil,
                        lifecycle: .nonReviewAssistantReply
                    )
                )
                return true
            }
        }
        let semanticMatchScore = inferredVoiceAuthorizationSemanticMatchScore(
            from: text,
            mobileConfirmed: voiceAuthorizationMobileConfirmationLatched
        )
        let resolution = await retryVoiceAuthorizationVerification(
            transcript: text,
            semanticMatchScore: semanticMatchScore
        )

        if isPendingGrantVerification, resolution.state == .verified {
            return true
        }

        let replyText = renderActiveVoiceAuthorizationVerificationReply(
            resolution: resolution,
            request: request
        )
        completeSupervisorAssistantTurn(
            SupervisorAfterTurnLifecycleContext(
                userMessage: text,
                responseText: replyText,
                triggerSource: .userTurn,
                triggeredByVoice: true,
                spokenOutcome: .spoken,
                replySource: "voice_auth_verification_reply",
                personaSlot: nil,
                lifecycle: .nonReviewAssistantReply
            )
        )
        return true
    }

    private func shouldCancelActiveVoiceAuthorization(from text: String) -> Bool {
        let normalized = normalizedLookupKey(text)
        guard !normalized.isEmpty else { return false }
        let cancelTokens = [
            "取消",
            "取消授权",
            "停止授权",
            "cancel",
            "abort",
            "stop"
        ]
        return cancelTokens.contains { normalized.contains(normalizedLookupKey($0)) }
    }

    private func shouldRepeatActiveVoiceAuthorizationPrompt(for text: String) -> Bool {
        let normalized = normalizedLookupKey(text)
        guard !normalized.isEmpty else { return false }
        let tokens = [
            "再说一遍",
            "重复一下",
            "怎么说",
            "提示",
            "help",
            "repeat",
            "challenge",
            "状态",
            "status",
            "what do i say"
        ]
        return tokens.contains { normalized.contains(normalizedLookupKey($0)) }
    }

    private struct VoiceAuthorizationPromptScopeSummary {
        var fields: [String: String]
        var freeformSegments: [String]

        func value(for key: String) -> String? {
            let token = fields[key.lowercased()]?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            return token.isEmpty ? nil : token
        }

        var project: String? { value(for: "project") }
        var capability: String? { value(for: "capability") }
        var source: String? { value(for: "source") }
        var reason: String? { value(for: "reason") }
        var goal: String? { value(for: "goal") }
        var rawScope: String? {
            if let first = freeformSegments.first {
                let trimmed = first.trimmingCharacters(in: .whitespacesAndNewlines)
                if !trimmed.isEmpty {
                    return trimmed
                }
            }
            return value(for: "scope")
        }
    }

    private func parseVoiceAuthorizationPromptScope(
        _ scopeText: String
    ) -> VoiceAuthorizationPromptScopeSummary {
        let normalized = scopeText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalized.isEmpty else {
            return VoiceAuthorizationPromptScopeSummary(fields: [:], freeformSegments: [])
        }

        var fields: [String: String] = [:]
        var freeformSegments: [String] = []
        let segments = normalized
            .replacingOccurrences(of: "\n", with: ";")
            .split(separator: ";")

        for rawSegment in segments {
            let segment = String(rawSegment).trimmingCharacters(in: .whitespacesAndNewlines)
            guard !segment.isEmpty else { continue }
            if let separator = segment.firstIndex(of: "=") {
                let key = String(segment[..<separator])
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                    .lowercased()
                let value = String(segment[segment.index(after: separator)...])
                    .trimmingCharacters(in: .whitespacesAndNewlines)
                if !key.isEmpty, !value.isEmpty {
                    fields[key] = value
                    continue
                }
            }
            freeformSegments.append(segment)
        }

        if fields.isEmpty, freeformSegments.isEmpty {
            freeformSegments.append(normalized)
        }

        return VoiceAuthorizationPromptScopeSummary(
            fields: fields,
            freeformSegments: freeformSegments
        )
    }

    private func voiceAuthorizationRiskSpeechText(_ riskTier: LaneRiskTier) -> String {
        switch riskTier {
        case .low:
            return "低风险"
        case .medium:
            return "中风险"
        case .high:
            return "高风险"
        case .critical:
            return "关键风险"
        }
    }

    private func voiceAuthorizationPromptHeadline(
        request: SupervisorVoiceAuthorizationRequest,
        scopeSummary: VoiceAuthorizationPromptScopeSummary
    ) -> String {
        let project = scopeSummary.project.map { capped($0, maxChars: 32) }
        let capability = scopeSummary.capability.map { capped($0, maxChars: 40) }
        let source = scopeSummary.source.map { capped($0, maxChars: 36) }
        let goal = scopeSummary.goal.map { capped($0, maxChars: 48) }
        let rawScope = scopeSummary.rawScope.map { capped($0, maxChars: 48) }
        let actionText = request.actionText.trimmingCharacters(in: .whitespacesAndNewlines)
        let action = actionText.isEmpty ? nil : capped(actionText, maxChars: 48)

        let summary: String
        if let project, let capability {
            summary = "\(project) 现在要处理一笔 \(capability) 授权"
        } else if let capability {
            summary = "现在要处理一笔 \(capability) 授权"
        } else if let project {
            summary = "\(project) 现在有一笔待确认授权"
        } else if let goal {
            summary = "当前要确认的一次受治理执行，目标是 \(goal)"
        } else if let action {
            summary = "当前要确认的动作是 \(action)"
        } else if let rawScope {
            summary = "当前要确认一笔语音授权：\(rawScope)"
        } else {
            summary = "当前有一笔待确认语音授权"
        }

        let sourceSuffix = source.map { "，来源是 \($0)" } ?? ""
        return "这是一笔\(voiceAuthorizationRiskSpeechText(request.riskTier))语音授权。\(summary)\(sourceSuffix)。"
    }

    private func voiceAuthorizationPromptInstructionLine(
        challengeCode: String,
        requiresMobileConfirm: Bool,
        mobileConfirmed: Bool
    ) -> String {
        let normalizedCode = challengeCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let instruction = normalizedCode.isEmpty
            ? "继续说授权短语即可"
            : "说授权短语 \(normalizedCode)"

        if requiresMobileConfirm {
            if mobileConfirmed {
                return "移动端确认已记录，现在直接\(instruction)。"
            }
            return "先在手机上确认，再\(instruction)。"
        }
        return "现在直接\(instruction)。"
    }

    private func renderActiveVoiceAuthorizationPrompt(
        request: SupervisorVoiceAuthorizationRequest
    ) -> String {
        let actionText = request.actionText.trimmingCharacters(in: .whitespacesAndNewlines)
        let challengeToken = activeVoiceChallenge?.challengeId.trimmingCharacters(in: .whitespacesAndNewlines) ?? "n/a"
        let challengeCode = activeVoiceChallenge?.challengeCode.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let requiresMobileConfirm = voiceAuthorizationResolution?.requiresMobileConfirm ?? false
        let scopeSummary = parseVoiceAuthorizationPromptScope(request.scopeText)
        let actionUsedAsHeadlineFallback =
            scopeSummary.project == nil &&
            scopeSummary.capability == nil &&
            scopeSummary.goal == nil &&
            scopeSummary.rawScope == nil

        var lines: [String] = []
        lines.append(
            voiceAuthorizationPromptHeadline(
                request: request,
                scopeSummary: scopeSummary
            )
        )
        lines.append(
            voiceAuthorizationPromptInstructionLine(
                challengeCode: challengeCode,
                requiresMobileConfirm: requiresMobileConfirm,
                mobileConfirmed: voiceAuthorizationMobileConfirmationLatched
            )
        )
        if let reason = scopeSummary.reason {
            lines.append("原因：\(capped(reason, maxChars: 96))")
        }
        let amountText = request.amountText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !amountText.isEmpty {
            lines.append("约束：\(capped(amountText, maxChars: 96))")
        }
        if !actionText.isEmpty, !actionUsedAsHeadlineFallback {
            lines.append("目标动作：\(capped(actionText, maxChars: 96))")
        }
        if challengeToken != "n/a" {
            lines.append("challenge=\(challengeToken)")
        }
        return lines.joined(separator: "\n")
    }

    private func inferredMobileConfirmationState(
        from text: String,
        requiresMobileConfirm: Bool
    ) -> Bool {
        guard requiresMobileConfirm else { return false }
        let normalized = normalizedLookupKey(text)
        guard !normalized.isEmpty else { return false }
        let tokens = [
            "手机已确认",
            "移动端已确认",
            "已经确认",
            "已确认",
            "mobile confirmed",
            "confirmed on phone",
            "phone confirmed"
        ]
        return tokens.contains { normalized.contains(normalizedLookupKey($0)) }
    }

    private func isStandaloneMobileConfirmationUtterance(
        _ text: String,
        requiresMobileConfirm: Bool
    ) -> Bool {
        guard requiresMobileConfirm else { return false }
        var remainder = normalizedLookupKey(text)
        guard !remainder.isEmpty else { return false }

        let fragments = [
            "手机已确认",
            "移动端已确认",
            "mobile confirmed",
            "confirmed on phone",
            "phone confirmed",
            "paired mobile confirmation",
            "手机",
            "移动端",
            "mobile",
            "phone",
            "paired",
            "terminal",
            "确认",
            "已确认",
            "已经确认",
            "confirmed",
            "confirm",
            "already",
            "done",
            "ok",
            "okay",
            "好了",
            "已经",
            "已",
            "了",
            "在",
            "上",
            "我",
            "现在"
        ]

        for fragment in fragments.sorted(by: { $0.count > $1.count }) {
            let normalizedFragment = normalizedLookupKey(fragment)
            guard !normalizedFragment.isEmpty else { continue }
            remainder = remainder.replacingOccurrences(of: normalizedFragment, with: "")
        }

        return remainder.isEmpty
    }

    private func inferredVoiceAuthorizationSemanticMatchScore(
        from text: String,
        mobileConfirmed: Bool
    ) -> Double {
        let normalized = normalizedLookupKey(text)
        guard !normalized.isEmpty else { return 0.95 }
        if mobileConfirmed {
            return 0.99
        }
        if normalized.count >= 20 {
            return 0.99
        }
        return 0.97
    }

    private func isCurrentPendingGrantVoiceAuthorization(
        _ request: SupervisorVoiceAuthorizationRequest
    ) -> Bool {
        guard let context = activeVoicePendingGrantAction else { return false }
        return context.requestId == request.requestId
    }

    private func renderActiveVoiceAuthorizationVerificationReply(
        resolution: SupervisorVoiceAuthorizationResolution,
        request: SupervisorVoiceAuthorizationRequest
    ) -> String {
        let actionText = request.actionText.trimmingCharacters(in: .whitespacesAndNewlines)
        let challengeToken = resolution.challengeId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "n/a"

        switch resolution.state {
        case .pending:
            return "语音授权挑战仍在等待校验（challenge=\(challengeToken)）。"
        case .escalatedToMobile:
            return "语音授权仍需移动端确认（challenge=\(challengeToken)）。完成确认后继续口述授权短语。"
        case .verified:
            if actionText.isEmpty {
                return "语音授权已验证通过。"
            }
            return "语音授权已验证通过，正在继续执行：\(actionText)"
        case .denied:
            let deny = resolution.denyCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "denied"
            return "语音授权被拒绝（challenge=\(challengeToken)，deny=\(deny)）。"
        case .failClosed:
            let reason = resolution.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "unknown"
            return "语音授权已失败闭锁（challenge=\(challengeToken)，reason=\(reason)）。"
        }
    }

    private func pendingGrantVoiceDecision(in text: String) -> Bool? {
        let normalized = normalizedLookupKey(text)
        guard !normalized.isEmpty else { return nil }
        return pendingGrantDecision(
            in: text,
            excludeGuidanceLikeTexts: false
        )
    }

    private func pendingGrantDecision(
        in text: String,
        excludeGuidanceLikeTexts: Bool
    ) -> Bool? {
        let normalized = normalizedLookupKey(text)
        guard !normalized.isEmpty else { return nil }
        if excludeGuidanceLikeTexts,
           normalizedContainsAny(normalized, ["建议", "方案", "方向", "guidance"]) {
            return nil
        }

        let hasApprove = normalizedContainsAny(normalized, pendingGrantApproveTokens())
        let hasDeny = normalizedContainsAny(normalized, pendingGrantDenyTokens())
        guard hasApprove != hasDeny else { return nil }

        let explicitGrantID = explicitPendingGrantRequestId(in: text) != nil
        let hasSubject = normalizedContainsAny(normalized, pendingGrantSubjectTokens())
        let hasDemonstrative = normalizedContainsAny(normalized, pendingGrantDemonstrativeTokens())
        let hasGrantContext = hasRecentSupervisorPendingGrantContext(
            currentUserMessage: text
        )
        guard explicitGrantID || hasSubject || hasDemonstrative || hasGrantContext else { return nil }
        return hasApprove
    }

