            "release",
            "deploy",
            "上线",
            "生产"
        ]
    }

    private func pendingGrantDemonstrativeTokens() -> [String] {
        [
            "this",
            "这个",
            "当前",
            "这项",
            "这笔"
        ]
    }

    private func hasRecentSupervisorGuidanceContext(
        currentUserMessage: String
    ) -> Bool {
        recentSupervisorContextMatches(
            [
                "待确认 guidance",
                "这条 guidance",
                "guidance",
                "injection=",
                "review guidance"
            ],
            currentUserMessage: currentUserMessage
        )
    }

    private func hasRecentSupervisorPendingGrantContext(
        currentUserMessage: String
    ) -> Bool {
        recentSupervisorContextMatches(
            [
                "Hub grant",
                "Hub 授权",
                "待授权",
                "grant=",
                "grant_request_id",
                "联网访问",
                "web.fetch",
                "web_fetch",
                "付费生成"
            ],
            currentUserMessage: currentUserMessage
        )
    }

    private func recentSupervisorContextMatches(
        _ needles: [String],
        currentUserMessage: String,
        maxMessages: Int = 4
    ) -> Bool {
        let currentNormalized = normalizedLookupKey(currentUserMessage)
        let now = Date().timeIntervalSince1970
        var skippedCurrentUserMessage = false
        var inspected = 0

        for message in messages.reversed() {
            let messageNormalized = normalizedLookupKey(message.content)
            if messageNormalized.isEmpty {
                continue
            }
            if !skippedCurrentUserMessage,
               message.role == .user,
               messageNormalized == currentNormalized {
                skippedCurrentUserMessage = true
                continue
            }
            if message.role == .user {
                break
            }
            guard message.role == .assistant || message.role == .system else {
                continue
            }
            if now - message.timestamp > supervisorEllipsisContextCarryWindowSec {
                break
            }
            inspected += 1
            if normalizedContainsAny(messageNormalized, needles) {
                return true
            }
            if inspected >= maxMessages {
                break
            }
        }
        return false
    }

    private func resolvePendingHubGrantForVoiceAction(
        _ userMessage: String,
        projects: [AXProjectEntry]
    ) -> (grant: SupervisorPendingGrant?, reply: String?) {
        let grants = pendingHubGrants
        guard !grants.isEmpty else {
            return (nil, XTHubGrantPresentation.emptyPendingReply(projectName: nil))
        }

        var candidates = grants
        let explicitGrantRequestId = explicitPendingGrantRequestId(in: userMessage)
        if let explicitGrantRequestId {
            let matches = candidates.filter { grant in
                let grantId = grant.grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
                guard !grantId.isEmpty else { return false }
                return grantId == explicitGrantRequestId.lowercased() ||
                    grantId.contains(explicitGrantRequestId.lowercased()) ||
                    explicitGrantRequestId.lowercased().contains(grantId)
            }
            guard !matches.isEmpty else {
                return (nil, "我没找到授权单号 \(explicitGrantRequestId) 对应的待处理 Hub 授权。")
            }
            candidates = matches
        }

        let focus = focusedSupervisorProjectSelection(
            projects: projects,
            userMessage: userMessage
        )
        if let focus, focus.source == "explicit_user_mention" {
            let projectMatches = candidates.filter { $0.projectId == focus.project.projectId }
            if !projectMatches.isEmpty {
                candidates = projectMatches
            } else if explicitGrantRequestId == nil {
                return (
                    nil,
                    XTHubGrantPresentation.emptyPendingReply(
                        projectName: focus.project.displayName
                    )
                )
            }
        }

        if candidates.count == 1, let grant = candidates.first {
            return (grant, nil)
        }

        let refined = refinedVoicePendingGrantCandidates(candidates, userMessage: userMessage)
        let ambiguous = refined.isEmpty ? candidates : refined
        if ambiguous.count == 1, let grant = ambiguous.first {
            return (grant, nil)
        }
        if let ordinalGrant = explicitPendingHubGrantOrdinalCandidate(
            candidates: ambiguous,
            userMessage: userMessage
        ) {
            return (ordinalGrant, nil)
        }

        if explicitGrantRequestId == nil,
           focus?.source != "explicit_user_mention",
           let contextualGrant = recentPendingHubGrantVoiceContextCandidate(
               candidates: ambiguous,
               userMessage: userMessage
           ) {
            return (contextualGrant, nil)
        }

        if let focus, focus.source != "explicit_user_mention" {
            let projectMatches = ambiguous.filter { $0.projectId == focus.project.projectId }
            if !projectMatches.isEmpty {
                if projectMatches.count == 1, let grant = projectMatches.first {
                    return (grant, nil)
                }
                candidates = projectMatches
            } else {
                candidates = ambiguous
            }
        } else {
            candidates = ambiguous
        }

        if candidates.count == 1, let grant = candidates.first {
            return (grant, nil)
        }

        return (
            nil,
            renderPendingGrantVoiceAmbiguityReply(
                candidates: candidates,
                focusedProjectName: focus?.source == "explicit_user_mention"
                    ? focus?.project.displayName
                    : nil
            )
        )
    }

    private func explicitPendingGrantRequestId(in userMessage: String) -> String? {
        for key in ["grant_request_id", "grant_id"] {
            let value = supervisorTriggerContextValue(key, userMessage: userMessage)?
                .trimmingCharacters(in: .whitespacesAndNewlines)
            if let value, !value.isEmpty {
                return value
            }
        }
        return nil
    }

    private func refinedVoicePendingGrantCandidates(
        _ candidates: [SupervisorPendingGrant],
        userMessage: String
    ) -> [SupervisorPendingGrant] {
        let foldedMessage = userMessage
            .folding(options: [.caseInsensitive, .diacriticInsensitive, .widthInsensitive], locale: .current)
            .lowercased()
        let normalizedMessage = normalizedLookupKey(userMessage)

        return candidates.filter { grant in
            let grantId = grant.grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            if !grantId.isEmpty, foldedMessage.contains(grantId) {
                return true
            }

            let modelId = grant.modelId.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
            if !modelId.isEmpty, foldedMessage.contains(modelId) {
                return true
            }
            let projectNameKey = normalizedLookupKey(grant.projectName)
            if !projectNameKey.isEmpty, normalizedMessage.contains(projectNameKey) {
                return true
            }
            if normalizedSupervisorProjectAliasTerms(grant.projectName).contains(where: {
                normalizedMessage.contains($0)
            }) {
                return true
            }

            if messageContainsMeaningfulSearchTerm(userMessage, source: grant.reason) {
                return true
            }
            if messageContainsMeaningfulSearchTerm(userMessage, source: grant.capability) {
                return true
            }

            return pendingGrantVoiceAliasTerms(for: grant).contains { term in
                foldedMessage.contains(term)
            } || pendingGrantVoiceSourceAliasTerms(for: grant).contains { term in
                !normalizedMessage.isEmpty && normalizedMessage.contains(term)
            }
        }
    }

    private func explicitPendingHubGrantOrdinalCandidate(
        candidates: [SupervisorPendingGrant],
        userMessage: String
    ) -> SupervisorPendingGrant? {
        guard let index = explicitSupervisorOrdinalSelectionIndex(
            in: userMessage,
            maxCount: candidates.count
        ) else {
            return nil
        }
        guard candidates.indices.contains(index) else { return nil }
        return candidates[index]
    }

    private func recentPendingHubGrantVoiceContextCandidate(
        candidates: [SupervisorPendingGrant],
        userMessage: String
    ) -> SupervisorPendingGrant? {
        let token = lastPendingHubGrantVoiceContextToken.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !token.isEmpty else { return nil }
        guard Date().timeIntervalSince1970 - lastPendingHubGrantVoiceContextAt <= supervisorEllipsisContextCarryWindowSec else {
            return nil
        }

        let normalized = normalizedLookupKey(userMessage)
        guard !normalized.isEmpty else { return nil }
        let hasDemonstrative = normalizedContainsAny(normalized, pendingGrantDemonstrativeTokens())
        let hasSubject = normalizedContainsAny(normalized, pendingGrantSubjectTokens())
        guard hasDemonstrative || hasSubject || hasRecentSupervisorPendingGrantContext(currentUserMessage: userMessage) else {
            return nil
        }

        let matches = candidates.filter { pendingGrantStableToken($0) == token }
        guard matches.count == 1 else { return nil }
        return matches[0]
    }

    private func messageContainsMeaningfulSearchTerm(
        _ userMessage: String,
        source: String
    ) -> Bool {
        let foldedMessage = userMessage
            .folding(options: [.caseInsensitive, .diacriticInsensitive, .widthInsensitive], locale: .current)
            .lowercased()
        let loweredSource = source
            .folding(options: [.caseInsensitive, .diacriticInsensitive, .widthInsensitive], locale: .current)
            .lowercased()

        let tokens = loweredSource
            .split { !$0.isLetter && !$0.isNumber }
            .map(String.init)
            .filter { token in
                guard !token.isEmpty else { return false }
                let isASCIIOnly = token.unicodeScalars.allSatisfy { $0.isASCII }
                return isASCIIOnly ? token.count >= 4 : token.count >= 2
            }

        return tokens.contains { foldedMessage.contains($0) }
    }

    private func pendingGrantVoiceAliasTerms(
        for grant: SupervisorPendingGrant
    ) -> [String] {
        let capability = grant.capability.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let reason = grant.reason.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let combined = "\(capability) \(reason)"
        var aliases: [String] = []

        if combined.contains("web_fetch") || combined.contains("web.fetch") || combined.contains("联网") {
            aliases.append(contentsOf: ["web", "fetch", "browser", "联网"])
        }
        if combined.contains("ai_generate_paid") || combined.contains("ai.generate.paid") || combined.contains("付费") {
            aliases.append(contentsOf: ["paid", "billing", "budget", "付费", "预算"])
        }
        if combined.contains("ai_generate_local") || combined.contains("ai.generate.local") || combined.contains("本地") {
            aliases.append(contentsOf: ["local", "本地"])
        }
        if combined.contains("release") || combined.contains("deploy") || combined.contains("production") || combined.contains("上线") || combined.contains("发布") {
            aliases.append(contentsOf: ["release", "deploy", "production", "上线", "发布", "生产"])
        }
        if combined.contains("connector") {
            aliases.append("connector")
        }
        if combined.contains("secret") || combined.contains("credential") || combined.contains("token") {
            aliases.append(contentsOf: ["secret", "credential", "token"])
        }

        return normalizedVoiceLookupTerms(aliases)
    }

    private func pendingGrantVoiceSourceAliasTerms(
        for grant: SupervisorPendingGrant,
        now: TimeInterval = Date().timeIntervalSince1970
    ) -> [String] {
        guard let receipt = latestConnectorIngressReceipt(for: grant, now: now) else {
            return []
        }

        let triggerType = hubConnectorIngressTriggerType(for: receipt)
        var aliases = remoteChannelProviderVoiceAliasTerms(receipt.connector)
        aliases.append(hubConnectorIngressDisplayName(receipt, triggerType: triggerType))
        aliases.append(contentsOf: hubConnectorIngressVoiceAliasTerms(receipt, triggerType: triggerType))
        return normalizedVoiceLookupTerms(aliases)
    }

    private func normalizedVoiceLookupTerms(_ aliases: [String]) -> [String] {
        var seen: Set<String> = []
        var out: [String] = []
        for alias in aliases {
            let normalized = normalizedLookupKey(alias)
            guard !normalized.isEmpty else { continue }
            if seen.insert(normalized).inserted {
                out.append(normalized)
            }
        }
        return out
    }

    private func makeVoiceAuthorizationRequestForPendingHubGrantAction(
        grant: SupervisorPendingGrant,
        approve: Bool
    ) -> SupervisorVoiceAuthorizationRequest {
        let stableGrantToken = {
            let preferred = grant.grantRequestId.trimmingCharacters(in: .whitespacesAndNewlines)
            if !preferred.isEmpty {
                return normalizedLookupKey(preferred)
            }
            return normalizedLookupKey(grant.id)
        }()
        let actionToken = approve ? "approve" : "deny"
        let capabilityText = grantCapabilityText(capability: grant.capability, modelId: grant.modelId)
        let reasonText = grant.reason.trimmingCharacters(in: .whitespacesAndNewlines)
        let sourceText = pendingGrantSourceSummary(grant) ?? ""
        let scopeFields = [
            "project=\(grant.projectName)",
            "capability=\(capabilityText)",
            sourceText.isEmpty ? "" : "source=\(sourceText)",
            reasonText.isEmpty ? "" : "reason=\(capped(reasonText, maxChars: 96))"
        ]
        .filter { !$0.isEmpty }
        let amountText: String? = {
            if grant.requestedTokenCap > 0 {
                return "token_cap=\(grant.requestedTokenCap)"
            }
            if grant.requestedTtlSec > 0 {
                return "ttl_sec=\(grant.requestedTtlSec)"
            }
            return nil
        }()
        let riskTier = pendingGrantVoiceAuthorizationRiskTier(
            for: grant,
            approve: approve
        )

        return SupervisorVoiceAuthorizationRequest(
            requestId: "voice_pending_grant_\(actionToken)_\(stableGrantToken)",
            projectId: grant.projectId,
            templateId: approve
                ? "voice.grant.pending_hub_grant_approve.v1"
                : "voice.grant.pending_hub_grant_deny.v1",
            actionText: approve
                ? "Approve Hub grant for \(grant.projectName)"
                : "Deny Hub grant for \(grant.projectName)",
            scopeText: scopeFields.joined(separator: "; "),
            amountText: amountText,
            riskTier: riskTier,
            boundDeviceId: preferredVoiceBoundDeviceId(for: grant.projectId),
            mobileTerminalId: nil,
            challengeCode: nil,
            ttlMs: riskTier >= .high ? 180_000 : 120_000
        )
    }

    private func pendingGrantVoiceAuthorizationRiskTier(
        for grant: SupervisorPendingGrant,
        approve: Bool
    ) -> LaneRiskTier {
        let capability = grant.capability.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let reason = grant.reason.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let combined = "\(capability) \(reason)"

        if combined.contains("web_fetch") ||
            combined.contains("web.fetch") ||
            combined.contains("ai_generate_paid") ||
            combined.contains("ai.generate.paid") ||
            combined.contains("production") ||
            combined.contains("prod") ||
            combined.contains("release") ||
            combined.contains("deploy") ||
            combined.contains("connector") ||
            combined.contains("secret") ||
            combined.contains("token") ||
            combined.contains("上线") ||
            combined.contains("生产") ||
            combined.contains("发布") ||
            combined.contains("联网") {
            return .high
        }

        if capability.contains("ai_generate_local") || capability.contains("ai.generate.local") {
            return approve ? .medium : .low
        }

        return approve ? .high : .medium
    }

    private func renderPendingGrantVoiceAuthorizationReply(
        resolution: SupervisorVoiceAuthorizationResolution,
        grant: SupervisorPendingGrant,
        approve: Bool,
        challengeAlreadyActive: Bool
    ) -> String {
        let actionText = approve ? "批准" : "拒绝"
        let capabilityText = grantCapabilityText(capability: grant.capability, modelId: grant.modelId)
        let challengeToken = resolution.challengeId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "n/a"
        let sourceText = pendingGrantSourceSummary(grant) ?? ""
        let grantSubject = sourceText.isEmpty
            ? grant.projectName
            : "\(grant.projectName)（来源：\(sourceText)）"

        switch resolution.state {
        case .pending:
            if challengeAlreadyActive {
                return "项目 \(grantSubject) 的 \(capabilityText) \(actionText)语音授权仍在等待口令校验（challenge=\(challengeToken)）。"
            }
            return "我已为 \(grantSubject) 的 \(capabilityText) 发起\(actionText)语音授权（challenge=\(challengeToken)）。请继续说出授权短语。"

        case .escalatedToMobile:
            if challengeAlreadyActive {
                return "项目 \(grantSubject) 的 \(capabilityText) \(actionText)语音授权仍等待移动端确认（challenge=\(challengeToken)）。"
            }
            return "我已为 \(grantSubject) 的 \(capabilityText) 发起\(actionText)语音授权（challenge=\(challengeToken)）。先在配对移动端确认，再继续口令校验。"

        case .verified:
            return "语音授权已通过，正在对 \(grantSubject) 执行这笔 Hub 授权的\(actionText)操作。"

        case .denied:
            let denyCode = resolution.denyCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "denied"
            return "这次对 \(grantSubject) 这笔 Hub 授权的\(actionText)语音授权未通过（deny=\(denyCode)）。"

        case .failClosed:
            let reason = resolution.reasonCode?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "unknown"
            return "我没有执行 \(grantSubject) 这笔 Hub 授权的\(actionText)操作。语音授权已 fail-closed（reason=\(reason)）。"
        }
    }

    private func renderPendingGrantVoiceAmbiguityReply(
        candidates: [SupervisorPendingGrant],
        focusedProjectName: String?
    ) -> String {
        let header = XTHubGrantPresentation.ambiguityHeader(projectName: focusedProjectName)

        let lines = candidates.prefix(3).enumerated().map { offset, grant in
            let summary = pendingGrantSummaryLine(
                grant,
                includeGrantToken: true,
                includeScope: true,
                includeReason: false,
                includeSource: true
            )
            return "\(offset + 1). \(summary)"
        }

        return ([header] + lines + [
            "如果要指定某一笔，可以直接补授权单号，也可以说“第2个”或补项目名、能力后再说批准或拒绝。"
        ]).joined(separator: "\n")
    }

    private func supervisorBriefProjectionReplyIfApplicable(
        _ text: String,
        fromVoice: Bool
    ) async -> SupervisorBriefProjectionVoiceReply? {
        guard activeSupervisorMemoryFactFollowUp() == nil else { return nil }
        guard !looksLikeSupervisorNaturalMemoryPatchFacts(text) else { return nil }
        guard shouldUseSupervisorBriefProjectionForStatusQuery(text) else { return nil }
        let projects = allProjects()
        guard let focus = focusedSupervisorProjectSelection(projects: projects, userMessage: text) else {
            return supervisorBriefProjectionUnavailableReply(
                presentation: supervisorBriefProjectionBindingRequiredPresentation(projects: projects),
                fromVoice: fromVoice
            )
        }
        let request = HubIPCClient.SupervisorBriefProjectionRequestPayload(
            requestId: "voice_query_brief_\(Int(Date().timeIntervalSince1970 * 1000))_\(UUID().uuidString.lowercased())",
            projectId: focus.project.projectId,
            runId: nil,
            missionId: nil,
            projectionKind: "progress_brief",
            trigger: supervisorBriefProjectionVoiceQueryTrigger(text),
            includeTtsScript: true,
            includeCardSummary: true,
            maxEvidenceRefs: 4
        )
        let fetcher = supervisorBriefProjectionRequestOverride
            ?? { payload in
                await HubIPCClient.requestSupervisorBriefProjection(payload)
            }
        let result = await fetcher(request)
        guard result.ok, let projection = result.projection else {
            let localSignal = heartbeatGovernanceVoicePresentation()
            return supervisorBriefProjectionUnavailableReply(
                presentation: supervisorBriefProjectionUnavailablePresentation(
                    projectName: focus.project.displayName,
                    reasonCode: result.reasonCode,
                    localSignal: localSignal
                ),
                fromVoice: fromVoice
            )
        }

        let replyText = renderSupervisorBriefProjectionVoiceReply(
            projection,
            projectName: focus.project.displayName
        )
        let script = projectionVoiceScript(from: projection)
        let spokenOutcome: SupervisorSpeechSynthesizer.Outcome
        if !fromVoice {
            spokenOutcome = .suppressed("not_voice_triggered")
        } else if script.isEmpty {
            spokenOutcome = speakSupervisorVoiceReply(replyText)
        } else {
            let job = SupervisorVoiceTTSJob(
                trigger: .userQueryReply,
                priority: .normal,
                script: script,
                dedupeKey: "voice-query:\(projectionVoiceDedupeKey(from: projection))"
            )
            spokenOutcome = dispatchSupervisorVoiceJob(
                job,
                preferences: currentVoicePreferences(),
                source: "brief_projection_voice_reply",
                suppressRapidSameSourceRepeat: false,
                cancelPendingHeartbeat: true
            )
        }
        return SupervisorBriefProjectionVoiceReply(
            text: replyText,
            spokenOutcome: spokenOutcome
        )
    }

    private func supervisorBriefProjectionUnavailableReply(
        presentation: SupervisorBriefProjectionUnavailablePresentation,
        fromVoice: Bool
    ) -> SupervisorBriefProjectionVoiceReply {
        let spokenOutcome: SupervisorSpeechSynthesizer.Outcome
        if !fromVoice {
            spokenOutcome = .suppressed("not_voice_triggered")
        } else if presentation.script.isEmpty {
            spokenOutcome = speakSupervisorVoiceReply(presentation.text)
        } else {
            let job = SupervisorVoiceTTSJob(
                trigger: .userQueryReply,
                priority: .normal,
                script: presentation.script,
                dedupeKey: presentation.dedupeKey
            )
            spokenOutcome = dispatchSupervisorVoiceJob(
                job,
                preferences: currentVoicePreferences(),
                source: "brief_projection_unavailable_reply",
                suppressRapidSameSourceRepeat: false,
                cancelPendingHeartbeat: true
            )
        }
        return SupervisorBriefProjectionVoiceReply(
            text: presentation.text,
            spokenOutcome: spokenOutcome
        )
    }

    private func supervisorBriefProjectionBindingRequiredPresentation(
        projects: [AXProjectEntry]
    ) -> SupervisorBriefProjectionUnavailablePresentation {
        let header = "⚠️ Hub Brief 需要项目绑定"
        var lines = [
            header,
            "Hub 统一投影现在按项目生成；我需要你先选中项目，或者直接说项目名后再问一次状态。",
            "按当前 fail-closed 规则，我先不在 XT 本地即兴拼接 Supervisor brief。"
        ]
        let examples = projects
            .prefix(2)
            .map { "“\($0.displayName) 现在状态怎么样”" }
        if !examples.isEmpty {
            lines.append("你可以直接说：\(examples.joined(separator: " / "))。")
        }
        return SupervisorBriefProjectionUnavailablePresentation(
            text: lines.joined(separator: "\n"),
            script: [
                "要给你正式的 Hub 简报，我还需要先绑定项目。",
                examples.isEmpty
                    ? "你先选中项目，或者直接说项目名后再问一次状态。"
                    : "你先选中项目，或者直接说项目名，比如 \(examples[0])。"
            ],
            dedupeKey: "voice-query:hub-brief-binding-required:\(projects.count)"
        )
    }

    private func supervisorBriefProjectionUnavailablePresentation(
        projectName: String,
        reasonCode: String?,
        localSignal: SupervisorGovernanceSignalVoicePresentation?
    ) -> SupervisorBriefProjectionUnavailablePresentation {
        let displayProjectName = projectName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? "当前项目"
            : projectName.trimmingCharacters(in: .whitespacesAndNewlines)
        let failureSummary = supervisorBriefProjectionFailureSummary(reasonCode)
        let repairAction = supervisorBriefProjectionFailureRepairAction(reasonCode)
        let normalizedReason = HubRouteStateMachine.normalizedReasonToken(reasonCode) ?? "hub_brief_unavailable"
        let header = "⚠️ Hub Brief 暂不可用 · \(displayProjectName)"

        var lines = [
            header,
            "这次没有拿到 Hub 统一投影：\(failureSummary)。",
            "按当前 fail-closed 规则，我先不在 XT 本地即兴拼接 Supervisor brief。"
        ]

        if let localSignal,
           !localSignal.headlineText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            lines.append("XT 本地信号：\(localSignal.headlineText)。")
            let action = localSignal.actionText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !action.isEmpty {
                lines.append("你现在可以先：\(action)。")
            } else {
                lines.append(repairAction)
            }
        } else {
            lines.append(repairAction)
        }

        var script = [
            "Hub 简报当前不可用。\(failureSummary)。",
            repairAction
        ]
        if let localSignal,
           !localSignal.headlineText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            let action = localSignal.actionText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            script = [
                "Hub 简报当前不可用。\(failureSummary)。",
                !action.isEmpty
                    ? "XT 本地信号提示你先：\(action)。"
                    : repairAction
            ]
        }

        return SupervisorBriefProjectionUnavailablePresentation(
            text: lines.joined(separator: "\n"),
            script: script,
            dedupeKey: "voice-query:hub-brief-unavailable:\(displayProjectName):\(normalizedReason)"
        )
    }

    private func supervisorBriefProjectionFailureSummary(_ reasonCode: String?) -> String {
        switch HubRouteStateMachine.normalizedReasonToken(reasonCode) {
        case "synchronous_projection_fetch_required":
            return "当前这条本地直答链还没接上 Hub 简报投影查询"
        case "hub_env_missing":
            return "当前 Hub 配对或运行时档案不可用"
        case "supervisor_brief_projection_file_ipc_not_supported":
            return "当前仍在本地 file route，Hub brief 投影还没接上"
        case "client_kit_missing":
            return "Hub client kit 还没准备好"
        case "node_missing":
            return "Hub brief bridge 缺少 Node 运行时"
        case "grpc_route_unavailable",
             "grpc_unavailable",
             "remote_supervisor_brief_projection_failed",
             "supervisor_brief_projection_failed",
             "projection_unavailable":
            return "Hub 没有返回这次统一简报"
        default:
            if let token = HubRouteStateMachine.normalizedReasonToken(reasonCode) {
                if token.contains("timeout") || token.contains("connect") || token.contains("unavailable") {
                    return "Hub 路由当前不可达"
                }
                return "Hub brief 投影失败（\(token)）"
            }
            return "Hub 没有返回这次统一简报"
        }
    }

    private func supervisorBriefProjectionFailureRepairAction(_ reasonCode: String?) -> String {
        switch HubRouteStateMachine.normalizedReasonToken(reasonCode) {
        case "synchronous_projection_fetch_required":
            return "等 Hub brief 投影查询链接上后再问一次状态；当前我不会在 XT 本地补写这份简报。"
        case "hub_env_missing":
            return "先修复 Hub 配对或运行 doctor / repair，再重新问一次状态。"
        case "supervisor_brief_projection_file_ipc_not_supported":
            return "先切回可用的 Hub pairing route，再重新问一次状态。"
        case "client_kit_missing", "node_missing":
            return "先修复 Hub 本地 runtime / bridge，再重新问一次状态。"
        default:
            return "先打开 Hub Diagnostics & Recovery 检查路由，再重新问一次状态。"
        }
    }

    private func localSupervisorBriefReply(
        focus: SupervisorFocusedProjectSelection,
        fromVoice: Bool
    ) -> SupervisorBriefProjectionVoiceReply? {
        localSupervisorBriefReply(
            projectName: focus.project.displayName,
            fromVoice: fromVoice
        )
    }

    private func localSupervisorBriefReply(
        projectName: String,
        fromVoice: Bool
    ) -> SupervisorBriefProjectionVoiceReply? {
        guard let signal = heartbeatGovernanceVoicePresentation() else { return nil }

        let replyText = renderLocalSupervisorGovernanceVoiceReply(
            signal,
            projectName: projectName
        )
        let spokenOutcome: SupervisorSpeechSynthesizer.Outcome
        if !fromVoice {
            spokenOutcome = .suppressed("not_voice_triggered")
        } else {
            let script = heartbeatScriptPrefixedWithMemoryReadiness(
                SupervisorVoiceScriptBuilder.governanceSignalHeartbeatScript(
                    signal: signal,
                    progressLine: nil,
                    nextStepLine: nil
                )
            )
            if script.isEmpty {
                spokenOutcome = speakSupervisorVoiceReply(replyText)
            } else {
                let job = SupervisorVoiceTTSJob(
                    trigger: .userQueryReply,
                    priority: .normal,
                    script: script,
                    dedupeKey: "voice-query:local-brief:\(signal.fingerprint)\(heartbeatMemoryReadinessDedupeSuffix())"
                )
                spokenOutcome = dispatchSupervisorVoiceJob(
                    job,
                    preferences: currentVoicePreferences(),
                    source: "brief_projection_local_voice_reply",
                    suppressRapidSameSourceRepeat: false,
                    cancelPendingHeartbeat: true
                )
            }
        }
        return SupervisorBriefProjectionVoiceReply(
            text: replyText,
            spokenOutcome: spokenOutcome
        )
    }

    private func shouldUseSupervisorBriefProjectionForStatusQuery(_ text: String) -> Bool {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty, !trimmed.hasPrefix("/") else { return false }
        let normalized = normalizedLookupKey(trimmed)
        guard !normalized.isEmpty else { return false }
        let tokens = [
            "进度",
            "状态",
            "卡点",
            "阻塞",
            "下一步",
            "建议",
            "授权",
            "grant",
            "status",
            "progress",
            "blocker",
            "brief",
            "summary",
            "nextstep",
            "next",
            "进展",
            "优先",
            "优先级",
            "先做哪个",
            "priority"
        ]
        return tokens.contains(where: { normalized.contains(normalizedLookupKey($0)) })
    }

    private func supervisorBriefProjectionVoiceQueryTrigger(_ text: String) -> String {
        let normalized = normalizedLookupKey(text)
        if normalized.contains("授权") || normalized.contains("grant") {
            return "awaiting_authorization"
        }
        if normalized.contains("卡点") || normalized.contains("阻塞") || normalized.contains("blocker") {
            return "blocked"
        }
        if normalized.contains("下一步") || normalized.contains("建议") || normalized.contains("nextstep") {
            return "critical_path_changed"
        }
        return "daily_digest"
    }

    private func renderSupervisorBriefProjectionVoiceReply(
        _ projection: HubIPCClient.SupervisorBriefProjectionSnapshot,
        projectName: String
    ) -> String {
        var lines = ["🧭 Supervisor Brief · \(projectName)"]
        if let memoryLine = supervisorMemoryReadinessBriefTextLine() {
            lines.append(memoryLine)
        }
        let topline = projection.topline.trimmingCharacters(in: .whitespacesAndNewlines)
        let blocker = projection.criticalBlocker.trimmingCharacters(in: .whitespacesAndNewlines)
        let next = projection.nextBestAction.trimmingCharacters(in: .whitespacesAndNewlines)
        let summary = projection.cardSummary.trimmingCharacters(in: .whitespacesAndNewlines)

        if !topline.isEmpty {
            lines.append(topline)
        } else if !summary.isEmpty {
            lines.append(summary)
        }
        if !blocker.isEmpty {
            lines.append("阻塞：\(blocker)")
        }
        if projection.pendingGrantCount > 0 {
            lines.append("待授权：\(projection.pendingGrantCount)")
        }
        if !next.isEmpty {
            lines.append("下一步：\(next)")
        }
        return lines.joined(separator: "\n")
    }

