    private func heartbeatGovernanceVoicePriority(
        _ signal: SupervisorGovernanceSignalVoicePresentation
    ) -> SupervisorVoiceJobPriority {
        switch signal.trigger {
        case .authorization:
            return .normal
        case .blocked:
            return .normal
        case .completed, .userQueryReply:
            return .quiet
        }
    }

    private func heartbeatGovernanceVoiceJob(
        signal: SupervisorGovernanceSignalVoicePresentation,
        progressVoiceLine: String?,
        nextStepLine: String?
    ) -> SupervisorVoiceTTSJob {
        SupervisorVoiceTTSJob(
            trigger: signal.trigger,
            priority: heartbeatGovernanceVoicePriority(signal),
            script: heartbeatScriptPrefixedWithMemoryReadiness(
                SupervisorVoiceScriptBuilder.governanceSignalHeartbeatScript(
                    signal: signal,
                    progressLine: progressVoiceLine,
                    nextStepLine: nextStepLine
                )
            ),
            dedupeKey: "heartbeat:governance_signal:\(signal.fingerprint)\(heartbeatMemoryReadinessDedupeSuffix())"
        )
    }

    private func heartbeatVoiceJob(
        reason: String,
        changed: Bool,
        projects: [AXProjectEntry],
        blockerProjects: [(projectId: String, blocker: String)],
        blockerSignal: BlockerSignal,
        permissionSignals: [ProjectPermissionSignal],
        governanceRepairSignals: [ProjectGovernanceRepairSignal],
        queueSignals: [ProjectQueueSignal],
        progressActions: [HeartbeatAutoProgressAction],
        nextStepSummary: String,
        routeAttentionSignal: HeartbeatRouteAttentionSignal?
    ) -> SupervisorVoiceTTSJob? {
        let nextStepLine = conciseHeartbeatNextStep(nextStepSummary)
        let voiceReadinessSignal = heartbeatVoiceReadinessSignal()
        let governanceVoiceSignal = heartbeatGovernanceVoicePresentation()
        let shouldEmitPassiveSummary = changed || reason != "timer" || !progressActions.isEmpty
        let progressVoiceLine: String? = {
            guard let first = progressActions.first else { return nil }
            switch first.kind {
            case .recover:
                return "我已主动恢复 \(first.projectName)。"
            case .start:
                return "我已主动启动 \(first.projectName)。"
            }
        }()

        if let firstBlocker = blockerProjects.first {
            let projectName = heartbeatProjectName(for: firstBlocker.projectId, in: projects) ?? "当前项目"
            return SupervisorVoiceTTSJob(
                trigger: .blocked,
                priority: blockerSignal.escalated ? .interrupt : .normal,
                script: heartbeatScriptPrefixedWithMemoryReadiness(
                    SupervisorVoiceScriptBuilder.blockedHeartbeatScript(
                        blockerCount: blockerProjects.count,
                        projectName: projectName,
                        blockerSummary: capped(firstBlocker.blocker, maxChars: 36),
                        progressLine: progressVoiceLine,
                        blockerStreak: max(1, blockerSignal.streak),
                        nextStepLine: nextStepLine
                    )
                ),
                dedupeKey: "heartbeat:blocker:\(firstBlocker.projectId):\(capped(firstBlocker.blocker, maxChars: 48)):\(blockerSignal.streak)\(heartbeatMemoryReadinessDedupeSuffix())"
            )
        }

        if let governanceVoiceSignal,
           governanceVoiceSignal.trigger == .authorization,
           shouldEmitPassiveSummary {
            return heartbeatGovernanceVoiceJob(
                signal: governanceVoiceSignal,
                progressVoiceLine: progressVoiceLine,
                nextStepLine: nextStepLine
            )
        }

        if let permission = permissionSignals.first {
            return SupervisorVoiceTTSJob(
                trigger: .blocked,
                priority: .normal,
                script: heartbeatScriptPrefixedWithMemoryReadiness(
                    SupervisorVoiceScriptBuilder.permissionHeartbeatScript(
                        permissionCount: permissionSignals.count,
                        projectName: permission.projectName,
                        summary: capped(permission.summary, maxChars: 36),
                        progressLine: progressVoiceLine,
                        nextStepLine: nextStepLine
                    )
                ),
                dedupeKey: "heartbeat:permission:\(permission.projectId):\(permission.kind.rawValue):\(capped(permission.summary, maxChars: 48))\(heartbeatMemoryReadinessDedupeSuffix())"
            )
        }

        if let repair = governanceRepairSignals.first {
            return SupervisorVoiceTTSJob(
                trigger: .blocked,
                priority: .normal,
                script: heartbeatScriptPrefixedWithMemoryReadiness(
                    SupervisorVoiceScriptBuilder.governanceRepairHeartbeatScript(
                        repairCount: governanceRepairSignals.count,
                        projectName: repair.projectName,
                        summary: repair.summary,
                        progressLine: progressVoiceLine,
                        nextStepLine: nextStepLine
                    )
                ),
                dedupeKey: "heartbeat:governance_repair:\(repair.projectId):\(repair.destination.rawValue):\(capped(repair.summary, maxChars: 48))\(heartbeatMemoryReadinessDedupeSuffix())"
            )
        }

        if let voiceReadinessSignal {
            return SupervisorVoiceTTSJob(
                trigger: voiceReadinessSignal.readyForFirstTask ? .completed : .blocked,
                priority: voiceReadinessSignal.readyForFirstTask ? .quiet : .normal,
                script: heartbeatScriptPrefixedWithMemoryReadiness(
                    SupervisorVoiceScriptBuilder.voiceReadinessHeartbeatScript(
                        readyForFirstTask: voiceReadinessSignal.readyForFirstTask,
                        headline: voiceReadinessSignal.headline,
                        summary: voiceReadinessSignal.overallSummary,
                        progressLine: progressVoiceLine,
                        nextStepLine: nextStepLine ?? voiceReadinessSignal.nextStep
                    )
                ),
                dedupeKey: "heartbeat:voice_readiness:\(voiceReadinessSignal.readyForFirstTask ? "ready" : "fail_closed"):\(voiceReadinessSignal.reasonCode):\(capped(voiceReadinessSignal.headline, maxChars: 48))\(heartbeatMemoryReadinessDedupeSuffix())"
            )
        }

        if queueSignals.isEmpty,
           let routeAttentionSignal,
           (reason != "timer" || routeAttentionSignal.shouldAlertOnTimer) {
            let routeReasonRaw = routeAttentionSignal.item.digest.topRouteReason?
                .trimmingCharacters(in: .whitespacesAndNewlines)
            let routeReasonDisplay = AXRouteRepairLogStore.userFacingRouteReason(
                routeReasonRaw ?? "",
                includeCode: false
            )
            let routeReason = routeReasonDisplay.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
                ? nil
                : routeReasonDisplay
            let failureActionDisplay = AXRouteRepairLogStore.userFacingActionLabel(
                routeAttentionSignal.item.digest.latestFailure?.actionId ?? ""
            )
            let failureAction = failureActionDisplay.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
                ? nil
                : failureActionDisplay
            return SupervisorVoiceTTSJob(
                trigger: .completed,
                priority: .normal,
                script: heartbeatScriptPrefixedWithMemoryReadiness(
                    SupervisorVoiceScriptBuilder.routeDiagnoseHeartbeatScript(
                        projectName: routeAttentionSignal.item.projectDisplayName,
                        routeReason: routeReason,
                        failureAction: failureAction,
                        progressLine: progressVoiceLine,
                        nextStepLine: nextStepLine
                    )
                ),
                dedupeKey: "heartbeat:route_repair:\(routeAttentionSignal.item.projectId):\(capped(routeReasonRaw ?? "", maxChars: 32)):\(capped(routeAttentionSignal.item.digest.latestFailure?.actionId ?? "", maxChars: 40))\(heartbeatMemoryReadinessDedupeSuffix())"
            )
        }

        if let governanceVoiceSignal,
           shouldEmitPassiveSummary {
            return heartbeatGovernanceVoiceJob(
                signal: governanceVoiceSignal,
                progressVoiceLine: progressVoiceLine,
                nextStepLine: nextStepLine
            )
        }

        guard shouldEmitPassiveSummary else {
            return nil
        }

        let queueCount = queueSignals.count
        let projectCount = projects.count
        let leadProjectName = queueSignals.first?.project.displayName ?? projects.first?.displayName ?? "当前项目"
        return SupervisorVoiceTTSJob(
            trigger: .completed,
            priority: .quiet,
            script: heartbeatScriptPrefixedWithMemoryReadiness(
                SupervisorVoiceScriptBuilder.stableHeartbeatScript(
                    projectCount: projectCount,
                    queueCount: queueCount,
                    leadProjectName: leadProjectName,
                    progressLine: progressVoiceLine,
                    nextStepLine: nextStepLine
                )
            ),
            dedupeKey: "heartbeat:summary:\(reason):\(projectCount):\(queueCount):\(leadProjectName)\(heartbeatMemoryReadinessDedupeSuffix())"
        )
    }

    private func heartbeatScriptPrefixedWithMemoryReadiness(
        _ script: [String]
    ) -> [String] {
        guard let readiness = currentSupervisorMemoryAssemblyReadinessForLanguageLayer(),
              !readiness.ready else {
            return script
        }
        let topIssue = readiness.issues.first?.summary.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let lead: String
        if topIssue.isEmpty {
            lead = "当前项目背景记忆还没喂够，我先不做战略纠偏，只汇报阻塞和下一步。"
        } else {
            lead = "当前项目背景记忆还没喂够，\(capped(topIssue, maxChars: 20))，我先不做战略纠偏，只汇报阻塞和下一步。"
        }
        guard script.first != lead else { return script }
        return [lead] + script
    }

    private func heartbeatMemoryReadinessDedupeSuffix() -> String {
        guard let readiness = currentSupervisorMemoryAssemblyReadinessForLanguageLayer(),
              !readiness.ready else {
            return ""
        }
        let issues = readiness.issueCodes.joined(separator: ",")
        return ":memory_underfed:\(issues.isEmpty ? "unspecified" : issues)"
    }

    private func heartbeatProjectName(
        for projectId: String,
        in projects: [AXProjectEntry]
    ) -> String? {
        projects.first(where: { $0.projectId == projectId })?.displayName
    }

    private func heartbeatProjectionRequest(
        reason: String,
        changed: Bool,
        projects: [AXProjectEntry],
        blockerProjects: [(projectId: String, blocker: String)],
        blockerSignal: BlockerSignal,
        permissionSignals: [ProjectPermissionSignal],
        governanceRepairSignals: [ProjectGovernanceRepairSignal],
        queueSignals: [ProjectQueueSignal],
        progressActions: [HeartbeatAutoProgressAction],
        nextStepSummary: String
    ) -> HubIPCClient.SupervisorBriefProjectionRequestPayload? {
        if heartbeatVoiceReadinessSignal() != nil,
           blockerProjects.isEmpty,
           permissionSignals.isEmpty,
           governanceRepairSignals.isEmpty {
            return nil
        }
        let focusProjectId = progressActions.first?.projectId
            ?? blockerProjects.first?.projectId
            ?? permissionSignals.first?.projectId
            ?? governanceRepairSignals.first?.projectId
            ?? queueSignals.first?.project.projectId
            ?? heartbeatLeadRouteRepairAttentionItem(projects: projects)?.projectId
        guard let focusProjectId,
              !focusProjectId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            return nil
        }
        return HubIPCClient.SupervisorBriefProjectionRequestPayload(
            requestId: "heartbeat_brief_\(Int(Date().timeIntervalSince1970 * 1000))_\(UUID().uuidString.lowercased())",
            projectId: focusProjectId,
            runId: nil,
            missionId: nil,
            projectionKind: "progress_brief",
            trigger: heartbeatProjectionTrigger(
                reason: reason,
                changed: changed,
                blockerProjects: blockerProjects,
                blockerSignal: blockerSignal,
                permissionSignals: permissionSignals,
                governanceRepairSignals: governanceRepairSignals,
                queueSignals: queueSignals,
                nextStepSummary: nextStepSummary
            ),
            includeTtsScript: true,
            includeCardSummary: false,
            maxEvidenceRefs: 4
        )
    }

    private func heartbeatProjectionTrigger(
        reason: String,
        changed: Bool,
        blockerProjects: [(projectId: String, blocker: String)],
        blockerSignal: BlockerSignal,
        permissionSignals: [ProjectPermissionSignal],
        governanceRepairSignals: [ProjectGovernanceRepairSignal],
        queueSignals: [ProjectQueueSignal],
        nextStepSummary: String
    ) -> String {
        if !permissionSignals.isEmpty {
            return "awaiting_authorization"
        }
        if !governanceRepairSignals.isEmpty {
            return "blocked"
        }
        if !blockerProjects.isEmpty {
            return "blocked"
        }
        if changed || blockerSignal.escalated || !nextStepSummary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return "critical_path_changed"
        }
        if reason == "timer" && !queueSignals.isEmpty {
            return "daily_digest"
        }
        return "daily_digest"
    }

    private func heartbeatProjectionVoiceResolution(
        request: HubIPCClient.SupervisorBriefProjectionRequestPayload,
        blockerSignal: BlockerSignal,
        projects: [AXProjectEntry]
    ) async -> HeartbeatProjectionVoiceResolution? {
        let fetcher = supervisorBriefProjectionRequestOverride
            ?? { payload in
                await HubIPCClient.requestSupervisorBriefProjection(payload)
            }
        let result = await fetcher(request)
        guard result.ok, let projection = result.projection else {
            return heartbeatProjectionUnavailableVoiceResolution(
                request: request,
                reasonCode: result.reasonCode,
                projects: projects
            )
        }
        let script = projectionVoiceScript(from: projection)
        guard !script.isEmpty else {
            return heartbeatProjectionUnavailableVoiceResolution(
                request: request,
                reasonCode: result.reasonCode ?? "projection_voice_script_missing",
                projects: projects
            )
        }
        return .projection(SupervisorVoiceTTSJob(
            trigger: projectionVoiceTrigger(from: projection),
            priority: projectionVoicePriority(from: projection, blockerSignal: blockerSignal),
            script: script,
            dedupeKey: projectionVoiceDedupeKey(from: projection)
        ))
    }

    private func heartbeatProjectionUnavailableVoiceResolution(
        request: HubIPCClient.SupervisorBriefProjectionRequestPayload,
        reasonCode: String?,
        projects: [AXProjectEntry]
    ) -> HeartbeatProjectionVoiceResolution? {
        let projectName = heartbeatProjectName(
            for: request.projectId,
            in: projects
        ) ?? "当前项目"
        let presentation = supervisorBriefProjectionUnavailablePresentation(
            projectName: projectName,
            reasonCode: reasonCode,
            localSignal: heartbeatGovernanceVoicePresentation()
        )
        let script = heartbeatScriptPrefixedWithMemoryReadiness(presentation.script)
        guard !script.isEmpty else { return nil }
        let normalizedReason = HubRouteStateMachine.normalizedReasonToken(reasonCode) ?? "hub_brief_unavailable"
        return .unavailable(
            SupervisorVoiceTTSJob(
                trigger: request.trigger == "awaiting_authorization" ? .authorization : .blocked,
                priority: .normal,
                script: script,
                dedupeKey: "heartbeat:hub_brief_unavailable:\(request.projectId):\(normalizedReason)\(heartbeatMemoryReadinessDedupeSuffix())"
            )
        )
    }

    private func projectionVoiceScript(
        from projection: HubIPCClient.SupervisorBriefProjectionSnapshot
    ) -> [String] {
        let ttsScript = projection.ttsScript
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        if !ttsScript.isEmpty {
            return heartbeatScriptPrefixedWithMemoryReadiness(
                SupervisorVoiceScriptBuilder.projectionScript(
                    ttsScript: ttsScript,
                    trigger: projectionVoiceTrigger(from: projection)
                )
            )
        }

        let topline = projection.topline.trimmingCharacters(in: .whitespacesAndNewlines)
        let blocker = projection.criticalBlocker.trimmingCharacters(in: .whitespacesAndNewlines)
        let next = projection.nextBestAction.trimmingCharacters(in: .whitespacesAndNewlines)
        let summary = projection.cardSummary.trimmingCharacters(in: .whitespacesAndNewlines)
        return heartbeatScriptPrefixedWithMemoryReadiness(
            SupervisorVoiceScriptBuilder.projectionFallbackScript(
                topline: topline,
                blocker: capped(blocker, maxChars: 48),
                pendingGrantCount: projection.pendingGrantCount,
                nextBestAction: capped(next, maxChars: 48),
                summary: summary
            )
        )
    }

    private func projectionVoiceTrigger(
        from projection: HubIPCClient.SupervisorBriefProjectionSnapshot
    ) -> SupervisorVoiceJobTrigger {
        let trigger = projection.trigger.trimmingCharacters(in: .whitespacesAndNewlines)
        if trigger == "awaiting_authorization" || projection.pendingGrantCount > 0 {
            return .authorization
        }
        if trigger == "blocked" || !projection.criticalBlocker.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            return .blocked
        }
        return .completed
    }

    private func projectionVoicePriority(
        from projection: HubIPCClient.SupervisorBriefProjectionSnapshot,
        blockerSignal: BlockerSignal
    ) -> SupervisorVoiceJobPriority {
        let trigger = projectionVoiceTrigger(from: projection)
        if trigger == .blocked && blockerSignal.escalated {
            return .interrupt
        }
        switch trigger {
        case .authorization, .blocked:
            return .normal
        case .completed, .userQueryReply:
            return .quiet
        }
    }

    private func projectionVoiceDedupeKey(
        from projection: HubIPCClient.SupervisorBriefProjectionSnapshot
    ) -> String {
        let projectionId = projection.projectionId.trimmingCharacters(in: .whitespacesAndNewlines)
        if !projectionId.isEmpty {
            return "hub-brief:\(projectionId)\(heartbeatMemoryReadinessDedupeSuffix())"
        }
        let auditRef = projection.auditRef.trimmingCharacters(in: .whitespacesAndNewlines)
        if !auditRef.isEmpty {
            return "hub-brief:\(auditRef)\(heartbeatMemoryReadinessDedupeSuffix())"
        }
        return "hub-brief:\(projection.projectId):\(projection.trigger):\(Int(projection.generatedAtMs))\(heartbeatMemoryReadinessDedupeSuffix())"
    }

    private func conciseHeartbeatNextStep(_ text: String) -> String? {
        for rawLine in text.split(separator: "\n") {
            let line = rawLine
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .replacingOccurrences(of: "•", with: "")
                .replacingOccurrences(
                    of: #"^\d+\.\s*"#,
                    with: "",
                    options: .regularExpression
                )
                .trimmingCharacters(in: .whitespacesAndNewlines)
            if !line.isEmpty {
                return capped(line, maxChars: 40)
            }
        }
        return nil
    }

    private func conciseVoiceReplyScript(_ text: String) -> [String] {
        let cueLine = extractSupervisorCalendarCueLine(from: text)
        let baseText = removingSupervisorCalendarCueLine(from: text)
        var script = SupervisorVoiceScriptBuilder.conciseReplyScript(from: baseText)

        guard let cueLine else {
            return script
        }

        if script.isEmpty {
            return [cueLine]
        }
        if script.count == 1 {
            script.append(cueLine)
            return script
        }
        script[1] = cueLine
        return script
    }

    private func extractSupervisorCalendarCueLine(from text: String) -> String? {
        text
            .components(separatedBy: .newlines)
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .first { line in
                line.hasPrefix("哦，对了，") || line.hasPrefix("Oh, one more thing,")
            }
    }

    private func removingSupervisorCalendarCueLine(from text: String) -> String {
        text
            .components(separatedBy: .newlines)
            .filter { line in
                let trimmed = line.trimmingCharacters(in: .whitespacesAndNewlines)
                return !trimmed.hasPrefix("哦，对了，") &&
                    !trimmed.hasPrefix("Oh, one more thing,")
            }
            .joined(separator: "\n")
    }

    private func heartbeatFocusActionURL(
        projects: [AXProjectEntry],
        progressActions: [HeartbeatAutoProgressAction],
        blockerProjects: [(projectId: String, blocker: String)],
        permissionSignals: [ProjectPermissionSignal],
        governanceRepairSignals: [ProjectGovernanceRepairSignal],
        queueSignals: [ProjectQueueSignal]
    ) -> String? {
        if let actionURL = permissionSignals.first?.actionURL {
            let trimmed = actionURL.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty {
                return trimmed
            }
        }

        if let actionURL = heartbeatGovernanceRepairActionURL(signals: governanceRepairSignals) {
            let trimmed = actionURL.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty {
                return trimmed
            }
        }

        if blockerProjects.isEmpty,
           permissionSignals.isEmpty,
           governanceRepairSignals.isEmpty,
           let actionURL = heartbeatVoiceReadinessSignal()?.actionURL {
            let trimmed = actionURL.trimmingCharacters(in: .whitespacesAndNewlines)
            if !trimmed.isEmpty {
                return trimmed
            }
        }

        let focusProjectId = progressActions.first?.projectId
            ?? blockerProjects.first?.projectId
            ?? permissionSignals.first?.projectId
            ?? governanceRepairSignals.first?.projectId
            ?? queueSignals.first?.project.projectId
        if let focusProjectId {
            return resumeProjectActionURL(projectId: focusProjectId)
        }

        if let routeProjectId = heartbeatRouteDiagnoseProjectId(projects: projects) {
            return routeDiagnoseActionURL(projectId: routeProjectId)
        }

        return XTDeepLinkURLBuilder.supervisorURL()?.absoluteString
    }

    private func heartbeatGovernanceRepairActionURL(
        signals: [ProjectGovernanceRepairSignal]
    ) -> String? {
        for signal in signals {
            let actionURL = signal.actionURL?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            if !actionURL.isEmpty {
                return actionURL
            }
        }
        return nil
    }

    private func heartbeatRouteDiagnoseProjectId(
        projects: [AXProjectEntry]
    ) -> String? {
        if let projectId = heartbeatLeadRouteRepairAttentionItem(projects: projects)?.projectId {
            return projectId
        }

        let orderedProjects = projects.sorted { p1, p2 in
            calculatePriority(p1) > calculatePriority(p2)
        }
        let routeMemorySnapshot = heartbeatRouteMemorySnapshot()
        for project in orderedProjects {
            if AXProjectModelRouteMemoryStore.heartbeatNotice(
                for: project,
                snapshot: routeMemorySnapshot
            ) != nil {
                return project.projectId
            }
        }
        return nil
    }

    private func supervisorActionURL(
        projectId: String?,
        focusTarget: XTDeepLinkFocusTarget? = nil,
        requestId: String? = nil,
        grantRequestId: String? = nil,
        capability: String? = nil
    ) -> String? {
        let normalizedRequestId = requestId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let grantId = grantRequestId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let capabilityToken = capability?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let resolvedFocusTarget: XTDeepLinkFocusTarget? = {
            if let focusTarget {
                return focusTarget
            }
            if !grantId.isEmpty || !capabilityToken.isEmpty {
                return .grant
            }
            if !normalizedRequestId.isEmpty {
                return .approval
            }
            return nil
        }()
        if let raw = projectId?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty {
            return XTDeepLinkURLBuilder.projectURL(
                projectId: raw,
                pane: .chat,
                openTarget: .supervisor,
                focusTarget: resolvedFocusTarget,
                requestId: normalizedRequestId.isEmpty ? nil : normalizedRequestId,
                grantRequestId: grantId.isEmpty ? nil : grantId,
                grantCapability: capabilityToken.isEmpty ? nil : capabilityToken
            )?.absoluteString
        }
        if resolvedFocusTarget != nil {
            return XTDeepLinkURLBuilder.supervisorURL(
                focusTarget: resolvedFocusTarget,
                requestId: normalizedRequestId.isEmpty ? nil : normalizedRequestId,
                grantRequestId: grantId.isEmpty ? nil : grantId,
                grantCapability: capabilityToken.isEmpty ? nil : capabilityToken
            )?.absoluteString
        }
        return XTDeepLinkURLBuilder.supervisorURL()?.absoluteString
    }

    private func resumeProjectActionURL(
        projectId: String?,
        openTarget: XTDeepLinkOpenTarget? = nil
    ) -> String? {
        guard let raw = projectId?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
            return XTDeepLinkURLBuilder.supervisorURL()?.absoluteString
        }
        return XTDeepLinkURLBuilder.projectURL(
            projectId: raw,
            pane: .chat,
            openTarget: openTarget,
            resumeRequested: true
        )?.absoluteString
    }

    private func toolApprovalActionURL(
        projectId: String?,
        requestId: String? = nil
    ) -> String? {
        guard let raw = projectId?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
            return nil
        }
        let normalizedRequestId = requestId?.trimmingCharacters(in: .whitespacesAndNewlines)
        return XTDeepLinkURLBuilder.projectURL(
            projectId: raw,
            pane: .chat,
            focusTarget: .toolApproval,
            requestId: normalizedRequestId?.isEmpty == false ? normalizedRequestId : nil
        )?.absoluteString
    }

    private func routeDiagnoseActionURL(
        projectId: String?
    ) -> String? {
        guard let raw = projectId?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
            return nil
        }
        return XTDeepLinkURLBuilder.projectURL(
            projectId: raw,
            pane: .chat,
            focusTarget: .routeDiagnose
        )?.absoluteString
    }

    private func projectGovernanceActionURL(
        projectId: String?,
        destination: XTProjectGovernanceDestination
    ) -> String? {
        guard let raw = projectId?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
            return nil
        }
        return XTDeepLinkURLBuilder.projectURL(
            projectId: raw,
            pane: .chat,
            governanceDestination: destination
        )?.absoluteString
    }

    private func governanceRepairHint(
        for record: SupervisorSkillCallRecord
    ) -> XTGuardrailRepairHint? {
        switch record.status {
        case .blocked, .failed:
            return XTGuardrailMessagePresentation.repairHint(
                denyCode: record.denyCode,
                policySource: record.policySource ?? "",
                policyReason: record.policyReason ?? ""
            )
        case .queued, .running, .awaitingAuthorization, .completed, .canceled:
            return nil
        }
    }

    private func supervisorSkillActivityActionURL(
        projectId: String,
        record: SupervisorSkillCallRecord,
        ctx: AXProjectContext
    ) -> String? {
        let capability = record.requiredCapability?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let grantRequestId = record.grantRequestId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if record.status == .awaitingAuthorization {
            if !capability.isEmpty || !grantRequestId.isEmpty {
                return supervisorActionURL(
                    projectId: projectId,
                    grantRequestId: grantRequestId.isEmpty ? nil : grantRequestId,
                    capability: capability.isEmpty ? nil : capability
                )
            }
            return supervisorActionURL(
                projectId: projectId,
                requestId: record.requestId
            )
        }
        if supervisorShouldRouteToUIReview(
            requestId: record.requestId,
            ctx: ctx
        ) {
            return projectGovernanceActionURL(
                projectId: projectId,
                destination: .uiReview
            )
        }
        if let repairHint = governanceRepairHint(for: record) {
            return projectGovernanceActionURL(
                projectId: projectId,
                destination: repairHint.destination
            )
        }
        return resumeProjectActionURL(projectId: projectId)
    }

    private func runSupervisorDoctorPreflight(
        reason: String,
        emitSystemMessage: Bool
    ) -> SupervisorDoctorReport {
        let input = SupervisorDoctorChecker.loadDefaultInputBundle(
            memoryAssemblySnapshot: supervisorMemoryAssemblySnapshot
        )
        let report = SupervisorDoctorChecker.runAndPersist(input: input)
        doctorReport = report
        doctorSuggestionCards = report.suggestions
        doctorHasBlockingFindings = report.summary.blockingCount > 0
        releaseBlockedByDoctorWithoutReport = report.summary.releaseBlockedByDoctorWithoutReport
        doctorReportPath = input.reportURL.path

        if report.ok {
            doctorStatusLine = "Doctor 已通过（\(report.summary.warningCount) 个告警）"
        } else {
            doctorStatusLine = "Doctor 阻断：\(report.summary.blockingCount) 项（\(report.summary.warningCount) 告警）"
        }

        if emitSystemMessage {
            let headline = report.ok ? "✅ Doctor 预检通过" : "⛔️ Doctor 预检阻断"
            let body = "\(headline)（reason=\(reason)）\n\(renderDoctorSummary(report))"
            addSystemMessage(body)
        }
        return report
    }

    private func handleLocalPreflightCommand(_ userMessage: String) async -> String? {
        let trimmed = userMessage.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }
        if let automationResponse = performAutomationRuntimeCommand(trimmed) {
            return automationResponse
        }
        if shouldRetryCanonicalMemorySyncCommand(trimmed) {
            retryCanonicalMemorySyncNow()
            return renderCanonicalMemoryRetryCommandResponse()
        }
        if shouldRunDoctorCommand(trimmed) {
            let report = runSupervisorDoctorPreflight(reason: "user_command_doctor", emitSystemMessage: false)
            return renderDoctorSummary(report)
        }
        if shouldRunSecretsDryRunCommand(trimmed) {
            let report = runSupervisorDoctorPreflight(reason: "user_command_secrets_dry_run", emitSystemMessage: false)
            return renderSecretsDryRunSummary(report)
        }
        if shouldShowXTReadyIncidentEventsStatusCommand(trimmed) {
            return renderXTReadyIncidentEventsStatus()
        }
        if shouldExportXTReadyIncidentEventsCommand(trimmed) {
            let result = exportXTReadyIncidentEventsReport()
            return renderXTReadyIncidentExportSummary(result)
        }
        if shouldInjectXTReadyIncidentsCommand(trimmed) {
            return await injectXTReadyIncidents(using: trimmed)
        }
        return nil
    }

    @discardableResult
    func performAutomationRuntimeCommand(
        _ userMessage: String,
        emitSystemMessage: Bool = false
    ) -> String? {
        let trimmed = userMessage.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return nil }
        guard looksLikeAutomationRuntimeCommand(trimmed) else { return nil }

        let response: String
        guard let command = parseAutomationRuntimeCommand(trimmed) else {
            response = automationRuntimeCommandHelpText()
            if emitSystemMessage {
                addSystemMessage(response)
            }
            return response
        }

        do {
            switch command.action {
            case .help:
                response = automationRuntimeCommandHelpText()

            case .status:
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                response = try renderAutomationRuntimeStatus(for: project, ctx: ctx)

            case .start:
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                let request = try makeManualAutomationRunRequest(for: project, ctx: ctx)
                let prepared = try startAutomationRun(for: ctx, request: request, emitSystemMessage: false)
                response = renderAutomationStartSummary(project: project, prepared: prepared)

            case .recover:
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                let decision = try recoverLatestAutomationRun(
                    for: ctx,
                    checkpointAgeSeconds: 0,
                    auditRef: automationRuntimeAuditRef(action: "recover", project: project),
                    emitSystemMessage: false
                )
                response = renderAutomationRecoverySummary(
                    project: project,
                    decision: decision,
                    retryPackage: automationLatestRetryPackage
                )

            case .cancel:
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                let runID = try latestAutomationLaunchRef(for: ctx)
                let decision = try cancelAutomationRun(
                    for: ctx,
                    runID: runID,
                    auditRef: automationRuntimeAuditRef(action: "cancel", project: project),
                    emitSystemMessage: false
                )
                response = renderAutomationCancelSummary(project: project, decision: decision)

            case .advance(let nextState):
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                let runID = try latestAutomationLaunchRef(for: ctx)
                let checkpoint = try advanceAutomationRun(
                    for: ctx,
                    to: nextState,
                    runID: runID,
                    auditRef: automationRuntimeAuditRef(action: "advance_\(nextState.rawValue)", project: project),
                    emitSystemMessage: false
                )
                response = renderAutomationAdvanceSummary(project: project, checkpoint: checkpoint)

            case .selfIterateStatus:
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                let config = try AXProjectStore.loadOrCreateConfig(for: ctx)
                response = renderAutomationSelfIterateSummary(
                    project: project,
                    config: config,
                    headline: "🧠 automation self-iterate 状态"
                )

            case .selfIterateSet(let enabled):
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                let config = try updateAutomationSelfIterateConfig(
                    for: project,
                    ctx: ctx,
                    enabled: enabled
                )
                response = renderAutomationSelfIterateSummary(
                    project: project,
                    config: config,
                    headline: enabled
                        ? "🧠 automation self-iterate 已开启"
                        : "🧠 automation self-iterate 已关闭"
                )

            case .selfIterateMax(let depth):
                let (project, ctx) = try resolveAutomationCommandProject(command.projectRef)
                let config = try updateAutomationSelfIterateConfig(
                    for: project,
                    ctx: ctx,
                    maxAutoRetryDepth: depth
                )
                response = renderAutomationSelfIterateSummary(
                    project: project,
                    config: config,
                    headline: "🧠 automation self-iterate 深度已更新"
                )
            }
        } catch {
            response = renderAutomationRuntimeError(error)
        }

        if emitSystemMessage {
            addSystemMessage(response)
        }
        return response
    }

    private func looksLikeAutomationRuntimeCommand(_ text: String) -> Bool {
        let head = text
            .split(whereSeparator: \.isWhitespace)
            .first?
            .lowercased() ?? ""
        return head == "/automation" || head == "automation"
    }

    private func parseAutomationRuntimeCommand(_ text: String) -> ParsedAutomationRuntimeCommand? {
        let tokens = text
            .split(whereSeparator: \.isWhitespace)
            .map(String.init)
        guard let head = tokens.first?.lowercased(),
              head == "/automation" || head == "automation" else {
            return nil
        }
        guard tokens.count >= 2 else {
            return ParsedAutomationRuntimeCommand(action: .help, projectRef: nil)
        }

        let actionToken = normalizedAutomationCommandToken(tokens[1])
        switch actionToken {
        case "help":
            return ParsedAutomationRuntimeCommand(action: .help, projectRef: nil)
        case "status":
            return ParsedAutomationRuntimeCommand(
                action: .status,
                projectRef: automationProjectRef(from: tokens, startingAt: 2)
            )
        case "start":
            return ParsedAutomationRuntimeCommand(
                action: .start,
                projectRef: automationProjectRef(from: tokens, startingAt: 2)
            )
        case "recover":
            return ParsedAutomationRuntimeCommand(
                action: .recover,
                projectRef: automationProjectRef(from: tokens, startingAt: 2)
            )
        case "cancel":
            return ParsedAutomationRuntimeCommand(
                action: .cancel,
                projectRef: automationProjectRef(from: tokens, startingAt: 2)
            )
        case "advance":
            guard tokens.count >= 3,
                  let nextState = automationRunState(from: tokens[2]) else {
                return nil
            }
            return ParsedAutomationRuntimeCommand(
                action: .advance(nextState),
                projectRef: automationProjectRef(from: tokens, startingAt: 3)
            )
        case "self_iterate":
            let modeToken = normalizedAutomationSelfIterateCommandToken(tokens.count > 2 ? tokens[2] : "")
            switch modeToken {
            case "", "status":
                return ParsedAutomationRuntimeCommand(
                    action: .selfIterateStatus,
                    projectRef: automationProjectRef(from: tokens, startingAt: modeToken.isEmpty ? 2 : 3)
                )
            case "on":
                return ParsedAutomationRuntimeCommand(
                    action: .selfIterateSet(true),
                    projectRef: automationProjectRef(from: tokens, startingAt: 3)
                )
            case "off":
                return ParsedAutomationRuntimeCommand(
                    action: .selfIterateSet(false),
                    projectRef: automationProjectRef(from: tokens, startingAt: 3)
                )
            case "max":
                guard tokens.count >= 4,
                      let depth = Int(tokens[3].trimmingCharacters(in: .whitespacesAndNewlines)),
                      depth >= 1 else {
                    return nil
                }
                return ParsedAutomationRuntimeCommand(
                    action: .selfIterateMax(depth),
                    projectRef: automationProjectRef(from: tokens, startingAt: 4)
                )
            default:
                return nil
            }
        default:
            return nil
        }
    }

    private func normalizedAutomationCommandToken(_ token: String) -> String {
        let lowered = token.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        switch lowered {
        case "help", "帮助":
            return "help"
        case "status", "状态":
            return "status"
        case "start", "启动", "开始":
            return "start"
        case "recover", "恢复":
            return "recover"
        case "cancel", "取消", "停止":
            return "cancel"
        case "advance", "推进", "更新":
            return "advance"
        case "self-iterate", "self_iterate", "selfiterate", "自迭代":
            return "self_iterate"
        default:
            return lowered
        }
    }

    private func normalizedAutomationSelfIterateCommandToken(_ token: String) -> String {
        let lowered = token.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        switch lowered {
        case "", "status", "状态":
            return lowered.isEmpty ? "" : "status"
        case "on", "enable", "enabled", "开启", "打开", "启用":
            return "on"
        case "off", "disable", "disabled", "关闭", "关掉", "停用":
            return "off"
        case "max", "depth", "最大", "深度":
            return "max"
        default:
            return lowered
        }
    }

    private func automationProjectRef(from tokens: [String], startingAt index: Int) -> String? {
        guard index < tokens.count else { return nil }
        let raw = tokens[index...].joined(separator: " ").trimmingCharacters(in: .whitespacesAndNewlines)
        guard !raw.isEmpty else { return nil }
        let sanitized = sanitizeProjectReference(raw)
        return sanitized.isEmpty ? nil : sanitized
    }

    private func automationRunState(from raw: String) -> XTAutomationRunState? {
        let token = raw
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
            .replacingOccurrences(of: "-", with: "_")
        switch token {
        case "queued", "queue", "排队", "排队中":
            return .queued
        case "running", "run", "运行", "运行中":
            return .running
        case "blocked", "block", "阻塞", "卡住":
            return .blocked
        case "takeover", "接管":
            return .takeover
        case "delivered", "deliver", "交付", "已交付":
            return .delivered
        case "failed", "fail", "失败":
            return .failed
        case "downgraded", "downgrade", "degraded", "降级":
            return .downgraded
        default:
            return nil
        }
    }

    private func automationRuntimeCommandHelpText() -> String {
        """
🤖 自动化执行命令
- /automation status [projectRef]
- /automation start [projectRef]
- /automation recover [projectRef]
- /automation cancel [projectRef]
- /automation advance <queued|running|blocked|takeover|delivered|failed|downgraded> [projectRef]
- /automation self-iterate status [projectRef]
- /automation self-iterate on [projectRef]
- /automation self-iterate off [projectRef]
- /automation self-iterate max <depth> [projectRef]

如果不传 projectRef，默认使用当前选中的项目；若当前未选中且存在多个项目，请显式指定项目名或 project_id。
"""
    }

    private func resolveAutomationCommandProject(_ projectRef: String?) throws -> (AXProjectEntry, AXProjectContext) {
        if let rawRef = projectRef?.trimmingCharacters(in: .whitespacesAndNewlines),
           !rawRef.isEmpty {
            let normalizedRef = sanitizeProjectReference(rawRef)
            switch resolveProjectReference(normalizedRef) {
            case .matched(let project):
                guard let ctx = projectContext(from: project) else {
                    throw SupervisorAutomationRuntimeError.projectContextMissing(project.projectId)
                }
                return (project, ctx)
            case .notFound:
                throw SupervisorAutomationRuntimeError.projectNotFound(normalizedRef)
            case .ambiguous(let candidates):
                let labels = candidates.map { "\($0.displayName)(\($0.projectId))" }
                throw SupervisorAutomationRuntimeError.projectAmbiguous(normalizedRef, labels)
            }
        }

        if let selectedProjectID = appModel?.selectedProjectId,
           selectedProjectID != AXProjectRegistry.globalHomeId,
           let project = allProjects().first(where: { $0.projectId == selectedProjectID }) {
            guard let ctx = projectContext(from: project) else {
                throw SupervisorAutomationRuntimeError.projectContextMissing(project.projectId)
            }
            return (project, ctx)
        }

        let projects = allProjects()
        if projects.count == 1, let project = projects.first {
            guard let ctx = projectContext(from: project) else {
                throw SupervisorAutomationRuntimeError.projectContextMissing(project.projectId)
            }
            return (project, ctx)
        }

        throw SupervisorAutomationRuntimeError.projectSelectionMissing
    }

    @discardableResult
    func ingestAutomationExternalTrigger(
        _ ingress: SupervisorAutomationExternalTriggerIngress,
        emitSystemMessage: Bool = false
    ) -> SupervisorAutomationExternalTriggerResult {
        let projectId = ingress.projectId.trimmingCharacters(in: .whitespacesAndNewlines)
        let triggerId = ingress.triggerId.trimmingCharacters(in: .whitespacesAndNewlines)
        let auditRef = automationExternalTriggerAuditRef(
            projectId: projectId,
            triggerId: triggerId,
            now: ingress.receivedAt
        )

        guard !projectId.isEmpty else {
            return SupervisorAutomationExternalTriggerResult(
                projectId: "",
                triggerId: triggerId,
                triggerType: ingress.triggerType,
                decision: .failClosed,
                reasonCode: "project_id_missing",
                runId: nil,
                auditRef: auditRef
            )
        }

        guard let project = allProjects().first(where: { $0.projectId == projectId }),
              let ctx = projectContext(from: project) else {
            return SupervisorAutomationExternalTriggerResult(
                projectId: projectId,
                triggerId: triggerId,
                triggerType: ingress.triggerType,
                decision: .failClosed,
                reasonCode: "project_context_missing",
                runId: nil,
                auditRef: auditRef
            )
        }

        return ingestAutomationExternalTrigger(
            ingress,
            for: project,
            ctx: ctx,
            auditRef: auditRef,
            emitSystemMessage: emitSystemMessage
        )
    }

    @discardableResult
    func serviceAutomationScheduleTriggers(
        now: Date = Date(),
        emitSystemMessage: Bool = false
    ) -> [SupervisorAutomationExternalTriggerResult] {
        let projects = allProjects()
        guard !projects.isEmpty else { return [] }

        var results: [SupervisorAutomationExternalTriggerResult] = []
        for project in projects {
            guard let ctx = projectContext(from: project) else { continue }
            guard automationProjectHasBlockingRun(ctx) == false else { continue }
            guard let config = try? AXProjectStore.loadOrCreateConfig(for: ctx),
                  let recipe = config.activeAutomationRecipe,
                  recipe.lifecycleState == .ready else {
                continue
            }

            let scheduleTriggerIds = automationTriggerIds(from: recipe.triggerRefs, matching: .schedule)
            guard !scheduleTriggerIds.isEmpty else { continue }

            let projectToken = normalizedLookupKey(project.displayName).isEmpty
                ? normalizedLookupKey(project.projectId)
                : normalizedLookupKey(project.displayName)

            for triggerId in scheduleTriggerIds {
                let intervalSec = automationScheduleMinimumInterval(for: triggerId)
                let windowStart = Int(floor(now.timeIntervalSince1970 / Double(intervalSec)) * Double(intervalSec))
                let dedupeKey = automationExternalTriggerDeterministicDigest(
                    stable: "schedule|\(project.projectId)|\(triggerId)|\(windowStart)"
                )
                if automationExternalTriggerReplaySeen(
                    projectId: project.projectId,
                    dedupeKey: dedupeKey,
                    ctx: ctx
                ) {
                    continue
                }
                if let lastAcceptedAt = automationExternalTriggerLastAcceptedAt(
                    projectId: project.projectId,
                    triggerId: triggerId,
                    ctx: ctx
                ),
                   now.timeIntervalSince1970 - lastAcceptedAt < Double(intervalSec) {
                    continue
                }

                let triggerToken = xtAutomationActionToken(triggerId, fallback: "schedule")
                let ingress = SupervisorAutomationExternalTriggerIngress(
                    projectId: project.projectId,
                    triggerId: triggerId,
                    triggerType: .schedule,
                    source: .timer,
                    payloadRef: "local://supervisor/scheduler_poll/\(projectToken)/\(triggerToken)/\(windowStart)",
                    dedupeKey: dedupeKey,
                    receivedAt: now,
                    ingressChannel: "scheduler_poll"
                )
                let result = ingestAutomationExternalTrigger(
                    ingress,
                    for: project,
                    ctx: ctx,
                    auditRef: automationExternalTriggerAuditRef(
                        projectId: project.projectId,
                        triggerId: triggerId,
                        now: now
                    ),
                    emitSystemMessage: emitSystemMessage
                )
                results.append(result)
                if result.decision == .run {
                    break
                }
            }
        }

        return results
    }

    @discardableResult
    func serviceHubConnectorIngressReceiptsForTesting(
        _ snapshot: HubIPCClient.ConnectorIngressSnapshot,
        now: Date = Date(),
        emitSystemMessage: Bool = false
    ) -> [SupervisorAutomationExternalTriggerResult] {
        connectorIngressSnapshot = snapshot
        connectorIngressLastSuccessAt = max(now.timeIntervalSince1970, snapshot.updatedAtMs / 1000.0)
        return serviceHubConnectorIngressReceipts(now: now, emitSystemMessage: emitSystemMessage)
    }

    @discardableResult
    private func serviceHubConnectorIngressReceipts(
        now: Date = Date(),
        emitSystemMessage: Bool = false
    ) -> [SupervisorAutomationExternalTriggerResult] {
        guard let snapshot = connectorIngressSnapshot else { return [] }

        let snapshotUpdatedAtSec: TimeInterval = {
            let ms = max(0, snapshot.updatedAtMs)
            if ms > 0 {
                return ms / 1000.0
            }
            return connectorIngressLastSuccessAt
        }()
        if snapshotUpdatedAtSec > 0, now.timeIntervalSince1970 - snapshotUpdatedAtSec > schedulerSnapshotStaleSec {
            return []
        }

        let projectMap = allProjects().reduce(into: [String: AXProjectEntry]()) { partialResult, project in
            partialResult[project.projectId] = project
        }
        guard !projectMap.isEmpty else { return [] }

        let receipts = snapshot.items.sorted { lhs, rhs in
            if lhs.receivedAtMs != rhs.receivedAtMs {
                return lhs.receivedAtMs < rhs.receivedAtMs
            }
            return lhs.receiptId.localizedCaseInsensitiveCompare(rhs.receiptId) == .orderedAscending
        }

        var results: [SupervisorAutomationExternalTriggerResult] = []
        var blockedProjects: Set<String> = []

        for receipt in receipts {
            let projectId = receipt.projectId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !projectId.isEmpty else { continue }
            guard blockedProjects.contains(projectId) == false else { continue }
            guard let project = projectMap[projectId],
                  let ctx = projectContext(from: project) else {
                continue
            }
            let dedupeKey = hubConnectorIngressDedupeKey(for: receipt)
            if automationExternalTriggerReplaySeen(
                projectId: projectId,
                dedupeKey: dedupeKey,
                ctx: ctx
            ) {
                continue
            }
            let resolution = resolveHubConnectorIngressReceipt(receipt, ctx: ctx, fallbackNow: now)
            switch resolution {
            case .route(let ingress):
                let result = ingestAutomationExternalTrigger(
                    ingress,
                    for: project,
                    ctx: ctx,
                    auditRef: automationExternalTriggerAuditRef(
                        projectId: projectId,
                        triggerId: ingress.triggerId,
                        now: ingress.receivedAt
                    ),
                    emitSystemMessage: emitSystemMessage
                )
                results.append(result)
                announceHubConnectorIngressReceiptResult(
                    receipt,
                    result: result,
                    projectName: project.displayName
                )
                if result.decision == .run || result.decision == .hold {
                    blockedProjects.insert(projectId)
                }
            case .failClosed(let ingress, let reasonCode):
                let result = recordAutomationExternalTriggerDecision(
                    ingress: ingress,
                    decision: .failClosed,
                    reasonCode: reasonCode,
                    runId: nil,
                    auditRef: automationExternalTriggerAuditRef(
                        projectId: projectId,
                        triggerId: ingress.triggerId,
                        now: ingress.receivedAt
                    ),
                    ctx: ctx,
                    emitSystemMessage: emitSystemMessage
                )
                results.append(result)
                announceHubConnectorIngressReceiptResult(
                    receipt,
                    result: result,
                    projectName: project.displayName
                )
            }
        }

        return results
    }

    @discardableResult
    func serviceOperatorChannelXTCommandsForTesting(
        _ snapshot: HubIPCClient.OperatorChannelXTCommandSnapshot,
        resultsSnapshot: HubIPCClient.OperatorChannelXTCommandResultSnapshot? = nil,
        now: Date = Date()
    ) -> [HubIPCClient.OperatorChannelXTCommandResultItem] {
        serviceOperatorChannelXTCommands(
            snapshot,
            resultsSnapshot: resultsSnapshot,
            now: now
        )
    }

    func executeOperatorChannelXTCommandForTesting(
        _ command: HubIPCClient.OperatorChannelXTCommandItem,
        project: AXProjectEntry,
        now: Date = Date()
    ) -> HubIPCClient.OperatorChannelXTCommandResultItem {
        executeOperatorChannelXTCommand(
            command,
            projectMap: [project.projectId: project],
            now: now
        )
    }

    @discardableResult
    private func serviceOperatorChannelXTCommands(
        _ snapshot: HubIPCClient.OperatorChannelXTCommandSnapshot,
        resultsSnapshot: HubIPCClient.OperatorChannelXTCommandResultSnapshot?,
        now: Date = Date()
    ) -> [HubIPCClient.OperatorChannelXTCommandResultItem] {
        let snapshotUpdatedAtSec: TimeInterval = {
            let ms = max(0, snapshot.updatedAtMs)
            if ms > 0 {
                return ms / 1000.0
            }
            return now.timeIntervalSince1970
        }()
        if snapshotUpdatedAtSec > 0, now.timeIntervalSince1970 - snapshotUpdatedAtSec > schedulerSnapshotStaleSec {
            return []
        }

        let completedCommandIDs = Set(
            (resultsSnapshot?.items ?? []).map { $0.commandId.trimmingCharacters(in: .whitespacesAndNewlines) }
                .filter { !$0.isEmpty }
        )
        let projectMap = allProjects().reduce(into: [String: AXProjectEntry]()) { partialResult, project in
            partialResult[project.projectId] = project
        }
        guard !projectMap.isEmpty else { return [] }

        let commands = snapshot.items.sorted { lhs, rhs in
            if lhs.createdAtMs != rhs.createdAtMs {
                return lhs.createdAtMs < rhs.createdAtMs
            }
            return lhs.commandId.localizedCaseInsensitiveCompare(rhs.commandId) == .orderedAscending
        }

        var outputs: [HubIPCClient.OperatorChannelXTCommandResultItem] = []
        for command in commands {
            let commandID = command.commandId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !commandID.isEmpty else { continue }
            guard !completedCommandIDs.contains(commandID) else { continue }

            let result = executeOperatorChannelXTCommand(
                command,
                projectMap: projectMap,
                now: now
            )
            outputs.append(result)
            _ = HubIPCClient.appendOperatorChannelXTCommandResult(result)
        }

        return outputs
    }

    private func executeOperatorChannelXTCommand(
        _ command: HubIPCClient.OperatorChannelXTCommandItem,
        projectMap: [String: AXProjectEntry],
        now: Date
    ) -> HubIPCClient.OperatorChannelXTCommandResultItem {
        let commandID = command.commandId.trimmingCharacters(in: .whitespacesAndNewlines)
        let requestID = command.requestId.trimmingCharacters(in: .whitespacesAndNewlines)
        let actionName = command.actionName.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let projectID = command.projectId.trimmingCharacters(in: .whitespacesAndNewlines)
        let resolvedDeviceID = command.resolvedDeviceId.trimmingCharacters(in: .whitespacesAndNewlines)
        let createdAtMs = max(0, command.createdAtMs)
        let completedAtMs = now.timeIntervalSince1970 * 1000.0
        let auditRef = command.auditRef.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? "audit-operator-channel-xt-command-\(commandID)"
            : command.auditRef.trimmingCharacters(in: .whitespacesAndNewlines)

        func finalize(
            status: String,
            denyCode: String = "",
            detail: String,
            runId: String = ""
        ) -> HubIPCClient.OperatorChannelXTCommandResultItem {
            HubIPCClient.OperatorChannelXTCommandResultItem(
                commandId: commandID,
                requestId: requestID,
                actionName: actionName,
                projectId: projectID,
                resolvedDeviceId: resolvedDeviceID,
                status: status,
                denyCode: denyCode,
                detail: detail,
                runId: runId,
                createdAtMs: createdAtMs,
                completedAtMs: completedAtMs,
                auditRef: auditRef
            )
        }

        guard actionName == "deploy.plan" else {
            let result = finalize(
                status: "failed",
                denyCode: "xt_command_action_not_supported_yet",
                detail: "xt command action not supported yet"
            )
            announceOperatorChannelXTCommandResult(
                command,
                result: result,
                projectName: nil
            )
            return result
        }

        guard let project = projectMap[projectID],
              let ctx = projectContext(from: project) else {
            let result = finalize(
                status: "failed",
                denyCode: "project_context_missing",
                detail: "project context missing"
            )
            announceOperatorChannelXTCommandResult(
                command,
                result: result,
                projectName: nil
            )
            return result
        }

        do {
            let config = try AXProjectStore.loadOrCreateConfig(for: ctx)
            let boundDeviceID = config.trustedAutomationDeviceId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !boundDeviceID.isEmpty, boundDeviceID == resolvedDeviceID else {
                let result = finalize(
                    status: "failed",
                    denyCode: "trusted_automation_project_not_bound",
                    detail: "trusted automation project not bound to routed device"
                )
                AXProjectStore.appendRawLog(
                    [
                        "type": "operator_channel_xt_command",
                        "phase": "failed",
                        "created_at": now.timeIntervalSince1970,
                        "command_id": commandID,
                        "request_id": requestID,
                        "action_name": actionName,
                        "provider": command.provider,
                        "conversation_id": command.conversationId,
                        "thread_key": command.threadKey,
                        "resolved_device_id": resolvedDeviceID,
                        "deny_code": result.denyCode,
                        "detail": result.detail,
                        "audit_ref": auditRef
                    ],
                    for: ctx
                )
                appendRecentEvent("operator channel xt command failed: \(project.projectId) -> \(actionName) (\(result.denyCode))")
                announceOperatorChannelXTCommandResult(
                    command,
                    result: result,
                    projectName: project.displayName
                )
                return result
            }

            let request = try makeOperatorChannelDeployPlanRequest(
                for: project,
                ctx: ctx,
                command: command
            )
            let prepared = try prepareAutomationRun(
                for: ctx,
                request: request,
                emitSystemMessage: false
            )
            let result = finalize(
                status: "prepared",
                detail: "automation prepared",
                runId: prepared.launchRef
            )
            AXProjectStore.appendRawLog(
                [
                    "type": "operator_channel_xt_command",
                    "phase": "prepared",
                    "created_at": now.timeIntervalSince1970,
                    "command_id": commandID,
                    "request_id": requestID,
                    "action_name": actionName,
                    "provider": command.provider,
                    "conversation_id": command.conversationId,
                    "thread_key": command.threadKey,
                    "resolved_device_id": resolvedDeviceID,
                    "run_id": prepared.launchRef,
                    "audit_ref": auditRef
                ],
                for: ctx
            )
            appendRecentEvent("operator channel xt command prepared: \(project.projectId) -> \(prepared.launchRef)")
            announceOperatorChannelXTCommandResult(
                command,
                result: result,
                projectName: project.displayName
            )
            return result
        } catch {
            let denyCode = operatorChannelXTCommandReasonCode(from: error)
            let result = finalize(
                status: "failed",
                denyCode: denyCode,
                detail: denyCode
            )
            AXProjectStore.appendRawLog(
                [
                    "type": "operator_channel_xt_command",
                    "phase": "failed",
                    "created_at": now.timeIntervalSince1970,
                    "command_id": commandID,
                    "request_id": requestID,
                    "action_name": actionName,
                    "provider": command.provider,
                    "conversation_id": command.conversationId,
                    "thread_key": command.threadKey,
                    "resolved_device_id": resolvedDeviceID,
                    "deny_code": denyCode,
                    "detail": String(describing: error),
                    "audit_ref": auditRef
                ],
                for: ctx
            )
            appendRecentEvent("operator channel xt command failed: \(project.projectId) -> \(actionName) (\(denyCode))")
            announceOperatorChannelXTCommandResult(
                command,
                result: result,
                projectName: project.displayName
            )
            return result
        }
    }

    private func announceOperatorChannelXTCommandResult(
        _ command: HubIPCClient.OperatorChannelXTCommandItem,
        result: HubIPCClient.OperatorChannelXTCommandResultItem,
        projectName: String?
    ) {
        let provider = operatorChannelProviderDisplayName(command.provider)
        let action = operatorChannelActionDisplayName(command.actionName)
        let projectToken = operatorChannelProjectDisplayName(projectName, projectID: result.projectId)
        let denyDisplay = operatorChannelXTCommandReasonDisplayName(
            result.denyCode.isEmpty ? result.detail : result.denyCode
        )

        let systemMessage: String
        let voiceText: String
        let title: String
        let body: String
        let voiceTrigger: SupervisorVoiceJobTrigger
        let voicePriority: SupervisorVoiceJobPriority

        switch result.status {
        case "prepared":
            let runToken = result.runId.trimmingCharacters(in: .whitespacesAndNewlines)
            systemMessage = "已接收来自 \(provider) 的 XT 指令：\(projectToken) -> \(action) 已准备执行（run=\(runToken.isEmpty ? "n/a" : runToken)）。"
            voiceText = "\(provider) 的 XT 指令我已经备好了。\(projectToken) 的\(action)马上就能接着跑。"
            title = "🛰️ \(provider) 指令已在 XT 准备"
            body = """
project=\(projectToken)
action=\(action)
status=\(result.status)
run=\(runToken.isEmpty ? "n/a" : runToken)
audit=\(result.auditRef)
"""
            voiceTrigger = .completed
            voicePriority = .normal
        default:
            let denyToken = result.denyCode.trimmingCharacters(in: .whitespacesAndNewlines)
            systemMessage = "来自 \(provider) 的 XT 指令失败闭锁：\(projectToken) -> \(action)（deny=\(denyToken.isEmpty ? "unknown" : denyToken)）。"
            voiceText = "\(provider) 的 XT 指令我先按失败闭锁拦下了。\(projectToken) 暂时不能做\(action)。原因：\(denyDisplay)。"
            title = "⛔️ \(provider) 指令在 XT 失败闭锁"
            body = """
project=\(projectToken)
action=\(action)
status=\(result.status)
deny=\(denyToken.isEmpty ? "unknown" : denyToken)
detail=\(result.detail)
audit=\(result.auditRef)
"""
            voiceTrigger = .blocked
            voicePriority = .interrupt
        }

        addSystemMessage(systemMessage)
        _ = speakOperatorChannelXTCommandUpdate(
            text: voiceText,
            trigger: voiceTrigger,
            priority: voicePriority,
            commandId: result.commandId,
            detailToken: result.status == "prepared"
                ? result.runId
                : (result.denyCode.isEmpty ? result.detail : result.denyCode)
        )

        guard backgroundSupervisorServicesEnabled else { return }
        let dedupeKey = "x_terminal_operator_channel_xt_command_\(result.commandId)_\(result.status)_\(result.denyCode)"
        let actionURL = resumeProjectActionURL(projectId: result.projectId)
        guard shouldMirrorNotificationToHub(actionURL: actionURL) else {
            HubIPCClient.removeNotification(dedupeKey: dedupeKey)
            return
        }
        HubIPCClient.pushNotification(
            source: "X-Terminal",
            title: title,
            body: body,
            dedupeKey: dedupeKey,
            actionURL: actionURL,
            unread: true
        )
    }

    @discardableResult
    private func speakOperatorChannelXTCommandUpdate(
        text: String,
        trigger: SupervisorVoiceJobTrigger,
        priority: SupervisorVoiceJobPriority,
        commandId: String,
        detailToken: String
    ) -> SupervisorSpeechSynthesizer.Outcome {
        let script = conciseVoiceReplyScript(text)
        guard !script.isEmpty else { return .suppressed("empty_script") }
        let detail = detailToken.trimmingCharacters(in: .whitespacesAndNewlines)
        let dedupeKey = "operator-xt-command:\(commandId):\(trigger.rawValue):\(detail.isEmpty ? "none" : detail)"
        let job = SupervisorVoiceTTSJob(
            trigger: trigger,
            priority: priority,
            script: script,
            dedupeKey: dedupeKey
        )
        return dispatchSupervisorVoiceJob(
            job,
            preferences: currentVoicePreferences(),
            source: "operator_xt_command:\(commandId)",
            suppressRapidSameSourceRepeat: true,
            cancelPendingHeartbeat: true
        )
    }

    private func announceHubConnectorIngressReceiptResult(
        _ receipt: HubIPCClient.ConnectorIngressReceipt,
        result: SupervisorAutomationExternalTriggerResult,
        projectName: String
    ) {
        let provider = remoteChannelProviderDisplayName(receipt.connector)
        let projectToken = operatorChannelProjectDisplayName(projectName, projectID: result.projectId)
        let ingress = hubConnectorIngressDisplayName(receipt, triggerType: result.triggerType)
        let reasonToken = result.reasonCode.trimmingCharacters(in: .whitespacesAndNewlines)
        let reasonDisplay = hubConnectorIngressReasonDisplayName(reasonToken)

        let systemMessage: String
        let voiceText: String
        let title: String
        let body: String
        let voiceTrigger: SupervisorVoiceJobTrigger
        let voicePriority: SupervisorVoiceJobPriority

        switch result.decision {
        case .run:
            let runToken = result.runId?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            systemMessage = "已接收来自 \(provider) 的 Hub 入口：\(projectToken) -> \(ingress) 已转入 XT automation（run=\(runToken.isEmpty ? "n/a" : runToken)）。"
            voiceText = "\(provider) 的远程入口我已经接进 XT 继续处理了。项目是 \(projectToken)，入口是\(ingress)。"
            title = "🛰️ \(provider) 入口已转入 XT"
            body = """
project=\(projectToken)
ingress=\(ingress)
decision=\(result.decision.rawValue)
run=\(runToken.isEmpty ? "n/a" : runToken)
audit=\(result.auditRef)
"""
            voiceTrigger = .completed
            voicePriority = .normal
        case .hold:
            let reasonSummary = reasonDisplay.isEmpty ? "项目已有进行中的 automation" : reasonDisplay
            systemMessage = "来自 \(provider) 的 Hub 入口暂缓：\(projectToken) -> \(ingress)（reason=\(reasonToken.isEmpty ? "unknown" : reasonToken)）。"
            voiceText = "\(provider) 的远程入口我先暂缓了。\(projectToken) 这边还有自动流程在跑。原因：\(reasonSummary)。"
            title = "⏸️ \(provider) 入口在 XT 暂缓"
            body = """
project=\(projectToken)
ingress=\(ingress)
decision=\(result.decision.rawValue)
reason=\(reasonToken.isEmpty ? "unknown" : reasonToken)
audit=\(result.auditRef)
"""
            voiceTrigger = .blocked
            voicePriority = .interrupt
        case .failClosed:
            systemMessage = "来自 \(provider) 的 Hub 入口失败闭锁：\(projectToken) -> \(ingress)（reason=\(reasonToken.isEmpty ? "unknown" : reasonToken)）。"
            voiceText = "\(provider) 的远程入口我先按失败闭锁拦下了。\(projectToken) 暂时不能接这个\(ingress)。原因：\(reasonDisplay)。"
            title = "⛔️ \(provider) 入口在 XT 失败闭锁"
            body = """
project=\(projectToken)
ingress=\(ingress)
decision=\(result.decision.rawValue)
reason=\(reasonToken.isEmpty ? "unknown" : reasonToken)
audit=\(result.auditRef)
"""
            voiceTrigger = .blocked
            voicePriority = .interrupt
        case .drop:
            return
        }

        addSystemMessage(systemMessage)
        _ = speakHubConnectorIngressUpdate(
            text: voiceText,
            trigger: voiceTrigger,
            priority: voicePriority,
            receiptId: receipt.receiptId,
            detailToken: result.runId ?? reasonToken
        )

        guard backgroundSupervisorServicesEnabled else { return }
        let dedupeKey = "x_terminal_hub_connector_ingress_\(receipt.receiptId)_\(result.decision.rawValue)_\(reasonToken)"
        let actionURL = resumeProjectActionURL(projectId: result.projectId)
        guard shouldMirrorNotificationToHub(actionURL: actionURL) else {
            HubIPCClient.removeNotification(dedupeKey: dedupeKey)
            return
        }
        HubIPCClient.pushNotification(
            source: "X-Terminal",
            title: title,
            body: body,
            dedupeKey: dedupeKey,
            actionURL: actionURL,
            unread: true
        )
    }

    @discardableResult
    private func speakHubConnectorIngressUpdate(
        text: String,
        trigger: SupervisorVoiceJobTrigger,
        priority: SupervisorVoiceJobPriority,
        receiptId: String,
        detailToken: String
    ) -> SupervisorSpeechSynthesizer.Outcome {
        let script = conciseVoiceReplyScript(text)
        guard !script.isEmpty else { return .suppressed("empty_script") }
        let detail = detailToken.trimmingCharacters(in: .whitespacesAndNewlines)
        let dedupeKey = "connector-ingress:\(receiptId):\(trigger.rawValue):\(detail.isEmpty ? "none" : detail)"
        let job = SupervisorVoiceTTSJob(
            trigger: trigger,
            priority: priority,
            script: script,
            dedupeKey: dedupeKey
        )
        return dispatchSupervisorVoiceJob(
            job,
            preferences: currentVoicePreferences(),
            source: "connector_ingress:\(receiptId)",
            suppressRapidSameSourceRepeat: true,
            cancelPendingHeartbeat: true
        )
    }

